window.RG_DATA["unit:03-pronouns"]={"id":"03-pronouns","num":3,"title":"PHẦN 3: Các đại từ nhân xưng và sở hữu ngôi thứ 3","vi":"Đại từ","ru":"Местоимение","icon":"👤","color":"#14b8a6","sections":[{"id":"03-s001","type":"exercise","title":"Bài 320 (Trang 155)","num":320,"blocks":[{"t":"para","text":"Đề bài: Đọc các câu văn. Xác định cách (case) và số của các đại từ in đậm (đã được thay bằng yêu cầu điền từ trong bài giải này). Giải thích sự hiện diện hoặc vắng mặt của chữ \"н\" ở đầu từ."},{"t":"para","text":"Giải thích ngữ pháp (Gợi ý trong khung trang 155):","b":1},{"t":"subhead","text":"Quy tắc thêm chữ \"н\":","b":1},{"t":"para","text":"Khi các đại từ nhân xưng ngôi thứ 3 (он, она́, оно́, они́) đứng sau giới từ (в, на, с, к, у, из-за, v.v.), ta phải thêm chữ н vào đầu đại từ."},{"t":"example","text":"Ví dụ: у него (của anh ấy), к ней (đến cô ấy), с ними (với họ)."},{"t":"para","text":"Tuyệt đối KHÔNG thêm \"н\" vào các đại từ sở hữu (его́, её, их) khi chúng đứng sau giới từ nhưng đi kèm với danh từ."},{"t":"example","text":"Ví dụ: у его́ сестры́ (ở chỗ chị gái anh ấy), к её до́му (đến nhà cô ấy)."},{"t":"para","text":"Giải chi tiết và Dịch:","b":1},{"t":"para","text":"a)","b":1},{"t":"para","text":"У него́ о́тпуск в ию́ле. У его́ сестры́ о́тпуск в ноябре́.","b":1},{"t":"example","text":"Dịch: Anh ấy có kỳ nghỉ vào tháng 7. Chị gái anh ấy có kỳ nghỉ vào tháng 11."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"У него́","vi":"Giới từ У + Đại từ nhân xưng он → Thêm н.","g":null},{"t":"vocab","ru":"У его́ сестры́","vi":"Giới từ У + Đại từ sở hữu его (bổ nghĩa cho сестры) → Không thêm н.","g":null},{"t":"para","text":"Из-за неё мы опозда́ли на по́езд. Из-за её медли́тельности мы прие́хали в аэропо́рт по́зже, чем плани́ровали.","b":1},{"t":"example","text":"Dịch: Tại cô ấy mà chúng tôi trễ tàu. Tại sự lề mề của cô ấy mà chúng tôi đến sân bay muộn hơn dự kiến."},{"t":"example","text":"Giải thích: Из-за неё (nhân xưng - có н). Из-за её (sở hữu - không н)."},{"t":"para","text":"О́коло них на земле́ сиде́ла соба́ка. У их ног сиде́л чёрный пу́дель.","b":1},{"t":"example","text":"Dịch: Cạnh họ có một con chó ngồi trên đất. Dưới chân họ có một con chó poodle đen ngồi."},{"t":"example","text":"Giải thích: Около них (nhân xưng - có н). У их (sở hữu - không н)."},{"t":"para","text":"б)","b":1},{"t":"para","text":"Мы прие́хали к нему́ в го́сти. Мы прие́хали в го́сти к его́ ро́дственникам.","b":1},{"t":"example","text":"Dịch: Chúng tôi đến làm khách chỗ anh ấy. Chúng tôi đến làm khách chỗ họ hàng của anh ấy."},{"t":"example","text":"Giải thích: к нему (nhân xưng - có н). к его (sở hữu - không н)."},{"t":"para","text":"Она́ всегда́ прихо́дит секу́нда в секу́нду, по ней мо́жно часы́ проверя́ть. Она́ огорчи́лась, но по её лицу́ ничего́ не́ было заме́тно.","b":1},{"t":"example","text":"Dịch: Cô ấy luôn đến chuẩn từng giây, có thể nhìn cô ấy mà chỉnh đồng hồ. Cô ấy buồn, nhưng trên gương mặt cô ấy không lộ vẻ gì."},{"t":"example","text":"Giải thích: по ней (nhân xưng - có н). по её (sở hữu - không н)."},{"t":"para","text":"Благодаря́ им мы зако́нчили рабо́ту во́время. Благодаря́ их по́мощи мы зако́нчили рабо́ту во́время.","b":1},{"t":"example","text":"Dịch: Nhờ họ mà chúng tôi xong việc đúng giờ. Nhờ sự giúp đỡ của họ mà chúng tôi xong việc đúng giờ."},{"t":"example","text":"Giải thích: Lưu ý: Sau các giới từ phái sinh như благодаря́, навстре́чу, вопреки́, согла́сно, đại từ nhân xưng ngôi thứ 3 thường không thêm н (theo quy tắc cổ điển), nhưng trong tiếng Nga hiện đại, việc thêm н hay không có thể dao động. Tuy nhiên, sách Glazunova (khung trang 155) lưu ý: \"Sau các giới từ благодаря, навстречу, вопреки, согласно, đại từ nhân xưng ngôi thứ 3 dùng không có н: навстречу ему, благодаря им\"."},{"t":"example","text":"Sửa lại theo sách: Благодаря́ им (không có н)."},{"t":"para","text":"в)","b":1},{"t":"para","text":"На него́ мо́жно положи́ться.","b":1},{"t":"example","text":"Dịch: Có thể tin cậy vào anh ấy."},{"t":"example","text":"Giải thích: На + он → него (có н)."},{"t":"para","text":"Ты всегда́ мо́жешь сосла́ться на его́ мне́ние.","b":1},{"t":"example","text":"Dịch: Bạn luôn có thể viện dẫn ý kiến của anh ấy."},{"t":"example","text":"Giải thích: Sở hữu его → không н."},{"t":"para","text":"Я поблагодари́л её за её сове́т.","b":1},{"t":"example","text":"Dịch: Tôi cảm ơn cô ấy vì lời khuyên của cô ấy."},{"t":"example","text":"Giải thích: её (sở hữu) → không н."},{"t":"para","text":"Не серди́сь на них, они́ не хоте́ли тебя́ оби́деть.","b":1},{"t":"example","text":"Dịch: Đừng giận họ, họ không muốn làm bạn tổn thương đâu."},{"t":"example","text":"Giải thích: На + они → них (có н)."},{"t":"para","text":"Я о́чень наде́юсь на их по́мощь.","b":1},{"t":"example","text":"Dịch: Tôi rất hy vọng vào sự giúp đỡ của họ."},{"t":"example","text":"Giải thích: Sở hữu их → không н."},{"t":"para","text":"г)","b":1},{"t":"para","text":"Мы просле́довали за ни́ми в ко́мнату. Наблюда́ть за их игро́й о́чень интере́сно.","b":1},{"t":"example","text":"Dịch: Chúng tôi đi theo họ vào phòng. Quan sát trò chơi của họ rất thú vị."},{"t":"example","text":"Giải thích: за ними (nhân xưng - có н). за их (sở hữu - không н)."},{"t":"para","text":"Мы бесе́довали с ней о́коло двух часо́в. Вчера́ я встре́тился с её нау́чным руководи́телем.","b":1},{"t":"example","text":"Dịch: Chúng tôi trò chuyện với cô ấy khoảng hai tiếng. Hôm qua tôi gặp người hướng dẫn khoa học của cô ấy."},{"t":"example","text":"Giải thích: с ней (nhân xưng - có н). с её (sở hữu - không н)."},{"t":"para","text":"Пе́ред ни́ми останови́лась маши́на.","b":1},{"t":"example","text":"Dịch: Một chiếc xe dừng lại trước mặt họ."},{"t":"example","text":"Giải thích: Перед + они → ними (có н)."},{"t":"para","text":"д)","b":1},{"t":"para","text":"По́сле того́ как карти́на э́того режиссёра получи́ла пе́рвую пре́мию, о нём написа́ли в газе́тах.","b":1},{"t":"example","text":"Dịch: Sau khi bộ phim của đạo diễn này nhận giải nhất, người ta đã viết về ông ấy trên báo."},{"t":"example","text":"Giải thích: О + он (Giới cách) → нём (có н)."},{"t":"para","text":"О его́ полёте на возду́шном ша́ре писа́ли в газе́тах.","b":1},{"t":"example","text":"Dịch: Người ta viết trên báo về chuyến bay của ông ấy trên khinh khí cầu."},{"t":"example","text":"Giải thích: Sở hữu его → không н."},{"t":"para","text":"При ней была́ ма́ленькая бе́лая су́мка.","b":1},{"t":"example","text":"Dịch: Bên cạnh cô ấy (cô ấy mang theo) có một chiếc túi trắng nhỏ."},{"t":"example","text":"Giải thích: При + она → ней (có н)."},{"t":"para","text":"При её подде́ржке ты мно́гого мо́жешь доби́ться.","b":1},{"t":"example","text":"Dịch: Với sự hỗ trợ của cô ấy, bạn có thể đạt được nhiều thứ."},{"t":"example","text":"Giải thích: Sở hữu её → không н."},{"t":"para","text":"Я узна́л в них свои́х шко́льных друзе́й. В их костю́мах не́ было ничего́ нео́бычного.","b":1},{"t":"example","text":"Dịch: Tôi nhận ra họ là bạn học cũ của mình. Trong trang phục của họ không có gì khác thường."},{"t":"example","text":"Giải thích: \"Я узнал в них...\" - Tôi nhận ra ở họ. Nếu là в них thì có н. Câu sau: В их (sở hữu) -> không н."}]},{"id":"03-s002","type":"exercise","title":"Bài 321 (Trang 156)","num":321,"blocks":[{"t":"example","text":"Đề bài: Điền vào chỗ trống các đại từ sở hữu его́ (của anh ấy), её (của cô ấy), их (của họ) phù hợp về nghĩa."},{"t":"para","text":"Giải thích ngữ pháp:","b":1},{"t":"para","text":"Các đại từ sở hữu ngôi thứ 3 (его́, её, их) không bao giờ thay đổi hình thức (không biến đổi theo cách/số/giống)."},{"t":"example","text":"Quan trọng: Khác với đại từ nhân xưng, đại từ sở hữu KHÔNG bao giờ thêm chữ н ở đầu, ngay cả khi đứng sau giới từ (Ví dụ: у его брата - ở chỗ anh trai của anh ấy)."},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"example","text":"Когда́ мы с мои́м но́вым знако́мым по́сле его́ о́тпуска верну́лись в го́род, я встре́тилась с его́ ро́дственниками.","b":1},{"t":"example","text":"Dịch: Khi tôi và người quen mới trở về thành phố sau kỳ nghỉ của anh ấy, tôi đã gặp gỡ những người họ hàng của anh ấy."},{"t":"example","text":"Ко мне до́лжный бы́ли прие́хать друзья́, незадо́лго до их прие́зда я снял до́мик на берегу́ мо́ря.","b":1},{"t":"example","text":"Dịch: Bạn bè sắp đến chỗ tôi, ngay trước khi họ đến (sự đến của họ), tôi đã thuê một ngôi nhà nhỏ bên bờ biển."},{"t":"example","text":"Я слу́шал её не о́чень внима́тельно, так как о её пробле́мах мне уже́ рассказа́ли.","b":1},{"t":"example","text":"Dịch: Tôi nghe cô ấy không chăm chú lắm, vì người ta đã kể cho tôi nghe về những vấn đề của cô ấy rồi."},{"t":"example","text":"Лицо́ молодо́го челове́ка на карти́не передава́ло вну́тренний его́ о́блик, са́мые значи́тельные черты́ его́ хара́ктера.","b":1},{"t":"example","text":"Dịch: Gương mặt chàng trai trẻ trong bức tranh truyền tải diện mạo nội tâm của anh ấy, những nét quan trọng nhất trong tính cách của anh ấy."},{"t":"example","text":"Я посмотре́л на него́ внима́тельно, но не уви́дел в его́ глаза́х насме́шки и успоко́ился.","b":1},{"t":"example","text":"Dịch: Tôi nhìn anh ấy chăm chú, nhưng không thấy sự chế giễu trong mắt anh ấy và tôi an tâm."},{"t":"example","text":"Моя́ ба́бушка была́ замеча́тельной расска́зчицей, в её расска́зах давно́ знако́мые сюже́ты преобража́лись, обраста́ли подро́бностями, станови́лись я́ркими и интере́сными.","b":1},{"t":"example","text":"Dịch: Bà tôi là một người kể chuyện tuyệt vời, trong những câu chuyện của bà, các cốt truyện quen thuộc từ lâu đã biến đổi, thêm thắt chi tiết, trở nên sống động và thú vị."},{"t":"example","text":"И в её сме́хе была́ де́тская непосре́дственность и теплота́.","b":1},{"t":"example","text":"Dịch: Và trong tiếng cười của bà (cô ấy) có sự hồn nhiên và ấm áp trẻ thơ."},{"t":"example","text":"Ко мне до́лжны бы́ли прие́хать колле́ги, и я наде́ялся, что с их прие́здом жизнь моя́ изме́нится к лу́чшему.","b":1},{"t":"example","text":"Dịch: Các đồng nghiệp sắp đến chỗ tôi, và tôi hy vọng rằng với sự đến của họ, cuộc sống của tôi sẽ thay đổi tốt hơn."},{"t":"example","text":"В соревнова́ниях уча́стие мно́гие спорти́вные клу́бы го́рода; в их подгото́вке при́няли уча́стие мно́гие.","b":1},{"t":"example","text":"Dịch: Nhiều câu lạc bộ thể thao thành phố tham gia thi đấu; nhiều người đã tham gia vào công tác chuẩn bị của họ (của các CLB)."},{"t":"example","text":"Э́то был ещё совсе́м не ста́рый челове́к, на его́ лице́ почти́ не́ было морщи́н.","b":1},{"t":"example","text":"Dịch: Đó là một người chưa già chút nào, trên gương mặt ông ấy hầu như không có nếp nhăn."},{"t":"example","text":"Они́ должны́ встре́титься в суббо́ту, по́сле их встре́чи мы узна́ем, что они́ собира́ются предприня́ть.","b":1},{"t":"example","text":"Dịch: Họ phải gặp nhau vào thứ Bảy, sau cuộc gặp của họ, chúng ta sẽ biết họ định làm gì."},{"t":"example","text":"У са́мого бе́рега я встре́тил де́вушку, у кото́рой спроси́л доро́гу; из её отве́тов я узна́л, что идти́ мне ещё придётся дово́льно до́лго.","b":1},{"t":"example","text":"Dịch: Ngay sát bờ sông tôi gặp một cô gái và hỏi đường; từ những câu trả lời của cô ấy, tôi biết rằng mình sẽ phải đi bộ khá lâu nữa."},{"t":"example","text":"В бума́гах мое́й ма́тери невозмо́жно ничего́ найти́, наприме́р, после́днее письмо́ я обнару́жил под её докуме́нтами среди́ квита́нций на опла́ту телефо́нных разгово́ров.","b":1},{"t":"example","text":"Dịch: Trong đống giấy tờ của mẹ tôi không thể tìm thấy gì cả, ví dụ, tôi đã tìm thấy lá thư cuối cùng nằm dưới các tài liệu của bà ấy, giữa các hóa đơn thanh toán điện thoại."},{"t":"example","text":"Они́ всегда́ встреча́ли меня́ с и́скренней ра́достью, в их отноше́нии ко мне чу́вствовалась роди́тельская забо́та.","b":1},{"t":"example","text":"Dịch: Họ luôn đón tiếp tôi với niềm vui chân thành, trong thái độ của họ đối với tôi cảm nhận được sự quan tâm như cha mẹ."},{"t":"example","text":"Он разгова́ривал в гости́ной со свои́ми гостя́ми, под звук их голосо́в я засну́л.","b":1},{"t":"example","text":"Dịch: Anh ấy trò chuyện trong phòng khách với những vị khách của mình, tôi đã ngủ thiếp đi trong tiếng giọng nói của họ."},{"t":"example","text":"То, что они́ промолча́ли и не заступи́лись за своего́ дру́га, пусть оста́нется на их со́вести.","b":1},{"t":"example","text":"Dịch: Việc họ im lặng và không bênh vực bạn mình, hãy để điều đó lương tâm họ tự phán xét."},{"t":"example","text":"При его́ обы́чном легкомы́сленном отноше́нии к де́лу она́ вряд ли спра́вится с э́той рабо́той. (Lưu ý: Câu này có sự mâu thuẫn về giới tính trong sách gốc она - cô ấy, nhưng его - của anh ấy. Nếu chủ ngữ là cô ấy thì phải là её thái độ. Nếu nói về một người nam thì dùng его. Dịch theo его):"},{"t":"example","text":"Dịch: Với thái độ hời hợt thường thấy của anh ấy đối với công việc, cô ấy khó mà hoàn thành việc này (hoặc: Với thái độ... của anh ấy, anh ấy khó mà...)."},{"t":"example","text":"Неда́вно нам пришла́ и рассказа́ла мне обо всём, из её слов ста́ло я́сно, что гото́вится но́вая экспеди́ция.","b":1},{"t":"example","text":"Dịch: Gần đây (cô ấy) đã đến và kể cho tôi mọi chuyện, từ những lời của cô ấy đã rõ ràng là một chuyến thám hiểm mới đang được chuẩn bị."}]},{"id":"03-s003","type":"exercise","title":"Bài 322 (Trang 157)","num":322,"blocks":[{"t":"para","text":"Đề bài: Mở ngoặc, sử dụng hình thức cần thiết của đại từ nhân xưng hoặc đại từ sở hữu."},{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"vocab","ru":"Đại từ nhân xưng (Личное местоимение)","vi":"он, она́, они́ → Thêm н sau giới từ nguyên thủy (у него́, к ней, с ни́ми).","g":null},{"t":"vocab","ru":"Đại từ sở hữu (Притяжательное местоимение)","vi":"его́, её, их → KHÔNG thêm н (у его́ бра́та, к её сестре́).","g":null},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"example","text":"Ду́маю, с (ним) у тебя́ не бу́дет хлопо́т. (с ним - nhân xưng: với anh ấy)."},{"t":"example","text":"Dịch: Tôi nghĩ, với anh ấy bạn sẽ không gặp rắc rối gì."},{"t":"example","text":"Ви́дишь де́рево, под (ним) мы мо́жем пережда́ть дождь. (под ним - nhân xưng: dưới nó)."},{"t":"example","text":"Dịch: Bạn thấy cái cây kia không, chúng ta có thể trú mưa dưới nó."},{"t":"vocab","ru":"До (его́) до́ма е́хать ещё два часа́. (до его дома - sở hữu","vi":"đến nhà của anh ấy).","g":null},{"t":"example","text":"Dịch: Còn phải đi hai tiếng nữa mới đến nhà anh ấy."},{"t":"example","text":"Мы слы́шали от (него́) мно́го интере́сного. (от него - nhân xưng: từ anh ấy)."},{"t":"example","text":"Dịch: Chúng tôi đã nghe được nhiều điều thú vị từ anh ấy."},{"t":"vocab","ru":"Я уста́л от (его́) вопро́сов. (от его вопросов - sở hữu","vi":"từ các câu hỏi của anh ấy).","g":null},{"t":"example","text":"Dịch: Tôi mệt mỏi vì những câu hỏi của anh ấy."},{"t":"vocab","ru":"С (ней) всегда́ интере́сно. (с ней - nhân xưng","vi":"với cô ấy).","g":null},{"t":"example","text":"Dịch: Ở bên cô ấy lúc nào cũng thú vị."},{"t":"example","text":"Мы собра́лись пе́ред (её) днём рожде́ния, что́бы обсуди́ть пода́рки. (перед её днём... - sở hữu: trước sinh nhật cô ấy)."},{"t":"example","text":"Dịch: Chúng tôi tụ tập trước sinh nhật cô ấy để thảo luận về quà tặng."},{"t":"example","text":"Я могу́ вме́сто (его́) вы́полнить э́ту рабо́ту. (вместо него - nhân xưng: thay cho anh ấy). Lưu ý: Вместо yêu cầu Giới cách (Genitive) và thêm н cho đại từ nhân xưng."},{"t":"example","text":"Dịch: Tôi có thể làm việc này thay anh ấy."},{"t":"example","text":"Согла́сно (их) распоряже́нию рабо́ту сле́дует нача́ть за́втра. (согласно их распоряжению - sở hữu: theo lệnh của họ)."},{"t":"example","text":"Dịch: Theo lệnh của họ, công việc phải bắt đầu vào ngày mai."},{"t":"example","text":"Под (их) руково́дством все иссле́дования бы́ли завершены́ в срок. (под их руководством - sở hữu: dưới sự hướng dẫn của họ)."},{"t":"example","text":"Dịch: Dưới sự hướng dẫn của họ, mọi nghiên cứu đã hoàn thành đúng hạn."},{"t":"example","text":"Я зна́ю язы́к хорошо́, то есть могу́ говори́ть; (на нём). (на нём - nhân xưng: bằng nó/ngôn ngữ đó)."},{"t":"example","text":"Dịch: Tôi biết ngôn ngữ này tốt, tức là tôi có thể nói bằng nó."},{"t":"example","text":"В (её) прису́тствии я чу́вствую себя́ неуве́ренно. (в её присутствии - sở hữu: trong sự hiện diện của cô ấy)."},{"t":"example","text":"Dịch: Trước mặt cô ấy, tôi cảm thấy không tự tin."},{"t":"vocab","ru":"Ключи́ мы нашли́ в (её) портфе́ле. (в её портфеле - sở hữu","vi":"trong cặp của cô ấy).","g":null},{"t":"example","text":"Dịch: Chúng tôi tìm thấy chìa khóa trong cặp cô ấy."},{"t":"example","text":"Я бою́сь, что от (её) по́мощи никако́го то́лка не бу́дет. (от её помощи - sở hữu: từ sự giúp đỡ của cô ấy)."},{"t":"example","text":"Dịch: Tôi e rằng sự giúp đỡ của cô ấy sẽ chẳng có ích gì."},{"t":"example","text":"Мы до́лжны с (ней) обсуди́ть на сле́дующей неде́ле. (с ней - nhân xưng: với cô ấy)."},{"t":"example","text":"Dịch: Chúng ta phải thảo luận với cô ấy vào tuần tới."},{"t":"example","text":"Доро́га проходи́ла че́рез (его́) уча́сток. (через его участок - sở hữu: qua khu đất của ông ấy)."},{"t":"example","text":"Dịch: Con đường chạy qua khu đất của ông ấy."},{"t":"vocab","ru":"Я сде́лал э́то по (её) про́сьбе. (по её просьбе - sở hữu","vi":"theo yêu cầu của cô ấy).","g":null},{"t":"example","text":"Dịch: Tôi làm điều này theo yêu cầu của cô ấy."},{"t":"example","text":"Несмотря́ на (её) отсу́тствие, нам удало́сь узна́ть мно́го но́вого. (на её отсутствие - sở hữu: sự vắng mặt của cô ấy)."},{"t":"example","text":"Dịch: Bất chấp sự vắng mặt của cô ấy, chúng tôi vẫn tìm hiểu được nhiều điều mới. (Nếu ý là \"bất chấp cô ấy\" thì là несмотря на неё - nhưng ngữ cảnh là \"sự vắng mặt\")."},{"t":"example","text":"Незадо́лго до (её) прие́зда я перешёл на другу́ю рабо́ту. (до её приезда - sở hữu: trước khi cô ấy đến)."},{"t":"example","text":"Dịch: Không lâu trước khi cô ấy đến, tôi đã chuyển sang công việc khác."},{"t":"example","text":"Ско́ро экза́мены, и к (ним) на́до гото́виться. (к ним - nhân xưng: cho chúng/các kỳ thi)."},{"t":"example","text":"Dịch: Sắp thi rồi, và cần phải chuẩn bị cho chúng."}]},{"id":"03-s004","type":"exercise","title":"Bài 323 (Trang 157)","num":323,"blocks":[{"t":"example","text":"Đề bài: Thay thế các từ được in đậm bằng các đại từ nhân xưng ngôi thứ 3 (он, она, они) hoặc đại từ sở hữu (его, её, их) phù hợp."},{"t":"example","text":"У меня́ к твое́й сестре́ (к ней) не́сколько вопро́сов.","b":1},{"t":"example","text":"Dịch: Tôi có vài câu hỏi cho cô ấy (chị gái bạn)."},{"t":"example","text":"Мы познако́мились с сы́ном на́ших друзе́й (с ним) в про́шлом году́.","b":1},{"t":"example","text":"Dịch: Chúng tôi đã làm quen với cậu ấy (con trai bạn bè) năm ngoái."},{"t":"vocab","ru":"Навстре́чу го́стье (ей) вы́шел хозя́ин кварти́ры. (Lưu ý","vi":"навстречу yêu cầu Cách 3, và theo quy tắc trong sách trang 155, sau навстречу không thêm н → ей).","g":null},{"t":"example","text":"Dịch: Chủ nhà bước ra đón cô ấy (vị khách nữ)."},{"t":"example","text":"Мы верну́лись от роди́телей (от них) по́здно ве́чером.","b":1},{"t":"example","text":"Dịch: Chúng tôi trở về từ chỗ họ (bố mẹ) vào tối muộn."},{"t":"example","text":"От до́ма (от него́) мои́х друзе́й до теа́тра е́хать не бо́лее двадцати́ мину́т.","b":1},{"t":"example","text":"Dịch: Từ đó/nó (nhà bạn tôi) đến nhà hát đi xe không quá 20 phút."},{"t":"example","text":"Я всё сде́лал пра́вильно благодаря́ сове́там друзе́й (благодаря́ им). (Theo sách: không thêm н sau благодаря)."},{"t":"example","text":"Dịch: Tôi đã làm đúng mọi thứ nhờ họ (lời khuyên của bạn bè)."},{"t":"example","text":"Я почти́ не знако́м с ва́шей племя́нницей (с ней) и с му́жем ва́шей племя́нницы (с ним).","b":1},{"t":"example","text":"Dịch: Tôi hầu như không quen cô ấy (cháu gái ông) và anh ấy (chồng cô ấy)."},{"t":"example","text":"Ря́дом с до́мом (с ним) мои́х но́вых знако́мых прохо́дит доро́га.","b":1},{"t":"example","text":"Dịch: Cạnh nó (nhà người quen mới) có một con đường đi qua."},{"t":"example","text":"Я беспоко́юсь о здоро́вье больно́го (о нём).","b":1},{"t":"example","text":"Dịch: Tôi lo lắng về nó (sức khỏe người bệnh)."},{"t":"example","text":"Вме́сто эстра́дных арти́стов (вместо них) бу́дут выступа́ть арти́сты ци́рка из Но́вгорода. (Giới từ вместо yêu cầu Giới cách và thêm н)."},{"t":"example","text":"Dịch: Thay vì họ (nghệ sĩ tạp kỹ), các nghệ sĩ xiếc từ Novgorod sẽ biểu diễn."},{"t":"example","text":"Я э́то сде́лал для бла́га всех прису́тствующих (для них).","b":1},{"t":"example","text":"Dịch: Tôi làm điều này vì lợi ích của họ (tất cả những người có mặt)."},{"t":"example","text":"Кро́ме Андре́я (кроме него́) ко мне должны́ прийти́ ещё два мои́х знако́мых.","b":1},{"t":"example","text":"Dịch: Ngoài anh ấy (Andrei), còn hai người quen của tôi sẽ đến."},{"t":"example","text":"Ме́жду мои́ми ро́дственниками и ро́дственниками жены́ (между ними) уже́ давно́ сложи́лись дру́жеские отноше́ния.","b":1},{"t":"example","text":"Dịch: Giữa họ (họ hàng tôi và vợ) đã hình thành quan hệ thân thiết từ lâu."},{"t":"example","text":"Дождь был таки́м си́льным, что вода́ проходи́ла сквозь оде́жду уча́стников экспеди́ции (сквозь неё).","b":1},{"t":"example","text":"Dịch: Mưa to đến mức nước thấm xuyên qua nó (quần áo của đoàn thám hiểm)."},{"t":"example","text":"Мы мо́жем пройти́ че́рез уча́сток мои́х ро́дственников (через него́).","b":1},{"t":"example","text":"Dịch: Chúng ta có thể đi qua nó (khu đất của họ hàng tôi)."},{"t":"example","text":"Я мно́го слы́шал о твоём знако́мом (о нём) от свои́х друзе́й.","b":1},{"t":"example","text":"Dịch: Tôi nghe nhiều về anh ấy (người quen của bạn) từ bạn bè mình."},{"t":"example","text":"Вопреки́ мне́нию мое́й до́чери (вопреки́ ему́) мы реши́ли отложи́ть пое́здку до за́втра. (Sách: không thêm н sau вопреки)."},{"t":"example","text":"Dịch: Trái với nó (ý kiến con gái tôi), chúng tôi quyết định hoãn chuyến đi đến ngày mai."},{"t":"example","text":"Я не ви́делся с ва́шим сы́ном (с ним) почти́ два го́да.","b":1},{"t":"example","text":"Dịch: Tôi không gặp cậu ấy (con trai ông) gần hai năm rồi."}]},{"id":"03-s005","type":"exercise","title":"Bài 324 (Trang 158)","num":324,"blocks":[{"t":"para","text":"Đề bài: Điền vào chỗ trống đại từ nhân xưng hoặc đại từ sở hữu ngôi thứ 3 kèm giới từ hoặc không có giới từ."},{"t":"example","text":"Она́ о́чень изве́стный врач, я слы́шал (о ней) мно́го хоро́шего. (о ней - về cô ấy)."},{"t":"example","text":"Твоего́ знако́мого я не зна́ю, но (с ним) бра́том мы встреча́лись не раз. → но с его братом (với anh trai của anh ấy)."},{"t":"example","text":"Пе́ред (нами) открыва́лся чуде́сный вид. (перед нами - trước mặt chúng tôi/chúng ta. Ngữ cảnh: \"Trước mắt chúng tôi mở ra...\")."},{"t":"example","text":"Мы уви́дели друзе́й и подошли́ (к ним). (к ним - đến chỗ họ)."},{"t":"example","text":"Он о́чень весёлый челове́к, (с ним) ты не бу́дешь скуча́ть. (с ним - với anh ấy)."},{"t":"example","text":"Э́то мои́ ста́рые друзья́, я познако́мился (с ними) ещё в институ́те. (с ними - với họ)."},{"t":"example","text":"Мой друг живёт в э́том до́ме, (у него) зна́комый предложи́л мне погости́ть. → Có vẻ câu này là: \"Bạn tôi sống ở nhà này, người quen của anh ấy (его знакомый)...\"."},{"t":"example","text":"Dịch: ...người quen của anh ấy đã mời tôi đến chơi."},{"t":"example","text":"Они́ пло́хо ориенти́руются в го́роде, я сомнева́юсь (в них). (Nghi ngờ họ? Hay là \"giúp họ\"? Văn cảnh: \"Tôi nghi ngờ khả năng của họ\"). Nhưng nếu điền sở hữu thì phải có danh từ. Ở đây kết thúc câu → в них (nghi ngờ họ)."},{"t":"example","text":"Hoặc: câu có thể là \"...сомневаюсь, что они найдут...\" (nghi ngờ liệu họ có tìm được...). Nếu chỉ điền đại từ: в них."},{"t":"example","text":"Я забо́чусь об их сы́не. (об их сыне - về con trai của họ)."},{"t":"example","text":"Мы давно́ не писа́ли свои́м друзья́м, на́до (им) много вре́мени на по́иски рабо́ты. → Câu này hơi tối nghĩa. \"Chúng tôi lâu không viết thư cho bạn bè, họ cần nhiều thời gian...?\" hay \"Cần viết cho họ\"?"},{"t":"example","text":"Sửa lại: Có lẽ ý là \"cần viết cho họ\" → написать им."},{"t":"example","text":"Dịch: ...cần viết cho họ."},{"t":"example","text":"О́пытом нетру́дно (с ней) найти́. (Câu gốc có vẻ bị lỗi in hoặc chép lại. Có thể là: \"С её опытом нетрудно найти...\" - Với kinh nghiệm của cô ấy thì không khó tìm...)."},{"t":"subhead","text":"Đáp án: С её."},{"t":"example","text":"У тебя́ замеча́тельные роди́тели, ты смог зако́нчить институ́т то́лько (благодаря им). (благодаря им - nhờ họ)."},{"t":"example","text":"Пе́ред са́мой экспеди́цией он неожи́данно заболе́л, и (вместо него) пое́хал Оле́г. (вместо него - thay cho anh ấy)."},{"t":"example","text":"Он не безразли́чен, я всегда́ ра́дуюсь (его) успе́хам и огорча́юсь, е́сли (у него) неприя́тности. (его успехам - thành công của anh ấy; у него - ở anh ấy có chuyện không vui)."},{"t":"example","text":"Он попроси́л меня́ зайти́ на по́чту, весь день я по́мнил (о его) про́сьбе. (о его просьбе - về lời nhờ vả của anh ấy)."},{"t":"example","text":"Я знал её ещё в университе́те, мы учи́лись (с ней) на одно́м ку́рсе. (с ней - với cô ấy)."},{"t":"example","text":"У тебя́ замеча́тельный брат, ты мо́жешь горди́ться (им). (им - tự hào về anh ấy)."}]},{"id":"03-s006","type":"exercise","title":"Bài 325 (Trang 158)","num":325,"blocks":[{"t":"example","text":"Đề bài: Xác định các từ э́то, э́тот, тот thuộc loại từ nào (Đại từ chỉ định làm định ngữ hay làm chủ ngữ/tiểu từ)."},{"t":"para","text":"Giải thích ngữ pháp (Gợi ý từ trang 158):","b":1},{"t":"vocab","ru":"Э́то (Làm chủ ngữ/Tiểu từ)","vi":"Dùng trong câu định nghĩa \"Đây là...\". Không thay đổi hình thức.","g":null},{"t":"example","text":"Ví dụ: Э́то мой дом (Đây là nhà tôi). Э́то моя мама (Đây là mẹ tôi)."},{"t":"vocab","ru":"Э́тот/Э́та/Э́то/Э́ти (Đại từ chỉ định làm định ngữ)","vi":"Đi kèm danh từ để chỉ trỏ \"Cái ... này\". Biến đổi theo giống, số, cách của danh từ.","g":null},{"t":"example","text":"Ví dụ: Э́тот дом (Ngôi nhà này), Э́та книга (Cuốn sách này)."},{"t":"vocab","ru":"Тот/Та/То/Те (Kia/Đó)","vi":"Chỉ sự vật ở xa hoặc trong quá khứ.","g":null},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"para","text":"а)","b":1},{"t":"vocab","ru":"Э́то мой дом. (Э́то - Chủ ngữ","vi":"Đây là). Э́тот дом был постро́ен... (Э́тот - Định ngữ: Ngôi nhà này).","g":null},{"t":"vocab","ru":"Э́то кварти́ра мое́й ба́бушки. (Э́то - Chủ ngữ","vi":"Đây là). Э́та кварти́ра нахо́дится... (Э́та - Định ngữ: Căn hộ này).","g":null},{"t":"vocab","ru":"Э́то свобо́дное ме́сто. (Э́то - Chủ ngữ","vi":"Đây là chỗ trống). Э́то ме́сто за́нято... (Э́то - Định ngữ: Chỗ này).","g":null},{"t":"vocab","ru":"Э́ти студе́нты у́чатся... (Э́ти - Định ngữ","vi":"Những sinh viên này).","g":null},{"t":"example","text":"2. Э́того до́ма ра́ньше не́ было. (Э́того - Định ngữ (Giới cách): Ngôi nhà này). Кро́ме э́той кварти́ры... (Э́той - Định ngữ: Căn hộ này)."},{"t":"vocab","ru":"С э́того ме́ста о́чень пло́хо ви́дно. (Э́того - Định ngữ","vi":"Chỗ này). Э́тих студе́нтов я ра́ньше здесь не ви́дел. (Э́тих - Định ngữ: Những sinh viên này).","g":null},{"t":"example","text":"3. Мы уже́ подходи́ли оди́н раз к э́тому до́му. (Э́тому - Định ngữ: Ngôi nhà này). По э́той кварти́ре мо́жно ката́ться... (Э́той - Định ngữ: Căn hộ này)."},{"t":"example","text":"Снача́ла он напра́вился к э́тому ме́сту... (Э́тому - Định ngữ: Chỗ này)."},{"t":"vocab","ru":"Вам на́до заверну́ть за э́тот дом... (Э́тот - Định ngữ","vi":"Ngôi nhà này). В э́ту кварти́ру неда́вно въе́хали жильцы́. (Э́ту - Định ngữ: Căn hộ này). На э́то ме́сто биле́ты уже́ про́даны. (Э́то - Định ngữ: Chỗ này).","g":null},{"t":"vocab","ru":"За э́тим до́мом располо́жен де́тский сад. (Э́тим - Định ngữ","vi":"Ngôi nhà này). Я о́чень дово́лен э́той кварти́рой. (Э́той - Định ngữ: Căn hộ này). С э́тим ме́стом у меня́ свя́заны... (Э́тим - Định ngữ: Chỗ này).","g":null},{"t":"vocab","ru":"В э́том до́ме живу́т мои́ роди́тели. (Э́том - Định ngữ","vi":"Ngôi nhà này). В э́той кварти́ре давно́ никто́ не живёт. (Э́той - Định ngữ: Căn hộ này). Мне нра́вится сиде́ть на э́том ме́сте. (Э́том - Định ngữ: Chỗ này).","g":null},{"t":"para","text":"б)","b":1},{"t":"vocab","ru":"Э́то но́вый дом, а тот дом... снесли́. (Э́то - Chủ ngữ","vi":"Đây là; тот - Định ngữ: ngôi nhà kia).","g":null},{"t":"example","text":"Та исто́рия, о кото́рой я тебе́ расска́зывал... (Та - Định ngữ: Câu chuyện đó)."},{"t":"vocab","ru":"Э́то то са́мое ме́сто... (Э́то - Chủ ngữ","vi":"Đây là; то - Định ngữ: chính cái nơi đó).","g":null},{"t":"example","text":"Мно́гие дома́ сохрани́лись, но того́ до́ма... нет. (того - Định ngữ: ngôi nhà đó)."},{"t":"vocab","ru":"Благодаря́ той исто́рии... (той - Định ngữ","vi":"câu chuyện đó).","g":null},{"t":"example","text":"Студе́нты, кото́рые у́чились здесь в то вре́мя... (то - Định ngữ: thời gian đó)."},{"t":"vocab","ru":"За те́ми драмати́ческими собы́тиями... (теми - Định ngữ","vi":"những sự kiện đó).","g":null},{"t":"vocab","ru":"О том до́ме... хо́дят леге́нды. (том - Định ngữ","vi":"ngôi nhà đó).","g":null}]},{"id":"03-s007","type":"exercise","title":"Bài 326 (Trang 159)","num":326,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 159):","b":1},{"t":"subhead","text":"Cấu trúc ban đầu: Э́то (Chủ ngữ giả/Tiểu từ) + Danh từ + Tính từ/Mệnh đề."},{"t":"example","text":"Ví dụ: Э́то о́чень ва́жный приме́р. (Đây là một ví dụ rất quan trọng)."},{"t":"subhead","text":"Cấu trúc chuyển đổi: Э́тот (э́та, э́то, э́ти) (Định ngữ) + Danh từ (làm Chủ ngữ) + Vị ngữ."},{"t":"para","text":"Khi chuyển đổi, phần định ngữ (tính từ, động tính từ, mệnh đề phụ) sẽ biến thành vị ngữ (thường là tính từ ngắn đuôi hoặc động từ)."},{"t":"example","text":"Ví dụ: Э́тот приме́р о́чень ва́жен. (Ví dụ này rất quan trọng)."},{"t":"para","text":"Đề bài: Sử dụng dạng cần thiết của đại từ chỉ định э́тот (này), hãy đưa ra phương án đồng nghĩa cho các câu."},{"t":"model","text":"Mẫu: Э́то о́чень ва́жный приме́р. — Э́тот приме́р о́чень ва́жен."},{"t":"para","text":"Э́то доста́точно глубо́кое о́зеро.","b":1},{"t":"para","text":"Viết lại: Э́то о́зеро доста́точно глубоко́.","b":1},{"t":"para","text":"Dịch: Cái hồ này khá sâu."},{"t":"example","text":"Giải thích: О́зеро (giống trung) → dùng э́то. Tính từ глубо́кое chuyển thành dạng ngắn глубоко́ làm vị ngữ."},{"t":"para","text":"Э́то бесконе́чный разгово́р.","b":1},{"t":"para","text":"Viết lại: Э́тот разгово́р бесконе́чен.","b":1},{"t":"para","text":"Dịch: Cuộc trò chuyện này là bất tận (không có hồi kết)."},{"t":"example","text":"Giải thích: Разгово́р (giống đực) → э́тот. Tính từ ngắn: бесконе́чен."},{"t":"para","text":"Э́то недолгове́чные успе́хи.","b":1},{"t":"para","text":"Viết lại: Э́ти успе́хи недолгове́чны.","b":1},{"t":"para","text":"Dịch: Những thành công này không bền vững (ngắn ngủi)."},{"t":"example","text":"Giải thích: Успе́хи (số nhiều) → э́ти. Tính từ ngắn: недолгове́чны."},{"t":"para","text":"Э́то нео́бычное поведе́ние.","b":1},{"t":"para","text":"Viết lại: Э́то поведе́ние нео́бычно.","b":1},{"t":"para","text":"Dịch: Hành vi này thật khác thường."},{"t":"example","text":"Giải thích: Поведе́ние (giống trung) → э́то."},{"t":"para","text":"Э́то во́лосы сре́дней длины́.","b":1},{"t":"para","text":"Viết lại: Э́ти во́лосы сре́дней длины́.","b":1},{"t":"para","text":"Dịch: Mái tóc này có độ dài trung bình."},{"t":"example","text":"Giải thích: Во́лосы (số nhiều) → э́ти. Cụm сре́дней длины́ giữ nguyên làm vị ngữ."},{"t":"para","text":"Э́то о́чень просто́е реше́ние.","b":1},{"t":"para","text":"Viết lại: Э́то реше́ние о́чень про́сто.","b":1},{"t":"para","text":"Dịch: Quyết định này rất đơn giản."},{"t":"example","text":"Giải thích: Реше́ние (giống trung) → э́то. Tính từ ngắn: про́сто."},{"t":"para","text":"Э́то бесконе́чная исто́рия.","b":1},{"t":"para","text":"Viết lại: Э́та исто́рия бесконе́чна.","b":1},{"t":"para","text":"Dịch: Câu chuyện này là bất tận (không bao giờ kết thúc)."},{"t":"example","text":"Giải thích: Исто́рия (giống cái) → э́та."},{"t":"para","text":"Э́то ме́стные жи́тели.","b":1},{"t":"para","text":"Viết lại: Э́ти жи́тели — ме́стные.","b":1},{"t":"para","text":"Dịch: Những cư dân này là người địa phương."},{"t":"example","text":"Giải thích: Жи́тели (số nhiều) → э́ти."},{"t":"para","text":"Э́то весьма́ це́нный сове́т.","b":1},{"t":"para","text":"Viết lại: Э́тот сове́т весьма́ це́нен.","b":1},{"t":"para","text":"Dịch: Lời khuyên này rất có giá trị."},{"t":"example","text":"Giải thích: Сове́т (giống đực) → э́тот. Tính từ ngắn: це́нен."},{"t":"para","text":"Э́то сло́жная рабо́та.","b":1},{"t":"para","text":"Viết lại: Э́та рабо́та сложна́.","b":1},{"t":"para","text":"Dịch: Công việc này phức tạp/khó khăn."},{"t":"example","text":"Giải thích: Рабо́та (giống cái) → э́та."},{"t":"para","text":"Э́то хозя́йская соба́ка.","b":1},{"t":"para","text":"Viết lại: Э́та соба́ка — хозя́йская.","b":1},{"t":"para","text":"Dịch: Con chó này là của chủ nhà."},{"t":"example","text":"Giải thích: Соба́ка (giống cái) → э́та."},{"t":"para","text":"Э́то магази́ны, кото́рые рабо́тают без переры́ва на обе́д.","b":1},{"t":"para","text":"Viết lại: Э́ти магази́ны рабо́тают без переры́ва на обе́д.","b":1},{"t":"para","text":"Dịch: Những cửa hàng này làm việc không nghỉ trưa."},{"t":"example","text":"Giải thích: Mệnh đề phụ кото́рые рабо́тают... chuyển thành động từ chính рабо́тают."},{"t":"para","text":"Э́то ча́сто встреча́ющиеся вариа́нты отве́тов.","b":1},{"t":"para","text":"Viết lại: Э́ти вариа́нты отве́тов ча́сто встреча́ются.","b":1},{"t":"para","text":"Dịch: Các phương án trả lời này thường xuyên gặp."},{"t":"example","text":"Giải thích: Động tính từ встреча́ющиеся chuyển thành động từ встреча́ются."},{"t":"para","text":"Э́то результа́т, кото́рого на́до до́лго добива́ться.","b":1},{"t":"para","text":"Viết lại: Э́того результа́та на́до до́лго добива́ться.","b":1},{"t":"para","text":"Dịch: Kết quả này cần phải nỗ lực lâu dài mới đạt được."},{"t":"example","text":"Giải thích: Cấu trúc добиваться yêu cầu Cách 2 (Genitive), nên Этот результат biến thành Этого результата."},{"t":"para","text":"Э́то собы́тие, кото́рому мо́жно то́лько ра́доваться.","b":1},{"t":"para","text":"Viết lại: Э́тому собы́тию мо́жно то́лько ра́доваться.","b":1},{"t":"para","text":"Dịch: Sự kiện này chỉ có thể khiến người ta vui mừng."},{"t":"example","text":"Giải thích: Cấu trúc радоваться yêu cầu Cách 3 (Dative), nên Это событие biến thành Этому событию."}]},{"id":"03-s008","type":"exercise","title":"Bài 327 (Trang 160)","num":327,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"vocab","ru":"Đại từ Э́ТОТ (э́та, э́то, э́ти)","vi":"Dùng để thay thế cho một danh từ cụ thể đã nhắc đến hoặc chỉ vào vật gần.","g":null},{"t":"vocab","ru":"Đại từ Э́ТО","vi":"Dùng để thay thế cho cả một ý, một mệnh đề hoặc một tình huống được nhắc đến trước đó (làm chủ ngữ hoặc bổ ngữ trừu tượng).","g":null},{"t":"note","text":"Lưu ý: Cần chia cách (case) phù hợp với động từ đi kèm."},{"t":"para","text":"Đề bài: Thay dấu ba chấm bằng hình thức cần thiết của э́тот (cụ thể) hoặc э́то (trừu tượng/tình huống) có hoặc không có giới từ."},{"t":"para","text":"Я прекра́сно гото́влю. ... меня́ научи́ла моя́ мать.","b":1},{"t":"para","text":"Điền: Э́тому","b":1},{"t":"para","text":"Dịch: Tôi nấu ăn rất giỏi. Mẹ tôi đã dạy tôi điều này."},{"t":"example","text":"Giải thích: Động từ научи́ть (dạy) yêu cầu Cách 3 (Dative) cho nội dung được dạy. Điều này = việc nấu ăn → Э́тому (từ э́то)."},{"t":"para","text":"По́мнишь, я расска́зывал тебе́ об ава́рии. ... произошло́ и́менно здесь.","b":1},{"t":"para","text":"Điền: Э́то","b":1},{"t":"para","text":"Dịch: Bạn nhớ không, tôi đã kể cho bạn về vụ tai nạn. Nó/Chuyện đó đã xảy ra chính tại đây."},{"t":"example","text":"Giải thích: Э́то thay thế cho sự việc \"vụ tai nạn\", đóng vai trò chủ ngữ (Cách 1)."},{"t":"para","text":"Мы не мо́жем заста́вить его́ измени́ть реше́ние. ... придётся мири́ться.","b":1},{"t":"para","text":"Điền: С э́тим","b":1},{"t":"para","text":"Dịch: Chúng tôi không thể bắt anh ấy thay đổi quyết định. Sẽ phải chấp nhận điều này."},{"t":"example","text":"Giải thích: Cụm мири́ться с чем? (chấp nhận/làm hòa với cái gì) → Cách 5 (Instrumental) của э́то là с э́тим."},{"t":"para","text":"Я хоте́л серьёзно с тобо́й поговори́ть. ... я тебя́ сюда́ и пригласи́л.","b":1},{"t":"para","text":"Điền: Ра́ди э́того (hoặc Для э́того)"},{"t":"para","text":"Dịch: Tôi đã muốn nói chuyện nghiêm túc với bạn. Vì điều này/Để làm việc này mà tôi đã mời bạn đến đây."},{"t":"example","text":"Giải thích: Chỉ mục đích → Giới từ для/ради + Cách 2 (э́того)."},{"t":"para","text":"Он не спо́рит, а всё вре́мя молчи́т. ... меня́ и беспоко́ит.","b":1},{"t":"para","text":"Điền: Э́то","b":1},{"t":"para","text":"Dịch: Cậu ấy không tranh luận mà cứ im lặng suốt. Điều này làm tôi lo lắng."},{"t":"example","text":"Giải thích: Э́то làm chủ ngữ cho động từ беспоко́ит."},{"t":"para","text":"Мы познако́мились в про́шлом году́. ... всё и начало́сь.","b":1},{"t":"para","text":"Điền: С э́того","b":1},{"t":"para","text":"Dịch: Chúng tôi quen nhau năm ngoái. Mọi chuyện đã bắt đầu từ đó/từ việc này."},{"t":"example","text":"Giải thích: Chỉ điểm khởi đầu thời gian/sự kiện → С + Cách 2 (э́того)."},{"t":"para","text":"Он отли́чно пла́вает. ... его́ взя́ли в университе́тскую кома́нду по пла́ванию.","b":1},{"t":"para","text":"Điền: Поэ́тому (Trạng từ) hoặc Благодаря́ э́тому (Nhờ điều này). Sách yêu cầu điền đại từ nên chọn Благодаря́ э́тому hoặc Из-за э́того."},{"t":"para","text":"Dịch: Cậu ấy bơi rất giỏi. Nhờ đó/Vì thế, người ta đã nhận cậu ấy vào đội bơi của trường đại học."},{"t":"para","text":"Он мог купи́ть биле́т на друго́й рейс. Как же я ... не поду́мал!","b":1},{"t":"para","text":"Điền: об э́том","b":1},{"t":"para","text":"Dịch: Anh ấy đã có thể mua vé chuyến khác. Sao tôi lại không nghĩ về điều này nhỉ!"},{"t":"example","text":"Giải thích: Поду́мать о чём? (Nghĩ về cái gì) → Cách 6 (Prepositional) об э́том."},{"t":"para","text":"Мне ва́жно, что́бы он при́нял уча́стие в на́шей рабо́те. ... я верю.","b":1},{"t":"para","text":"Điền: В э́то","b":1},{"t":"para","text":"Dịch: Việc anh ấy tham gia vào công việc của chúng ta rất quan trọng với tôi. Tôi tin vào điều này."},{"t":"example","text":"Giải thích: Ве́рить во что? (Tin vào cái gì) → Cách 4 (Accusative) в э́то."},{"t":"para","text":"Он всегда́ опа́здывает. Мы уже́ привы́кли ...","b":1},{"t":"para","text":"Điền: к э́тому","b":1},{"t":"para","text":"Dịch: Cậu ta luôn đi muộn. Chúng tôi đã quen với điều đó rồi."},{"t":"example","text":"Giải thích: Привы́кнуть к чему? (Quen với cái gì) → Cách 3 (Dative) к э́тому."},{"t":"para","text":"Тру́дно сказа́ть, кто прав, кто винова́т. ... мы не бу́дем сейча́с каса́ться.","b":1},{"t":"para","text":"Điền: Э́того","b":1},{"t":"para","text":"Dịch: Khó mà nói ai đúng ai sai. Chúng ta sẽ không đề cập đến việc này bây giờ."},{"t":"example","text":"Giải thích: Каса́ться чего? (Đề cập/chạm đến cái gì) → Cách 2 (Genitive) э́того."},{"t":"para","text":"На э́то число́ биле́тов мо́жет не быть. ... на́до зара́нее позабо́титься.","b":1},{"t":"para","text":"Điền: Об э́том","b":1},{"t":"para","text":"Dịch: Có thể không còn vé cho ngày này. Cần phải lo liệu về việc này từ trước."},{"t":"example","text":"Giải thích: Позабо́титься о чём? → Cách 6 об э́том."},{"t":"para","text":"Мой роди́тели не пое́дут во Фра́нцию, а прие́дут ко мне. Я ... о́чень рад.","b":1},{"t":"para","text":"Điền: э́тому","b":1},{"t":"para","text":"Dịch: Bố mẹ tôi sẽ không đi Pháp mà sẽ đến chỗ tôi. Tôi rất vui vì điều này."},{"t":"example","text":"Giải thích: Рад чему? (Vui vì cái gì) → Cách 3 э́тому."}]},{"id":"03-s009","type":"exercise","title":"Bài 328 (Trang 160)","num":328,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 160):","b":1},{"t":"vocab","ru":"Тот (та, то, те)","vi":"Dùng khi:","g":null},{"t":"example","text":"Nhắc đến thời gian trong quá khứ (в тот день - vào ngày hôm đó)."},{"t":"example","text":"Đối chiếu với этот (cái này - cái kia)."},{"t":"example","text":"Đi trong câu phức có mệnh đề quan hệ (тот, кто... - người mà...)."},{"t":"example","text":"Trong các cụm từ cố định (с тем чтобы, в то время как...)."},{"t":"para","text":"Đề bài: Điền э́тот (này) hoặc тот (kia/đó) ở dạng phù hợp."},{"t":"vocab","ru":"Я посмотре́л на своего́ сосе́да и поду́мал","vi":"... со всем спра́вится.","g":null},{"t":"para","text":"Điền: э́тот","b":1},{"t":"para","text":"Dịch: Tôi nhìn người hàng xóm của mình và nghĩ: người này sẽ giải quyết được mọi việc."},{"t":"example","text":"Giải thích: Chỉ người đang ở ngay trước mặt → э́тот."},{"t":"para","text":"Кто не рабо́тает, ... не ест (посло́вица).","b":1},{"t":"para","text":"Điền: тот","b":1},{"t":"para","text":"Dịch: Ai không làm thì kẻ đó không ăn (Tay làm hàm nhai)."},{"t":"example","text":"Giải thích: Cấu trúc Кто..., тот... (Ai... thì người đó...)."},{"t":"para","text":"Кни́жный магази́н напро́тив, тебе́ на́до перейти́ на ... сто́рону у́лицы.","b":1},{"t":"para","text":"Điền: ту","b":1},{"t":"para","text":"Dịch: Hiệu sách ở đối diện, bạn cần sang phía bên kia đường."},{"t":"example","text":"Giải thích: Напро́тив (đối diện) hàm ý phía xa/phía bên kia → ту (giống cái, Cách 4)."},{"t":"para","text":"Для ... что́бы успе́ть зако́нчить рабо́ту до ве́чера, на́до поторопи́ться.","b":1},{"t":"para","text":"Điền: того́","b":1},{"t":"para","text":"Dịch: Để (có thể) kịp hoàn thành công việc trước buổi tối, cần phải nhanh lên."},{"t":"example","text":"Giải thích: Cụm từ chỉ mục đích Для того́, что́бы...."},{"t":"para","text":"Нет, в ... выходны́е мы не смо́жем пое́хать на да́чу, мы е́здили туда́ на ... неде́ле.","b":1},{"t":"example","text":"Điền: э́ти ... той (hoặc про́шлой)."},{"t":"para","text":"Dịch: Không, cuối tuần này chúng tôi không thể đi nhà nghỉ ngoại ô, chúng tôi đã đi đến đó vào tuần trước/kia."},{"t":"example","text":"Giải thích: Эти chỉ tương lai gần/hiện tại. Той chỉ quá khứ xa hơn (tuần trước)."},{"t":"para","text":"Коне́чно, мы вам помо́жем, для ... мы сюда́ и прие́хали.","b":1},{"t":"example","text":"Điền: э́того (hoặc того)"},{"t":"para","text":"Dịch: Tất nhiên chúng tôi sẽ giúp bạn, chính vì điều này/để làm việc này mà chúng tôi đến đây."},{"t":"example","text":"Giải thích: Для этого (vì việc này - việc giúp đỡ). Для того cũng dùng được trong văn cảnh nhấn mạnh mục đích."},{"t":"para","text":"... случи́лось лет пять наза́д. В ... вре́мя я был ещё о́чень мо́лод.","b":1},{"t":"para","text":"Điền: Э́то ... то","b":1},{"t":"para","text":"Dịch: Chuyện này xảy ra khoảng 5 năm trước. Vào thời gian đó, tôi còn rất trẻ."},{"t":"example","text":"Giải thích: Э́то (chủ ngữ chỉ sự việc). В то вре́мя (cụm cố định chỉ quá khứ)."},{"t":"para","text":"Он почти́ не измени́лся, на его́ голове́ красова́лась ... же са́мая шля́па, в кото́рой я его́ ви́дел в про́шлый раз.","b":1},{"t":"para","text":"Điền: та","b":1},{"t":"para","text":"Dịch: Ông ấy hầu như không thay đổi, trên đầu ông ấy vẫn diện chính cái mũ đó, cái mà tôi đã thấy lần trước."},{"t":"example","text":"Giải thích: Cấu trúc та же самая (chính cái đó), so sánh với quá khứ."},{"t":"para","text":"Нам пришло́сь отмени́ть свой пла́ны и оста́ться до́ма, из-за ... что весь день шёл дождь.","b":1},{"t":"para","text":"Điền: того́","b":1},{"t":"para","text":"Dịch: Chúng tôi phải hủy kế hoạch và ở nhà, bởi vì trời mưa cả ngày."},{"t":"example","text":"Giải thích: Cụm từ chỉ nguyên nhân: из-за того́, что..."},{"t":"para","text":"Он уже́ ждал нас на верши́не горы́, в ... вре́мя как мы то́лько туда́ добира́лись.","b":1},{"t":"para","text":"Điền: то","b":1},{"t":"para","text":"Dịch: Anh ấy đã đợi chúng tôi trên đỉnh núi, trong khi chúng tôi mới đang đi tới đó."},{"t":"example","text":"Giải thích: Liên từ thời gian в то время как (trong khi)."},{"t":"para","text":"Я заболе́л и из-за ... не смог приня́ть уча́стие в соревнова́ниях.","b":1},{"t":"para","text":"Điền: э́того","b":1},{"t":"para","text":"Dịch: Tôi bị ốm và vì việc này (việc ốm) nên không thể tham gia thi đấu."},{"t":"example","text":"Giải thích: Thay thế cho sự việc ngay trước đó → э́того."},{"t":"para","text":"Они́ приближа́лись к ... ме́сту, с кото́рого должно́ бы́ло нача́ться их путеше́ствие.","b":1},{"t":"para","text":"Điền: тому́","b":1},{"t":"para","text":"Dịch: Họ đang đến gần cái địa điểm đó, nơi mà chuyến đi của họ sẽ bắt đầu."},{"t":"example","text":"Giải thích: Тому... с которого (Cái... mà...) - cấu trúc tương liên từ."},{"t":"para","text":"Я прекра́сно по́мню карти́ну, о кото́рой вы говори́те. Я не раз проходи́л ми́мо ... карти́ны в Ру́сском музе́е.","b":1},{"t":"example","text":"Điền: э́той (hoặc той)"},{"t":"para","text":"Dịch: Tôi nhớ rất rõ bức tranh ông nói. Tôi đã không ít lần đi ngang qua bức tranh đó/này trong Bảo tàng Nga."},{"t":"example","text":"Giải thích: Dùng э́той để nhấn mạnh sự cụ thể đã được nhắc đến trong tâm trí. Dùng той để chỉ vật ở xa trong quá khứ. Этой phổ biến hơn khi nhắc lại."},{"t":"para","text":"... слу́чай, о кото́ром он нам расска́зывал, произошёл и́менно здесь.","b":1},{"t":"para","text":"Điền: Тот","b":1},{"t":"para","text":"Dịch: Cái vụ việc đó/kia, cái mà anh ấy kể cho chúng ta, đã xảy ra chính tại đây."},{"t":"example","text":"Giải thích: Тот..., о котором (Cái kia... mà...)."},{"t":"para","text":"До ... пор пока́ я не получу́ от него́ письмо́, я никуда́ не пое́ду.","b":1},{"t":"para","text":"Điền: тех","b":1},{"t":"para","text":"Dịch: Cho đến khi tôi nhận được thư anh ấy, tôi sẽ không đi đâu cả."},{"t":"example","text":"Giải thích: Cụm từ chỉ thời gian: До тех пор, пока (не)..."}]},{"id":"03-s010","type":"exercise","title":"Bài 329 (Trang 161)","num":329,"blocks":[{"t":"para","text":"Đề bài: Đọc các câu văn, chú ý ý nghĩa của các từ chỉ định. Xác định ý nghĩa của chúng."},{"t":"para","text":"Я прие́хал в э́тот го́род четы́ре го́да тому́ наза́д.","b":1},{"t":"example","text":"Ý nghĩa: Э́тот chỉ địa điểm cụ thể nơi người nói đang ở (thành phố này)."},{"t":"para","text":"Он не то что (что́бы) хоте́л с на́ми е́хать, про́сто у него́ бы́ли дела́ в го́роде.","b":1},{"t":"example","text":"Ý nghĩa: Не то что(бы) là một thành ngữ (idiom), mang nghĩa \"Không hẳn là..., mà là...\"."},{"t":"para","text":"О нём нельзя́ сказа́ть ничего́ определённого, стра́нный челове́к, ни то ни сё.","b":1},{"t":"example","text":"Ý nghĩa: Ни то ни сё là thành ngữ, nghĩa là \"không ra cái này cũng chẳng ra cái kia\", \"dở dở ương ương\", không có đặc điểm rõ ràng."},{"t":"vocab","ru":"Не поня́тно, что он хо́чет ска́зать","vi":"то он хо́чет идти́, то не хо́чет.","g":null},{"t":"example","text":"Ý nghĩa: То..., то... là liên từ lặp, chỉ sự thay đổi luân phiên của hành động/trạng thái (lúc thì thế này, lúc thì thế kia)."},{"t":"para","text":"При тако́й за́сухе не прихо́дится ждать хоро́шего урожа́я, того́ и гляди́ вообщé ничего́ не вы́растет.","b":1},{"t":"example","text":"Ý nghĩa: Того́ и гляди́ là thành ngữ, nghĩa là \"có nguy cơ là\", \"nhìn tình hình này thì sắp sửa...\" (chỉ điều gì đó sắp xảy ra, thường là tiêu cực)."},{"t":"para","text":"Ты что встал не с той ноги́? Заче́м на люде́й кричи́шь?","b":1},{"t":"example","text":"Ý nghĩa: Встать не с той ноги́ là thành ngữ (dậy nhầm chân/bước chân trái ra đường), nghĩa là \"tâm trạng cáu kỉnh, khó chịu vô cớ\"."},{"t":"para","text":"Он меня́ оби́дел, и я отплачу́ ему́ той же моне́той, не обра́дуется.","b":1},{"t":"example","text":"Ý nghĩa: Отплати́ть той же моне́той là thành ngữ (trả bằng cùng một đồng xu), nghĩa là \"ăn miếng trả miếng\", đối xử lại y hệt như người ta làm với mình."},{"t":"para","text":"Мы все хоти́м услы́шать э́ту исто́рию. — Ну что ж, е́сли на то пошло́, я расскажу́ вам всё по поря́дку.","b":1},{"t":"example","text":"Ý nghĩa: Е́сли на то пошло́ là thành ngữ, nghĩa là \"nếu sự việc đã đến nước này\", \"nếu đã như vậy thì\", \"nếu thực sự cần thiết\"."},{"t":"para","text":"Он ду́мал, что я мо́жно обману́ть! Не на того́ напа́л!","b":1},{"t":"example","text":"Ý nghĩa: Не на того́ напа́л là thành ngữ (tấn công nhầm người rồi), nghĩa là \"nhầm đối tượng rồi\", \"tôi không dễ bị bắt nạt/lừa đâu\"."},{"t":"para","text":"Вчера́ он опя́ть опозда́л на заня́тие, к тому́ же (кро́ме того́; при э́том) забы́л взять с собо́й уче́бник.","b":1},{"t":"example","text":"Ý nghĩa: К тому́ же là liên từ, nghĩa là \"thêm vào đó\", \"hơn nữa\", \"ngoài ra\"."}]},{"id":"03-s011","type":"exercise","title":"Bài 330 (Trang 161)","num":330,"blocks":[{"t":"para","text":"Đề bài: Sử dụng các cụm từ cố định với đại từ тот (đã cho trong danh sách hoặc phải tự suy luận từ nghĩa), hãy chọn từ đồng nghĩa cho các từ/cụm từ in đậm (đã được thay thế trong bài giải)."},{"t":"example","text":"Danh sách cụm từ gợi ý (từ ngữ cảnh): во что бы то ни стало (bằng mọi giá), ни с того ни с сего (tự nhiên/không có lý do), и тот и друго́й (cả hai), того́ и гляди́ (sắp sửa/e rằng), тем же (như thế), не то что́бы (không hẳn là), к тому́ же (hơn nữa), по все́й вероя́тности (rất có thể/chắc là), в том-то и де́ло (vấn đề là ở chỗ đó)."},{"t":"example","text":"Я обяза́тельно до́лжен верну́ться в пя́тницу.","b":1},{"t":"para","text":"Thay thế: во что бы то ни ста́ло","b":1},{"t":"para","text":"Dịch: Tôi phải trở về vào thứ Sáu bằng mọi giá/bằng bất cứ giá nào."},{"t":"example","text":"Он э́то сде́лал без ви́димых причи́н.","b":1},{"t":"para","text":"Thay thế: ни с того́ ни с сего́","b":1},{"t":"para","text":"Dịch: Anh ta làm điều đó tự dưng/không đâu (không có lý do rõ ràng)."},{"t":"example","text":"Мы рассмо́трим о́ба слу́чая.","b":1},{"t":"para","text":"Thay thế: и тот и друго́й слу́чай","b":1},{"t":"para","text":"Dịch: Chúng ta sẽ xem xét cả hai trường hợp (trường hợp này và trường hợp kia)."},{"t":"example","text":"Он сего́дня о́чень серди́тый, о́чень вероя́тно, что он сейча́с закричи́т.","b":1},{"t":"para","text":"Thay thế: того́ и гляди́","b":1},{"t":"para","text":"Dịch: Hôm nay ông ấy rất cáu kỉnh, khéo/e rằng ông ấy hét toáng lên bây giờ."},{"t":"example","text":"Не сомнева́йтесь, я ему́ отомщу́, с ним ну́жно де́йствовать та́к же, как он.","b":1},{"t":"para","text":"Thay thế: тем же (оружием / способом) / платить той же монетой","b":1},{"t":"para","text":"Dịch: Đừng nghi ngờ, tôi sẽ trả thù hắn, cần phải hành động với hắn y như vậy (gậy ông đập lưng ông)."},{"t":"example","text":"У него́ не совсе́м ры́жие во́лосы, скоре́е све́тло-кашта́новые с золоти́стым отли́вом.","b":1},{"t":"para","text":"Thay thế: не то что́бы ры́жие... а...","b":1},{"t":"para","text":"Dịch: Tóc anh ấy không hẳn là đỏ, mà là màu hạt dẻ sáng ánh vàng."},{"t":"example","text":"День вчера́ был ужа́сный, на рабо́те ничего́ не получа́лось, вдоба́вок я потеря́л кошелёк.","b":1},{"t":"para","text":"Thay thế: к тому́ же","b":1},{"t":"para","text":"Dịch: Hôm qua là một ngày tồi tệ, công việc chẳng đâu vào đâu, thêm vào đó/hơn nữa tôi còn làm mất ví."},{"t":"example","text":"С восто́ка иду́т чёрные ту́чи, весьма́ вероя́тно, бу́дет гроза́.","b":1},{"t":"example","text":"Thay thế: того́ и гляди́ (chỉ điều sắp xảy ra ngay) hoặc похо́же, что.... Trong bài luyện тот, того и гляди phù hợp ngữ cảnh \"mây đen kéo đến -> sắp mưa\"."},{"t":"para","text":"Dịch: Mây đen đang kéo đến từ phía đông, trông thì/e là sắp có giông bão."},{"t":"example","text":"Выбира́ть не прихо́дится, в э́том слу́чае на́до е́хать на по́езде.","b":1},{"t":"example","text":"Thay thế: в том слу́чае (nếu so sánh) hoặc đơn giản là cụm cố định раз так / раз дело пошло на то. Tuy nhiên, nếu đề yêu cầu thay в этом случае bằng cụm với тот, có thể là раз так (không có тот). Có thể ý đề là: \"Nếu đã thế -> раз так -> раз дело дошло до того\"?"},{"t":"example","text":"Phương án khác: в таком случае."},{"t":"example","text":"Что за челове́к? Тру́дно сказа́ть. И́менно, что неизве́стно, что это за челове́к.","b":1},{"t":"para","text":"Thay thế: В том-то и де́ло","b":1},{"t":"para","text":"Dịch: Người thế nào ư? Khó nói lắm. Vấn đề chính là ở chỗ không ai biết đó là người thế nào."}]},{"id":"03-s012","type":"grammar","title":"Đại từ phản thân \"СЕБЯ\" (Возвра́тное местоиме́ние \"СЕБЯ\")","num":null,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 162):","b":1},{"t":"subhead","text":"Quy tắc:","b":1},{"t":"para","text":"Đại từ phản thân себя́ (bản thân mình/tự mình) không thay đổi theo giống, ngôi và số."},{"t":"example","text":"Ví dụ: я у себя́ (tôi đang ở chỗ tôi), ты у себя́ (bạn đang ở chỗ bạn), они́ у себя́ (họ đang ở chỗ họ)."},{"t":"para","text":"Đại từ này không có dạng Cách 1 (Danh cách - Имени́тельный паде́ж). Nó chỉ tồn tại ở các cách gián tiếp để chỉ hành động quay trở lại chủ ngữ."}]},{"id":"03-s013","type":"exercise","title":"Bài 331 (Trang 161)","num":331,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu văn. Xác định ý nghĩa của себя. Xác định cách (case) của nó."},{"t":"para","text":"Ве́чером я бу́ду у друзе́й на да́че. Ве́чером я бу́ду у себя́ на да́че.","b":1},{"t":"example","text":"Dịch: Buổi tối tôi sẽ ở nhà bạn bè tại nhà nghỉ ngoại ô. Buổi tối tôi sẽ ở chỗ mình/nhà mình tại nhà nghỉ ngoại ô."},{"t":"example","text":"Giải thích: у себя́ (Cách 2 - Sinh cách) chỉ địa điểm thuộc về chủ ngữ \"tôi\"."},{"t":"para","text":"Он о́чень строг к ученика́м, его́ боя́тся и уважа́ют. Пре́жде всего́, он о́чень строг к себе́, не позволя́ет себе́ рассла́биться.","b":1},{"t":"example","text":"Dịch: Ông ấy rất nghiêm khắc với học sinh, họ sợ và kính trọng ông. Trước hết, ông ấy rất nghiêm khắc với bản thân mình, không cho phép mình buông thả."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"к себе́ (Cách 3 - Tặng cách)","vi":"Nghiêm khắc hướng về ai? → Hướng về chính ông ấy.","g":null},{"t":"vocab","ru":"себе́ (Cách 3 - Tặng cách)","vi":"Cho phép ai? → Cho phép chính mình.","g":null},{"t":"para","text":"Посмотри́ на ста́ршего бра́та, он всегда́ оде́т аккура́тно. Посмотри́ на себя́, у тебя́ на руба́шке не хвата́ет пу́говицы.","b":1},{"t":"example","text":"Dịch: Hãy nhìn anh trai cả đi, anh ấy luôn ăn mặc gọn gàng. Hãy nhìn lại bản thân mình đi, áo sơ mi của bạn bị đứt cúc kìa."},{"t":"example","text":"Giải thích: на себя́ (Cách 4 - Đối cách): Hành động nhìn hướng vào chính người nghe."},{"t":"para","text":"Я дово́лен ва́шими успе́хами, вы отли́чно спра́вились с зада́нием. Я дово́лен собо́й, мне удало́сь довести́ до конца́ э́ту рабо́ту.","b":1},{"t":"example","text":"Dịch: Tôi hài lòng với thành tích của các bạn, các bạn đã hoàn thành xuất sắc nhiệm vụ. Tôi hài lòng với chính mình, tôi đã nỗ lực làm đến cùng công việc này."},{"t":"example","text":"Giải thích: собо́й (Cách 5 - Tạo cách): Hài lòng bởi ai? → Bởi chính tôi."},{"t":"para","text":"Она́ не лю́бит расска́зывать о пробле́мах в рабо́те. Она́ не лю́бит расска́зывать о себе́.","b":1},{"t":"example","text":"Dịch: Cô ấy không thích kể về những vấn đề trong công việc. Cô ấy không thích kể về bản thân mình."},{"t":"example","text":"Giải thích: о себе́ (Cách 6 - Giới cách): Kể về ai? → Về chính cô ấy."}]},{"id":"03-s014","type":"exercise","title":"Bài 332 (Trang 162)","num":332,"blocks":[{"t":"para","text":"Đề bài: Mở ngoặc, sử dụng hình thức cần thiết của đại từ nhân xưng (của người khác) hoặc đại từ phản thân (của chính chủ ngữ) tùy theo ngữ cảnh."},{"t":"note","text":"Lưu ý:","b":1},{"t":"para","text":"Dùng себя́ (theo các cách) khi tân ngữ chỉ cùng một người với chủ ngữ."},{"t":"example","text":"Dùng đại từ nhân xưng (меня, тебя, его, её...) khi tân ngữ chỉ người khác."},{"t":"para","text":"Ты мо́жешь горди́ться (собо́й), ты сде́лал то, что ещё никому́ не удава́лось.","b":1},{"t":"example","text":"Dịch: Bạn có thể tự hào về chính mình, bạn đã làm được điều mà chưa ai làm được."},{"t":"example","text":"Giải thích: Chủ ngữ là Ты, tự hào về chính bạn → собо́й."},{"t":"para","text":"Твой сын лу́чше всех отвеча́л на вопро́сы, ты мо́жешь горди́ться (им).","b":1},{"t":"example","text":"Dịch: Con trai bạn trả lời câu hỏi tốt nhất, bạn có thể tự hào về nó (cậu ấy)."},{"t":"example","text":"Giải thích: Chủ ngữ là Ты, nhưng tự hào về con trai (người khác) → им (Cách 5 của он)."},{"t":"para","text":"Она́ без ума́ от э́того актёра, ей нра́вится ви́деть (его́) на экра́не.","b":1},{"t":"example","text":"Dịch: Cô ấy mê mẩn nam diễn viên này, cô ấy thích nhìn thấy anh ta trên màn ảnh."},{"t":"example","text":"Giải thích: Thích nhìn diễn viên (người khác) → его́."},{"t":"para","text":"Она́ сли́шком лю́бит находи́ться в це́нтре внима́ния, для неё честь уви́деть (себя́) на обло́жке журна́ла — цель жи́зни.","b":1},{"t":"example","text":"Dịch: Cô ấy quá thích ở trung tâm sự chú ý, đối với cô ấy vinh dự được nhìn thấy mình trên bìa tạp chí là mục đích sống."},{"t":"example","text":"Giải thích: Cô ấy nhìn thấy chính cô ấy → себя́."},{"t":"para","text":"По доро́ге в теа́тр мне на́до зайти́ (к себе́) и переоде́ться.","b":1},{"t":"example","text":"Dịch: Trên đường đến nhà hát tôi cần ghé qua nhà tôi/chỗ tôi và thay đồ."},{"t":"example","text":"Giải thích: Tôi ghé qua chỗ của chính tôi → к себе́."},{"t":"para","text":"Я забы́л у роди́телей зо́нтик, мне на́до зайти́ (к ним) ве́чером.","b":1},{"t":"example","text":"Dịch: Tôi để quên ô ở chỗ bố mẹ, tôi cần ghé qua chỗ họ vào buổi tối."},{"t":"example","text":"Giải thích: Ghé qua chỗ bố mẹ (người khác) → к ним."},{"t":"para","text":"Мой друг всегда́ ря́дом, я зна́ю, что могу́ на (него́) рассчи́тывать.","b":1},{"t":"example","text":"Dịch: Bạn tôi luôn ở bên cạnh, tôi biết là tôi có thể trông cậy vào cậu ấy."},{"t":"example","text":"Giải thích: Trông cậy vào bạn (người khác) → на него́ (thêm н sau giới từ)."},{"t":"para","text":"Я всегда́ была́ о (ней) высо́кого мне́ния, и на э́тот раз она́ меня́ не подвела́.","b":1},{"t":"example","text":"Dịch: Tôi luôn đánh giá cao về cô ấy, và lần này cô ấy đã không làm tôi thất vọng."},{"t":"example","text":"Giải thích: Đánh giá về cô ấy (người được nhắc đến ở vế sau) → о ней."},{"t":"para","text":"Мне ка́жется, она́ переоце́нивает свои́ спосо́бности, она́ сли́шком высо́кого мне́ния о (себе́).","b":1},{"t":"example","text":"Dịch: Tôi thấy hình như cô ấy đánh giá quá cao năng lực của mình, cô ấy đánh giá quá cao về bản thân."},{"t":"example","text":"Giải thích: Cô ấy nghĩ về chính cô ấy → о себе́."},{"t":"para","text":"Посмотри́ на (меня́), почему́ я всё успева́ю? Посмотри́ на (себя́), ты опя́ть не гото́в к заня́тиям.","b":1},{"t":"example","text":"Dịch: Hãy nhìn tôi đi, tại sao tôi làm kịp mọi thứ? Hãy nhìn lại bản thân bạn đi, bạn lại chưa sẵn sàng cho buổi học."},{"t":"example","text":"Giải thích: Vế đầu so sánh với người nói → на меня́. Vế sau bảo người nghe tự nhìn lại mình → на себя́."},{"t":"para","text":"Э́то его́ брат, во вся́ком слу́чае, он так нам (себя́) предста́вил. Так как меня́ здесь никто́ не зна́ет, ду́маю, мне на́до предста́вить (себя́).","b":1},{"t":"example","text":"Dịch: Đó là anh trai của cậu ấy, dù sao thì anh ta cũng đã tự giới thiệu mình với chúng tôi như vậy. Vì ở đây không ai biết tôi, tôi nghĩ tôi cần phải giới thiệu bản thân."},{"t":"example","text":"Giải thích: Anh ta giới thiệu chính anh ta → себя́. Tôi giới thiệu tôi → себя́."},{"t":"para","text":"Я позво́лю (себе́) сде́лать одно́ замеча́ние. Не зна́ю, почему́ он взял твою́ кни́гу, я не позволя́л (ему́) де́лать э́того.","b":1},{"t":"example","text":"Dịch: Tôi xin phép (cho phép bản thân) đưa ra một nhận xét. Tôi không biết tại sao cậu ấy lấy sách của bạn, tôi đâu có cho phép cậu ấy làm điều đó."},{"t":"example","text":"Giải thích: Tôi cho phép tôi → себе́. Tôi không cho phép cậu ấy → ему́."}]},{"id":"03-s015","type":"exercise","title":"Bài 333 (Trang 162)","num":333,"blocks":[{"t":"example","text":"Đề bài: Điền vào chỗ trống hình thức cần thiết của đại từ nhân xưng hoặc đại từ phản thân (себя), có hoặc không có giới từ."},{"t":"para","text":"Он бо́лен, на́до вы́звать (ему́) врача́.","b":1},{"t":"example","text":"Dịch: Anh ấy bị ốm, cần gọi bác sĩ cho anh ấy. (Cho người khác → ему)."},{"t":"para","text":"Не обма́нывай (себя́), тебе́ не уда́стся спра́виться с э́той рабо́той одному́.","b":1},{"t":"example","text":"Dịch: Đừng tự lừa dối bản thân, bạn sẽ không thể tự mình hoàn thành việc này đâu. (Lừa dối chính mình → себя)."},{"t":"para","text":"Ты отдаёшь (себе́) отчёт в том, что ты де́лаешь?","b":1},{"t":"example","text":"Dịch: Bạn có nhận thức rõ (tự báo cáo cho mình) về việc bạn đang làm không? (Cụm cố định: отдавать себе отчёт → себе)."},{"t":"para","text":"Он уже́ не раз подводи́л нас, не сто́ит (ему́) доверя́ть.","b":1},{"t":"example","text":"Dịch: Hắn ta đã chơi xấu chúng tôi nhiều lần rồi, không nên tin tưởng hắn. (Tin người khác → ему)."},{"t":"para","text":"Все мы о́чень уста́ли, но нам на́до найти́ (в себе́) си́лы продо́лжить путь.","b":1},{"t":"example","text":"Dịch: Tất cả chúng tôi đều rất mệt, nhưng chúng tôi cần tìm thấy sức mạnh trong chính mình để tiếp tục đi. (Trong bản thân → в себе)."},{"t":"para","text":"Он всё смо́жет купи́ть на ме́сте, ему́ ничего́ не на́до брать (с собо́й).","b":1},{"t":"example","text":"Dịch: Anh ấy có thể mua mọi thứ tại chỗ, không cần mang theo gì theo mình. (Mang theo người chủ ngữ → с собой)."},{"t":"para","text":"Предложи́ (ему́) пое́хать с на́ми, она́ мечта́ла провести́ ле́то в гора́х.","b":1},{"t":"example","text":"Dịch: Hãy mời/đề nghị cô ấy đi cùng chúng ta, cô ấy đã mơ ước trải qua mùa hè trên núi. (Lưu ý: Động từ \"мечтала\" chia giống cái → điền ей mới đúng, nhưng nếu sách in \"мечтал\" thì là ему. Giả sử là cô ấy → ей). Sách viết \"она мечтала\" → Điền: ей."},{"t":"para","text":"Мне ле́гче име́ть де́ло с людьми́, уве́ренными (в себе́).","b":1},{"t":"example","text":"Dịch: Tôi thấy dễ làm việc với những người tự tin vào bản thân. (Tự tin vào chính họ → в себе)."},{"t":"para","text":"Извини́, что я сомнева́лся, я был не прав, и ты доказа́л (мне) э́то.","b":1},{"t":"example","text":"Dịch: Xin lỗi vì tôi đã nghi ngờ, tôi đã sai, và bạn đã chứng minh điều đó cho tôi. (Chứng minh cho người nói → мне)."},{"t":"para","text":"Весь ве́чер он вёл (себя́) ка́к-то неуве́ренно.","b":1},{"t":"example","text":"Dịch: Cả buổi tối anh ta cư xử (dẫn dắt bản thân) có vẻ không tự tin. (Cụm: вести себя - cư xử → себя)."},{"t":"para","text":"Он снял (с себя́) пальто́ и аккура́тно пове́сил его́ в шкаф.","b":1},{"t":"example","text":"Dịch: Anh ấy cởi áo khoác khỏi người và treo cẩn thận vào tủ. (Cởi khỏi chính mình → с себя)."},{"t":"para","text":"Она́ о́чень не́рвничает, (вне себя́).","b":1},{"t":"example","text":"Dịch: Cô ấy đang rất căng thẳng, mất bình tĩnh (như người điên/thoát xác). (Thành ngữ: быть вне себя → вне себя)."},{"t":"para","text":"Е́сли ты не возража́ешь, я хочу́ оста́вить (у себя́ / себе́) на па́мять оди́н экземпля́р твое́й кни́ги.","b":1},{"t":"example","text":"Dịch: Nếu bạn không phản đối, tôi muốn giữ lại cho mình/ở chỗ mình một bản cuốn sách của bạn làm kỷ niệm. (Giữ cho mình → себе hoặc у себя)."},{"t":"para","text":"Нет, с ним я не был знако́м, меня́ пригласи́ли (к нему́) на спекта́кль на́ши о́бщие знако́мые.","b":1},{"t":"example","text":"Dịch: Không, tôi không quen anh ấy, những người quen chung đã mời tôi đến xem kịch của anh ấy/chỗ anh ấy. (Đến chỗ người khác → к нему)."},{"t":"para","text":"Поду́май немно́го (о себе́), нельзя́ же всё вре́мя забо́титься о други́х.","b":1},{"t":"example","text":"Dịch: Hãy nghĩ cho bản thân một chút đi, không thể lúc nào cũng lo cho người khác được. (Nghĩ về mình → о себе)."},{"t":"para","text":"Я пое́ду (с ним), мы должны́ быть вме́сте.","b":1},{"t":"example","text":"Dịch: Tôi sẽ đi cùng anh ấy, chúng tôi phải ở bên nhau. (Đi cùng người khác → с ним)."},{"t":"para","text":"У них дво́е дете́й, они́ не мо́гут жить то́лько (для себя́).","b":1},{"t":"example","text":"Dịch: Họ có hai con, họ không thể chỉ sống cho bản thân mình. (Sống cho chính họ → для себя)."},{"t":"para","text":"Кни́га у меня́ до́ма, дава́й по доро́ге зайдём (ко мне) и возьмём её.","b":1},{"t":"example","text":"Dịch: Sách ở nhà tôi, chúng ta hãy ghé qua chỗ tôi trên đường đi và lấy nó. (Về chỗ người nói → ко мне)."}]},{"id":"03-s016","type":"exercise","title":"Bài 334 (Trang 163)","num":334,"blocks":[{"t":"example","text":"Đề bài: Hoàn thành câu, sử dụng đại từ phản thân (себя...) hoặc đại từ nhấn mạnh сам (tự mình) ở dạng phù hợp."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 163 - Khung):","b":1},{"t":"vocab","ru":"Сам (сама́, само́, са́ми)","vi":"Đại từ xác định (nhấn mạnh). Có nghĩa là \"tự mình làm, không ai giúp\". Biến đổi theo giống, số, cách như tính từ.","g":null},{"t":"example","text":"Ví dụ: Я сам это сделал (Tôi tự làm điều đó)."},{"t":"vocab","ru":"Себя́","vi":"Đại từ phản thân. Có nghĩa là hành động tác động lên chính chủ thể.","g":null},{"t":"example","text":"Ví dụ: Я купил себе книгу (Tôi mua cho mình một cuốn sách)."},{"t":"subhead","text":"Đáp án:","b":1},{"t":"para","text":"А ты (сам) ве́ришь?","b":1},{"t":"example","text":"Dịch: Còn bạn, bản thân bạn có tin không?"},{"t":"para","text":"Ты мо́жешь сде́лать (себе́) причёску?","b":1},{"t":"example","text":"Dịch: Bạn có thể tự làm tóc cho mình không?"},{"t":"para","text":"Она́ вы́звала врача́ (сама́).","b":1},{"t":"example","text":"Dịch: Cô ấy đã tự mình gọi bác sĩ. (Nhấn mạnh cô ấy tự làm)."},{"t":"para","text":"Он тре́бователен (к себе́).","b":1},{"t":"example","text":"Dịch: Anh ấy khắt khe với bản thân."},{"t":"para","text":"Не сто́ит обма́нывать (себя́ / самого́ себя́).","b":1},{"t":"example","text":"Dịch: Không nên tự lừa dối mình / chính mình."},{"t":"para","text":"Поче́му ты разгова́риваешь (сам с собо́й)?","b":1},{"t":"example","text":"Dịch: Tại sao bạn lại nói chuyện một mình (tự với mình)?"},{"t":"para","text":"Случи́лось так, что я слома́л (себе́) па́лец.","b":1},{"t":"example","text":"Dịch: Chuyện là tôi đã làm gãy ngón tay của mình (gãy ngón tay cho mình - tiếng Nga dùng себе để chỉ bộ phận cơ thể bị tác động)."},{"t":"para","text":"Дава́й позвони́м (к тебе́ / ко мне) домо́й?","b":1},{"t":"example","text":"Dịch: Hãy gọi về nhà bạn/tôi đi? (Ở đây không dùng phản thân vì \"chúng ta\" gọi về nhà của một người cụ thể)."},{"t":"para","text":"Положи́ (себе́) на таре́лку всё, что ты хо́чешь.","b":1},{"t":"example","text":"Dịch: Hãy lấy (đặt) vào đĩa cho mình tất cả những gì bạn muốn."},{"t":"para","text":"Следи́ (за собо́й), мо́жет быть, симпто́мы боле́зни не повторя́тся.","b":1},{"t":"example","text":"Dịch: Hãy theo dõi/chăm sóc bản thân, có thể triệu chứng bệnh sẽ không tái phát."},{"t":"para","text":"Будь внима́тельным (к себе́).","b":1},{"t":"example","text":"Dịch: Hãy chú ý đến bản thân."},{"t":"para","text":"Тебе́ на́до сде́лать (себе́) макия́ж.","b":1},{"t":"example","text":"Dịch: Bạn cần trang điểm (làm mặt cho mình)."},{"t":"para","text":"Он никогда́ не ду́мает (о себе́).","b":1},{"t":"example","text":"Dịch: Anh ấy không bao giờ nghĩ cho bản thân."},{"t":"para","text":"Он про́сто добива́ется внима́ния (к себе́).","b":1},{"t":"example","text":"Dịch: Anh ta chỉ đang cố kiếm sự chú ý về mình."},{"t":"para","text":"Я хочу́ сде́лать (себе́) пода́рок.","b":1},{"t":"example","text":"Dịch: Tôi muốn tặng cho mình một món quà."},{"t":"para","text":"Мне никогда́ не ску́чно (с сами́м собо́й).","b":1},{"t":"example","text":"Dịch: Tôi không bao giờ thấy chán khi ở một mình (với chính mình)."},{"t":"para","text":"Мне на́до приду́мать план де́йствий (самому́).","b":1},{"t":"example","text":"Dịch: Tôi cần phải tự mình nghĩ ra kế hoạch hành động."},{"t":"para","text":"Вы должны́ найти́ си́лы (в себе́).","b":1},{"t":"example","text":"Dịch: Các bạn phải tìm thấy sức mạnh trong chính mình."},{"t":"para","text":"Нельзя́ так относи́ться (к себе́)!","b":1},{"t":"example","text":"Dịch: Không được đối xử với bản thân như thế!"}]},{"id":"03-s017","type":"exercise","title":"Bài 335 (Trang 163)","num":335,"blocks":[{"t":"example","text":"Đề bài: Điền себя (với giới từ hoặc không) hoặc сам (ở dạng đúng). Giải thích sự lựa chọn."},{"t":"para","text":"Поче́му ты расска́зываешь то́лько о други́х, а что ты мо́жешь сказа́ть (о себе́)?","b":1},{"t":"example","text":"Dịch: Tại sao bạn chỉ kể về người khác, thế bạn có thể nói gì về mình?"},{"t":"example","text":"Giải thích: Kể về chủ ngữ → о себе (Cách 6)."},{"t":"para","text":"Я не могу́ найти́ твою́ ру́чку, посмотри́ (сам) на столе́.","b":1},{"t":"example","text":"Dịch: Tôi không tìm thấy bút của bạn, bạn hãy tự xem trên bàn đi."},{"t":"example","text":"Giải thích: Nhấn mạnh chủ ngữ tự làm → сам."},{"t":"para","text":"Поздравле́ний ещё не́ было, но я реши́л поздра́вить (себя́ / сам себя́).","b":1},{"t":"example","text":"Dịch: Chưa có lời chúc nào, nhưng tôi quyết định tự chúc mừng mình."},{"t":"example","text":"Giải thích: Hành động hướng vào bản thân → себя (Cách 4)."},{"t":"para","text":"Он лю́бит исключи́тельно (себя́).","b":1},{"t":"example","text":"Dịch: Anh ta chỉ yêu duy nhất bản thân mình."},{"t":"example","text":"Giải thích: Yêu chính mình → себя (Cách 4)."},{"t":"para","text":"Ты ни для кого́ друго́го не до́лжен гото́вить, но ты мо́жешь свари́ть таре́лку су́па (себе́ / для себя́).","b":1},{"t":"example","text":"Dịch: Bạn không phải nấu cho ai khác, nhưng bạn có thể nấu một bát súp cho mình."},{"t":"example","text":"Giải thích: Nấu cho ai hưởng → себе (Cách 3) hoặc для себя (Cách 2)."},{"t":"para","text":"Я не смогу́ вы́полнить твою́ про́сьбу, тебе́ придётся (самому́) купи́ть ... слова́рь.","b":1},{"t":"example","text":"Dịch: Tôi không thể thực hiện yêu cầu của bạn, bạn sẽ phải tự mình mua từ điển."},{"t":"example","text":"Giải thích: Bạn phải tự làm lấy → самому (Dative của сам, đi với cấu trúc тебе придется)."},{"t":"para","text":"Коне́чно, мы все придём к тебе́ на по́мощь, но пре́жде всего́ ты до́лжен помо́чь (себе́ сам).","b":1},{"t":"example","text":"Dịch: Tất nhiên chúng tôi sẽ đến giúp, nhưng trước hết bạn phải tự giúp chính mình."},{"t":"example","text":"Giải thích: Giúp mình (себе) + nhấn mạnh tự (сам)."},{"t":"para","text":"Ты совсе́м не отдыха́ешь, рабо́таешь без переры́ва, нельзя́ быть таки́м стро́гим (к себе́).","b":1},{"t":"example","text":"Dịch: Bạn không nghỉ ngơi chút nào... không thể nghiêm khắc với bản thân như thế được."},{"t":"example","text":"Giải thích: Nghiêm khắc với mình → к себе (Cách 3)."},{"t":"para","text":"Не обраща́й внима́ния на сове́ты други́х, слуша́йся (себя́)...","b":1},{"t":"example","text":"Dịch: Đừng để ý lời khuyên người khác, hãy nghe theo chính mình..."},{"t":"example","text":"Giải thích: Nghe lời ai → себя (Cách 4)."},{"t":"para","text":"Коне́чно, преподава́тель прове́рит твою́ рабо́ту, но снача́ла ты до́лжен прове́рить (её сам).","b":1},{"t":"example","text":"Dịch: Tất nhiên giáo viên sẽ kiểm tra bài của bạn, nhưng trước tiên bạn phải tự mình kiểm tra nó."},{"t":"example","text":"Giải thích: Tự làm → сам."},{"t":"para","text":"Я ду́маю, никто́ не до́лжен дава́ть ему́ сове́ты, он до́лжен разобра́ться (сам / в себе́).","b":1},{"t":"example","text":"Dịch: Tôi nghĩ không ai nên khuyên anh ấy, anh ấy phải tự mình giải quyết (hoặc: hiểu rõ bản thân mình)."},{"t":"example","text":"Giải thích: Nếu ý là \"tự giải quyết vấn đề\" → сам. Nếu ý là \"hiểu nội tâm mình\" → в себе. Ngữ cảnh \"không cần lời khuyên\" thiên về сам."},{"t":"para","text":"Никто́ меня́ не бил, я упа́л и разби́л (себе́) лицо́.","b":1},{"t":"example","text":"Dịch: Không ai đánh tôi cả, tôi ngã và làm dập mặt mình (làm dập mặt cho tôi)."},{"t":"example","text":"Giải thích: Làm đau bộ phận cơ thể mình → себе."},{"t":"para","text":"Никто́ в э́том не винова́т, ты страда́ешь исключи́тельно (из-за себя́ / по свое́й вине́).","b":1},{"t":"example","text":"Dịch: Không ai có lỗi cả, bạn đau khổ chỉ tại chính mình."},{"t":"example","text":"Giải thích: Tại ai → из-за себя (Cách 2)."},{"t":"para","text":"Мы ему́ ве́рим, но пре́жде всего́ он до́лжен пове́рить (в себя́).","b":1},{"t":"example","text":"Dịch: Chúng tôi tin anh ấy, nhưng trước hết anh ấy phải tin vào chính mình."},{"t":"example","text":"Giải thích: Tin vào ai → в себя (Cách 4)."}]},{"id":"03-s018","type":"exercise","title":"Bài 336 (Trang 164)","num":336,"blocks":[{"t":"para","text":"Đề bài: Đọc các câu văn, chú ý các cụm từ cố định với đại từ phản thân. Xác định ý nghĩa của chúng."},{"t":"subhead","text":"Giải thích ngữ pháp (Thành ngữ với СЕБЯ):","b":1},{"t":"vocab","ru":"Не по себе́","vi":"Cảm thấy khó ở, không thoải mái, bối rối.","g":null},{"t":"vocab","ru":"Прийти́ в себя́","vi":"Tỉnh lại (sau khi ngất), trấn tĩnh lại (sau khi sốc).","g":null},{"t":"vocab","ru":"Про себя́","vi":"Đọc thầm (không ra tiếng), nghĩ thầm trong đầu.","g":null},{"t":"vocab","ru":"Взять себя́ в ру́ки","vi":"Kiềm chế cảm xúc, trấn tĩnh lại (nghĩa đen: nắm lấy bản thân trong tay).","g":null},{"t":"vocab","ru":"Само́ собо́й (разуме́ется)","vi":"Tất nhiên, điều hiển nhiên (tự nó đã rõ).","g":null},{"t":"vocab","ru":"Себе́ на уме́","vi":"Kín đáo, khôn ngầm, láu cá (người không để lộ suy nghĩ).","g":null},{"t":"vocab","ru":"Говори́ть са́ми за себя́","vi":"Tự nói lên tất cả (rõ ràng, không cần giải thích thêm).","g":null},{"t":"vocab","ru":"Выводи́ть из себя́","vi":"Làm ai đó phát điên, mất bình tĩnh.","g":null},{"t":"vocab","ru":"Брать на себя́ (сме́лость / отве́тственность)","vi":"Gánh vác, đảm nhận (trách nhiệm, sự táo bạo).","g":null},{"t":"vocab","ru":"Вы́дать себя́ (с голово́й)","vi":"Tự để lộ tẩy, tự tố cáo mình (lộ sơ hở).","g":null},{"t":"vocab","ru":"Сам по себе́","vi":"Độc lập, riêng biệt, tự thân nó.","g":null},{"t":"para","text":"Dịch và Giải nghĩa chi tiết:","b":1},{"t":"para","text":"Как ты себя́ чу́вствуешь? Ничего́ стра́шного, про́сто мне ста́ло не по себе́, наве́рное, от шу́ма и духоты́.","b":1},{"t":"example","text":"Dịch: Bạn cảm thấy thế nào? Không có gì đáng sợ đâu, chỉ là tôi thấy khó ở/nôn nao (không khỏe), chắc là do ồn ào và ngột ngạt."},{"t":"example","text":"Ý nghĩa: не по себе = cảm thấy mệt hoặc khó chịu trong người."},{"t":"para","text":"Э́сли ты не мо́жешь запо́мнить сра́зу, повтори́ не́сколько раз про себя́, но так, что́бы никому́ не меша́ть.","b":1},{"t":"example","text":"Dịch: Nếu bạn không thể nhớ ngay lập tức, hãy nhẩm lại vài lần trong đầu/thầm, nhưng sao cho không làm phiền ai cả."},{"t":"example","text":"Ý nghĩa: про себя = thầm, không thành tiếng."},{"t":"para","text":"Возьми́ себя́ в ру́ки, как бы ни бы́ло тру́дно, ты до́лжен довести́ де́ло до конца́.","b":1},{"t":"example","text":"Dịch: Hãy trấn tĩnh lại/kiềm chế bản thân, dù khó khăn thế nào, bạn cũng phải hoàn thành công việc."},{"t":"example","text":"Ý nghĩa: взять себя в руки = kiểm soát cảm xúc để hành động."},{"t":"para","text":"Так ты пое́дешь с на́ми в Но́вгород? — Само́ собо́й (разуме́ется), пое́ду, ведь э́то была́ моя́ иде́я.","b":1},{"t":"example","text":"Dịch: Thế bạn có đi Novgorod với chúng tôi không? — Tất nhiên là (tự nó đã rõ) tôi đi rồi, đó là ý tưởng của tôi mà."},{"t":"example","text":"Ý nghĩa: само собой = đương nhiên."},{"t":"para","text":"Будь с ним осторо́жен, он себе́ на уме́, э́то то́лько с ви́ду он тако́й простоду́шный.","b":1},{"t":"example","text":"Dịch: Hãy cẩn thận với hắn, hắn khôn ngầm/thâm nho đấy, vẻ ngoài đơn giản thế thôi."},{"t":"example","text":"Ý nghĩa: себе на уме = người có toan tính riêng, không lộ ra."},{"t":"para","text":"Не ду́маю, что тебе́ придётся что́-то объясня́ть, твой посту́пки са́ми за себя́ говоря́т.","b":1},{"t":"example","text":"Dịch: Tôi không nghĩ bạn cần phải giải thích gì đâu, hành động của bạn đã tự nói lên tất cả rồi."},{"t":"example","text":"Ý nghĩa: сами за себя говорят = rõ ràng, không thể chối cãi."},{"t":"para","text":"Ра́ди бо́га переста́нь опя́ть говори́ть об э́том, не выво́ди меня́ из себя́!","b":1},{"t":"example","text":"Dịch: Vì Chúa, hãy ngừng nói về chuyện đó đi, đừng làm tôi điên lên/mất bình tĩnh nữa!"},{"t":"example","text":"Ý nghĩa: выводить из себя = chọc tức, làm ai nổi giận."},{"t":"para","text":"С тобо́й возмо́жно рабо́тать одному́ за всех, ты сли́шком мно́го берёшь на себя́.","b":1},{"t":"example","text":"Dịch: Làm việc với bạn thì thà làm một mình còn hơn, bạn ôm đồm quá nhiều/tự cho mình quyền quá lớn."},{"t":"example","text":"Ý nghĩa: брать на себя = nhận trách nhiệm hoặc quyền hạn quá mức."},{"t":"para","text":"Да он испуга́лся, когда́ ты его́ спра́шивал о вчера́шнем ве́чере, и э́тим вы́дал себя́ с голово́й, тепе́рь никто́ не сомнева́ется в том, что он вино́вен.","b":1},{"t":"example","text":"Dịch: Hắn đã sợ hãi khi bạn hỏi về tối qua, và chính điều đó đã tố cáo hắn hoàn toàn, giờ thì không ai nghi ngờ việc hắn có tội nữa."},{"t":"example","text":"Ý nghĩa: выдал себя с головой = lộ tẩy hoàn toàn."},{"t":"para","text":"Разреши́те мне взять на себя́ сме́лость пе́рвым поздра́вить молоды́х: “Сове́т да любо́вь!”.","b":1},{"t":"example","text":"Dịch: Cho phép tôi mạo muội/mạnh dạn là người đầu tiên chúc mừng đôi uyên ương: \"Hạnh phúc và hòa thuận nhé!\"."},{"t":"example","text":"Ý nghĩa: взять на себя смелость = xin phép làm điều gì đó táo bạo/trang trọng."},{"t":"para","text":"Нет, я ни к како́й полити́ческой па́ртии не принадлежу́, я сам по себе́.","b":1},{"t":"example","text":"Dịch: Không, tôi không thuộc đảng phái chính trị nào cả, tôi độc lập/đứng riêng một mình."},{"t":"example","text":"Ý nghĩa: сам по себе = tự do, không phụ thuộc."}]},{"id":"03-s019","type":"exercise","title":"Bài 337 (Trang 164)","num":337,"blocks":[{"t":"example","text":"Đề bài: Sử dụng các cụm từ cố định với đại từ phản thân себя (từ bài 336), hãy đưa ra lời khuyên cho người quen của bạn."},{"t":"vocab","ru":"Ситуация","vi":"Bạn của bạn lo lắng và bực bội vì những chuyện vặt vãnh.","g":null},{"t":"subhead","text":"Đáp án: Возьми́ себя́ в ру́ки! (Hãy bình tĩnh lại/Kiềm chế bản thân đi!)"},{"t":"example","text":"Hoặc: Не выво́ди себя́ из равнове́сия. (Đừng tự làm mình mất cân bằng)."},{"t":"vocab","ru":"Ситуация","vi":"Bạn ấy rất lo lắng về việc mình sẽ trông như thế nào trong buổi lễ ngày mai.","g":null},{"t":"subhead","text":"Đáp án: Будь уве́рен в себе́! (Hãy tự tin vào bản thân!)"},{"t":"example","text":"Hoặc nếu ý là chăm chút ngoại hình: Приведи́ себя́ в поря́док. (Hãy chỉnh trang lại mình). Nhưng ngữ cảnh \"lo lắng\" thường cần lời khuyên về tâm lý → Владей собой (Làm chủ bản thân)."},{"t":"vocab","ru":"Ситуация","vi":"Bạn ấy học thuộc lòng bài thơ, lặp lại to lời trong phòng nơi mọi người đang nói chuyện.","g":null},{"t":"subhead","text":"Đáp án: Чита́й про себя́! (Hãy đọc thầm đi!)"}]},{"id":"03-s020","type":"grammar","title":"Đại từ sở hữu phản thân \"СВОЙ\" (Местоимение \"свой\")","num":null,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 165):","b":1},{"t":"example","text":"Ý nghĩa: Свой (của mình/của bản thân) chỉ sự sở hữu thuộc về chủ ngữ của câu. Nó biến đổi theo giống, số, cách như tính từ (свой, своя́, своё, свои́...)."},{"t":"subhead","text":"Quy tắc phân biệt:","b":1},{"t":"vocab","ru":"Với chủ ngữ là ngôi thứ 1 và 2 (я, ты, мы, вы)","vi":"Có thể dùng свой hoặc đại từ sở hữu tương ứng (мой, твой, наш, ваш). Свой mang sắc thái nhấn mạnh sự sở hữu riêng.","g":null},{"t":"vocab","ru":"Với chủ ngữ là ngôi thứ 3 (он, она, они)","vi":"Bắt buộc phải phân biệt.","g":null},{"t":"vocab","ru":"Свой","vi":"Của chính chủ ngữ (Ví dụ: Он любит свою жену - Nó yêu vợ của nó).","g":null},{"t":"vocab","ru":"Его́/Её/Их","vi":"Của người khác (Ví dụ: Он любит его жену - Nó yêu vợ của thằng kia).","g":null}]},{"id":"03-s021","type":"exercise","title":"Bài 338 (Trang 165)","num":338,"blocks":[{"t":"para","text":"Đề bài: Xác định giống, cách và số của các đại từ được in đậm (đã được chuyển thành dạng điền trong bài giải)."},{"t":"para","text":"Его́ руба́шка... (своя́) руба́шка...","b":1},{"t":"vocab","ru":"Его","vi":"Giống đực, Cách 2 (Sở hữu cách - của anh ấy), Số ít. (Không biến đổi).","g":null},{"t":"vocab","ru":"Своя","vi":"Giống cái (theo рубашка), Cách 1 (Danh cách), Số ít.","g":null},{"t":"para","text":"О́коло его́ до́ма... о́коло (своего́) до́ма.","b":1},{"t":"vocab","ru":"Его","vi":"Không đổi.","g":null},{"t":"vocab","ru":"Своего","vi":"Giống đực, Cách 2 (Sinh cách), Số ít.","g":null},{"t":"para","text":"Я отпра́вила сы́на к его́ роди́телям... к (свои́м) роди́телям.","b":1},{"t":"vocab","ru":"Его","vi":"Không đổi.","g":null},{"t":"vocab","ru":"Своим","vi":"Số nhiều, Cách 3 (Tặng cách).","g":null},{"t":"para","text":"Твоего́ уче́бника... (своего́) уче́бника...","b":1},{"t":"vocab","ru":"Твоего","vi":"Giống đực, Cách 2, Số ít.","g":null},{"t":"vocab","ru":"Своего","vi":"Giống đực, Cách 2, Số ít.","g":null},{"t":"para","text":"Твои́ми успе́хами... (свои́м) сы́ном.","b":1},{"t":"vocab","ru":"Твоими","vi":"Số nhiều, Cách 5 (Tạo cách).","g":null},{"t":"vocab","ru":"Своим","vi":"Giống đực, Cách 5, Số ít.","g":null},{"t":"para","text":"О твое́й рабо́те... о (свое́й) рабо́те.","b":1},{"t":"vocab","ru":"Твоей","vi":"Giống cái, Cách 6 (Giới cách), Số ít.","g":null},{"t":"vocab","ru":"Своей","vi":"Giống cái, Cách 6, Số ít.","g":null}]},{"id":"03-s022","type":"exercise","title":"Bài 339 (Trang 165)","num":339,"blocks":[{"t":"example","text":"Đề bài: Thay dấu ba chấm bằng dạng cần thiết của đại từ свой (của mình)."},{"t":"note","text":"Lưu ý: Trong câu phức, свой trong mệnh đề phụ chỉ sự sở hữu của chủ ngữ của mệnh đề phụ đó."},{"t":"para","text":"Я хочу́ от тебя́ услы́шать (свою́) ве́рсию того́, что произошло́.","b":1},{"t":"example","text":"Dịch: Tôi muốn nghe từ bạn phiên bản của bạn (phiên bản mà bạn kể) về chuyện đã xảy ra."},{"t":"example","text":"Giải thích: Mặc dù chủ ngữ chính là Я, nhưng ý nghĩa là nghe phiên bản của người kể (bạn). Tuy nhiên, theo quy tắc chặt chẽ, свой theo chủ ngữ Я sẽ là \"phiên bản của tôi\". Nhưng ngữ cảnh này là \"phiên bản của bạn\". Lưu ý: Nếu dùng свою, nó ám chỉ về chủ ngữ Я (tôi muốn nghe phiên bản của tôi?). Trong khẩu ngữ, đôi khi свой dùng cho người đối thoại. Nhưng đáp án chính xác theo chủ ngữ Я phải là твою. Đề bài bắt điền свой? Nếu bắt buộc điền свой, thì có nghĩa là \"Tôi muốn nghe câu chuyện của riêng mình (tự mình kể??)\"."},{"t":"example","text":"Sách bài tập có thể ngụ ý: \"Tôi muốn nghe phiên bản của bạn (твою).\" Nhưng đề bài yêu cầu свой. Trong mệnh đề \"чтобы ты рассказал мне свою версию\" (để bạn kể cho tôi phiên bản của bạn) thì свою đúng vì chủ ngữ là ты."},{"t":"subhead","text":"Đáp án câu này trong ngữ cảnh câu ghép: Я хочу, чтобы ты рассказал мне свою (của bạn) версию... (Ở đây chủ ngữ mệnh đề phụ là ты)."},{"t":"para","text":"Он ду́мал, что помо́жет дру́гу спра́виться с (его́ / свои́ми) тру́дностями.","b":1},{"t":"example","text":"Dịch: Anh ấy nghĩ rằng sẽ giúp bạn giải quyết khó khăn của anh ta (bạn) hay của mình?"},{"t":"example","text":"Phân tích: Chủ ngữ là Он. Nếu giúp bạn giải quyết khó khăn của bạn → dùng его. Nếu giúp bạn bằng khó khăn của mình (vô lý)."},{"t":"example","text":"Tuy nhiên: Trong cấu trúc nguyên thể помочь другу справиться..., chủ ngữ ngầm của справиться là друг. Vì vậy, справиться со своими трудностями (bạn tự giải quyết khó khăn của bạn) là đúng."},{"t":"subhead","text":"Đáp án: со своими."},{"t":"para","text":"Мы хоти́м взять то́лько (свои́) ве́щи.","b":1},{"t":"example","text":"Dịch: Chúng tôi chỉ muốn lấy đồ của mình."},{"t":"subhead","text":"Đáp án: свои́ (Cách 4, số nhiều)."},{"t":"para","text":"Вы мо́жете отпра́вить (свою́) посы́лку со мной, я уезжа́ю за́втра.","b":1},{"t":"example","text":"Dịch: Bạn có thể gửi bưu kiện của bạn qua tôi, mai tôi đi rồi."},{"t":"subhead","text":"Đáp án: свою́ (Cách 4, giống cái)."},{"t":"para","text":"Вы мо́жете в любо́е вре́мя прийти́ к нам со (свои́ми) пробле́мами.","b":1},{"t":"example","text":"Dịch: Các bạn có thể đến chỗ chúng tôi bất cứ lúc nào với những vấn đề của các bạn."},{"t":"subhead","text":"Đáp án: со свои́ми (Cách 5, số nhiều)."},{"t":"para","text":"На (своё / моё) письмо́ я не получи́ла никако́го отве́та.","b":1},{"t":"example","text":"Dịch: Tôi không nhận được hồi âm nào cho lá thư của mình."},{"t":"subhead","text":"Đáp án: своё (hoặc моё). Với chủ ngữ Я, dùng своё rất tự nhiên."},{"t":"para","text":"Я попроси́л дру́га переда́ть ей (мои́ / свои́) наилу́чшие пожела́ния.","b":1},{"t":"example","text":"Dịch: Tôi nhờ bạn chuyển cho cô ấy những lời chúc tốt đẹp nhất của tôi."},{"t":"example","text":"Phân tích: Chủ ngữ Я nhờ. Lời chúc là của Я. Nhưng hành động передать (chuyển) do друг làm. Nếu dùng свои ở đây, nó có thể bị hiểu là lời chúc của người bạn. Để tránh mơ hồ, tốt nhất dùng мои. Tuy nhiên, nếu đề bắt buộc điền свой, thì trong cấu trúc này đôi khi người Nga vẫn dùng свои nếu ngữ cảnh rõ ràng là chủ ngữ chính sở hữu. (Nhưng мои chuẩn hơn)."},{"t":"example","text":"Nếu theo sách: Có thể sách chấp nhận свои (lời chúc của người thực hiện hành động chuyển? Không, lời chúc của tôi). Khả năng cao sách muốn điền мои. (Đề bài 339 nói: điền cần thiết)."},{"t":"para","text":"Я забы́л очки́ и попроси́л сосе́да написа́ть на конве́рте (мой / свой) обра́тный а́дрес.","b":1},{"t":"example","text":"Dịch: Tôi quên kính và nhờ hàng xóm viết địa chỉ gửi lại của tôi lên phong bì."},{"t":"example","text":"Phân tích: Tương tự câu 7. Địa chỉ là của tôi. Người viết là hàng xóm. Nếu dùng свой, nghĩa là hàng xóm viết địa chỉ của ông ấy. Dùng мой để chỉ địa chỉ của tôi."},{"t":"para","text":"Вы мо́жете оста́вить (свои́) ве́щи в ка́мере хране́ния.","b":1},{"t":"example","text":"Dịch: Ông có thể để đồ của mình ở tủ giữ đồ."},{"t":"subhead","text":"Đáp án: свои́."},{"t":"para","text":"Кни́ги лежа́т на (своём) ме́сте.","b":1},{"t":"example","text":"Dịch: Sách nằm ở chỗ của chúng (đúng chỗ)."},{"t":"subhead","text":"Đáp án: своём."}]},{"id":"03-s023","type":"exercise","title":"Bài 340 (Trang 166)","num":340,"blocks":[{"t":"example","text":"Đề bài: Điền vào chỗ trống đại từ sở hữu (его, её, их, мой...) hoặc đại từ sở hữu phản thân (свой)."},{"t":"subhead","text":"Gợi ý quan trọng (Trang 166):","b":1},{"t":"example","text":"Trong các câu bị động (Passive voice), свой thường chỉ sự sở hữu của Chủ ngữ (ở Cách 1)."},{"t":"example","text":"Ví dụ: Эта проблема еще не нашла своего решения. (Vấn đề này vẫn chưa tìm ra giải pháp của nó)."},{"t":"example","text":"Nếu câu có chủ thể hành động ở Cách 5 (Tạo cách), việc dùng свой có thể gây mơ hồ, nên thường dùng đại từ sở hữu (его, её) nếu muốn chỉ chủ thể đó. Nhưng nếu chỉ chủ ngữ của câu thì dùng свой."},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"para","text":"Она́ назвала́ (своего́) ребёнка Серге́ем.","b":1},{"t":"example","text":"Dịch: Cô ấy đặt tên cho con của mình là Sergey."},{"t":"example","text":"Giải thích: Chủ động, chủ ngữ là cô ấy → своего."},{"t":"para","text":"...ребёнок был на́зван (свои́м) отцо́м.","b":1},{"t":"example","text":"Dịch: ...đứa trẻ được đặt tên bởi cha của nó (cha ruột)."},{"t":"example","text":"Giải thích: Bị động. Chủ ngữ là đứa trẻ. Cha là của đứa trẻ → своим. (Nếu cha của người khác thì dùng его)."},{"t":"para","text":"Мы прове́рили (свои́) зада́ния.","b":1},{"t":"example","text":"Dịch: Chúng tôi đã kiểm tra bài tập của mình."},{"t":"example","text":"Giải thích: Chủ động → свои."},{"t":"para","text":"...зада́ния бы́ли прове́рены (свои́ми/на́шими) исполни́телями. (Câu này trong sách có thể khác, kiểm tra lại)."},{"t":"example","text":"Sách: \"...задания были проверены.\" (Không có chỗ trống ở câu bị động trong sách gốc hình ảnh, chỉ có câu chủ động cần điền)."},{"t":"example","text":"Nếu có: Задания (chủ ngữ) được kiểm tra bởi người làm (исполнителями)."},{"t":"para","text":"Мы полго́да стро́или (свой) дом.","b":1},{"t":"example","text":"Dịch: Chúng tôi xây nhà của mình suốt nửa năm."},{"t":"example","text":"Giải thích: Chủ động → свой."},{"t":"para","text":"...дом стро́ится уже́ бо́лее го́да. (Câu bị động không có chỗ trống)."},{"t":"para","text":"Я э́то сде́лал (свои́ми) рука́ми.","b":1},{"t":"example","text":"Dịch: Tôi đã làm điều đó bằng chính đôi tay của mình."},{"t":"example","text":"Giải thích: Chủ động → своими."},{"t":"para","text":"Э́то бы́ло сде́лано (мои́ми) рука́ми. (Trong sách có thể là chỗ trống)."},{"t":"example","text":"Giải thích: Это (chủ ngữ). Làm bởi tay của tôi → моими. Dùng своими ở đây có thể bị hiểu là \"tay của Nó (chủ ngữ)\". Để rõ ràng là tay tôi, dùng моими. Tuy nhiên, thành ngữ \"сделано своими руками\" (handmade) rất phổ biến và dùng своими cho nghĩa chung. Nếu cụ thể là tôi làm: моими."},{"t":"para","text":"Все спо́рные вопро́сы реша́ются в (своём) коллекти́ве.","b":1},{"t":"example","text":"Dịch: Mọi vấn đề tranh chấp đều được giải quyết trong tập thể của chúng/của nó (nơi phát sinh)."},{"t":"example","text":"Giải thích: Bị động. Chủ ngữ вопросы. Tập thể là nơi của các vấn đề đó → своём."},{"t":"para","text":"Поздравля́ю тебя́! Твой друг доби́лся измене́ния (своего́) вне́шнего ви́да.","b":1},{"t":"example","text":"Dịch: Chúc mừng bạn! Bạn của bạn đã đạt được sự thay đổi ngoại hình của cậu ấy."},{"t":"example","text":"Giải thích: Chủ ngữ друг. Ngoại hình của друг → своего."},{"t":"para","text":"Журна́л публику́ет о́тлики (свои́х) чита́телей на но́вые произведе́ния.","b":1},{"t":"example","text":"Dịch: Tạp chí đăng tải phản hồi của độc giả của nó (tạp chí) về các tác phẩm mới."},{"t":"example","text":"Giải thích: Chủ ngữ Журнал. Độc giả của Журнал → своих."},{"t":"para","text":"Они́ сда́ли (свои́) рабо́ты во́время.","b":1},{"t":"example","text":"Dịch: Họ đã nộp bài làm của mình đúng hạn."},{"t":"example","text":"Giải thích: Chủ ngữ Они. Bài của Они → свои."}]},{"id":"03-s024","type":"grammar","title":"Lý thuyết ngữ pháp: Đại từ \"СВОЙ\" (Của mình)","num":null,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Tổng hợp từ sách):","b":1},{"t":"subhead","text":"Quy tắc cơ bản: Đại từ свой (của mình) chỉ sự sở hữu thuộc về chủ ngữ của câu (hoặc mệnh đề)."},{"t":"example","text":"Ví dụ: Я люблю свою маму. (Tôi yêu mẹ của mình - Mẹ của Tôi)."},{"t":"example","text":"Он любит свою маму. (Nó yêu mẹ của mình - Mẹ của Nó)."},{"t":"subhead","text":"Sự khác biệt với мой, твой, его...:","b":1},{"t":"vocab","ru":"Với ngôi thứ 1 và 2 (я, мы, ты, вы)","vi":"Có thể dùng cả свой hoặc мой/твой... (nghĩa tương đương, свой phổ biến hơn).","g":null},{"t":"vocab","ru":"Với ngôi thứ 3 (он, она, они)","vi":"Bắt buộc phải phân biệt.","g":null},{"t":"para","text":"Dùng свой nếu vật thuộc về chủ ngữ."},{"t":"para","text":"Dùng его/её/их nếu vật thuộc về người khác."},{"t":"example","text":"Ví dụ: Он взял свою книгу (Nó lấy sách của chính nó). Он взял его книгу (Nó lấy sách của thằng khác)."},{"t":"note","text":"Lưu ý quan trọng:","b":1},{"t":"example","text":"Свой thường không được dùng làm chủ ngữ (trừ các thành ngữ hoặc nghĩa tổng quát \"người nhà\"). Ví dụ: Không nói Свой дом стоит там (Nhà của mình đứng đó), phải nói Мой/Его дом...."},{"t":"para","text":"Trong các cấu trúc không có chủ ngữ rõ ràng (vô nhân xưng), việc chọn từ phụ thuộc vào chủ thể logic hoặc ngữ cảnh."}]},{"id":"03-s025","type":"exercise","title":"Bài 341 (Trang 166)","num":341,"blocks":[{"t":"example","text":"Đề bài: Điền đại từ sở hữu свой (ở cách phù hợp) vào chỗ trống nếu có thể. Nếu không, hãy giải thích và dùng đại từ khác (его, её...). (Lưu ý: Đề bài gốc yêu cầu điền \"свой\", nhưng trong thực tế một số câu không dùng được \"свой\", ta sẽ phân tích kỹ)."},{"t":"para","text":"Он не был в ... родном городе почти два года.","b":1},{"t":"para","text":"Điền: своём","b":1},{"t":"para","text":"Dịch: Anh ấy đã không ở thành phố quê hương của mình gần hai năm rồi."},{"t":"example","text":"Giải thích: Chủ ngữ là Он. Thành phố thuộc về Он. → Dùng свой."},{"t":"para","text":"В ... городе за это время многое изменилось.","b":1},{"t":"para","text":"Điền: его","b":1},{"t":"para","text":"Dịch: Trong thành phố của anh ấy, trong thời gian qua đã thay đổi nhiều thứ."},{"t":"example","text":"Giải thích: Chủ ngữ của câu này là многое (nhiều thứ), không phải anh ấy. Do đó không thể dùng свой (vì свой phải chỉ về chủ ngữ). Phải dùng его."},{"t":"para","text":"... бумаги я обычно держу на письменном столе.","b":1},{"t":"example","text":"Điền: Свои (hoặc Мои)"},{"t":"para","text":"Dịch: Giấy tờ của mình, tôi thường để trên bàn viết."},{"t":"example","text":"Giải thích: Chủ ngữ là Я. Giấy tờ của tôi. Dùng свои là tự nhiên nhất."},{"t":"para","text":"Он очень неаккуратен, в ... бумагах трудно что-нибудь найти.","b":1},{"t":"para","text":"Điền: его","b":1},{"t":"para","text":"Dịch: Anh ấy rất bừa bãi, trong giấy tờ của anh ấy thật khó tìm được cái gì."},{"t":"example","text":"Giải thích: Mệnh đề \"trudno nayti\" là vô nhân xưng (khó để tìm). Chủ thể hành động \"tìm\" là người nói/người chung chung, không phải là \"anh ấy\". Giấy tờ thuộc về \"anh ấy\" (người thứ 3). Vì chủ thể hành động và người sở hữu khác nhau → Dùng его."},{"t":"para","text":"Вы очень категоричны, с (со) ... высказываниями трудно согласиться.","b":1},{"t":"para","text":"Điền: вашими","b":1},{"t":"para","text":"Dịch: Các bạn rất cực đoan/dứt khoát, khó mà đồng ý với những phát ngôn của các bạn."},{"t":"example","text":"Giải thích: Tương tự câu 4. \"Khó đồng ý\" (vô nhân xưng). Phát ngôn của \"các bạn\". Dùng вашими. (Nếu dùng своими sẽ có nghĩa là \"người ta khó đồng ý với phát ngôn của chính người ta\" - sai nghĩa)."},{"t":"para","text":"С (Со) ... высказываниями ты можешь нажить себе врагов.","b":1},{"t":"para","text":"Điền: своими","b":1},{"t":"para","text":"Dịch: Với những phát ngôn của mình, bạn có thể chuốc lấy kẻ thù đấy."},{"t":"example","text":"Giải thích: Chủ ngữ là Ты. Phát ngôn của Ты. → Dùng своими."},{"t":"para","text":"... опыт всегда полезнее.","b":1},{"t":"para","text":"Điền: Свой","b":1},{"t":"para","text":"Dịch: Kinh nghiệm của chính mình bao giờ cũng hữu ích hơn."},{"t":"example","text":"Giải thích: Đây là câu nhận định tổng quát (dạng châm ngôn). Свой ở đây mang nghĩa \"của bản thân mỗi người\"."},{"t":"para","text":"... опыт работы очень полезно изучать, он лучший специалист в этой области.","b":1},{"t":"para","text":"Điền: Его","b":1},{"t":"para","text":"Dịch: Rất nên nghiên cứu kinh nghiệm làm việc của ông ấy, ông ấy là chuyên gia giỏi nhất trong lĩnh vực này."},{"t":"example","text":"Giải thích: \"Hữu ích để nghiên cứu\" (vô nhân xưng). Kinh nghiệm của \"ông ấy\". → Его."},{"t":"para","text":"Тебе надо ещё раз посмотреть ... работу, прежде чем сдавать её.","b":1},{"t":"para","text":"Điền: свою","b":1},{"t":"para","text":"Dịch: Bạn cần xem lại bài làm của mình một lần nữa trước khi nộp nó."},{"t":"example","text":"Giải thích: Chủ ngữ logic là Ты (trong \"тебе надо\"). Bài làm của bạn. → свою."},{"t":"para","text":"... работу уже смотрел преподаватель, он просил тебя зайти к нему после занятий.","b":1},{"t":"para","text":"Điền: Твою","b":1},{"t":"para","text":"Dịch: Bài làm của bạn đã được giáo viên xem rồi, ông ấy nhắn bạn đến gặp sau giờ học."},{"t":"example","text":"Giải thích: Chủ ngữ là Преподаватель. Bài làm thuộc về Bạn (người nghe). Chủ ngữ (giáo viên) khác với người sở hữu (bạn) → Không dùng свой. Dùng твою."}]},{"id":"03-s026","type":"exercise","title":"Bài 342 (Trang 167)","num":342,"blocks":[{"t":"example","text":"Đề bài: Điền свой hoặc đại từ sở hữu (мой, твой, его, её, их) phù hợp vào chỗ trống."},{"t":"para","text":"Мой друг просил меня заехать к ... родителям передать посылку.","b":1},{"t":"para","text":"Điền: его","b":1},{"t":"para","text":"Dịch: Bạn tôi nhờ tôi ghé qua chỗ bố mẹ của cậu ấy để đưa bưu kiện."},{"t":"example","text":"Giải thích: Hành động \"ghé qua\" do \"tôi\" thực hiện (tôi là chủ thể của động từ nguyên thể). Bố mẹ là của \"bạn\". Chủ thể (tôi) $\\neq$ Người sở hữu (bạn) → его."},{"t":"para","text":"... работы после проверки оставьте на столе.","b":1},{"t":"para","text":"Điền: Свои","b":1},{"t":"para","text":"Dịch: Hãy để lại bài làm của các em/các bạn trên bàn sau khi kiểm tra xong."},{"t":"example","text":"Giải thích: Mệnh lệnh thức \"оставьте\" (các bạn - chủ ngữ). Bài của \"các bạn\". → Свои."},{"t":"para","text":"Дай мне посмотреть ... на документы, может быть, я смогу тебе что-нибудь посоветовать.","b":1},{"t":"para","text":"Điền: твои","b":1},{"t":"para","text":"Dịch: Đưa tôi xem giấy tờ của bạn nào, biết đâu tôi khuyên được gì đó."},{"t":"example","text":"Giải thích: \"Tôi\" xem (chủ thể hành động). Giấy tờ của \"bạn\". → твои."},{"t":"para","text":"Она очень легкомысленно относится к бумагам, ... документы валяются повсюду.","b":1},{"t":"para","text":"Điền: её","b":1},{"t":"para","text":"Dịch: Cô ấy rất cẩu thả với giấy tờ, tài liệu của cô ấy vứt lung tung khắp nơi."},{"t":"example","text":"Giải thích: Chủ ngữ là документы. Sở hữu là cô ấy. Свой không làm chủ ngữ cho vật thuộc về người cụ thể theo cách này → её."},{"t":"para","text":"На ... имя пришло письмо, посмотри на столе.","b":1},{"t":"example","text":"Điền: твоё (hoặc ваше)"},{"t":"para","text":"Dịch: Có thư gửi đến tên bạn đấy, xem trên bàn đi."},{"t":"example","text":"Giải thích: Chủ ngữ là письмо. Tên của bạn. → твоё."},{"t":"para","text":"Не в ... сани не садись (посло́вица).","b":1},{"t":"para","text":"Điền: свои","b":1},{"t":"para","text":"Dịch: Đừng ngồi lên xe trượt không phải của mình (Chớ trèo cao, chớ phận sự nào chớ lo)."},{"t":"example","text":"Giải thích: Câu tục ngữ, khuyên \"bạn\" (chủ ngữ ẩn). Xe của \"bạn\". → свои."},{"t":"para","text":"Конечно, лучше учиться на чужих ошибках, но мы всегда учимся на ...","b":1},{"t":"para","text":"Điền: своих","b":1},{"t":"para","text":"Dịch: Tất nhiên, học từ lỗi người khác thì tốt hơn, nhưng chúng ta luôn học từ lỗi của chính mình."},{"t":"example","text":"Giải thích: Chủ ngữ Мы. Lỗi của Chúng ta. → своих."},{"t":"para","text":"К ... стыду, я забыл всё, о чём ты мне говорил.","b":1},{"t":"para","text":"Điền: своему","b":1},{"t":"para","text":"Dịch: Thật đáng xấu hổ cho tôi (Trước sự xấu hổ của mình), tôi đã quên hết những gì bạn nói."},{"t":"example","text":"Giải thích: Cụm cố định к своему стыду (tôi tự xấu hổ)."},{"t":"para","text":"А как ... хобби сочетается с её работой?","b":1},{"t":"para","text":"Điền: её","b":1},{"t":"para","text":"Dịch: Thế sở thích của cô ấy kết hợp với công việc của cô ấy thế nào?"},{"t":"example","text":"Giải thích: Chủ ngữ là хобби. → её."},{"t":"para","text":"У него есть ... причины не говорить нам об этом.","b":1},{"t":"para","text":"Điền: свои","b":1},{"t":"para","text":"Dịch: Anh ấy có những lý do riêng/của mình để không nói với chúng tôi về điều đó."},{"t":"example","text":"Giải thích: Cấu trúc У него есть... (Anh ấy có). Свои ở đây nhấn mạnh sự sở hữu riêng biệt."},{"t":"para","text":"Ты объяснил ... поведение, но ... объяснения кажутся малоубедительными.","b":1},{"t":"para","text":"Điền: своё ... твои","b":1},{"t":"para","text":"Dịch: Bạn đã giải thích hành vi của mình, nhưng những lời giải thích của bạn có vẻ thiếu thuyết phục."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Chủ ngữ Ты, hành vi của bạn → своё."},{"t":"example","text":"Vế 2: Chủ ngữ объяснения, sở hữu của bạn → твои."},{"t":"para","text":"Вообще они люди выдержанные и уравновешенные, но в этой ситуации мне трудно предсказать ... реакцию.","b":1},{"t":"para","text":"Điền: их","b":1},{"t":"para","text":"Dịch: Nói chung họ là người điềm đạm và cân bằng, nhưng trong tình huống này tôi khó mà đoán trước phản ứng của họ."},{"t":"example","text":"Giải thích: \"Tôi\" (chủ thể logic của \"đoán\"). Phản ứng của \"họ\". → их."},{"t":"para","text":"... ответы запишите, пожалуйста, в тетрадь.","b":1},{"t":"para","text":"Điền: Свои","b":1},{"t":"para","text":"Dịch: Hãy ghi các câu trả lời của mình vào vở nhé."},{"t":"example","text":"Giải thích: Mệnh lệnh thức (các bạn). → Свои."},{"t":"para","text":"В его ответах есть ... смысл, но согласиться с ним очень трудно.","b":1},{"t":"para","text":"Điền: свой","b":1},{"t":"para","text":"Dịch: Trong các câu trả lời của anh ấy có ý nghĩa riêng/đặc thù (cái lý riêng), nhưng rất khó đồng ý."},{"t":"example","text":"Giải thích: Свой ở đây mang nghĩa \"đặc trưng, riêng biệt\", không chỉ thuần túy sở hữu."},{"t":"para","text":"Я не хочу слышать ... оправдания, слишком часто ты подводил меня.","b":1},{"t":"para","text":"Điền: твои","b":1},{"t":"para","text":"Dịch: Tôi không muốn nghe những lời bào chữa của bạn, bạn đã làm tôi thất vọng quá nhiều lần."},{"t":"example","text":"Giải thích: Chủ ngữ Я. Bào chữa của bạn. → твои."},{"t":"para","text":"В ... сорок с небольшим лет он выглядит великолепно.","b":1},{"t":"para","text":"Điền: свои","b":1},{"t":"para","text":"Dịch: Ở tuổi hơn bốn mươi của mình, ông ấy trông thật tuyệt vời."},{"t":"example","text":"Giải thích: Chủ ngữ Он. Tuổi của Ông ấy. → свои."},{"t":"para","text":"Я уже далеко не молод. Где ... двадцать лет!","b":1},{"t":"para","text":"Điền: мои","b":1},{"t":"para","text":"Dịch: Tôi đã không còn trẻ nữa. Đâu rồi tuổi hai mươi của tôi!"},{"t":"example","text":"Giải thích: Câu cảm thán vắng chủ ngữ, nói về tuổi của người nói. → мои."},{"t":"para","text":"Не верю ... глазам, неужели это ты?","b":1},{"t":"para","text":"Điền: своим","b":1},{"t":"para","text":"Dịch: Tôi không tin vào mắt mình, có thật là bạn không?"},{"t":"example","text":"Giải thích: Chủ ngữ Я (ẩn). Mắt của tôi. → своим."},{"t":"para","text":"... локтя не укусишь (пословица).","b":1},{"t":"para","text":"Điền: Своего","b":1},{"t":"para","text":"Dịch: Không cắn được khuỷu tay của mình đâu (Gần ngay trước mắt xa tận chân trời / Lực bất tòng tâm)."},{"t":"example","text":"Giải thích: Chủ ngữ tổng quát (ai đó). Khuỷu tay của chính người đó. → Своего."},{"t":"para","text":"Ты уже прочитал телеграмму? ... родственники приезжают завтра.","b":1},{"t":"para","text":"Điền: Твои","b":1},{"t":"para","text":"Dịch: Bạn đã đọc bức điện chưa? Họ hàng của bạn mai đến đấy."},{"t":"example","text":"Giải thích: Chủ ngữ родственники. Họ hàng của bạn. → Твои."}]},{"id":"03-s027","type":"exercise","title":"Bài 343 (Trang 167)","num":343,"blocks":[{"t":"example","text":"Đề bài: Sử dụng mẫu câu để chuyển đổi các câu sau, dùng đại từ свой để nhấn mạnh sự sở hữu cá nhân. Mẫu: У меня есть родители. → У меня есть свои (собственные) родители. (Tôi có bố mẹ riêng của mình)."},{"t":"para","text":"Мне хочется иметь собаку.","b":1},{"t":"example","text":"Viết lại: Мне хо́чется иметь свою́ соба́ку."},{"t":"example","text":"Dịch: Tôi muốn có một con chó của riêng mình."},{"t":"para","text":"Он всегда увлечён делами.","b":1},{"t":"example","text":"Viết lại: Он всегда́ увлечён свои́ми дела́ми."},{"t":"example","text":"Dịch: Anh ấy luôn bận bịu với công việc của mình."},{"t":"para","text":"У всех нас заботы.","b":1},{"t":"example","text":"Viết lại: У всех нас свои́ забо́ты."},{"t":"example","text":"Dịch: Tất cả chúng ta đều có những lo toan riêng."},{"t":"para","text":"Он закончил работу к двум часам.","b":1},{"t":"example","text":"Viết lại: Он зако́нчил свою́ рабо́ту к двум часа́м."},{"t":"example","text":"Dịch: Anh ấy đã hoàn thành công việc của mình trước hai giờ."},{"t":"para","text":"Нам надо решить проблемы.","b":1},{"t":"example","text":"Viết lại: Нам на́до реши́ть свои́ пробле́мы."},{"t":"example","text":"Dịch: Chúng ta cần giải quyết các vấn đề của mình."},{"t":"para","text":"Им надо предпринять шаги.","b":1},{"t":"example","text":"Viết lại: Им на́до предприня́ть свои́ шаги́."},{"t":"example","text":"Dịch: Họ cần thực hiện các bước đi của mình."},{"t":"para","text":"Ты пожертвовал ради нас отпуском.","b":1},{"t":"example","text":"Viết lại: Ты поже́ртвовал ра́ди нас свои́м о́тпуском."},{"t":"example","text":"Dịch: Bạn đã hy sinh kỳ nghỉ của mình vì chúng tôi."},{"t":"para","text":"День рождения я решил отметить в субботу.","b":1},{"t":"example","text":"Viết lại: Свой день рожде́ния я решил отме́тить в суббо́ту."},{"t":"example","text":"Dịch: Tôi quyết định tổ chức sinh nhật của mình vào thứ Bảy."},{"t":"para","text":"К образованию он всегда относился серьёзно.","b":1},{"t":"example","text":"Viết lại: К своему́ образова́нию он всегда́ относи́лся серьёзно."},{"t":"example","text":"Dịch: Anh ấy luôn nghiêm túc với việc học hành của mình."},{"t":"para","text":"В обеденный перерыв я имею право делать то, что я хочу.","b":1},{"t":"example","text":"Viết lại: В свой обе́денный переры́в я име́ю пра́во де́лать то, что я хочу́."},{"t":"example","text":"Dịch: Trong giờ nghỉ trưa của mình, tôi có quyền làm những gì tôi muốn."},{"t":"para","text":"Он может уделить время семье.","b":1},{"t":"example","text":"Viết lại: Он мо́жет удели́ть вре́мя свое́й семье́."},{"t":"example","text":"Dịch: Anh ấy có thể dành thời gian cho gia đình của mình."},{"t":"para","text":"Так хочется иметь дом на берегу моря!","b":1},{"t":"example","text":"Viết lại: Так хо́чется иметь свой дом на берегу́ мо́ря!"},{"t":"example","text":"Dịch: Thật muốn có một ngôi nhà riêng bên bờ biển!"},{"t":"para","text":"Ты должен сделать выбор.","b":1},{"t":"example","text":"Viết lại: Ты до́лжен сде́лать свой вы́бор."},{"t":"example","text":"Dịch: Bạn phải đưa ra lựa chọn của mình."},{"t":"para","text":"Я хочу потратить деньги на путешествие.","b":1},{"t":"example","text":"Viết lại: Я хочу́ потра́тить свои́ де́ньги на путеше́ствие."},{"t":"example","text":"Dịch: Tôi muốn tiêu tiền của mình cho chuyến du lịch."}]},{"id":"03-s028","type":"exercise","title":"Bài 345 (Trang 168)","num":345,"blocks":[{"t":"example","text":"Đề bài: Xác định nghĩa của đại từ свой theo ngữ cảnh. Chọn từ đồng nghĩa."},{"t":"para","text":"Nhóm a)","b":1},{"t":"example","text":"Он в нашем доме свой человек, почти родственник. (Ông ấy là người thân tín/người nhà trong gia đình chúng tôi, gần như họ hàng)."},{"t":"example","text":"Вечером у меня соберутся человек пять, только свои. (Tối nay chỗ tôi có khoảng 5 người tụ tập, toàn người thân/người quen thôi)."},{"t":"example","text":"В нашем коллективе его хорошо знали, любили, считали своим. (Trong tập thể chúng tôi, mọi người biết rõ, yêu mến và coi anh ấy là người của mình)."},{"t":"example","text":"Свой свояка видит издалека. (Người cùng hội cùng thuyền thì nhận ra nhau từ xa / Ngưu tầm ngưu, mã tầm mã)."},{"t":"para","text":"Nghĩa: Thân thiết, gần gũi, người nhà, cùng phe cánh (родной, близкий, свойский)."},{"t":"para","text":"Nhóm б)","b":1},{"t":"vocab","ru":"Что о нас говорить","vi":"мы своё отжили, теперь ваше время. (Nói về chúng tôi làm gì: chúng tôi đã sống hết phần đời/thời của mình rồi, giờ là thời của các bạn).","g":null},{"t":"example","text":"Они сделали своё дело, теперь очередь за нами. (Họ đã làm xong việc của họ/phận sự, giờ đến lượt chúng ta)."},{"t":"example","text":"Не пытайся выпытать у меня информацию, в своё время ты всё узнаешь. (Đừng cố moi thông tin từ tôi, đến thời điểm thích hợp/của nó, bạn sẽ biết hết)."},{"t":"example","text":"Каждому овощу своё время. (Rau nào sâu nấy / Mọi thứ đều có thời điểm của nó/phù hợp)."},{"t":"para","text":"Nghĩa: Dành riêng, thích hợp, cụ thể, được quy định (отведённый, определённый, надлежащий)."}]},{"id":"03-s029","type":"exercise","title":"Bài 346 (Trang 168)","num":346,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu, chú ý đến các cụm từ cố định với đại từ свой (của mình). Xác định ý nghĩa của chúng."},{"t":"para","text":"Я привы́к говори́ть пря́мо, ничего́ не скрыва́я, позво́льте мне и сейча́с называ́ть ве́щи свои́ми имена́ми.","b":1},{"t":"example","text":"Dịch: Tôi đã quen nói thẳng, không giấu giếm gì cả, cho phép tôi bây giờ cũng được gọi sự vật bằng đúng tên của chúng (nói toạc móng heo/nói thẳng sự thật)."},{"t":"example","text":"Ý nghĩa: Называ́ть ве́щи свои́ми имена́ми = Nói thẳng thắn, không dùng uyển ngữ hay che đậy."},{"t":"para","text":"Не тро́гай его́, он сего́дня сам не свой, вчера́шнее происше́ствие потрясло́ его́!","b":1},{"t":"example","text":"Dịch: Đừng động vào anh ấy, hôm nay anh ấy như người mất hồn/không còn là chính mình, vụ việc hôm qua đã làm anh ấy chấn động!"},{"t":"example","text":"Ý nghĩa: Сам не свой = Bối rối, lo lắng, buồn bã, mất bình tĩnh (trạng thái tâm lý bất thường)."},{"t":"para","text":"Чем ты недово́лен? Живёшь в своё удово́льствие, никаки́х обя́занностей, одни́ развлече́ния!","b":1},{"t":"example","text":"Dịch: Bạn còn bất mãn cái gì? Bạn đang sống thỏa thích/theo ý thích của mình, không trách nhiệm, chỉ toàn giải trí!"},{"t":"example","text":"Ý nghĩa: Жить в своё удово́льствие = Sống hưởng thụ, chỉ làm điều mình thích."},{"t":"para","text":"Он, безусло́вно, на своём ме́сте, он как бу́дто со́здан для э́той до́лжности.","b":1},{"t":"example","text":"Dịch: Anh ấy chắc chắn là người thích hợp/đúng vị trí, anh ấy như thể được sinh ra cho chức vụ này vậy."},{"t":"example","text":"Ý nghĩa: Быть на своём ме́сте = Phù hợp với công việc/vị trí đang đảm nhận."},{"t":"para","text":"Не слу́шай ничьи́х сове́тов, ты не ребёнок, пора́ тебе́ жить свои́м умо́м.","b":1},{"t":"example","text":"Dịch: Đừng nghe lời khuyên của ai cả, bạn không còn là trẻ con nữa, đã đến lúc bạn phải sống bằng trí óc của mình/tự chủ suy nghĩ."},{"t":"example","text":"Ý nghĩa: Жить свои́м умо́м = Độc lập trong suy nghĩ và quyết định, không phụ thuộc người khác."},{"t":"para","text":"Наизу́сть учи́ть текст не на́до, перескажи́те его́ свои́ми слова́ми.","b":1},{"t":"example","text":"Dịch: Không cần học thuộc lòng văn bản, hãy kể lại nó bằng lời lẽ của chính mình."},{"t":"example","text":"Ý nghĩa: Свои́ми слова́ми = Diễn đạt lại ý bằng ngôn từ tự nhiên, không đọc chép."},{"t":"para","text":"Он ведёт себя́ как-то стра́нно. Он себе́ на уме́, всё ли у него́ в поря́дке с голово́й?","b":1},{"t":"example","text":"Dịch: Hắn cư xử có vẻ lạ lùng. Hắn là kẻ thâm trầm/kín đáo/khôn ngầm, đầu óc hắn có bình thường không đấy?"},{"t":"example","text":"Ý nghĩa: Себе́ на уме́ = Kín tiếng, có toan tính riêng, không để lộ suy nghĩ thật."},{"t":"para","text":"Не принима́й его́ ре́зких слов на свой счёт, он не хоте́л тебя́ оби́деть.","b":1},{"t":"example","text":"Dịch: Đừng để bụng/nhận vơ những lời gay gắt của anh ấy vào mình, anh ấy không muốn xúc phạm bạn đâu."},{"t":"example","text":"Ý nghĩa: Принима́ть на свой счёт = Nghĩ rằng người ta đang nói xấu hoặc chỉ trích mình."},{"t":"para","text":"Из прису́тствующих на ве́чере я почти́ ни с кем не был знако́м и чу́вствовал себя́ не в свое́й таре́лке.","b":1},{"t":"example","text":"Dịch: Trong số những người có mặt tại buổi tiệc tôi hầu như không quen ai và cảm thấy không thoải mái/lạc lõng."},{"t":"example","text":"Ý nghĩa: Не в свое́й таре́лке = Cảm thấy gượng gạo, không tự nhiên, khó chịu (như cá mắc cạn)."},{"t":"para","text":"Будь с ним осторо́жен, мо́жет быть, он то́лько говори́т, что хо́чет помо́чь, а у самого́ своё на уме́.","b":1},{"t":"example","text":"Dịch: Hãy cẩn thận với hắn, có thể hắn chỉ nói là muốn giúp, nhưng bản thân hắn có toan tính riêng/âm mưu riêng."},{"t":"example","text":"Ý nghĩa: Своё на уме́ = Có ý đồ riêng (thường là vụ lợi) được giấu kín."},{"t":"para","text":"Он в э́той о́бласти первокла́ссный специали́ст, ма́стер своего́ де́ла.","b":1},{"t":"example","text":"Dịch: Trong lĩnh vực này ông ấy là chuyên gia hạng nhất, là bậc thầy trong nghề."},{"t":"example","text":"Ý nghĩa: Ма́стер своего́ де́ла = Người rất giỏi chuyên môn."},{"t":"para","text":"Да никто́ не дава́л мне разреше́ния вы́играть биле́ты на друго́е число́, я э́то сде́лал на свой страх и риск.","b":1},{"t":"example","text":"Dịch: Chẳng ai cho phép tôi đổi vé sang ngày khác cả, tôi đã làm điều đó bằng sự liều lĩnh của chính mình/tự chịu rủi ro."},{"t":"example","text":"Ý nghĩa: На свой страх и риск = Tự quyết định và chấp nhận mọi hậu quả/rủi ro."},{"t":"para","text":"Ка́ждый челове́к хо́чет дожи́ть до ста́рости и умере́ть свое́й сме́ртью.","b":1},{"t":"example","text":"Dịch: Ai cũng muốn sống đến già và chết già/chết tự nhiên."},{"t":"example","text":"Ý nghĩa: Умере́ть свое́й сме́ртью = Chết vì nguyên nhân tự nhiên (tuổi già, bệnh tật), không phải do tai nạn hay bị giết."}]},{"id":"03-s030","type":"exercise","title":"Bài 347 (Trang 169)","num":347,"blocks":[{"t":"example","text":"Đề bài: Sử dụng các cụm từ cố định với đại từ свой (từ bài 346), hãy đưa ra lời khuyên cho người quen của bạn."},{"t":"para","text":"Tình huống: Bạn ấy cố gắng lặp lại từng từ một của văn bản bức điện."},{"t":"para","text":"Lời khuyên: Перескажи́ свои́ми слова́ми!","b":1},{"t":"example","text":"Dịch: Hãy kể lại bằng lời của mình đi!"},{"t":"para","text":"Tình huống: Bạn ấy không đưa ra bất kỳ quyết định nào mà không tham khảo ý kiến cha mẹ."},{"t":"para","text":"Lời khuyên: Живи́ свои́м умо́м!","b":1},{"t":"example","text":"Dịch: Hãy sống bằng trí óc của mình đi (Hãy tự chủ đi)!"},{"t":"para","text":"Tình huống: Bạn ấy bị xúc phạm bởi những lời nói vô tình về mình (hoặc ai đó nói bâng quơ)."},{"t":"para","text":"Lời khuyên: Не принима́й на свой счёт!","b":1},{"t":"example","text":"Dịch: Đừng có vơ vào mình (Đừng để bụng)!"},{"t":"para","text":"Tình huống: Bạn ấy rời nhà đi nghỉ lễ, nhưng không thi đỗ kỳ thi (và phải quay về)."},{"t":"example","text":"Lời khuyên: Возвраща́йся восвоя́си! (Cụm từ này có gốc свой, nghĩa là quay về nhà/nơi xuất phát, thường dùng khi thất bại hoặc xong việc)."},{"t":"example","text":"Dịch: Hãy quay về nhà đi!"},{"t":"para","text":"Tình huống: Bạn ấy làm việc quá nhiều, quên cả bản thân."},{"t":"para","text":"Lời khuyên: Поживи́ в своё удово́льствие!","b":1},{"t":"example","text":"Dịch: Hãy sống hưởng thụ chút đi!"},{"t":"para","text":"Tình huống: Bạn ấy cố gắng trình bày các yêu cầu của mình dưới dạng ẩn dụ/bóng gió."},{"t":"para","text":"Lời khuyên: Называ́й ве́щи свои́ми имена́ми!","b":1},{"t":"example","text":"Dịch: Hãy nói toạc móng heo ra (Nói thẳng vào vấn đề)!"}]},{"id":"03-s031","type":"exercise","title":"Bài 348 (Trang 169)","num":348,"blocks":[{"t":"example","text":"Đề bài: Sử dụng các cụm từ cố định với свой, hãy chọn từ đồng nghĩa cho các từ/cụm từ in đậm (đã được thay thế trong bài giải)."},{"t":"example","text":"Что произошло́? Ты сего́дня вы́глядишь ка́к-то стра́нно.","b":1},{"t":"para","text":"Thay thế: сам не свой","b":1},{"t":"example","text":"Dịch: Chuyện gì xảy ra vậy? Hôm nay trông bạn không giống ngày thường/như người mất hồn."},{"t":"example","text":"Он был далеко́ не мо́лод и у́мер есте́ственной сме́ртью.","b":1},{"t":"para","text":"Thay thế: свое́й сме́ртью","b":1},{"t":"example","text":"Dịch: Ông ấy đã không còn trẻ và đã chết già/chết tự nhiên."},{"t":"example","text":"Мне не хоте́лось беспоко́ить его́, я чу́вствовал себя́ нело́вко.","b":1},{"t":"para","text":"Thay thế: себя́ не в свое́й таре́лке","b":1},{"t":"example","text":"Dịch: Tôi không muốn làm phiền anh ấy, tôi cảm thấy không thoải mái/gượng gạo."},{"t":"example","text":"Он то́лько на слова́х тако́й до́брый, а сам ду́мает то́лько о себе́.","b":1},{"t":"para","text":"Thay thế: себе́ на уме́","b":1},{"t":"example","text":"Dịch: Hắn chỉ tốt mã ngoài miệng thôi, chứ thực ra là kẻ có toan tính riêng/ích kỷ ngầm."},{"t":"example","text":"По́вар он первокла́ссный, отли́чный специали́ст.","b":1},{"t":"para","text":"Thay thế: ма́стер своего́ де́ла","b":1},{"t":"example","text":"Dịch: Anh ấy là đầu bếp hạng nhất, là bậc thầy trong nghề."},{"t":"example","text":"Ра́зве мо́жно бы́ло тако́е говори́ть дека́ну?! У тебя́ всё в поря́дке с голово́й?","b":1},{"t":"example","text":"Thay thế: ты в своём уме́? (Lưu ý: Cụm быть в своём уме - tỉnh táo/bình thường)."},{"t":"example","text":"Dịch: Sao lại có thể nói thế với chủ nhiệm khoa?! Bạn có điên không đấy/có tỉnh táo không?"}]},{"id":"03-s032","type":"grammar","title":"Ngữ pháp: Đại từ phủ định (Отрица́тельные местоиме́ния)","num":null,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 169):","b":1},{"t":"subhead","text":"Nhóm НИ- (никто́, ничто́, никако́й, ниче́й...):","b":1},{"t":"example","text":"Dùng trong câu phủ định (có từ не đi kèm động từ)."},{"t":"para","text":"Biểu thị sự vắng mặt hoàn toàn của đối tượng hoặc tính chất."},{"t":"example","text":"Ví dụ: Никто́ не зна́ет (Không ai biết)."},{"t":"subhead","text":"Nhóm НЕ- (не́кого, не́чего...):","b":1},{"t":"para","text":"Trọng âm luôn rơi vào НЕ."},{"t":"para","text":"Dùng trong câu vô nhân xưng (không có chủ ngữ), đi kèm động từ nguyên thể (infinitive)."},{"t":"para","text":"Biểu thị sự không có đối tượng để thực hiện hành động hoặc tình trạng bế tắc."},{"t":"example","text":"Ví dụ: Не́чего де́лать (Chẳng có gì để làm), Не́кого спроси́ть (Không có ai để hỏi)."},{"t":"note","text":"Lưu ý: Khi đi kèm giới từ, giới từ sẽ chen vào giữa: ни у кого́, не́ у кого."}]},{"id":"03-s033","type":"exercise","title":"Bài 349 (Trang 169)","num":349,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu văn. Xác định sự khác biệt trong cách dùng các đại từ phủ định với tiểu từ не và ни."},{"t":"para","text":"a)","b":1},{"t":"para","text":"Никто́ не зна́ет об э́том. (Không ai biết về việc này - Phủ định chủ ngữ). В э́той ситуа́ции ничто́ ему́ не помо́жет. (Trong tình huống này không gì giúp được anh ấy - Phủ định chủ ngữ)."},{"t":"example","text":"В э́то вре́мя в лаборато́рии никого́ нельзя́ заста́ть на ме́сте. (Vào giờ này không thể gặp ai ở phòng thí nghiệm - Phủ định tân ngữ với нельзя). Мне не́кого спроси́ть об э́том. (Tôi không có ai để hỏi về việc này - Vô nhân xưng, không có đối tượng để hỏi)."},{"t":"para","text":"Ничего́ не на́до покупа́ть, все проду́кты у нас есть. (Không cần mua gì cả... - Phủ định tân ngữ). Сего́дня мне не́чего покупа́ть, у меня́ есть все проду́кты. (Hôm nay tôi không có gì để mua / không cần mua gì - Vô nhân xưng)."},{"t":"example","text":"Я ни к кому́ не могу́ обрати́ться за по́мощью. (Tôi không thể nhờ vả ai - Ни tách rời bởi giới từ). Мне не́ к кому обрати́ться за по́мощью. (Tôi không có ai để nhờ vả - Не tách rời, trọng âm ở đầu)."},{"t":"para","text":"Я ничего́ не слы́шал об э́том собы́тии. (Tôi chưa nghe gì về sự kiện này). Нам сейча́с сказа́ть не́чего. (Chúng tôi bây giờ không có gì để nói)."},{"t":"subhead","text":"б) (Sử dụng никакой - không ... nào cả):","b":1},{"t":"para","text":"Никако́й ваш сове́т мне не помо́жет. (Lời khuyên nào của bạn cũng không giúp được tôi / Không lời khuyên nào...)."},{"t":"para","text":"Ни до како́го го́рода мы в э́тот день не добра́лись. (Chúng tôi không đến được thành phố nào trong ngày hôm đó)."},{"t":"para","text":"Ни по како́й у́лице мы не гуля́ли, сиде́ли до́ма. (Chúng tôi chẳng đi dạo ở phố nào cả...)."},{"t":"para","text":"Никако́й ру́чки я здесь не ви́дел. (Tôi không thấy cái bút nào ở đây cả)."},{"t":"para","text":"Мы не остано́вимся пе́ред каки́ми тру́дностями. (Chúng tôi sẽ không dừng bước trước bất kỳ khó khăn nào)."},{"t":"para","text":"Ни при каки́х обстоя́тельствах он не изме́нит реше́ния. (Dù trong bất cứ hoàn cảnh nào anh ấy cũng không thay đổi quyết định)."},{"t":"subhead","text":"в) (Sử dụng ничей - không của ai):","b":1},{"t":"para","text":"Мне ка́жется, э́то ничья́ соба́ка, у неё нет оше́йника. (Tôi nghĩ đây là con chó vô chủ / không của ai, nó không có vòng cổ)."},{"t":"para","text":"Ни у чьи́х ро́дственников я не остана́вливался. (Tôi không ở lại chỗ người họ hàng nào cả)."},{"t":"para","text":"Ничьему́ прика́зу мы подчиня́ться не бу́дем. (Chúng tôi sẽ không tuân theo mệnh lệnh của bất kỳ ai)."},{"t":"para","text":"Ни че́рез чей сад мы не пойдём. (Chúng ta sẽ không đi xuyên qua vườn của ai cả)."},{"t":"para","text":"Ни с чьи́ми измене́ниями я не соглашу́сь. (Tôi sẽ không đồng ý với sự thay đổi của bất kỳ ai)."},{"t":"para","text":"Ни на чье́й террито́рии мы встреча́ться не бу́дем. (Chúng ta sẽ không gặp nhau trên lãnh thổ của ai cả)."}]},{"id":"03-s034","type":"exercise","title":"Bài 350 (Trang 170)","num":350,"blocks":[{"t":"para","text":"Đề bài: Điền vào chỗ trống đại từ ниче́й (không của ai) ở dạng cần thiết, có hoặc không có giới từ."},{"t":"para","text":"Не ну́жно вам (ничьи́х) сове́тов. Зна́ньем Превы́ше са́ми вы всего́ (А. Пушкин).","b":1},{"t":"example","text":"Dịch: Các ngài không cần lời khuyên của ai cả. Với kiến thức, các ngài cao hơn tất cả."},{"t":"example","text":"Giải thích: Cần Cách 2 số nhiều (советов) → ничьи́х."},{"t":"para","text":"Я зна́ю э́ти голоса́ ... (ничьи́) (Б. Ахмадулина).","b":1},{"t":"example","text":"Dịch: Tôi biết những giọng nói này... [chúng] không phải của ai cả."},{"t":"example","text":"Giải thích: Vị ngữ danh từ → ничьи́."},{"t":"para","text":"... (Ничья́) судьба́, кро́ме свое́й со́бственной, вас бо́лее не интересу́ет (М. Булгаков).","b":1},{"t":"example","text":"Dịch: Số phận của bất kỳ ai/không của ai, ngoài chính mình, không còn làm ông quan tâm nữa."},{"t":"example","text":"Giải thích: Chủ ngữ → Ничья́."},{"t":"para","text":"Она́ до́лго не могла́ пове́рить тому́, что раздо́р начался́ с тако́го безоби́дного, ... (ничьему́) се́рдцу разгово́ра (Л. Толстой).","b":1},{"t":"example","text":"Dịch: Cô ấy mãi không thể tin rằng sự bất hòa lại bắt đầu từ một cuộc trò chuyện vô hại, không (động chạm/gần gũi) đến trái tim của ai như thế."},{"t":"example","text":"Giải thích: близкого (ngầm hiểu) + Cách 3 (сердцу) → ничьему́. (Lưu ý: Văn cảnh gốc Tolstoy có thể khác, nhưng theo ngữ pháp điền từ thì đây là dạng phù hợp)."},{"t":"para","text":"Я одино́к, не согре́т ... (ничье́й) привя́занностью, мне хо́лодно, как в подземе́лье (А. Чехов).","b":1},{"t":"example","text":"Dịch: Tôi cô đơn, không được sưởi ấm bởi sự gắn bó của ai, tôi lạnh lẽo như trong hầm ngục."},{"t":"example","text":"Giải thích: Bị động (được sưởi ấm bởi) → Cách 5 (привязанностью) → ничье́й."},{"t":"para","text":"Всё бы́ло ти́хо, и не слы́шно бы́ло ... (ничье́й) шаго́в (Ф. Достоевский).","b":1},{"t":"example","text":"Dịch: Mọi thứ tĩnh lặng, và không nghe thấy bước chân của ai."},{"t":"example","text":"Giải thích: Cách 2 (шагов) → ничьи́х (hoặc nếu ý là bước chân của một người nào đó: ничьей ноги - nhưng ở đây là шагов số nhiều nên là ничьи́х). Sửa lại theo sách gốc: Nếu điền cho từ шагов thì phải là ничьи́х. Nếu điền cho từ ноги (ẩn) thì là ничьей. Văn cảnh thường gặp: ничьих шагов."},{"t":"para","text":"И вот бреду́ я по земле́ И у Небытия́ прошу́ аре́нду ... (ничью́) (И. Бродский).","b":1},{"t":"example","text":"Dịch: Và tôi lang thang trên mặt đất, và xin Hư Vô cho thuê mướn [một cái gì đó] không của ai."},{"t":"example","text":"Giải thích: Аренду (Cách 4). Tính từ bổ nghĩa → ничью́."},{"t":"para","text":"Он подъе́хал к бесе́дкам в са́мое вы́годное вре́мя для того́, что́бы не обраща́ть на себя́ ... (ничьего́) внима́ния (Л. Толстой).","b":1},{"t":"example","text":"Dịch: Anh ta lái xe đến các chòi nghỉ vào thời điểm thuận lợi nhất để không thu hút sự chú ý của ai vào mình."},{"t":"example","text":"Giải thích: Внимания (Cách 2) → ничьего́."},{"t":"para","text":"Для тебя́ я, Русь, Э́ти ска́зы спел, Потому́ что был И правди́в, и смел. Был маста́к слага́ть Э́ти при́тчины, Не боя́сь ... (ничьи́х) зуботы́чины (С. Есенин).","b":1},{"t":"example","text":"Dịch: Vì người, hỡi nước Nga, ta hát những câu chuyện này... Không sợ những cú đấm/cái tát của bất kỳ ai."},{"t":"example","text":"Giải thích: Зуботычины (Cách 2 số nhiều hoặc Cách 1 số nhiều? Ở đây sau боясь là Cách 2) → ничьи́х."},{"t":"para","text":"Мне всегда́ каза́лось, что И́горь на осо́бый, ... (ни на чей) не похо́жий лад поёт пе́сню свое́й жи́зни (Ю. Нагибин).","b":1},{"t":"example","text":"Dịch: Tôi luôn cảm thấy rằng Igor đang hát bài ca cuộc đời mình theo một điệu riêng, không giống với bất kỳ ai."},{"t":"example","text":"Giải thích: Похожий на кого? (Giống ai) → Cách 4. Có giới từ на chen giữa ни và чей → ни на чей."}]},{"id":"03-s035","type":"grammar","title":"Lý thuyết ngữ pháp (Dựa trên khung trong bài)","num":null,"blocks":[{"t":"subhead","text":"1. Đại từ phủ định (Отрица́тельные местоиме́ния):","b":1},{"t":"vocab","ru":"Nhóm НИ- (никто́, ничто́, никако́й, ниче́й...)","vi":"Dùng trong câu phủ định (có từ не hoặc нет). Biểu thị sự vắng mặt hoàn toàn của đối tượng.","g":null},{"t":"example","text":"Ví dụ: Я никого́ не ви́дел (Tôi không thấy ai cả)."},{"t":"subhead","text":"Nhóm НЕ- (не́кого, не́чего...):","b":1},{"t":"para","text":"Trọng âm luôn rơi vào НЕ."},{"t":"para","text":"Dùng với động từ nguyên thể (infinitive) trong câu vô nhân xưng (không có chủ ngữ)."},{"t":"para","text":"Biểu thị sự không có đối tượng/hoàn cảnh để thực hiện hành động (không có ai để..., không có gì để...)."},{"t":"example","text":"Ví dụ: Мне не́кого спроси́ть (Tôi chẳng có ai để hỏi)."},{"t":"note","text":"Lưu ý về Giới từ: Nếu đại từ đi kèm giới từ, giới từ sẽ chen vào giữa:"},{"t":"example","text":"Никого́ → Ни у кого́ (Không ở chỗ ai)."},{"t":"example","text":"Не́кого → Не́ у кого (Không có ai để [ở/hỏi])."},{"t":"para","text":"2. Quy tắc hợp dạng (Trang 172):","b":1},{"t":"para","text":"Никто́ → Động từ chia ở Giống đực, Số ít."},{"t":"para","text":"Ничто́ → Động từ chia ở Giống trung, Số ít."}]},{"id":"03-s036","type":"exercise","title":"Bài 351 (Trang 171)","num":351,"blocks":[{"t":"para","text":"Đề bài: Điền vào chỗ trống các đại từ phủ định có tiểu từ не hoặc ни ở dạng phù hợp."},{"t":"para","text":"Giải thích cách chọn:","b":1},{"t":"para","text":"Nếu câu có nghĩa \"không làm gì cả\" (phủ định chung) → Dùng НИ-."},{"t":"para","text":"Nếu câu có nghĩa \"không có gì/ai để làm\" (thiếu đối tượng) → Dùng НЕ-."},{"t":"para","text":"Он кого́?... не ви́дел. Ему́ с кем?... ви́деться в э́том го́роде.","b":1},{"t":"subhead","text":"Đáp án: никого́ ... не́ с кем"},{"t":"example","text":"Viết lại: Он никого́ не ви́дел. Ему́ не́ с кем ви́деться в э́том го́роде."},{"t":"example","text":"Dịch: Anh ấy đã không gặp bất cứ ai. Anh ấy không có ai để gặp gỡ ở thành phố này."},{"t":"para","text":"Я у кого́?... не проси́л сове́та. Здесь кто?... — не проси́л у меня́ сове́та.","b":1},{"t":"subhead","text":"Đáp án: ни у кого́ ... не́ у кого"},{"t":"example","text":"Viết lại: Я ни у кого́ не проси́л сове́та. Здесь не́ у кого проси́ть сове́та."},{"t":"example","text":"Dịch: Tôi đã không xin lời khuyên từ ai cả. Ở đây chẳng có ai để mà xin lời khuyên."},{"t":"para","text":"В э́той ситуа́ции о чём?... жале́ть. Нам чегó?... — не сто́ит жале́ть;","b":1},{"t":"subhead","text":"Đáp án: не́ о чем ... ни о чём"},{"t":"example","text":"Viết lại: В э́той ситуа́ции не́ о чем жале́ть. Нам ни о чём не сто́ит жале́ть."},{"t":"example","text":"Dịch: Trong tình huống này chẳng có gì để mà hối tiếc. Chúng ta không đáng phải hối tiếc về bất cứ điều gì."},{"t":"para","text":"Его́ что?... не занима́ет. Ему́ чем?... занима́ться.","b":1},{"t":"subhead","text":"Đáp án: ничто́ (hoặc ничего́) ... не́чем"},{"t":"example","text":"Viết lại: Его́ ничто́ (hoặc ничего́) не занима́ет. Ему́ не́чем занима́ться."},{"t":"example","text":"Dịch: Không gì làm anh ấy quan tâm. Anh ấy chẳng có việc gì để làm."},{"t":"para","text":"Он чем?... не занима́ется. Ему́ с кем?... занима́ться.","b":1},{"t":"subhead","text":"Đáp án: ничем ... не́ с кем"},{"t":"example","text":"Viết lại: Он ниче́м не занима́ется. Ему́ не́ с кем занима́ться."},{"t":"example","text":"Dịch: Anh ấy không bận rộn với việc gì cả. Anh ấy không có ai để cùng học tập/làm việc."},{"t":"para","text":"Мне кого?... слу́шать. Я о ком?... — ничего́ не слы́шал;","b":1},{"t":"subhead","text":"Đáp án: не́кого ... ни о ком"},{"t":"example","text":"Viết lại: Мне не́кого слу́шать. Я ни о ком ничего́ не слы́шал."},{"t":"example","text":"Dịch: Tôi chẳng có ai để mà nghe. Tôi chưa nghe gì về bất cứ ai."},{"t":"para","text":"Ему́ что?... не удаётся сде́лать. Ему́ с чем?... — не удаётся спра́виться. Ему́ что?... — с чем?... справля́ться.","b":1},{"t":"subhead","text":"Đáp án: ничего́ ... ни с чем ... не́ с чем"},{"t":"example","text":"Viết lại: Ему́ ничего́ не удаётся сде́лать. Ему́ ни с чем не удаётся спра́виться. Ему́ не́ с чем справля́ться."},{"t":"example","text":"Dịch: Anh ấy không làm được việc gì cả. Anh ấy không giải quyết được việc gì cả. Anh ấy không có gì để mà giải quyết."}]},{"id":"03-s037","type":"exercise","title":"Bài 352 (Trang 171)","num":352,"blocks":[{"t":"para","text":"Đề bài: Đọc các câu văn, sử dụng các động từ trong ngoặc ở dạng phù hợp."},{"t":"note","text":"Lưu ý ngữ pháp (Trang 171):","b":1},{"t":"para","text":"Đại từ ничто́ yêu cầu động từ ở dạng Giống trung, Số ít."},{"t":"para","text":"Đại từ никто́ yêu cầu động từ ở dạng Giống đực, Số ít."},{"t":"para","text":"Никто́ не (слы́шать), как он (войти́). (Измени́ться) в на́шей жи́зни в ближай́шие не́сколько лет;","b":1},{"t":"subhead","text":"Đáp án: слы́шал ... вошёл ... Изме́нится / измени́лось"},{"t":"example","text":"Viết lại: Никто́ не слы́шал, как он вошёл. Ничто́ не изме́нится (hoặc измени́лось) в на́шей жи́зни... (Lưu ý: Câu gốc trong sách có thể là Ничто не... ở vế sau)."},{"t":"example","text":"Dịch: Không ai nghe thấy anh ấy đi vào như thế nào. Không gì thay đổi trong cuộc sống của chúng tôi trong vài năm tới."},{"t":"para","text":"По́сле того́, как он вы́ступил, никто́ не (реша́ться) сказа́ть ни сло́ва; 4. Ничего́ (интере́сный) (произойти́) вчера́ на (мой) глазах.","b":1},{"t":"subhead","text":"Đáp án: реша́лся ... интере́сного ... не произошло́ ... мои́х"},{"t":"example","text":"Viết lại: ...никто́ не реша́лся сказа́ть... Ничего́ интере́сного не произошло́ вчера́ на мои́х глаза́х."},{"t":"example","text":"Dịch: Sau khi anh ấy phát biểu, không ai dám nói nửa lời. Không có gì thú vị xảy ra trước mắt tôi hôm qua."},{"t":"para","text":"В на́ших ряда́х никого́ (но́вый) не (приба́виться);","b":1},{"t":"subhead","text":"Đáp án: но́вого ... приба́вилось"},{"t":"example","text":"Viết lại: В на́ших ряда́х никого́ но́вого не приба́вилось."},{"t":"example","text":"Dịch: Trong hàng ngũ của chúng tôi không có thêm ai mới. (Cấu trúc vô nhân xưng với не + Cách 2 → động từ giống trung số ít)."},{"t":"para","text":"Ничто́ (челове́ческий) мне не чу́ждо;","b":1},{"t":"subhead","text":"Đáp án: челове́ческое"},{"t":"example","text":"Viết lại: Ничто́ челове́ческое мне не чу́ждо."},{"t":"example","text":"Dịch: Không có gì thuộc về con người mà xa lạ với tôi."},{"t":"para","text":"Ничего́ (стра́нный) я в его́ поведе́нии не (находи́ть);","b":1},{"t":"subhead","text":"Đáp án: стра́нного ... нахожу́ (hoặc находи́л)"},{"t":"example","text":"Viết lại: Ничего́ стра́нного я в его́ поведе́нии не нахожу́."},{"t":"example","text":"Dịch: Tôi không tìm thấy điều gì lạ trong hành vi của anh ấy."},{"t":"para","text":"Никто́ (челове́ческий) мне не чу́ждо; 7. Ничего́ (стра́нный) я в его́ поведе́нии не (находи́ть) в том, что он сде́лал.","b":1},{"t":"example","text":"(Lưu ý: Câu 6 và 7 trong sách có vẻ bị trùng lặp ý với câu 4 và 5. Câu 6 trong bài gốc có thể là: \"Ничто (человеческий)...\" giống câu 4. Câu 7 giống câu 5)."},{"t":"para","text":"Никто́, ни мо́и роди́тели, ни моя́ ба́бушка, не (представля́ть) себе́ сло́жности ситуа́ции;","b":1},{"t":"subhead","text":"Đáp án: представля́л"},{"t":"example","text":"Viết lại: Никто́... не представля́л себе́..."},{"t":"example","text":"Dịch: Không một ai, kể cả bố mẹ tôi hay bà tôi, hình dung được mức độ phức tạp của tình huống. (Никто quyết định động từ → giống đực số ít)."},{"t":"para","text":"За после́дний год со мной ничего́ не (случи́ться);","b":1},{"t":"subhead","text":"Đáp án: случи́лось"},{"t":"example","text":"Viết lại: ...ничего́ не случи́лось."},{"t":"example","text":"Dịch: Trong năm qua không có chuyện gì xảy ra với tôi cả."},{"t":"para","text":"Неуже́ли вчера́ никто́ из вас, да́же са́мая реши́тельная, не (сказа́ть) ему́ всей пра́вды!","b":1},{"t":"subhead","text":"Đáp án: сказа́л"},{"t":"example","text":"Viết lại: ...никто́... не сказа́л..."},{"t":"example","text":"Dịch: Chẳng lẽ hôm qua không một ai trong các bạn, kể cả người quyết đoán nhất (nữ), đã nói cho anh ấy toàn bộ sự thật sao! (Никто → сказал)."},{"t":"para","text":"Пока́ я был в до́ме о́тдыха, никто́, ни мо́и друзья́, ни мо́и знако́мые, меня́ не (навеща́ть);","b":1},{"t":"subhead","text":"Đáp án: навеща́л"},{"t":"example","text":"Viết lại: ...никто́... не навеща́л."},{"t":"example","text":"Dịch: Khi tôi ở nhà nghỉ dưỡng, không một ai, kể cả bạn bè hay người quen, đến thăm tôi."},{"t":"para","text":"Никто́ не (смочь) помо́чь мне в э́той ситуа́ции;","b":1},{"t":"subhead","text":"Đáp án: смог"},{"t":"example","text":"Viết lại: Никто́ не смог помо́чь..."},{"t":"example","text":"Dịch: Không ai đã có thể giúp tôi trong tình huống này."},{"t":"para","text":"Вчера́ мне ничего́ не (сни́ться);","b":1},{"t":"subhead","text":"Đáp án: сни́лось"},{"t":"example","text":"Viết lại: Вчера́ мне ничего́ не сни́лось."},{"t":"example","text":"Dịch: Hôm qua tôi không mơ thấy gì cả."},{"t":"para","text":"Никто́ не (входи́ть) в тот день в его́ ко́мнату.","b":1},{"t":"subhead","text":"Đáp án: входи́л"},{"t":"example","text":"Viết lại: Никто́ не входи́л..."},{"t":"example","text":"Dịch: Không ai đã bước vào phòng anh ấy ngày hôm đó."}]},{"id":"03-s038","type":"exercise","title":"Bài 353 (Trang 171)","num":353,"blocks":[{"t":"para","text":"Đề bài: Đọc các câu văn, sử dụng động từ trong ngoặc ở dạng phù hợp."},{"t":"para","text":"Никто́ не (принима́ть) уча́стия в ко́нкурсе на про́шлой неде́ле;","b":1},{"t":"subhead","text":"Đáp án: принима́л"},{"t":"example","text":"Viết lại: Никто́ не принима́л уча́стия..."},{"t":"example","text":"Dịch: Tuần trước không ai tham gia cuộc thi."},{"t":"para","text":"Ни с кем ра́ньше не (случа́ться) таки́е интере́сные исто́рии;","b":1},{"t":"subhead","text":"Đáp án: случа́лись"},{"t":"example","text":"Viết lại: ...не случа́лись таки́е интере́сные исто́рии."},{"t":"example","text":"Dịch: Chưa từng xảy ra những câu chuyện thú vị như thế với bất kỳ ai trước đây. (Chủ ngữ là истории → động từ số nhiều)."},{"t":"para","text":"В настоя́щее вре́мя ничто́ не (представля́ть) для него́ интере́са;","b":1},{"t":"subhead","text":"Đáp án: представля́ет"},{"t":"example","text":"Viết lại: ...ничто́ не представля́ет..."},{"t":"example","text":"Dịch: Vào lúc này không gì mang lại sự hứng thú cho anh ấy. (Ничто → số ít, giống trung/hoặc theo quy tắc hiện đại dùng представляет)."},{"t":"para","text":"Ни от чего́ на́ши пла́ны не (измени́ться) в ближай́шем бу́дущем;","b":1},{"t":"subhead","text":"Đáp án: изме́нятся"},{"t":"example","text":"Viết lại: ...пла́ны не изме́нятся..."},{"t":"example","text":"Dịch: Các kế hoạch của chúng ta sẽ không thay đổi vì bất cứ điều gì trong tương lai gần. (Chủ ngữ là планы → số nhiều)."},{"t":"para","text":"Ничто́ не (нару́шить) на́ши пла́ны;","b":1},{"t":"subhead","text":"Đáp án: нару́шит"},{"t":"example","text":"Viết lại: Ничто́ не нару́шит на́ши пла́ны."},{"t":"example","text":"Dịch: Sẽ không có gì phá vỡ được kế hoạch của chúng ta. (Ничто chủ ngữ → số ít)."},{"t":"para","text":"Я ду́маю, за́втра моё настрое́ние ни от чего́ не (испо́ртиться);","b":1},{"t":"subhead","text":"Đáp án: испо́ртится"},{"t":"example","text":"Viết lại: ...настрое́ние... не испо́ртится."},{"t":"example","text":"Dịch: Tôi nghĩ ngày mai tâm trạng tôi sẽ không bị hỏng vì bất cứ điều gì. (Chủ ngữ настроение)."},{"t":"para","text":"Никто́ и никогда́ не (сде́лать) э́то лу́чше вас;","b":1},{"t":"subhead","text":"Đáp án: сде́лает (hoặc сде́лал)"},{"t":"example","text":"Viết lại: Никто́... не сде́лает..."},{"t":"example","text":"Dịch: Sẽ không có ai và không bao giờ làm điều này tốt hơn bạn."},{"t":"para","text":"К сожале́нию, в настоя́щее вре́мя никто́ не (занима́ться) изуче́нием э́того вопро́са;","b":1},{"t":"subhead","text":"Đáp án: занима́ется"},{"t":"example","text":"Viết lại: ...никто́ не занима́ется..."},{"t":"example","text":"Dịch: Tiếc là hiện nay không ai đảm nhận/làm việc nghiên cứu vấn đề này."},{"t":"para","text":"За всё э́то вре́мя ни к чему́ хоро́шему ва́ша болтли́вость вас не (привести́);","b":1},{"t":"subhead","text":"Đáp án: привела́"},{"t":"example","text":"Viết lại: ...болтли́вость... не привела́."},{"t":"example","text":"Dịch: Suốt thời gian qua sự lắm mồm của bạn đã chẳng dẫn bạn đến điều gì tốt đẹp. (Chủ ngữ болтливость → giống cái)."},{"t":"para","text":"Никто́ не (понима́ть) меня́ так, как вы;","b":1},{"t":"subhead","text":"Đáp án: понима́ет"},{"t":"example","text":"Viết lại: Никто́ не понима́ет..."},{"t":"example","text":"Dịch: Không ai hiểu tôi như bạn."},{"t":"para","text":"В то вре́мя моя́ жизнь ни от кого́ не (зави́сеть);","b":1},{"t":"subhead","text":"Đáp án: зави́села"},{"t":"example","text":"Viết lại: ...жизнь... не зави́села."},{"t":"example","text":"Dịch: Vào thời gian đó cuộc sống của tôi đã không phụ thuộc vào bất kỳ ai. (Chủ ngữ жизнь)."},{"t":"para","text":"Никто́ не (тре́бовать) сде́лать э́то сего́дня;","b":1},{"t":"subhead","text":"Đáp án: тре́бует"},{"t":"example","text":"Viết lại: Никто́ не тре́бует..."},{"t":"example","text":"Dịch: Không ai yêu cầu làm điều này hôm nay."},{"t":"para","text":"Ничто́ не (испо́ртить) мне необы́чные исто́рии;","b":1},{"t":"subhead","text":"Đáp án: испо́ртит (nếu ничто là chủ ngữ)"},{"t":"example","text":"Viết lại: Ничто́ не испо́ртит мне..."},{"t":"example","text":"Dịch: Sẽ không có gì làm hỏng những câu chuyện lạ thường của tôi."},{"t":"para","text":"В том го́роде ни с кем не (происходи́ть) необы́чные исто́рии;","b":1},{"t":"subhead","text":"Đáp án: происхо́дят (hoặc происходи́ли)"},{"t":"example","text":"Viết lại: ...не происхо́дят необы́чные исто́рии."},{"t":"example","text":"Dịch: Ở thành phố đó không xảy ra những câu chuyện lạ thường với bất kỳ ai. (Chủ ngữ истории → số nhiều)."},{"t":"para","text":"Тут не́ о чем (говори́ть). Ничего́ не (сказа́ть).","b":1},{"t":"subhead","text":"Đáp án: говори́ть ... ска́жешь (hoặc сказа́ть)"},{"t":"example","text":"Viết lại: Тут не́ о чем говори́ть. Ничего́ не ска́жешь."},{"t":"example","text":"Dịch: Ở đây chẳng có gì để mà nói. Chẳng thể nói được gì cả (Bó tay)."}]},{"id":"03-s039","type":"exercise","title":"Bài 354 (Trang 172)","num":354,"blocks":[{"t":"example","text":"Đề bài: Điền vào chỗ trống đại từ phủ định có hoặc không có не/ни và giới từ."},{"t":"subhead","text":"Gợi ý:","b":1},{"t":"vocab","ru":"Dùng Не́- + (giới từ) + đại từ","vi":"Khi ý là \"không có [người/vật] để...\". (Ví dụ: không có ai để nói → не с кем).","g":null},{"t":"vocab","ru":"Dùng Ни- + (giới từ) + đại từ","vi":"Khi ý là phủ định chung. (Ví dụ: tôi không nói với ai cả → ни с кем).","g":null},{"t":"para","text":"Мне ... поговори́ть; → не́ с кем (Tôi không có ai để nói chuyện)."},{"t":"para","text":"Им ... попроси́ть сове́та; → не́ у кого (Họ không có ai để xin lời khuyên)."},{"t":"para","text":"С тех пор он ... не разгова́ривает; → ни с кем (Từ đó anh ta không nói chuyện với ai cả)."},{"t":"para","text":"Нам ... не помо́жет; → ничто́ / никто́ (Không gì/Không ai giúp được chúng ta)."},{"t":"para","text":"Ему́ ... сожале́ть; → не́ о чем (Anh ấy chẳng có gì để hối tiếc)."},{"t":"para","text":"... не помеша́ет нам зако́нчить рабо́ту во́время; → Ничто́ (Không gì cản trở được chúng ta)."},{"t":"para","text":"... обстоя́тельствах нам не зако́нчить рабо́ту к суббо́те; → Ни при каки́х (Dù trong hoàn cảnh nào chúng ta cũng không xong việc)."},{"t":"para","text":"Она́ ... в семье́ не похо́жа; → ни на кого́ (Cô ấy không giống ai trong gia đình)."},{"t":"para","text":"Им ... не нра́вится; → ничего́ (Họ không thích cái gì cả)."},{"t":"para","text":"Мы не бу́дем сле́довать ... сове́там; → ничьи́м (Chúng tôi sẽ không làm theo lời khuyên của bất kỳ ai)."},{"t":"para","text":"Э́то ... дом, там ... не живёт; → ниче́й ... никто́ (Đây là ngôi nhà vô chủ, không ai sống ở đó)."},{"t":"para","text":"Ему́ ... не нра́вится; → ничего́ (Nó chẳng thích cái gì)."},{"t":"para","text":"... вы́воду мы не пришли́; → Ни к како́му (Chúng tôi đã không đi đến kết luận nào)."},{"t":"para","text":"Она́ не слу́шает ... сове́тов; → ничьи́х (Cô ấy không nghe lời khuyên của ai cả)."},{"t":"para","text":"... пое́здке ре́чи быть не мо́жет, мы остаёмся до́ма; → Ни о како́й (Không thể có chuyện đi đâu cả/Chuyến đi nào cả, chúng ta ở nhà)."},{"t":"para","text":"Мне ... расска́зывать, всё уже́ решено́; → не́чего (Tôi chẳng có gì để kể/nói, mọi thứ đã được quyết định)."},{"t":"para","text":"Мне ... соглаша́ться, ещё ... не предла́гали; → не́ с чем ... ничего́ (Tôi chẳng có gì để mà đồng ý, người ta đã đề nghị gì đâu)."},{"t":"para","text":"Нет, всё в поря́дке, меня́ не беспоко́ят ... голоса́; → никаки́е (Không, mọi thứ ổn, không có giọng nói nào làm phiền tôi cả)."},{"t":"para","text":"Мы не рассчи́тывали ... по́мощь; → ни на чью́ (Chúng tôi đã không trông cậy vào sự giúp đỡ của ai)."},{"t":"para","text":"Здесь ... нет, ... перебро́ситься сло́вом. → никого́ ... не́ с кем (Ở đây không có ai cả, chẳng có ai để trao đổi vài câu)."}]},{"id":"03-s040","type":"exercise","title":"Bài 355 (Trang 172)","num":355,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu văn. Chú ý đến ý nghĩa của đại từ не́чего ở vị trí vị ngữ. Xác định ý nghĩa của nó."},{"t":"note","text":"Lưu ý ngữ pháp (Trang 173):","b":1},{"t":"para","text":"Trong khẩu ngữ, cấu trúc не́чего + động từ nguyên thể (ở vị trí vị ngữ) mang nghĩa: \"không cần thiết, vô ích, không nên\" (нет смысла, не стоит, не нужно)."},{"t":"para","text":"“Впро́чем, э́то де́ло ко́нчено, не́чего ду́мать об э́том”, — сказа́л себе́ Алексе́й Алекса́ндрович.","b":1},{"t":"example","text":"Dịch: \"Tuy nhiên, việc này đã xong rồi, không cần/chẳng ích gì khi nghĩ về nó nữa\", — Alexei Alexandrovich tự nhủ."},{"t":"example","text":"Ý nghĩa: Không cần thiết, vô ích."},{"t":"para","text":"Ещё был у нас оди́н расска́зчик, но тот (не́чего бы к но́чи и вспомина́ть о нём) таки́е выка́пывал стра́шные исто́рии, что во́лосы ходи́ли по голове́.","b":1},{"t":"example","text":"Dịch: Chúng tôi còn một người kể chuyện nữa, nhưng gã đó (không nên nhắc đến vào ban đêm làm gì) chuyên đào bới những câu chuyện đáng sợ đến mức tóc dựng đứng."},{"t":"example","text":"Ý nghĩa: Không nên (vì sợ hãi/điềm gở)."},{"t":"para","text":"— Я ей растолку́ю, что ей не́чего меня́ стыди́ться.","b":1},{"t":"example","text":"Dịch: — Tôi sẽ giải thích cho cô ấy hiểu rằng cô ấy không có gì phải xấu hổ vì tôi cả (không cần thiết)."},{"t":"example","text":"Ý nghĩa: Không có lý do gì, không cần."},{"t":"para","text":"Не́чего торча́ть под дождём. Входи́те в дом в конце́ концо́в.","b":1},{"t":"example","text":"Dịch: Chẳng việc gì phải/Đừng có đứng chôn chân dưới mưa nữa. Vào nhà ngay đi."},{"t":"example","text":"Ý nghĩa: Vô ích, không nên."},{"t":"para","text":"Да не́чего на меня́ так смотре́ть! Ве́рно говорю́.","b":1},{"t":"example","text":"Dịch: Này, đừng có/không cần nhìn tôi như thế! Tôi nói thật đấy."},{"t":"example","text":"Ý nghĩa: Cấm đoán, không cần thiết."},{"t":"para","text":"Меня́ не́чего поздравля́ть! Поздра́вь ты лу́чше самого́ себя́!","b":1},{"t":"example","text":"Dịch: Không cần chúc mừng tôi đâu! Tốt hơn là bạn chúc mừng chính mình đi!"},{"t":"example","text":"Ý nghĩa: Không cần thiết."},{"t":"para","text":"— Да не́чего скуча́ть, — сказа́ла Ага́фья Миха́йловна. — Ну, что вы сиди́те до́ма? Е́хали бы на тёплые во́ды...","b":1},{"t":"example","text":"Dịch: — Chà, việc gì phải/không có lý do gì để buồn chán cả, — Agafya Mikhailovna nói. — Sao ông lại cứ ngồi nhà? Ông nên đi suối nước nóng..."},{"t":"example","text":"Ý nghĩa: Không có lý do gì, không cần."}]},{"id":"03-s041","type":"exercise","title":"Bài 356 (Trang 173)","num":356,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 173):","b":1},{"t":"example","text":"Trong văn nói (разгово́рная речь), từ не́чего (trọng âm rơi vào не) đi kèm với động từ nguyên thể (infinitive) được dùng ở vị trí vị ngữ với ý nghĩa: \"không cần thiết\" (не на́до)."},{"t":"para","text":"Đề bài: Đọc các câu văn, chú ý đến các cụm từ cố định với đại từ phủ định. Xác định ý nghĩa của chúng."},{"t":"para","text":"Ну что ж! Де́лать не́чего! (Ничего́ не поде́лаешь!) Хо́чешь, не хо́чешь, а на́до е́хать.","b":1},{"t":"example","text":"Dịch: Thôi được rồi! Chẳng làm gì được nữa (Đành chịu thôi)! Muốn hay không thì vẫn phải đi."},{"t":"example","text":"Giải thích: Cụm Де́лать не́чего ở đây có nghĩa là sự bất lực trước hoàn cảnh, đành chấp nhận."},{"t":"para","text":"Да я взяла́ э́ту кни́гу случа́йно, от ску́ки реши́ла почита́ть, от не́чего де́лать;","b":1},{"t":"example","text":"Dịch: Tôi cầm cuốn sách này tình cờ thôi, vì buồn chán nên quyết định đọc, vì rảnh rỗi quá (không có việc gì để làm)."},{"t":"example","text":"Giải thích: От не́чего де́лать = làm gì đó chỉ để giết thời gian."},{"t":"para","text":"Чего́ ты бои́шься? Нам теря́ть не́чего! Пусть други́е боя́тся.","b":1},{"t":"example","text":"Dịch: Bạn sợ cái gì? Chúng ta không còn gì để mất! Hãy để những kẻ khác phải sợ."},{"t":"example","text":"Giải thích: Теря́ть не́чего = tình thế đường cùng hoặc không có tài sản/địa vị gì đáng giá để lo sợ bị mất."},{"t":"para","text":"Ничего́ себе́ пого́дка! Це́лый день с утра́ идёт дождь;","b":1},{"t":"example","text":"Dịch: Chà, thời tiết ghê thật! Mưa suốt cả ngày từ sáng."},{"t":"example","text":"Giải thích: Ничего́ себе́! là một thán từ (interjection) trong khẩu ngữ, biểu thị sự ngạc nhiên (tích cực hoặc tiêu cực). Ở đây là ngạc nhiên/than phiền về thời tiết xấu."},{"t":"para","text":"а) Разгова́ривать с ним мне ни к чему́. Заче́м по́ртить себе́ настрое́ние?","b":1},{"t":"example","text":"Dịch: Tôi chẳng việc gì phải/chẳng cần thiết nói chuyện với hắn. Tại sao phải tự làm hỏng tâm trạng của mình?"},{"t":"example","text":"Giải thích: Ни к чему́ = không cần thiết, vô ích."},{"t":"para","text":"Что вы на меня́ так смо́трите? Я тут ни при чём, я случа́йно здесь оказа́лся;","b":1},{"t":"example","text":"Dịch: Sao các ông nhìn tôi như thế? Tôi không liên quan gì đâu/vô can, tôi tình cờ có mặt ở đây thôi."},{"t":"example","text":"Giải thích: Быть ни при чём = không dính líu, không có lỗi trong việc gì đó."},{"t":"para","text":"Обману́л он нас, ничего́ не дал, так мы и ушли́ ни с чем;","b":1},{"t":"example","text":"Dịch: Hắn đã lừa chúng tôi, chẳng đưa gì cả, thế là chúng tôi đành ra về tay trắng (không được gì)."},{"t":"example","text":"Giải thích: Уйти́ ни с чем = ra về mà không đạt được kết quả gì."},{"t":"para","text":"Я зна́ю его́ давно́ и ни за что́ не пове́рю в то, что о нём говоря́т;","b":1},{"t":"example","text":"Dịch: Tôi biết anh ấy đã lâu và không đời nào/không bao giờ tin vào những điều người ta nói về anh ấy."},{"t":"example","text":"Giải thích: Ни за что́ (nghĩa đen: không vì cái gì) = tuyệt đối không, dù bất cứ giá nào cũng không."},{"t":"para","text":"— Вы хоти́те уе́хать? — Ничего́ подо́бного! Вы нас непра́вильно по́няли;","b":1},{"t":"example","text":"Dịch: — Các bạn muốn rời đi à? — Không đời nào/Làm gì có chuyện đó! Ông hiểu lầm chúng tôi rồi."},{"t":"example","text":"Giải thích: Ничего́ подо́бного = Phủ định mạnh mẽ một ý kiến/nhận định."},{"t":"para","text":"Друго́й бы на его́ ме́сте у́мер от стыда́, а он хо́дит как ни в чём не быва́ло, посме́ивается;","b":1},{"t":"example","text":"Dịch: Người khác ở địa vị nó chắc chết vì xấu hổ, còn nó thì cứ đi lại như không có chuyện gì xảy ra, cười khẩy."},{"t":"example","text":"Giải thích: Как ни в чём не быва́ло = thản nhiên, tỉnh bơ như chưa từng có rắc rối gì."},{"t":"para","text":"Моя́ э́то вина́, не́чего греха́ таи́ть, всё расскажу́, как бы́ло;","b":1},{"t":"example","text":"Dịch: Đó là lỗi của tôi, không giấu giếm tội lỗi làm gì (chẳng việc gì phải giấu), tôi sẽ kể hết mọi chuyện đã diễn ra."},{"t":"example","text":"Giải thích: Не́чего + động từ = không nên/không cần thiết làm gì."},{"t":"para","text":"— Кто вы́играл па́ртию в ша́хматы на э́тот раз? — Никто́ не вы́играл, ничья́.","b":1},{"t":"example","text":"Dịch: — Ai thắng ván cờ vua lần này? — Chẳng ai thắng cả, hòa."},{"t":"example","text":"Giải thích: Ничья́ (danh từ) = ván hòa (xuất phát từ đại từ ниче́й - không của ai)."}]},{"id":"03-s042","type":"exercise","title":"Bài 357 (Trang 173)","num":357,"blocks":[{"t":"para","text":"Đề bài: Sử dụng các cụm từ cố định với đại từ phủ định (từ bài 356 và kiến thức liên quan), hãy chọn từ/cụm từ đồng nghĩa cho các phần in đậm (đã được thay thế trong bài giải)."},{"t":"example","text":"Чего́ ты разду́мываешь? Положе́ние у тебя́ сло́жное, ху́же быть не мо́жет, на́до де́йствовать реши́тельно;","b":1},{"t":"para","text":"Thay thế: Теря́ть не́чего (Không còn gì để mất)."},{"t":"example","text":"Dịch: Bạn còn đắn đo gì nữa? Tình thế của bạn phức tạp, không thể tồi tệ hơn được nữa, không còn gì để mất (nên phải hành động)."},{"t":"example","text":"— Почемý ты так раздражён? — Раздражён? Совсе́м нет! Почемý мне зли́ться?","b":1},{"t":"para","text":"Thay thế: С чего́ (Tại sao/Cớ gì); Не́чего / Ни к чему́ (Không việc gì phải/Vô ích)."},{"t":"example","text":"Dịch: — Cớ sao bạn lại cáu kỉnh thế? — Cáu à? Hoàn toàn không! Việc gì tôi phải tức giận?"},{"t":"example","text":"Воды́ остава́лось на три дня. Невозмо́жно бы́ло что́-то измени́ть, мы эконо́мили во́ду, как могли́.","b":1},{"t":"para","text":"Thay thế: Де́лать бы́ло не́чего (Chẳng làm gì được khác)."},{"t":"example","text":"Dịch: Nước chỉ còn đủ cho ba ngày. Chẳng làm gì được, chúng tôi tiết kiệm nước hết mức có thể."},{"t":"example","text":"** На́до призна́ть, ка́ждый из нас в отве́те за случи́вшееся;**"},{"t":"para","text":"Thay thế: Не́чего греха́ таи́ть / Не́чего скрыва́ть (Không việc gì phải giấu/Thú thật là)."},{"t":"example","text":"Dịch: Thú thật là/Không chối cãi gì nữa, mỗi người chúng ta đều phải chịu trách nhiệm cho chuyện đã xảy ra."},{"t":"para","text":"Э́ту па́ртию никто́ не вы́играл;","b":1},{"t":"para","text":"Thay thế: Ничья́ (Hòa)."},{"t":"example","text":"Dịch: Ván này hòa."},{"t":"para","text":"Он никогда́ не сде́лает то, о чём ты его́ про́сишь;","b":1},{"t":"para","text":"Thay thế: Ни за что́ (Không đời nào/Không bao giờ)."},{"t":"example","text":"Dịch: Hắn không đời nào làm điều bạn nhờ đâu."},{"t":"example","text":"Э́то про́сто несча́стный слу́чай, он к э́тому не прича́стен;","b":1},{"t":"para","text":"Thay thế: Ни при чём (Vô can/Không liên quan)."},{"t":"example","text":"Dịch: Đó chỉ là tai nạn, anh ấy không liên quan gì đến việc này."},{"t":"example","text":"Встава́ть так ра́но тебе́ не ну́жно, мы зае́дем за тобо́й в оди́ннадцать;","b":1},{"t":"para","text":"Thay thế: Не́зачем / Не́чего (Không cần thiết/Chẳng việc gì phải)."},{"t":"example","text":"Dịch: Bạn chẳng việc gì phải dậy sớm thế, 11 giờ chúng tôi mới qua đón."},{"t":"para","text":"Он сиде́л, как бу́дто ничего́ не случи́лось, и смотре́л на меня́;","b":1},{"t":"para","text":"Thay thế: Как ни в чём не быва́ло (Như không có chuyện gì xảy ra)."},{"t":"example","text":"Dịch: Hắn ngồi đó tỉnh bơ như không, nhìn tôi."},{"t":"example","text":"Коне́чно, я не поэ́т, но от безде́лья иногда́ попи́сываю стихи́;","b":1},{"t":"para","text":"Thay thế: От не́чего де́лать (Do rảnh rỗi quá/Do không có việc gì làm)."},{"t":"example","text":"Dịch: Tất nhiên tôi không phải nhà thơ, nhưng do rảnh quá nên thỉnh thoảng cũng viết lách vài câu."},{"t":"example","text":"До́лго мы жда́ли, но он так и не пришёл, пришло́сь нам возвраща́ться, ничего́ не доби́вшись;","b":1},{"t":"para","text":"Thay thế: Ни с чем (Tay trắng/Không được việc gì)."},{"t":"example","text":"Dịch: Chúng tôi đợi mãi mà nó không đến, đành phải quay về tay trắng."},{"t":"example","text":"Да, то́же мне о́тдых, ни мину́ты поко́я нет!","b":1},{"t":"para","text":"Thay thế: Никако́го (Không có chút... nào)."},{"t":"example","text":"Dịch: Vâng, nghỉ với chả ngơi, chẳng có chút yên bình nào cả!"}]},{"id":"03-s043","type":"grammar","title":"Ngữ pháp: Đại từ bất định (Неопределённые местоимения)","num":null,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 174):","b":1},{"t":"vocab","ru":"Не́кто (Ai đó - chỉ người)","vi":"Dùng trong Cách 1 (Nominative). Mang sắc thái trang trọng hoặc bí ẩn.","g":null},{"t":"vocab","ru":"Не́что (Cái gì đó - chỉ vật/tính chất)","vi":"Dùng trong Cách 1 và Cách 4 (Nominative/Accusative). Thường chỉ một hiện tượng mơ hồ, khó tả.","g":null},{"t":"vocab","ru":"Не́кий (Một... nào đó)","vi":"Biến đổi như tính từ. Nghĩa tương tự како́й-то, nhưng mang sắc thái văn chương.","g":null},{"t":"vocab","ru":"Не́который (Một số, một vài, nào đó)","vi":"Biến đổi như tính từ. Thường dùng ở số nhiều (некоторые - một số người/vật).","g":null},{"t":"vocab","ru":"Не́сколько (Một vài/Một số lượng)","vi":"Chỉ số lượng không xác định.","g":null}]},{"id":"03-s044","type":"exercise","title":"Bài 358 (Trang 174)","num":358,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu văn. Chú ý việc sử dụng các đại từ bất định не́кто, не́что, не́кий, не́который và số từ не́сколько. Giải thích đặc điểm sử dụng."},{"t":"subhead","text":"a) Не́кто, не́что (Dùng cho đối tượng không xác định rõ danh tính/bản chất):","b":1},{"t":"example","text":"Тут без тебя́ приходи́л не́кто Петро́в... (Lúc không có bạn, có người nào đó tên là Petrov đến... - Người nói không biết Petrov là ai). ...произошло́ не́что стра́нное... (...đã xảy ra một chuyện gì đó lạ lùng - Sự việc mơ hồ)."},{"t":"example","text":"...уви́дел не́что, порази́вшее меня́... (...thấy một thứ gì đó làm tôi kinh ngạc...)."},{"t":"subhead","text":"б) Не́кий (Dùng như tính từ, nghĩa là \"một... nào đó\", hơi trang trọng/cổ):","b":1},{"t":"example","text":"Вас спра́шивал не́кий молодо́й челове́к... (Có một chàng trai trẻ nào đó hỏi thăm bạn... - Người nói không quen anh ta)."},{"t":"para","text":"Các dạng biến đổi: не́кую (cách 4), с не́ким (cách 5), о не́кой (cách 6)."},{"t":"subhead","text":"в) Не́который (Một số/Một phần):","b":1},{"t":"example","text":"Не́которые из студе́нтов... (Một số sinh viên...)."},{"t":"example","text":"...не́которых уча́стников... (...một số người tham gia...)."},{"t":"example","text":"Не́которым из нас... (Cho một số người trong chúng tôi...)."},{"t":"example","text":"...не́которую часть рабо́ты... (...một phần công việc nào đó...)."},{"t":"example","text":"...с не́которыми успе́хами... (...với một số thành công...)."},{"t":"example","text":"...на не́которых собы́тиях... (...vào một số sự kiện...)."},{"t":"subhead","text":"г) Не́сколько (Chỉ số lượng):","b":1},{"t":"example","text":"...не́сколько отзы́вов... (...vài nhận xét...)."},{"t":"example","text":"...не́скольких страни́ц... (...vài trang...)."},{"t":"example","text":"...не́сколько са́мых бли́зких друзе́й... (...vài người bạn thân nhất...)."},{"t":"example","text":"...над не́сколькими прое́ктами... (...trên vài dự án...)."},{"t":"example","text":"...на не́скольких подходя́щих вариа́нтах... (...trên vài phương án phù hợp...)."}]},{"id":"03-s045","type":"exercise","title":"Bài 359 (Trang 175)","num":359,"blocks":[{"t":"para","text":"Đề bài: Điền vào chỗ trống đại từ phủ định не́кого, не́чего (không có ai/gì để...) hoặc đại từ bất định не́кто, не́что (ai đó/cái gì đó bí ẩn) phù hợp."},{"t":"para","text":"Сего́дня ... посла́ть за хле́бом на ра́боте?","b":1},{"t":"example","text":"Điền: не́кого"},{"t":"example","text":"Dịch: Hôm nay không có ai để sai đi mua bánh mì ở chỗ làm à?"},{"t":"para","text":"Я узна́л ... интере́сное об исто́рии го́рода;","b":1},{"t":"example","text":"Điền: не́что"},{"t":"example","text":"Dịch: Tôi đã biết được một điều gì đó thú vị về lịch sử thành phố."},{"t":"para","text":"Здесь говори́ть ..., и так всё поня́тно;","b":1},{"t":"example","text":"Điền: не́ о чем (hoặc не́чего)"},{"t":"example","text":"Dịch: Ở đây chẳng có gì để mà nói nữa, mọi thứ đã rõ ràng rồi."},{"t":"para","text":"Нам ... доба́вить к тому́, что бы́ло ска́зано;","b":1},{"t":"example","text":"Điền: не́чего"},{"t":"example","text":"Dịch: Chúng tôi không có gì để bổ sung vào những điều đã nói."},{"t":"para","text":"В ко́мнату вошёл ... граждани́н с уса́ми и в шля́пе;","b":1},{"t":"example","text":"Điền: не́кто (hoặc не́кий)"},{"t":"example","text":"Dịch: Có một công dân nào đó có ria mép và đội mũ bước vào phòng."},{"t":"vocab","ru":"Тру́дно определи́ть вкус э́того пече́нья","vi":"... возду́шное, та́ющее во рту;","g":null},{"t":"example","text":"Điền: не́что"},{"t":"example","text":"Dịch: Khó mà xác định vị của cái bánh này: một cái gì đó xốp nhẹ, tan trong miệng."},{"t":"para","text":"К сожале́нию, мне ... вам сообщи́ть;","b":1},{"t":"example","text":"Điền: не́чего"},{"t":"example","text":"Dịch: Tiếc là tôi không có gì để thông báo cho bạn."},{"t":"para","text":"Тут ..., воше́дший в ко́мнату, заговори́л гро́мким го́лосом;","b":1},{"t":"example","text":"Điền: не́кто"},{"t":"example","text":"Dịch: Lúc này người (lạ/nào đó) vừa bước vào phòng cất giọng nói to."},{"t":"para","text":"... удиви́тельное произошло́ со мной вчера́ на да́че;","b":1},{"t":"example","text":"Điền: не́что"},{"t":"example","text":"Dịch: Một chuyện gì đó lạ lùng đã xảy ra với tôi hôm qua ở nhà nghỉ ngoại ô."},{"t":"para","text":"Е́сли вам ... де́лать, посмотри́те телеви́зор;","b":1},{"t":"example","text":"Điền: не́чего"},{"t":"example","text":"Dịch: Nếu bạn không có gì để làm (rảnh rỗi), hãy xem tivi đi."},{"t":"para","text":"Послу́шай, ... похо́жее бы́ло со мной;","b":1},{"t":"example","text":"Điền: не́что"},{"t":"example","text":"Dịch: Nghe này, một chuyện gì đó tương tự đã từng xảy ra với tôi."},{"t":"para","text":"Им ... попроси́ть подвезти́ их до до́ма;","b":1},{"t":"example","text":"Điền: не́кого"},{"t":"example","text":"Dịch: Họ không có ai để nhờ chở về nhà."},{"t":"para","text":"На́до бы узна́ть доро́гу, но спроси́ть ..., круго́м ни души́;","b":1},{"t":"example","text":"Điền: не́ у кого"},{"t":"example","text":"Dịch: Cần phải hỏi đường, nhưng chẳng có ai để mà hỏi, xung quanh không một bóng người."},{"t":"para","text":"Ему́ каза́лось, что ... вдали́ ма́шет ему́ руко́й;","b":1},{"t":"example","text":"Điền: не́кто"},{"t":"example","text":"Dịch: Anh ấy tưởng như có ai đó đằng xa đang vẫy tay với mình."},{"t":"para","text":"Тебе́ ... вини́ть в свои́х оши́бках, то́лько самого́ себя́.","b":1},{"t":"example","text":"Điền: не́кого"},{"t":"example","text":"Dịch: Bạn không có ai để đổ lỗi cho sai lầm của mình đâu, chỉ trách bản thân thôi."}]},{"id":"03-s046","type":"exercise","title":"Bài 360 (Trang 175)","num":360,"blocks":[{"t":"para","text":"Đề bài: Mở ngoặc, sử dụng đại từ не́который (một số/nào đó) ở dạng phù hợp."},{"t":"para","text":"При (не́который) обстоя́тельствах я мог бы помо́чь вам;","b":1},{"t":"subhead","text":"Đáp án: не́которых (Cách 6 số nhiều)"},{"t":"example","text":"Dịch: Trong một số hoàn cảnh, tôi đã có thể giúp bạn."},{"t":"para","text":"Он произнёс э́ти слова́ с (не́который) смуще́нием;","b":1},{"t":"subhead","text":"Đáp án: не́которым (Cách 5 số ít, giống trung)"},{"t":"example","text":"Dịch: Anh ấy nói những lời này với chút/một sự bối rối nào đó."},{"t":"para","text":"(Не́который) часть пути́ мы шли мо́лча;","b":1},{"t":"subhead","text":"Đáp án: Не́которую (Cách 4 số ít, giống cái)"},{"t":"example","text":"Dịch: Một phần đường nào đó, chúng tôi đã đi trong im lặng."},{"t":"para","text":"Я по́нял э́то по (не́который) мелоча́м в его́ поведе́нии;","b":1},{"t":"subhead","text":"Đáp án: не́которым (Cách 3 số nhiều)"},{"t":"example","text":"Dịch: Tôi hiểu điều đó qua một vài chi tiết nhỏ trong hành vi của anh ta."},{"t":"para","text":"В (не́который) слу́чаях тако́е поведе́ние опра́вдано.","b":1},{"t":"subhead","text":"Đáp án: не́которых (Cách 6 số nhiều)"},{"t":"example","text":"Dịch: Trong một số trường hợp, hành vi như vậy là chính đáng."},{"t":"para","text":"Он зада́л вопро́с и посмотре́л на меня́ с (не́который) недове́рием;","b":1},{"t":"subhead","text":"Đáp án: не́которым (Cách 5 số ít)"},{"t":"example","text":"Dịch: Anh ta đặt câu hỏi và nhìn tôi với chút nghi ngờ."},{"t":"para","text":"(Не́который) вре́мя мы смо́жем контроли́ровать ситуа́цию;","b":1},{"t":"subhead","text":"Đáp án: Не́которое (Cách 4 số ít, giống trung)"},{"t":"example","text":"Dịch: Trong một thời gian nào đó, chúng tôi có thể kiểm soát tình hình."},{"t":"para","text":"В его́ го́лосе чу́вствовалось (не́который) беспоко́йство;","b":1},{"t":"subhead","text":"Đáp án: не́которое (Cách 1 số ít, giống trung)"},{"t":"example","text":"Dịch: Trong giọng nói anh ấy cảm nhận được chút lo lắng."},{"t":"para","text":"О его́ раздражи́тельном хара́ктере мо́жно суди́ть по (не́который) его́ посту́пкам;","b":1},{"t":"subhead","text":"Đáp án: не́которым (Cách 3 số nhiều)"},{"t":"example","text":"Dịch: Có thể phán đoán tính khí nóng nảy của anh ta qua một số hành động của anh ta."},{"t":"para","text":"Мне нра́вятся (не́который) ва́ши карти́ны;","b":1},{"t":"subhead","text":"Đáp án: не́которые (Cách 1 số nhiều)"},{"t":"example","text":"Dịch: Tôi thích một số bức tranh của bạn."},{"t":"para","text":"В ва́шем предложе́нии есть (не́который) здра́вый смысл, но оно́ нужда́ется в дета́льной разрабо́тке;","b":1},{"t":"subhead","text":"Đáp án: не́который (Cách 1 số ít, giống đực)"},{"t":"example","text":"Dịch: Trong đề xuất của bạn có chút ý nghĩa thực tế (có lý), nhưng nó cần được phát triển chi tiết."},{"t":"para","text":"В (не́который) слу́чаях э́то лека́рство помога́ет;","b":1},{"t":"subhead","text":"Đáp án: не́которых (Cách 6 số nhiều)"},{"t":"example","text":"Dịch: Trong một số trường hợp, thuốc này có tác dụng."},{"t":"para","text":"Нам пона́добится (не́который) коли́чество пре́сной воды́;","b":1},{"t":"subhead","text":"Đáp án: не́которое (Cách 1/4 số ít, giống trung)"},{"t":"example","text":"Dịch: Chúng ta sẽ cần một lượng nước ngọt nào đó."},{"t":"para","text":"При (не́который) измене́ниях, пожа́луй, мы смо́жем приня́ть ваш прое́кт;","b":1},{"t":"subhead","text":"Đáp án: не́которых (Cách 6 số nhiều)"},{"t":"example","text":"Dịch: Với một số thay đổi, có lẽ chúng tôi sẽ chấp nhận dự án của bạn."},{"t":"para","text":"(Не́который) черты́ его́ хара́ктера мне не нра́вились;","b":1},{"t":"subhead","text":"Đáp án: Не́которые (Cách 1 số nhiều)"},{"t":"example","text":"Dịch: Một vài nét trong tính cách anh ta tôi không thích."},{"t":"para","text":"Спорти́вные тренажёры займу́т (не́который) простра́нство в э́той ко́мнате;","b":1},{"t":"subhead","text":"Đáp án: не́которое (Cách 4 số ít, giống trung)"},{"t":"example","text":"Dịch: Máy tập thể thao sẽ chiếm một khoảng không gian nào đó trong phòng này."},{"t":"para","text":"Я могу́ позвони́ть (не́который) мои́м друзья́м и спроси́ть их об э́том;","b":1},{"t":"subhead","text":"Đáp án: не́которым (Cách 3 số nhiều)"},{"t":"example","text":"Dịch: Tôi có thể gọi cho một số bạn bè của mình và hỏi họ về việc này."},{"t":"para","text":"(Не́который) интере́с э́та информа́ция мо́жет вы́звать, но в це́лом, вряд ли на неё обратя́т внима́ние.","b":1},{"t":"subhead","text":"Đáp án: Не́который (Cách 4 số ít, giống đực)"},{"t":"example","text":"Dịch: Thông tin này có thể gây ra một chút quan tâm nào đó, nhưng nhìn chung, khó có khả năng người ta chú ý đến nó."}]},{"id":"03-s047","type":"exercise","title":"Bài 361 (Trang 175)","num":361,"blocks":[{"t":"example","text":"Đề bài: Phân loại các câu trong bài tập 360 vào ba cột dựa trên ý nghĩa của đại từ не́который:"},{"t":"para","text":"а) ‘отде́льный’ (riêng biệt, một số... nhất định trong nhóm)."},{"t":"para","text":"б) ‘неопределённый’ (không xác định, một cái gì đó, một khoảng nào đó)."},{"t":"para","text":"в) ‘незначи́тельный’ (không đáng kể, một chút, phần nào)."},{"t":"para","text":"Giải thích ngữ pháp:","b":1},{"t":"subhead","text":"Đại từ не́который có thể mang các sắc thái nghĩa khác nhau tùy ngữ cảnh:"},{"t":"example","text":"Nhất định/Cụ thể (Specific/Certain): Chỉ một bộ phận, một nhóm cụ thể nhưng không nêu tên (некоторые люди - một số người nhất định)."},{"t":"example","text":"Không xác định (Indefinite): Thường dùng với thời gian hoặc không gian (некоторое время - một khoảng thời gian nào đó)."},{"t":"example","text":"Không đáng kể/Một chút (Slight): Thường đi với danh từ trừu tượng chỉ cảm xúc (с некоторым sмущением - với chút bối rối)."},{"t":"subhead","text":"Đáp án chi tiết (Dựa trên nội dung các câu ở bài 360):","b":1},{"t":"table","rows":[["а) Отде́льный (Riêng biệt/Nhất định)","б) Неопределённый (Không xác định)","в) Незначи́тельный (Không đáng kể/Một chút)"],["1. При неко́торых обстоя́тельствах...*(Trong những hoàn cảnh nhất định...)*","3. Неко́торую часть пути́ мы шли мо́лча.*(Chúng tôi đi lặng lẽ trong một phần đường nào đó)*","2. Он произнёс э́ти слова́ с неко́торым смуще́нием.*(Anh ấy nói những lời này với một chút bối rối)*"],["4. Я по́нял э́то по неко́торым мелоча́м...*(Tôi hiểu điều này qua một số chi tiết nhỏ nhất định)*","7. Неко́торое вре́мя мы смо́жем контроли́ровать ситуа́цию.*(Chúng ta có thể kiểm soát tình hình trong một khoảng thời gian nào đó)*","6. Он посмотре́л на меня́ с неко́торым недове́рием.*(Anh ấy nhìn tôi với chút nghi ngờ)*"],["5. В неко́торых слу́чаях...*(Trong một số trường hợp nhất định)*","13. Нам пона́добится неко́торое коли́чество пре́сной воды́.*(Chúng ta sẽ cần một lượng nước ngọt nào đó)*","8. В его́ го́лосе чу́вствовалось неко́торое беспоко́йство.*(Trong giọng anh ấy cảm thấy có chút lo lắng)*"],["9. О его́ хара́ктере мо́жно суди́ть по неко́торым его́ посту́пкам.*(Có thể đánh giá tính cách qua một số hành động nhất định của anh ấy)*","16. Спортивные тренажёры займу́т неко́торое простра́нство...*(Máy tập sẽ chiếm một khoảng không gian nào đó)*","11. В ва́шем предложе́нии есть неко́торый здра́вый смысл.*(Trong đề xuất của bạn có chút ý nghĩa đúng đắn/lẽ thường)*"],["10. Мне нра́вятся неко́торые ва́ши карти́ны.*(Tôi thích một số bức tranh nhất định của bạn)*","","18. Неко́торый интере́с э́та информа́ция мо́жет вы́звать.*(Thông tin này có thể gây ra chút quan tâm)*"],["12. В неко́торых слу́чаях э́то лека́рство помога́ет.*(Trong một số trường hợp nhất định thuốc này có tác dụng)*","",""],["14. При неко́торых измене́ниях...*(Với một số thay đổi nhất định...)*","",""],["15. Неко́торые черты́ его́ хара́ктера...*(Một số nét tính cách nhất định của anh ấy...)*","",""],["17. Я могу́ позвони́ть неко́торым мои́м друзья́м...*(Tôi có thể gọi cho một số người bạn nhất định của mình...)*","",""]]}]},{"id":"03-s048","type":"exercise","title":"Bài 362 (Trang 176)","num":362,"blocks":[{"t":"para","text":"Đề bài: Chọn động từ phù hợp trong ngoặc."},{"t":"subhead","text":"Gợi ý ngữ pháp (Quy tắc hòa hợp chủ ngữ - vị ngữ):","b":1},{"t":"subhead","text":"Не́сколько (vài, một số) + Danh từ:","b":1},{"t":"example","text":"Nếu danh từ chỉ vật (bất động vật) → Động từ thường để ở số ít, giống trung (ví dụ: произошло несколько событий)."},{"t":"example","text":"Nếu danh từ chỉ người (động vật) → Động từ thường để ở số nhiều (ví dụ: пришли несколько человек)."},{"t":"subhead","text":"Не́который/Не́кий (một số/một ... nào đó) + Danh từ:","b":1},{"t":"example","text":"Động từ luôn hòa hợp theo giống và số của danh từ đi kèm (ví dụ: некий гражданин спрашивал, некоторые люди говорили)."},{"t":"vocab","ru":"Не́кто (ai đó)","vi":"Luôn đi với động từ giống đực, số ít.","g":null},{"t":"vocab","ru":"Не́что (cái gì đó)","vi":"Luôn đi với động từ giống trung, số ít.","g":null},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"В на́шем го́роде (произошли́, произошло́) не́сколько стра́нных собы́тий;","b":1},{"t":"subhead","text":"Đáp án: произошло́","b":1},{"t":"example","text":"Dịch: Ở thành phố chúng tôi đã xảy ra một vài sự kiện lạ lùng."},{"t":"example","text":"Giải thích: Событий (sự kiện - bất động vật) đi với несколько → động từ số ít giống trung."},{"t":"para","text":"У нас (бы́ли, бы́ло) не́которые основа́ния сомнева́ться в его́ сло́вах;","b":1},{"t":"subhead","text":"Đáp án: бы́ли","b":1},{"t":"example","text":"Dịch: Chúng tôi đã có một số căn cứ nhất định để nghi ngờ lời nói của anh ấy."},{"t":"example","text":"Giải thích: Chủ ngữ là некоторые основания (số nhiều) → động từ số nhiều."},{"t":"para","text":"В не́бе (промелькну́ли, промелькну́ло) не́сколько коме́т;","b":1},{"t":"subhead","text":"Đáp án: промелькну́ли (theo sách đáp án trang 383, dù комета là bất động vật, nhưng khi nhấn mạnh tính tích cực của hành động có thể dùng số nhiều. Tuy nhiên, промелькнуло cũng đúng ngữ pháp cơ bản. Sách chọn số nhiều)."},{"t":"example","text":"Dịch: Trên bầu trời đã vụt qua một vài ngôi sao chổi."},{"t":"para","text":"Со мной (случи́лись, случи́лось) не́что стра́нное, как бу́дто не́кто в толпе́ (вы́крикнул, вы́крикнули) моё и́мя;","b":1},{"t":"subhead","text":"Đáp án: случи́лось ... вы́крикнул"},{"t":"example","text":"Dịch: Một chuyện lạ đã xảy ra với tôi, cứ như thể ai đó trong đám đông đã hét tên tôi."},{"t":"example","text":"Giải thích: Нечто → giống trung số ít (случилось). Некто → giống đực số ít (выкрикнул)."},{"t":"para","text":"Тебя́ (спра́шивали, спра́шивало) не́кий пожило́й граждани́н;","b":1},{"t":"subhead","text":"Đáp án: спра́шивал (Sách in thiếu tùy chọn này hoặc dùng mẹo, đáp án đúng phải hòa hợp với гражданин). Lưu ý: Nếu đề bắt chọn спрашивали (số nhiều để chỉ sự tôn trọng hoặc không xác định) thì không chuẩn lắm với некий. Theo đáp án chuẩn: спра́шивал."},{"t":"example","text":"Dịch: Có một công dân lớn tuổi nào đó đã hỏi tìm bạn."},{"t":"para","text":"В гости́ную (пришли́, пришло́) не́сколько мои́х знако́мых;","b":1},{"t":"subhead","text":"Đáp án: пришли́","b":1},{"t":"example","text":"Dịch: Một vài người quen của tôi đã đến phòng khách."},{"t":"example","text":"Giải thích: Знакомых (người quen - động vật/chỉ người) + несколько → động từ số nhiều."},{"t":"para","text":"Не́которые обстоя́тельства (заста́вили, заста́вило) меня́ измени́ть приня́тое реше́ние;","b":1},{"t":"subhead","text":"Đáp án: заста́вили","b":1},{"t":"example","text":"Dịch: Một số hoàn cảnh nhất định đã buộc tôi thay đổi quyết định đã chọn."},{"t":"example","text":"Giải thích: Некоторые обстоятельства (số nhiều) → động từ số nhiều."},{"t":"para","text":"До́лжен призна́ться, не́кие сомне́ния у меня́ (бы́ли, бы́ло);","b":1},{"t":"subhead","text":"Đáp án: бы́ли","b":1},{"t":"example","text":"Dịch: Phải thú nhận là tôi đã có những nghi ngờ nào đó."},{"t":"example","text":"Giải thích: Некие сомнения (số nhiều)."},{"t":"para","text":"Не́сколько собы́тий, произоше́дших за после́дний год, (измени́ли, измени́ло) мою́ жизнь по́лностью;","b":1},{"t":"subhead","text":"Đáp án: измени́ли","b":1},{"t":"example","text":"Dịch: Một vài sự kiện xảy ra trong năm qua đã thay đổi hoàn toàn cuộc đời tôi."},{"t":"example","text":"Giải thích: Dù là bất động vật, nhưng khi chủ ngữ đứng xa động từ và có mệnh đề quan hệ bổ nghĩa, xu hướng dùng số nhiều (изменили) mạnh hơn để nhấn mạnh từng sự kiện."},{"t":"para","text":"На ве́чер (пришли́, пришло́) не́сколько мои́х знако́мых;","b":1},{"t":"subhead","text":"Đáp án: пришли́ (hoặc приехало nếu đi xe, nhưng ở đây dùng từ пришли)."},{"t":"example","text":"Dịch: Một vài người quen của tôi đã đến dự buổi tối. (Chỉ người → số nhiều)."}]},{"id":"03-s049","type":"exercise","title":"Bài 363 (Trang 176)","num":363,"blocks":[{"t":"example","text":"Đề bài: Điền не́который (nào đó/nhất định - biến đổi như tính từ) hoặc не́сколько (vài/một số - chỉ số lượng, dùng với Cách 2 số nhiều)."},{"t":"subhead","text":"Phân biệt:","b":1},{"t":"para","text":"Не́сколько = How many? (Số lượng). Dùng cho đếm được."},{"t":"para","text":"Не́который = Which ones? (Chất lượng/Xác định một nhóm). Dùng để chỉ một phần trong tổng thể hoặc một cái gì đó không xác định rõ."},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"Мы шли по пусты́не уже́ ... (дни).","b":1},{"t":"para","text":"Điền: не́сколько дней","b":1},{"t":"para","text":"Dịch: Chúng tôi đã đi trên sa mạc được vài ngày rồi. (Chỉ số lượng thời gian)."},{"t":"para","text":"В ... (дни), когда́ температу́ра во́здуха доходи́ла до тридцати́ пяти́ гра́дусов по Це́льсию, бы́ло осо́бенно тяжело́ идти́.","b":1},{"t":"para","text":"Điền: не́которые дни","b":1},{"t":"para","text":"Dịch: Vào một số ngày nhất định, khi nhiệt độ không khí lên tới 35 độ C, việc đi lại đặc biệt khó khăn. (Chỉ những ngày cụ thể có đặc điểm này)."},{"t":"para","text":"Я подожда́л ... (вре́мя) и пошёл к остано́вке авто́буса.","b":1},{"t":"para","text":"Điền: не́которое вре́мя","b":1},{"t":"example","text":"Dịch: Tôi đã đợi một khoảng thời gian rồi đi đến trạm xe buýt. (Cụm cố định некоторое время)."},{"t":"para","text":"Подожди́ меня́, пожа́луйста, ... (мину́ты).","b":1},{"t":"para","text":"Điền: не́сколько мину́т","b":1},{"t":"para","text":"Dịch: Làm ơn đợi tôi vài phút nhé. (Số lượng)."},{"t":"para","text":"Он сказа́л ... (фра́зы) и замолча́л.","b":1},{"t":"para","text":"Điền: не́сколько фраз","b":1},{"t":"para","text":"Dịch: Anh ấy nói vài câu rồi im lặng. (Số lượng)."},{"t":"para","text":"Я люблю́ перечи́тывать ... (страни́цы) из рома́на Достое́вского “Идио́т”.","b":1},{"t":"para","text":"Điền: не́которые страни́цы","b":1},{"t":"para","text":"Dịch: Tôi thích đọc lại một số trang nhất định trong tiểu thuyết \"Chàng ngốc\" của Dostoevsky. (Chọn lọc những trang hay)."},{"t":"para","text":"Я успе́л прочита́ть ... (страни́цы), пре́жде чем зазвони́л телефо́н.","b":1},{"t":"para","text":"Điền: не́сколько страни́ц","b":1},{"t":"para","text":"Dịch: Tôi đã kịp đọc vài trang trước khi điện thoại reo. (Số lượng trang đọc được)."},{"t":"para","text":"Попро́буй вы́разить свою́ мысль в ... (сло́ва).","b":1},{"t":"para","text":"Điền: не́скольких слова́х (Cách 6) hoặc не́которых слова́х? Ngữ cảnh \"in a few words\" → в не́скольких слова́х."},{"t":"para","text":"Dịch: Hãy thử diễn đạt suy nghĩ của bạn trong vài từ."},{"t":"para","text":"Он говори́т по-ру́сски, но в ... (сло́ва) он непра́вильно ста́вит ударе́ние.","b":1},{"t":"para","text":"Điền: не́которых слова́х","b":1},{"t":"para","text":"Dịch: Anh ấy nói tiếng Nga, nhưng ở một số từ nhất định, anh ấy nhấn trọng âm sai. (Chỉ ra các từ cụ thể bị sai)."}]},{"id":"03-s050","type":"exercise","title":"Bài 364 (Trang 177)","num":364,"blocks":[{"t":"example","text":"Đề bài: Điền не́который hoặc не́сколько ở dạng phù hợp."},{"t":"para","text":"... (моне́ты) (упа́ли, упа́ло) в во́ду.","b":1},{"t":"example","text":"Điền: Не́сколько моне́т упа́ло (hoặc упали)"},{"t":"para","text":"Dịch: Vài đồng xu đã rơi xuống nước. (Số lượng)."},{"t":"para","text":"... (моне́ты) (па́дали, па́дало) в во́ду и исчеза́ли из ви́ду, други́е блесте́ли на со́лнце.","b":1},{"t":"para","text":"Điền: Не́которые моне́ты па́дали","b":1},{"t":"example","text":"Dịch: Một số đồng xu rơi xuống nước và biến mất, những đồng khác thì lấp lánh dưới nắng. (Phân loại: nhóm này thế này, nhóm kia thế kia → Некоторые)."},{"t":"para","text":"... (собы́тия), о кото́рых ты спра́шивал, (происходи́ли, происходи́ло) здесь в про́шлом году́.","b":1},{"t":"example","text":"Điền: Не́которые собы́тия ... происходи́ли (hoặc Те события). Nếu bắt buộc dùng nhóm từ này: Не́которые собы́тия (Một số sự kiện nhất định mà bạn hỏi)."},{"t":"note","text":"Lưu ý: Nếu ý là \"vài sự kiện\" → Несколько событий происходило. Nhưng mệnh đề \"mà bạn hỏi\" gợi ý sự xác định → Некоторые."},{"t":"para","text":"Пока́ тебя́ не́ было, (произошли́, произошло́) ... (собы́тия).","b":1},{"t":"para","text":"Điền: произошло́ не́сколько собы́тий","b":1},{"t":"para","text":"Dịch: Khi bạn vắng mặt, đã xảy ra vài sự kiện. (Thông báo số lượng sự việc)."},{"t":"para","text":"Впереди́ нас (шли, шло) ... (лю́ди).","b":1},{"t":"example","text":"Điền: шло не́сколько люде́й (hoặc человек) / шли не́которые лю́ди."},{"t":"example","text":"Ngữ cảnh tự nhiên: шло не́сколько челове́к. (Đi phía trước chúng tôi là vài người)."},{"t":"para","text":"... (лю́ди) не понима́ют хоро́шего к себе́ отноше́ния.","b":1},{"t":"para","text":"Điền: Не́которые лю́ди","b":1},{"t":"para","text":"Dịch: Một số người không hiểu được thái độ tốt dành cho họ. (Chỉ nhóm người có tính cách này)."},{"t":"para","text":"... (пе́сни), испо́лненные в сопровожде́нии орке́стра, (звуча́ли, звуча́ло) осо́бенно торже́ственно.","b":1},{"t":"para","text":"Điền: Не́которые пе́сни ... звуча́ли","b":1},{"t":"para","text":"Dịch: Một số bài hát được trình diễn cùng dàn nhạc đã vang lên đặc biệt trang trọng."},{"t":"para","text":"(Прозвуча́ли, прозвуча́ло) ... (пе́сни) на стихи́ С. Есе́нина.","b":1},{"t":"para","text":"Điền: Прозвуча́ло не́сколько пе́сен","b":1},{"t":"para","text":"Dịch: Đã vang lên vài bài hát phổ thơ S. Yesenin."},{"t":"para","text":"У меня́ (появи́лись, появи́лось) ... (предложе́ния) по э́тому по́воду.","b":1},{"t":"para","text":"Điền: появи́лось не́сколько предложе́ний","b":1},{"t":"para","text":"Dịch: Tôi đã nảy ra vài đề xuất về vấn đề này."},{"t":"para","text":"Вре́мя от вре́мени у меня́ (появля́лись, появля́лось) ... (предложе́ния) по э́тому по́воду, но серьёзно я э́тот вопро́с не обду́мывал.","b":1},{"t":"para","text":"Điền: появля́лись не́которые предложе́ния","b":1},{"t":"para","text":"Dịch: Thỉnh thoảng tôi có xuất hiện một số đề xuất về việc này, nhưng tôi chưa suy nghĩ nghiêm túc."}]},{"id":"03-s051","type":"exercise","title":"Bài 365 (Trang 177)","num":365,"blocks":[{"t":"example","text":"Đề bài: Điền đại từ bất định (не́кто, не́что, не́кий) hoặc не́сколько (với nghĩa trạng từ chỉ mức độ) phù hợp."},{"t":"para","text":"При пе́рвом на́шем знако́мстве я обрати́л внима́ние на ... постоя́нную холо́дность в выраже́нии его́ лица́.","b":1},{"t":"para","text":"Điền: не́кую","b":1},{"t":"example","text":"Dịch: Trong lần đầu tiên chúng tôi làm quen, tôi đã chú ý đến một sự lạnh lùng nào đó thường trực trên nét mặt anh ấy. (Некую đi với danh từ giống cái, chỉ tính chất không xác định rõ)."},{"t":"para","text":"Его́ лицо́, ... холо́дное, но тем не ме́нее доста́точно прия́тное, выража́ло живе́йший интере́с ко всему́ происходя́щему.","b":1},{"t":"para","text":"Điền: не́сколько","b":1},{"t":"example","text":"Dịch: Khuôn mặt anh ấy, hơi/có phần lạnh lùng, nhưng dù sao cũng khá dễ chịu, thể hiện sự quan tâm sống động đến mọi việc đang diễn ra. (Несколько + tính từ = hơi, một chút)."},{"t":"para","text":"Возни́кло ... замеша́тельство. Мы заме́шкались в дверя́х, так как встре́тили ста́рых знако́мых.","b":1},{"t":"example","text":"Điền: не́кое (hoặc не́которое)"},{"t":"para","text":"Dịch: Đã nảy sinh một sự bối rối nào đó. Chúng tôi chần chừ ở cửa vì gặp người quen cũ."},{"t":"para","text":"Для меня́ ва́ше предложе́ние явля́ется ... неожи́данным. Меня́ напуга́ла ... неожи́данность его́ появле́ния.","b":1},{"t":"para","text":"Điền: не́сколько ... не́кая","b":1},{"t":"para","text":"Dịch: Đối với tôi đề nghị của bạn là hơi bất ngờ. Tôi bị hoảng sợ bởi một sự bất ngờ nào đó trong sự xuất hiện của anh ấy."},{"t":"para","text":"Мне ка́жется, ты к нему́ отно́сишься ... суро́во. Ей сво́йственна ... врождённая суро́вость в обраще́нии с окружа́ющими.","b":1},{"t":"para","text":"Điền: не́сколько ... не́кая","b":1},{"t":"para","text":"Dịch: Tôi thấy hình như bạn đối xử với cậu ấy hơi nghiêm khắc. Cô ấy có một sự nghiêm khắc bẩm sinh nào đó trong cách cư xử với mọi người."},{"t":"para","text":"Безусло́вно, ... тру́дности нас ожида́ют, но в це́лом всё пройдёт без пробле́м.","b":1},{"t":"para","text":"Điền: не́которые","b":1},{"t":"para","text":"Dịch: Chắc chắn là một số khó khăn nhất định đang chờ đợi chúng ta, nhưng nhìn chung mọi việc sẽ trôi qua êm đẹp."},{"t":"para","text":"Ты не поду́мал о после́дствиях свое́го посту́пка и поста́вил меня́ в ... тру́дное положе́ние.","b":1},{"t":"example","text":"Điền: не́сколько (hoặc весьма́ - nhưng đề bài yêu cầu nhóm từ này)."},{"t":"para","text":"Dịch: Bạn đã không nghĩ đến hậu quả hành động của mình và đã đặt tôi vào tình thế hơi/khá khó khăn."},{"t":"para","text":"Всем нам сво́йственны ... сла́бости. Сейча́с твоё положе́ние мо́жно счита́ть ... сла́бым, но, ду́маю, ско́ро всё изме́нится.","b":1},{"t":"para","text":"Điền: не́которые ... не́сколько","b":1},{"t":"para","text":"Dịch: Tất cả chúng ta đều có những điểm yếu nhất định. Bây giờ vị thế của bạn có thể coi là hơi yếu, nhưng tôi nghĩ mọi thứ sẽ sớm thay đổi."},{"t":"para","text":"Ты ... поторопи́лся с реше́нием. Да́же несмотря́ на ... торопли́вость в движе́ниях, он производи́л впечатле́ние челове́ка выде́ржанного и основа́тельного.","b":1},{"t":"example","text":"Điền: не́сколько ... не́кую (hoặc не́которую)"},{"t":"para","text":"Dịch: Bạn đã hơi vội vàng với quyết định đó. Ngay cả bất chấp một sự vội vàng nào đó trong cử chỉ, anh ấy vẫn tạo ấn tượng là người điềm đạm và chắc chắn."}]},{"id":"03-s052","type":"exercise","title":"Bài 366 (Trang 178)","num":366,"blocks":[{"t":"example","text":"Đề bài: Thay thế các dấu ba chấm bằng các đại từ bất định (не́кто, не́что, не́кий, не́который, не́сколько) ở dạng phù hợp. Mở ngoặc và chọn dạng đúng của động từ nếu cần."},{"t":"para","text":"Giải thích ngữ pháp:","b":1},{"t":"vocab","ru":"Не́что (cái gì đó)","vi":"Dùng cho sự vật/hiện tượng trừu tượng, không xác định rõ, đi với tính từ/động từ giống trung số ít.","g":null},{"t":"vocab","ru":"Не́кто (ai đó)","vi":"Dùng cho người, thường đi với động từ giống đực số ít.","g":null},{"t":"vocab","ru":"Не́кий (một ... nào đó)","vi":"Dùng như tính từ (како́й-то), mang sắc thái văn phong trang trọng hoặc bí ẩn.","g":null},{"t":"vocab","ru":"Не́который (một số, nhất định)","vi":"Chỉ một phần trong nhóm hoặc một lượng không xác định (thời gian).","g":null},{"t":"vocab","ru":"Не́сколько (vài, một số lượng)","vi":"Chỉ số lượng. Với danh từ chỉ người (động vật), động từ thường ở số nhiều; với danh từ bất động vật, động từ thường ở số ít (giống trung).","g":null},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"para","text":"Со мной произошло́ не́что фантасти́ческое.","b":1},{"t":"example","text":"Dịch: Đã xảy ra với tôi một chuyện gì đó thật huyền bí."},{"t":"example","text":"Giải thích: Фантастическое (tính từ giống trung) → dùng не́что."},{"t":"para","text":"Я почу́вствовал не́который (не́кий) страх.","b":1},{"t":"example","text":"Dịch: Tôi đã cảm thấy một nỗi sợ hãi nào đó."},{"t":"example","text":"Giải thích: Страх (giống đực). Dùng некоторый hoặc некий để chỉ cảm giác không rõ ràng."},{"t":"para","text":"Телефо́н был за́нят, и мне пришло́сь подожда́ть не́которое вре́мя.","b":1},{"t":"example","text":"Dịch: Điện thoại bị bận, và tôi đã phải đợi một khoảng thời gian."},{"t":"example","text":"Giải thích: Cụm cố định не́которое вре́мя."},{"t":"para","text":"Он вернётся че́рез не́сколько мину́т.","b":1},{"t":"example","text":"Dịch: Anh ấy sẽ quay lại sau vài phút."},{"t":"example","text":"Giải thích: Chỉ lượng thời gian → не́сколько."},{"t":"para","text":"Я спра́шивал у него́ не́сколько раз, но он так и не отве́тил.","b":1},{"t":"example","text":"Dịch: Tôi đã hỏi anh ấy vài lần, nhưng anh ấy vẫn không trả lời."},{"t":"example","text":"Giải thích: Chỉ số lần → не́сколько."},{"t":"para","text":"Не́которые экза́мены я сдава́л в зи́мнюю се́ссию.","b":1},{"t":"example","text":"Dịch: Tôi đã thi một số môn thi vào kỳ thi mùa đông."},{"t":"example","text":"Giải thích: Chỉ một bộ phận trong các môn thi → не́которые."},{"t":"para","text":"У меня́ есть не́который о́пыт рабо́ты в э́той о́бласти.","b":1},{"t":"example","text":"Dịch: Tôi có một chút kinh nghiệm làm việc trong lĩnh vực này."},{"t":"example","text":"Giải thích: Chỉ mức độ kinh nghiệm → не́который."},{"t":"para","text":"В разгово́ре возни́кло не́которое замеша́тельство.","b":1},{"t":"example","text":"Dịch: Trong cuộc trò chuyện đã nảy sinh một sự bối rối nhất định/nào đó."},{"t":"example","text":"Giải thích: Замешательство (giống trung) → не́которое."},{"t":"para","text":"Да, ты прав, в нём есть не́что незауря́дное.","b":1},{"t":"example","text":"Dịch: Ừ, bạn nói đúng, ở con người anh ấy có điều gì đó phi thường."},{"t":"example","text":"Giải thích: Незаурядное (giống trung) → не́что."},{"t":"para","text":"Не́которые страни́цы рома́на прочи́тываются на одно́м дыха́нии.","b":1},{"t":"example","text":"Dịch: Một số trang của cuốn tiểu thuyết được đọc một mạch (rất lôi cuốn)."},{"t":"example","text":"Giải thích: Một phần các trang → не́которые. Động từ số nhiều прочитываются."},{"t":"para","text":"Не́которые са́мые я́ркие звёзды отража́лись в воде́, как в зе́ркале.","b":1},{"t":"example","text":"Dịch: Một số ngôi sao sáng nhất đã phản chiếu trong nước như trong gương."},{"t":"example","text":"Giải thích: Некоторые (một số ngôi sao cụ thể). Động từ số nhiều отражались."},{"t":"para","text":"Он сообщи́л мне не́что стра́нное, я до сих пор не могу́ в э́то пове́рить.","b":1},{"t":"example","text":"Dịch: Anh ấy đã thông báo cho tôi một điều gì đó kỳ lạ, đến giờ tôi vẫn không thể tin được."},{"t":"example","text":"Giải thích: Странное → не́что."},{"t":"para","text":"И всё же не́которые сомне́ния у меня́ остаю́тся.","b":1},{"t":"example","text":"Dịch: Và dù vậy tôi vẫn còn lại những nghi ngờ nhất định."},{"t":"example","text":"Giải thích: Сомнения (số nhiều) → не́которые."},{"t":"para","text":"Не́которые студе́нты во́время не сдали зачёт.","b":1},{"t":"example","text":"Dịch: Một số sinh viên đã không nộp bài kiểm tra đúng hạn."},{"t":"example","text":"Giải thích: Chỉ nhóm người → не́которые."},{"t":"para","text":"Я хоте́л вам рассказа́ть не́что интере́сное о свои́х пла́нах на бу́дущее.","b":1},{"t":"example","text":"Dịch: Tôi muốn kể cho bạn một điều gì đó thú vị về các kế hoạch tương lai của mình."},{"t":"example","text":"Giải thích: Интересное → не́что."},{"t":"para","text":"В твои́х слова́х чу́вствуется не́которая заинтересо́ванность в э́том де́ле.","b":1},{"t":"example","text":"Dịch: Trong lời nói của bạn cảm nhận được một sự quan tâm nhất định đến vụ việc này."},{"t":"example","text":"Giải thích: Заинтересованность (giống cái) → не́которая."},{"t":"para","text":"Безусло́вно, мы доби́лись не́которого успе́ха, но рабо́та предстои́т больша́я.","b":1},{"t":"example","text":"Dịch: Chắc chắn là chúng tôi đã đạt được một chút thành công nào đó, nhưng công việc phía trước còn nhiều."},{"t":"example","text":"Giải thích: Успеха (Cách 2 do добились) → не́которого."},{"t":"para","text":"Не́которые соревнова́ния проходи́ли одновре́менно, и я был вы́нужден выбира́ть, в како́м из них приня́ть уча́стие.","b":1},{"t":"example","text":"Dịch: Một số cuộc thi diễn ra cùng lúc, và tôi buộc phải chọn tham gia cái nào."},{"t":"example","text":"Giải thích: Nhóm sự kiện → не́которые."},{"t":"example","text":"Я с интере́сом наблюда́л, как с горы́ спуска́лись не́сколько лы́жников. (Hoặc спускалось)."},{"t":"example","text":"Dịch: Tôi thích thú quan sát cảnh vài người trượt tuyết đang lao xuống núi."},{"t":"example","text":"Giải thích: Несколько chỉ số lượng. Với danh từ chỉ người, động từ quá khứ thường để số nhiều (спускались), nhưng số ít giống trung (спускалось) cũng chấp nhận được. Sách thường ưu tiên số nhiều cho hoạt động của người."},{"t":"para","text":"Вас дожида́ется не́кто (не́кий) Си́доров, он не сказа́л, по како́му вопро́су вы ему́ нужны́.","b":1},{"t":"example","text":"Dịch: Có người tên là Sidorov đang đợi ông, ông ta không nói ông ta cần gặp ông về việc gì."},{"t":"example","text":"Giải thích: Некто/Некий dùng trước họ tên để chỉ người lạ, không quen biết."},{"t":"para","text":"В приёмной тебя́ ждут не́сколько молоды́х люде́й.","b":1},{"t":"example","text":"Dịch: Có vài thanh niên đang đợi bạn ở phòng tiếp tân."},{"t":"example","text":"Giải thích: Несколько + Danh từ số nhiều Cách 2. Động từ ждут (số nhiều) phù hợp với người."},{"t":"para","text":"Гу́бы на его́ лице́ бы́ли не́сколько тонки́ (то́нкие), но не по́ртили о́бщего впечатле́ния.","b":1},{"t":"example","text":"Dịch: Môi trên khuôn mặt anh ấy hơi mỏng, nhưng không làm hỏng ấn tượng chung."},{"t":"example","text":"Giải thích: Несколько ở đây là trạng từ chỉ mức độ (= hơi, một chút)."},{"t":"para","text":"Когда́ я тебя́ слу́шаю, у меня́ возника́ет не́кий (оди́н) просто́й вопро́с.","b":1},{"t":"example","text":"Dịch: Khi tôi nghe bạn nói, trong tôi nảy sinh một câu hỏi đơn giản nào đó."},{"t":"example","text":"Giải thích: Возникает (số ít) → некий (một... nào đó)."}]},{"id":"03-s053","type":"exercise","title":"Bài 367 (Trang 178) - Đại từ КАЖДЫЙ, ЛЮБОЙ, ВСЯКИЙ","num":367,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 178):","b":1},{"t":"vocab","ru":"Ка́ждый (Mỗi/Mọi)","vi":"Mang ý nghĩa \"từng cái một trong một dãy các vật thể đồng nhất\", \"lần lượt\". Nhấn mạnh tính cá thể, không bỏ sót ai/cái gì.","g":null},{"t":"vocab","ru":"Любо́й (Bất kỳ)","vi":"Mang ý nghĩa \"tùy chọn\", \"cái nào cũng được\". Thường dùng khi có sự lựa chọn.","g":null},{"t":"vocab","ru":"Вся́кий (Mọi/Đủ loại)","vi":"Mang ý nghĩa \"khác nhau\", \"đa dạng\" (giống tính từ ра́зный, разнообра́зный). Đôi khi dùng đồng nghĩa với каждый hoặc любой nhưng mang sắc thái khái quát hơn.","g":null},{"t":"para","text":"Đề bài: Đọc các câu văn. Xác định ý nghĩa của các đại từ."},{"t":"para","text":"a)","b":1},{"t":"para","text":"Снима́й с по́лки по о́череди ка́ждую кни́гу и запи́сывай её да́нные в картоте́ку.","b":1},{"t":"example","text":"Dịch: Hãy lấy từng cuốn sách một trên kệ xuống và ghi dữ liệu của nó vào tủ phiếu."},{"t":"example","text":"Ý nghĩa: Ка́ждую = Từng cuốn một, lần lượt, không bỏ sót (Distributive)."},{"t":"para","text":"Ты мо́жешь взять любу́ю кни́гу, кото́рая тебе́ понра́вится.","b":1},{"t":"example","text":"Dịch: Bạn có thể lấy bất kỳ cuốn sách nào mà bạn thích."},{"t":"example","text":"Ý nghĩa: Любу́ю = Tùy chọn (Choice)."},{"t":"vocab","ru":"С собо́й я взял вся́кие словари́","vi":"не зна́ю, что мне пона́добится в ближа́йшее вре́мя.","g":null},{"t":"example","text":"Dịch: Tôi đã mang theo đủ loại từ điển: không biết sắp tới tôi sẽ cần cái nào."},{"t":"example","text":"Ý nghĩa: Вся́кие = Các loại khác nhau (разные)."},{"t":"para","text":"б)","b":1},{"t":"para","text":"Он вздра́гивал при ка́ждом зву́ке. (Anh ấy giật mình với mỗi/từng tiếng động). → Mọi tiếng động xảy ra (lần lượt)."},{"t":"para","text":"Он вздра́гивал при лю́бом зву́ке, доноси́вшемся из са́да. (Anh ấy giật mình với bất kỳ tiếng động nào vọng ra từ vườn). → Tiếng động nào cũng gây ra phản ứng (như nhau)."},{"t":"para","text":"Он вздра́гивал при вся́ком зву́ке. (Anh ấy giật mình với mọi tiếng động). → Tiếng động đủ loại."},{"t":"para","text":"в)","b":1},{"t":"para","text":"Вы мо́жете прийти́ ко мне в любо́е вре́мя. (Bạn có thể đến chỗ tôi vào bất cứ lúc nào). → Tùy bạn chọn."},{"t":"para","text":"Ка́ждый раз, когда́ я вспомина́ю об э́том, мне стано́вится не по себе́. (Mỗi lần tôi nhớ về điều đó, tôi lại thấy khó chịu). → Lặp đi lặp lại."},{"t":"para","text":"Ка́ждую мину́ту (в любу́ю мину́ту) он мо́жет позвони́ть. (Mỗi phút / Bất cứ phút nào cậu ấy cũng có thể gọi). → Tính liên tục hoặc khả năng xảy ra ở bất kỳ thời điểm nào."}]},{"id":"03-s054","type":"exercise","title":"Bài 368 (Trang 179)","num":368,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung):","b":1},{"t":"vocab","ru":"Ка́ждый","vi":"Một trong dãy các đối tượng giống nhau, lấy theo thứ tự.","g":null},{"t":"vocab","ru":"Любо́й","vi":"Dùng khi có sự lựa chọn tùy ý (на вы́бор).","g":null},{"t":"vocab","ru":"Вся́кий","vi":"Đồng nghĩa với ра́зный, разнообра́зный (khác nhau, đa dạng).","g":null},{"t":"example","text":"Đề bài: Điền vào chỗ trống ка́ждый, любо́й, вся́кий phù hợp."},{"t":"para","text":"Ты мо́жешь обраща́ться ко мне в (во) ... слу́чае. В ... слу́чае на́до разбира́ться отде́льно. Он знал ... слу́чаи из жи́зни знамени́тых люде́й и с удово́льствием нам их расска́зывал.","b":1},{"t":"para","text":"Điền: любо́м ... ка́ждом ... вся́кие"},{"t":"example","text":"Dịch: Bạn có thể tìm tôi trong bất cứ trường hợp nào (dù thế nào đi nữa). Trong mỗi trường hợp cần phải xem xét riêng biệt. Ông ấy biết đủ loại trường hợp (câu chuyện) từ cuộc đời của những người nổi tiếng và kể cho chúng tôi nghe với sự thích thú."},{"t":"example","text":"Giải thích:"},{"t":"example","text":"В любом случае = Bất luận thế nào."},{"t":"example","text":"В каждом случае = Xét từng cái riêng biệt (отдельно)."},{"t":"example","text":"Всякие случаи = Các loại chuyện khác nhau (разные)."},{"t":"para","text":"Ему́ прихо́дилось подо́лгу разбира́ться с (со) ... пробле́мой, возника́ющей в рабо́те ста́нции. ... пробле́му мо́жно реши́ть, е́сли хорошо́ поду́мать. Несмотря́ на то что в рабо́те постоя́нно возника́ли ... пробле́мы, мы сдава́ли её в срок.","b":1},{"t":"para","text":"Điền: ка́ждой ... Любу́ю ... вся́кие"},{"t":"example","text":"Dịch: Anh ấy đã phải mất nhiều thời gian giải quyết từng/mỗi vấn đề nảy sinh trong hoạt động của nhà ga. Bất kỳ vấn đề nào cũng có thể giải quyết nếu suy nghĩ kỹ. Mặc dù trong công việc liên tục nảy sinh đủ loại vấn đề, chúng tôi vẫn nộp đúng hạn."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"С каждой проблемой","vi":"Từng cái một (do подолгу разбираться - mất nhiều thời gian cho từng cái).","g":null},{"t":"vocab","ru":"Любую проблему","vi":"Cái nào cũng được (khả năng giải quyết chung).","g":null},{"t":"vocab","ru":"Всякие проблемы","vi":"Các vấn đề lặt vặt/khác nhau.","g":null},{"t":"para","text":"Он подава́л нам ... зна́ки глаза́ми и рука́ми, но мы не могли́ поня́ть, о чём он хоте́л нас предупреди́ть. В автошко́ле мы подро́бно остана́вливались на назначе́нии ... доро́жного зна́ка. В э́том ме́сте ты мо́жешь поста́вить ... знак препина́ния, всё зави́сит от того́, что ты хо́чешь сказа́ть.","b":1},{"t":"para","text":"Điền: вся́кие ... ка́ждого ... любо́й"},{"t":"example","text":"Dịch: Anh ấy đã ra đủ loại dấu hiệu bằng mắt và tay, nhưng chúng tôi không hiểu anh ấy muốn cảnh báo điều gì. Ở trường lái xe, chúng tôi đã dừng lại kỹ ở công dụng của từng/mỗi biển báo giao thông. Ở chỗ này bạn có thể đặt bất kỳ dấu câu nào, tất cả phụ thuộc vào điều bạn muốn nói."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"Всякие знаки","vi":"Các kiểu dấu hiệu lung tung.","g":null},{"t":"vocab","ru":"Каждого знака","vi":"Từng biển báo một (học kỹ).","g":null},{"t":"vocab","ru":"Любой знак","vi":"Tùy chọn (dấu chấm, phẩy đều được tùy ý).","g":null},{"t":"para","text":"В связи́ со вчера́шнем собы́тием в голове́ у меня́ возника́ли ... иде́и. ... иде́и, кото́рые приду́т вам в го́лову, лу́чше запи́сывать. Дава́й ... твою́ иде́ю прове́рим отде́льно на пра́ктике.","b":1},{"t":"para","text":"Điền: вся́кие ... Любы́е ... ка́ждую"},{"t":"example","text":"Dịch: Liên quan đến sự kiện hôm qua, trong đầu tôi nảy sinh đủ loại ý tưởng. Bất kỳ ý tưởng nào đến trong đầu bạn, tốt nhất nên ghi lại. Hãy cùng kiểm tra từng/mỗi ý tưởng của bạn một cách riêng biệt trong thực tế."}]},{"id":"03-s055","type":"exercise","title":"Bài 369 (Trang 180)","num":369,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 180):","b":1},{"t":"para","text":"Любо́й và вся́кий có nghĩa gần giống nhau (đều chỉ tính chất bao quát)."},{"t":"para","text":"Tuy nhiên:"},{"t":"example","text":"Nếu câu nói về một tập hợp cụ thể, xác định (конкре́тное мно́жество), thì KHÔNG dùng вся́кий. Chỉ dùng ка́ждый hoặc любо́й (nếu có lựa chọn)."},{"t":"example","text":"Ví dụ: За столом мы обсуждали каждое блюдо (Chúng tôi bàn về từng món - đúng). Không nói всякое блюдо (mọi món - nghe không tự nhiên trong ngữ cảnh cụ thể này)."},{"t":"example","text":"Đề bài: Điền любо́й hoặc вся́кий. Giải thích sự lựa chọn."},{"t":"para","text":"Вы мо́жете взять ... кни́гу из мое́й библиоте́ки.","b":1},{"t":"para","text":"Điền: любу́ю","b":1},{"t":"example","text":"Dịch: Bạn có thể lấy bất kỳ cuốn sách nào từ thư viện của tôi. (Sự lựa chọn tùy ý)."},{"t":"para","text":"... кни́га поле́зна.","b":1},{"t":"example","text":"Điền: Вся́кая (hoặc Люба́я)"},{"t":"example","text":"Dịch: Mọi/Bất kỳ cuốn sách nào cũng có ích. (Chân lý chung)."},{"t":"para","text":"... мысль должна́ быть прове́рена на пра́ктике.","b":1},{"t":"example","text":"Điền: Вся́кая (hoặc Люба́я)"},{"t":"example","text":"Dịch: Mọi ý tưởng đều cần được kiểm nghiệm trong thực tế. (Quy luật chung)."},{"t":"para","text":"... его́ мысль подтвержда́ется пра́ктикой.","b":1},{"t":"example","text":"Điền: Вся́кая (hoặc Ка́ждая)"},{"t":"example","text":"Dịch: Mọi ý tưởng của anh ấy đều được thực tế xác nhận. (Nhấn mạnh sự toàn vẹn của các ý tưởng cụ thể của anh ấy)."},{"t":"para","text":"В на́шем теа́тре ста́вят ... спекта́кли, мы не ограни́чиваем себя́ класси́ческими произведе́ниями или пье́сами совреме́нных а́второв.","b":1},{"t":"example","text":"Điền: вся́кие (hoặc любы́е)"},{"t":"example","text":"Dịch: Nhà hát chúng tôi dựng đủ loại vở diễn, chúng tôi không giới hạn mình trong các tác phẩm cổ điển hay hiện đại. (Đa dạng)."},{"t":"para","text":"Вы мо́жете посмотре́ть ... спекта́кли из репертуа́ра на́шего теа́тра.","b":1},{"t":"para","text":"Điền: любы́е","b":1},{"t":"example","text":"Dịch: Các bạn có thể xem bất kỳ vở diễn nào trong danh mục của nhà hát chúng tôi. (Lựa chọn)."},{"t":"para","text":"Вы́бери ... сло́ва из запи́санных на доске́.","b":1},{"t":"para","text":"Điền: любы́е","b":1},{"t":"example","text":"Dịch: Hãy chọn bất kỳ từ nào trong số những từ được viết trên bảng. (Lựa chọn từ một nhóm cụ thể)."},{"t":"para","text":"... сло́во должно́ быть произнесено́ во́время.","b":1},{"t":"example","text":"Điền: Вся́кое (hoặc Любо́е)"},{"t":"example","text":"Dịch: Mọi lời nói cần phải được nói ra đúng lúc."}]},{"id":"03-s056","type":"exercise","title":"Bài 370 (Trang 180)","num":370,"blocks":[{"t":"example","text":"Đề bài: Điền ка́ждый, любо́й hoặc вся́кий."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 180 - dưới cùng):","b":1},{"t":"subhead","text":"Ка́ждый (Mỗi) được dùng:","b":1},{"t":"para","text":"Ở vị trí chủ ngữ với vị ngữ là động từ ở thì quá khứ hoặc hiện tại hoàn thành (để chỉ từng cá nhân thực hiện hành động)."},{"t":"example","text":"Với danh từ số nhiều (khi đi kèm số từ: каждые два дня - cứ mỗi hai ngày)."},{"t":"para","text":"Với danh từ đếm được, nhấn mạnh sự tách biệt."},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"para","text":"Я вспомина́ю об э́том ... раз, когда́ возвраща́юсь в э́тот го́род.","b":1},{"t":"para","text":"Điền: ка́ждый","b":1},{"t":"example","text":"Dịch: Tôi nhớ về điều này mỗi lần tôi trở lại thành phố này. (Lặp lại định kỳ)."},{"t":"para","text":"Он постоя́нно обраща́ется ко мне с (со) ... свои́ми пробле́мами.","b":1},{"t":"example","text":"Điền: вся́кими (hoặc со все́ми)"},{"t":"example","text":"Dịch: Anh ấy thường xuyên tìm đến tôi với đủ loại vấn đề của mình."},{"t":"para","text":"... пра́вило нужда́ется в коммента́риях.","b":1},{"t":"example","text":"Điền: Ка́ждое (hoặc Любо́е/Вся́кое)"},{"t":"example","text":"Dịch: Mỗi/Bất kỳ quy tắc nào cũng cần có lời bình giải. (Thường dùng Каждое để nhấn mạnh sự cụ thể hóa từng quy tắc)."},{"t":"para","text":"... день приноси́л с собо́й но́вые неожи́данности.","b":1},{"t":"para","text":"Điền: Ка́ждый","b":1},{"t":"example","text":"Dịch: Mỗi ngày lại mang đến những bất ngờ mới. (Tiến trình thời gian)."},{"t":"para","text":"При ... результа́те я оста́нусь в вы́игрыше.","b":1},{"t":"para","text":"Điền: любо́м","b":1},{"t":"example","text":"Dịch: Với bất kỳ kết quả nào, tôi cũng sẽ là người có lợi. (Điều kiện tùy ý)."},{"t":"para","text":"Ты мо́жешь купи́ть биле́т на ... ближа́йший рейс.","b":1},{"t":"para","text":"Điền: любо́й","b":1},{"t":"example","text":"Dịch: Bạn có thể mua vé cho bất kỳ chuyến bay gần nhất nào. (Lựa chọn)."},{"t":"para","text":"Он остана́вливался на ... этаже́ и отдыха́л.","b":1},{"t":"para","text":"Điền: ка́ждом","b":1},{"t":"example","text":"Dịch: Anh ấy dừng lại ở mỗi/từng tầng và nghỉ ngơi. (Lần lượt)."},{"t":"para","text":"... сообще́ние доходи́ло до нас с опозда́нием на неде́лю.","b":1},{"t":"para","text":"Điền: Ка́ждое","b":1},{"t":"example","text":"Dịch: Mỗi tin nhắn đều đến với chúng tôi trễ một tuần."},{"t":"para","text":"Он переска́зывал мне по не́скольку раз ... слу́чай, кото́рый происходи́л с ним на охо́те.","b":1},{"t":"para","text":"Điền: ка́ждый","b":1},{"t":"example","text":"Dịch: Anh ấy kể đi kể lại cho tôi nghe từng/mỗi sự việc xảy ra với anh ấy trong lúc đi săn."},{"t":"para","text":"Позвони́ мне в (во) ... день, когда́ вернёшься от о́тпуска.","b":1},{"t":"para","text":"Điền: любо́й","b":1},{"t":"example","text":"Dịch: Hãy gọi cho tôi vào bất kỳ ngày nào khi bạn đi nghỉ về."},{"t":"para","text":"Мы проверя́ем показа́ния прибо́ра ... су́тки.","b":1},{"t":"para","text":"Điền: ка́ждые","b":1},{"t":"example","text":"Dịch: Chúng tôi kiểm tra chỉ số thiết bị mỗi ngày đêm (cứ 24h một lần). Сутки là danh từ số nhiều → каждые."},{"t":"para","text":"Э́то слу́чай осо́бый, и ... сравне́ния здесь неуме́стны.","b":1},{"t":"example","text":"Điền: вся́кие (hoặc любы́е)"},{"t":"example","text":"Dịch: Đây là trường hợp đặc biệt, và mọi/bất kỳ sự so sánh nào ở đây đều không phù hợp."},{"t":"para","text":"Она́ расстра́ивается по ... по́воду.","b":1},{"t":"example","text":"Điền: любо́му (hoặc вся́кому)"},{"t":"example","text":"Dịch: Cô ấy buồn phiền vì bất cứ lý do gì (hơi tí là buồn)."},{"t":"para","text":"Нет, я никуда́ не уходи́, ты мо́жешь в (во) ... мину́ту ему́ пона́добиться.","b":1},{"t":"para","text":"Điền: любу́ю","b":1},{"t":"example","text":"Dịch: Không, đừng đi đâu cả, cậu có thể được ông ấy cần đến vào bất cứ phút nào."},{"t":"para","text":"Никуда́ не уходи́, ты мо́жешь в (во) ... мину́ту ему́ пона́добиться. (Câu này lặp lại câu 14)."},{"t":"para","text":"С ... днём больно́му станови́лось всё ху́же.","b":1},{"t":"para","text":"Điền: ка́ждым","b":1},{"t":"example","text":"Dịch: Cứ mỗi ngày (qua từng ngày), bệnh nhân lại trở nên tồi tệ hơn."},{"t":"para","text":"Он руга́л меня́ за ... самостоя́тельное, не согласо́ванное с ним реше́ние.","b":1},{"t":"example","text":"Điền: ка́ждое (hoặc любо́е)"},{"t":"example","text":"Dịch: Ông ấy mắng tôi vì mỗi/bất kỳ quyết định độc lập nào không được thống nhất với ông ấy."},{"t":"para","text":"Мы пое́дем за́ город при ... пого́де.","b":1},{"t":"para","text":"Điền: любо́й","b":1},{"t":"example","text":"Dịch: Chúng tôi sẽ đi ra ngoại ô trong bất kỳ thời tiết nào."},{"t":"para","text":"На ... твой аргуме́нт всегда́ мо́жно найти́ контраргуме́нт.","b":1},{"t":"example","text":"Điền: любо́й (hoặc ка́ждый)"},{"t":"example","text":"Dịch: Với bất kỳ lập luận nào của bạn cũng luôn có thể tìm thấy phản biện."},{"t":"para","text":"В (Во) ... вре́мя го́да я бе́гаю по утра́м по па́рку.","b":1},{"t":"example","text":"Điền: вся́кое (hoặc любо́е)"},{"t":"example","text":"Dịch: Vào mọi/bất kỳ thời điểm nào trong năm (mùa nào cũng vậy), tôi đều chạy bộ buổi sáng trong công viên."}]},{"id":"03-s057","type":"exercise","title":"Bài 371 (Trang 181)","num":371,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 181):","b":1},{"t":"subhead","text":"Trong các cấu trúc phủ định (Отрица́тельные констру́кции):","b":1},{"t":"para","text":"Khi đi kèm với các động từ mang ý nghĩa \"mất mát, tước bỏ\" như лиши́ть (tước bỏ), утра́тить (đánh mất), потеря́ть (làm mất) hoặc các danh từ trừu tượng."},{"t":"para","text":"Đại từ вся́кий (mọi/bất cứ) được sử dụng để nhấn mạnh ý nghĩa phủ định (mang nghĩa \"hoàn toàn không có\", \"không có bất cứ cái gì\")."},{"t":"note","text":"Lưu ý: Cần chia đại từ всякий cùng cách (case) với danh từ nó đi kèm."},{"t":"example","text":"Đề bài: Hoàn thành câu, sử dụng đại từ вся́кий ở dạng cần thiết. Mẫu: Он э́то сде́лал без уси́лий. (Anh ấy làm điều đó không tốn sức). → Он э́то сде́лал без вся́ких уси́лий. (Anh ấy làm điều đó không tốn bất kỳ công sức nào)."},{"t":"para","text":"Я гуля́л по го́роду без це́ли.","b":1},{"t":"para","text":"Viết lại: Я гуля́л по го́роду без вся́кой це́ли."},{"t":"para","text":"Dịch: Tôi đã đi dạo quanh thành phố mà không có bất cứ mục đích nào."},{"t":"example","text":"Giải thích: Цели (giống cái, Cách 2 số ít sau giới từ без) → всякой."},{"t":"para","text":"Не обраща́йся ко мне с чепухо́й, у меня́ совсе́м нет вре́мени.","b":1},{"t":"para","text":"Viết lại: Не обраща́йся ко мне со вся́кой чепухо́й..."},{"t":"para","text":"Dịch: Đừng tìm tôi với mấy chuyện vớ vẩn linh tinh, tôi hoàn toàn không có thời gian đâu."},{"t":"example","text":"Giải thích: Чепухой (giống cái, Cách 5 sau giới từ с) → всякой."},{"t":"para","text":"На пе́рвый взгля́д, он э́то сде́лал без причи́н.","b":1},{"t":"para","text":"Viết lại: На пе́рвый взгля́д, он э́то сде́лал без вся́ких причи́н."},{"t":"para","text":"Dịch: Thoạt nhìn, anh ấy đã làm điều đó mà không có bất kỳ lý do nào."},{"t":"example","text":"Giải thích: Причин (số nhiều, Cách 2) → всяких."},{"t":"para","text":"В его́ голове́ постоя́нно возника́ют иде́и.","b":1},{"t":"para","text":"Viết lại: В его́ голове́ постоя́нно возника́ют вся́кие иде́и."},{"t":"para","text":"Dịch: Trong đầu anh ấy liên tục nảy sinh đủ loại ý tưởng."},{"t":"example","text":"Giải thích: Идеи (số nhiều, Cách 1 - chủ ngữ) → всякие."},{"t":"para","text":"Э́та фра́за лишена́ смы́сла.","b":1},{"t":"para","text":"Viết lại: Э́та фра́за лишена́ вся́кого смы́сла."},{"t":"para","text":"Dịch: Câu nói này hoàn toàn vô nghĩa (thiếu vắng mọi ý nghĩa)."},{"t":"example","text":"Giải thích: Смысла (giống đực, Cách 2) → всякого."},{"t":"para","text":"Ду́маю, мы без пробле́м реши́м э́тот вопро́с.","b":1},{"t":"para","text":"Viết lại: Ду́маю, мы без вся́ких пробле́м реши́м э́тот вопро́с."},{"t":"para","text":"Dịch: Tôi nghĩ chúng ta sẽ giải quyết vấn đề này mà không gặp bất cứ trở ngại nào."},{"t":"example","text":"Giải thích: Проблем (số nhiều, Cách 2) → всяких."},{"t":"para","text":"В э́том де́ле возни́кли обстоя́тельства, о кото́рых я не хоте́л бы сейча́с говори́ть.","b":1},{"t":"para","text":"Viết lại: В э́том де́ле возни́кли вся́кие обстоя́тельства..."},{"t":"para","text":"Dịch: Trong vụ việc này đã nảy sinh đủ loại tình huống mà tôi không muốn nói đến bây giờ."},{"t":"example","text":"Giải thích: Обстоятельства (số nhiều, Cách 1) → всякие."},{"t":"para","text":"Я загля́нул к тебе́ про́сто так, без по́вода.","b":1},{"t":"para","text":"Viết lại: Я загля́нул к тебе́ про́сто так, без вся́кого по́вода."},{"t":"para","text":"Dịch: Tôi ghé qua chỗ bạn chỉ vậy thôi, không có lý do đặc biệt nào cả."},{"t":"example","text":"Giải thích: Повода (giống đực, Cách 2) → всякого."},{"t":"para","text":"Он переска́зывал э́ту исто́рию до́лго, с подро́бностями, не пропуска́я ничего́ из улы́шанного.","b":1},{"t":"para","text":"Viết lại: Он переска́зывал э́ту исто́рию до́лго, со вся́кими подро́бностями..."},{"t":"para","text":"Dịch: Anh ấy kể lại câu chuyện này rất lâu, với đủ loại chi tiết, không bỏ sót điều gì đã nghe được."},{"t":"example","text":"Giải thích: Подробностями (số nhiều, Cách 5) → всякими."},{"t":"para","text":"Без обяза́тельств с его́ стороны́ тру́дно бу́дет с ним рабо́тать.","b":1},{"t":"para","text":"Viết lại: Без вся́ких обяза́тельств с его́ стороны́..."},{"t":"para","text":"Dịch: Nếu không có bất kỳ cam kết nào từ phía anh ấy, sẽ rất khó làm việc cùng."},{"t":"example","text":"Giải thích: Обязательств (số nhiều, Cách 2) → всяких."},{"t":"para","text":"Со вре́менем я утра́тил интере́с к э́тому де́лу.","b":1},{"t":"para","text":"Viết lại: Со вре́менем я утра́тил вся́кий интере́с к э́тому де́лу."},{"t":"para","text":"Dịch: Theo thời gian, tôi đã đánh mất mọi hứng thú với việc này."},{"t":"example","text":"Giải thích: Интерес (giống đực, Cách 4 - bất động vật) → всякий."}]},{"id":"03-s058","type":"exercise","title":"Bài 372 (Trang 181)","num":372,"blocks":[{"t":"para","text":"Đề bài: Hoàn thành câu, sử dụng đại từ вся́кий hoặc đại từ phủ định никако́й. Giải thích sự lựa chọn."},{"t":"subhead","text":"Quy tắc phân biệt:","b":1},{"t":"vocab","ru":"Dùng Никако́й (không ... nào cả)","vi":"Khi trong câu đã có từ phủ định не hoặc нет (cấu trúc phủ định kép).","g":null},{"t":"vocab","ru":"Dùng Вся́кий (mọi/bất kỳ)","vi":"Khi đi với các từ mang nghĩa tước bỏ/mất mát (лишиться, потерять, утратить) mà không có từ не, hoặc để nhấn mạnh ý \"tất cả mọi loại\" trong câu khẳng định.","g":null},{"t":"para","text":"Э́то не име́ет для меня́ (никако́го) значе́ния.","b":1},{"t":"para","text":"Dịch: Điều này chẳng có ý nghĩa gì đối với tôi."},{"t":"example","text":"Giải thích: Có từ не → dùng никакого."},{"t":"para","text":"Э́то утра́тило для меня́ (вся́кий) смысл.","b":1},{"t":"para","text":"Dịch: Điều này đã mất đi mọi ý nghĩa đối với tôi."},{"t":"example","text":"Giải thích: Động từ утратило (mất) + không có не → dùng всякий."},{"t":"para","text":"Мы не располага́ем (никаки́ми) све́дениями об э́том корабле́.","b":1},{"t":"para","text":"Dịch: Chúng tôi không nắm được thông tin nào về con tàu này."},{"t":"example","text":"Giải thích: Có từ не → dùng никакими."},{"t":"para","text":"Мы потеря́ли (вся́кую) возмо́жность обща́ться с ни́ми.","b":1},{"t":"para","text":"Dịch: Chúng tôi đã đánh mất mọi cơ hội giao tiếp với họ."},{"t":"example","text":"Giải thích: Động từ потеряли (mất) → dùng всякую."},{"t":"para","text":"У него́ нет (никако́й) специа́льности.","b":1},{"t":"para","text":"Dịch: Anh ấy không có chuyên môn nào cả."},{"t":"example","text":"Giải thích: Có từ нет → dùng никакой."},{"t":"para","text":"По́сле э́того посту́пка он лиши́лся (вся́кого) дове́рия со стороны́ друзе́й.","b":1},{"t":"para","text":"Dịch: Sau hành động này, anh ấy đã đánh mất mọi niềm tin từ phía bạn bè."},{"t":"example","text":"Giải thích: Động từ лишился (bị tước mất) → dùng всякого."},{"t":"para","text":"В на́шем го́роде он не владе́ет (никако́й) со́бственностью.","b":1},{"t":"para","text":"Dịch: Ở thành phố chúng tôi, ông ấy không sở hữu tài sản nào."},{"t":"example","text":"Giải thích: Có từ не → dùng никакой."},{"t":"para","text":"Он давно́ потеря́л (вся́кую) наде́жду найти́ своего́ бра́та.","b":1},{"t":"para","text":"Dịch: Anh ấy đã mất mọi hy vọng tìm thấy anh trai mình từ lâu."},{"t":"example","text":"Giải thích: Động từ потерял → dùng всякую."},{"t":"para","text":"У него́ не́ было (никаки́х) прав на насле́дство.","b":1},{"t":"para","text":"Dịch: Anh ấy đã không có quyền nào đối với di sản thừa kế."},{"t":"example","text":"Giải thích: Có từ не было → dùng никаких."},{"t":"para","text":"Во мне не оста́лось (никако́го) жела́ния продолжа́ть э́ту рабо́ту.","b":1},{"t":"para","text":"Dịch: Trong tôi không còn lại chút mong muốn nào để tiếp tục công việc này."},{"t":"example","text":"Giải thích: Có từ не → dùng никакого."},{"t":"para","text":"Разгова́ривая с тобо́й, мо́жно потеря́ть (вся́кое) терпе́ние.","b":1},{"t":"para","text":"Dịch: Nói chuyện với bạn có thể làm người ta mất hết (mọi) kiên nhẫn."},{"t":"example","text":"Giải thích: Động từ потерять → dùng всякое."},{"t":"para","text":"Она́ не облада́ла (никаки́ми) осо́быми досто́инствами.","b":1},{"t":"para","text":"Dịch: Cô ấy không sở hữu phẩm chất đặc biệt nào."},{"t":"example","text":"Giải thích: Có từ не → dùng никакими."},{"t":"para","text":"Полага́ясь всё вре́мя на мне́ние други́х, мо́жно утра́тить (вся́кую) спосо́бность ду́мать самостоя́тельно.","b":1},{"t":"para","text":"Dịch: Cứ dựa dẫm mãi vào ý kiến người khác, có thể đánh mất mọi khả năng tư duy độc lập."},{"t":"example","text":"Giải thích: Động từ утратить → dùng всякую."},{"t":"para","text":"В настоя́щее вре́мя я не име́ю (никако́й) возмо́жности вы́полнить ва́ше поруче́ние.","b":1},{"t":"para","text":"Dịch: Hiện tại tôi không có khả năng nào để thực hiện ủy thác của ngài."},{"t":"example","text":"Giải thích: Có từ не → dùng никакой."},{"t":"para","text":"На́до оста́вить (вся́кие) попы́тки разреши́ть э́тот конфли́кт с по́мощью вое́нной си́лы.","b":1},{"t":"para","text":"Dịch: Cần phải từ bỏ mọi nỗ lực giải quyết xung đột này bằng vũ lực."},{"t":"example","text":"Giải thích: Оставить (từ bỏ/để lại) mang hàm ý tước bỏ trong ngữ cảnh này → dùng всякие."}]},{"id":"03-s059","type":"exercise","title":"Bài 373 (Trang 182)","num":373,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 182):","b":1},{"t":"vocab","ru":"Ка́ждый (Mỗi)","vi":"Nhấn mạnh sự tách biệt từng cá thể trong nhóm.","g":null},{"t":"vocab","ru":"Любо́й (Bất kỳ)","vi":"Nhấn mạnh sự tùy chọn, tự do lựa chọn.","g":null},{"t":"vocab","ru":"Вся́кий (Mọi/Kẻ nào đó)","vi":"Thường dùng khi không có danh từ đi kèm (đại từ hóa), mang nghĩa \"bất cứ ai\", \"mọi người\".","g":null},{"t":"subhead","text":"Cấu trúc: Каждый (любой, всякий) из нас (Mỗi/Bất cứ ai trong chúng ta)."},{"t":"example","text":"Đề bài: Sử dụng mọi biến thể có thể (каждый, любой, всякий) để điền vào chỗ trống. Mẫu: Ка́ждый жи́тель зна́ет об э́том. (Mỗi người dân đều biết). Ка́ждый из нас зна́ет об э́том. (Mỗi người trong chúng ta đều biết). Ка́ждый зна́ет об э́том. (Ai cũng biết)."},{"t":"para","text":"(Ка́ждому / Любо́му / Вся́кому) иссле́дователю пришло́сь столкну́ться с э́тими пробле́мами."},{"t":"example","text":"Viết lại (dạng rút gọn): Ка́ждому (hoặc Любо́му, Вся́кому) пришло́сь столкну́ться..."},{"t":"para","text":"Dịch: Mỗi / Bất kỳ / Mọi nhà nghiên cứu đều phải đối mặt với những vấn đề này. (Ai cũng phải đối mặt...)."},{"t":"para","text":"Он поздоро́вался с (ка́ждым / любы́м / вся́ким) прису́тствующим."},{"t":"example","text":"Viết lại: Он поздоро́вался с ка́ждым (hoặc любы́м, вся́ким)."},{"t":"para","text":"Dịch: Anh ấy chào hỏi từng / bất kỳ / mọi người có mặt. (Anh ấy chào từng người)."},{"t":"para","text":"Без (любо́го / ка́ждого) сотру́дника наш коллекти́в не смо́жет да́льше рабо́тать."},{"t":"example","text":"Viết lại: Без ка́ждого (hoặc любо́го)..."},{"t":"para","text":"Dịch: Thiếu vắng bất kỳ / mỗi nhân viên nào, tập thể chúng ta cũng không thể làm việc tiếp. (Thiếu bất cứ ai...)."},{"t":"para","text":"(Ка́ждому / Вся́кому / Любо́му) спортсме́ну ну́жен о́тдых."},{"t":"example","text":"Viết lại: Вся́кому (hoặc Ка́ждому, Любо́му)..."},{"t":"para","text":"Dịch: Mọi / Mỗi / Bất kỳ vận động viên nào cũng cần nghỉ ngơi. (Ai cũng cần nghỉ...)."},{"t":"para","text":"Со (вся́ким / любы́м / ка́ждым) челове́ком э́то мо́жет случи́ться."},{"t":"example","text":"Viết lại: Со вся́ким (hoặc любы́м, ка́ждым)..."},{"t":"para","text":"Dịch: Điều này có thể xảy ra với mọi / bất kỳ người nào. (Với bất cứ ai)."},{"t":"para","text":"(Любо́й / Ка́ждый / Вся́кий) отдыха́ющий знако́м с э́тими пра́вилами."},{"t":"example","text":"Viết lại: Любо́й (hoặc Ка́ждый, Вся́кий)..."},{"t":"para","text":"Dịch: Bất kỳ người đi nghỉ nào cũng biết quy định này. (Ai cũng biết...)."},{"t":"para","text":"(Ка́ждый / Любо́й) посети́тель мо́жет оста́вить за́пись в кни́ге о́тзывов."},{"t":"example","text":"Viết lại: Ка́ждый (hoặc Любо́й)..."},{"t":"para","text":"Dịch: Mỗi / Bất kỳ khách tham quan nào cũng có thể để lại lưu bút. (Ai cũng có thể...)."},{"t":"para","text":"Об э́том вариа́нте зна́ет (вся́кий / ка́ждый / любо́й) игро́к в ша́хматы."},{"t":"example","text":"Viết lại: ...зна́ет вся́кий (hoặc ка́ждый, любо́й)."},{"t":"para","text":"Dịch: Mọi người chơi cờ vua đều biết về biến thể này. (Ai cũng biết)."},{"t":"para","text":"Он обраща́лся с одни́м и тем же вопро́сом к (ка́ждому / любо́му) входя́щему."},{"t":"example","text":"Viết lại: ...к ка́ждому (hoặc любо́му)."},{"t":"para","text":"Dịch: Anh ấy hỏi cùng một câu hỏi với mỗi người bước vào. (Với từng người)."},{"t":"para","text":"За ве́чер она́ успе́ла всех обойти́ и (ка́ждому / любо́му) го́стю сказа́ть что́-нибудь прия́тное."},{"t":"example","text":"Viết lại: ...и ка́ждому (hoặc любо́му) сказа́ть..."},{"t":"para","text":"Dịch: Trong buổi tối cô ấy đã kịp đi một vòng và nói điều gì đó dễ chịu với từng / bất kỳ vị khách nào. (Với mọi người)."},{"t":"para","text":"У (ка́ждого / любо́го) подозрева́емого бы́ли свой причи́ны не отвеча́ть на вопро́сы."},{"t":"example","text":"Viết lại: У ка́ждого (hoặc любо́го)..."},{"t":"para","text":"Dịch: Mỗi nghi phạm đều có lý do riêng để không trả lời câu hỏi. (Ai cũng có lý do...)."}]},{"id":"03-s060","type":"exercise","title":"Bài 374 (Trang 182)","num":374,"blocks":[{"t":"para","text":"Đề bài: Sử dụng cấu trúc với giới từ \"из\" (trong số) ở đâu có thể. Đưa ra các phương án đồng nghĩa."},{"t":"para","text":"Он поздоро́вался с ка́ждым студе́нтом на́шей гру́ппы.","b":1},{"t":"para","text":"Viết lại: Он поздоро́вался с ка́ждым из студе́нтов на́шей гру́ппы."},{"t":"para","text":"Dịch: Anh ấy chào hỏi từng người trong số sinh viên của nhóm chúng tôi."},{"t":"para","text":"Любо́й рассмо́тренный вариа́нт мо́жет быть применён на пра́ктике.","b":1},{"t":"para","text":"Viết lại: Любо́й из рассмо́тренных вариа́нтов..."},{"t":"para","text":"Dịch: Bất kỳ phương án nào trong số các phương án đã xem xét đều có thể áp dụng vào thực tế."},{"t":"para","text":"На́до быть гото́вым ко вся́ким неожи́данностям.","b":1},{"t":"note","text":"Lưu ý: Không dùng из được vì всякие ở đây nghĩa là \"đủ loại/các kiểu\" (tính từ chỉ phẩm chất/loại hình), không phải trích xuất từ một tập hợp đếm được."},{"t":"para","text":"Dịch: Cần phải chuẩn bị sẵn sàng cho mọi loại bất ngờ."},{"t":"para","text":"При любо́м раскла́де мы ничего́ не потеря́ем.","b":1},{"t":"note","text":"Lưu ý: При любом раскладе là thành ngữ (dù tình thế nào đi nữa). Không dùng из."},{"t":"para","text":"Dịch: Dù trong bất kỳ tình huống nào (dù thế nào đi nữa), chúng ta cũng không mất gì."},{"t":"para","text":"Э́то мо́жет произойти́ в любу́ю мину́ту.","b":1},{"t":"note","text":"Lưu ý: Chỉ thời gian, không tách из."},{"t":"para","text":"Dịch: Điều này có thể xảy ra vào bất kỳ phút nào."},{"t":"para","text":"Я могу́ э́то повтори́ть при любо́м ва́шем знако́мом.","b":1},{"t":"para","text":"Viết lại: ...при любо́м из ва́ших знако́мых."},{"t":"para","text":"Dịch: Tôi có thể nhắc lại điều này trước mặt bất kỳ ai trong số người quen của bạn."},{"t":"para","text":"Для кома́нды представля́ется ва́жным ка́ждое соревнова́ние.","b":1},{"t":"para","text":"Viết lại: ...ка́ждое из соревнова́ний."},{"t":"para","text":"Dịch: Đối với đội, từng cuộc thi trong số các cuộc thi đều quan trọng."},{"t":"para","text":"Любо́й прису́тствующий мо́жет прове́рить мой слова́.","b":1},{"t":"para","text":"Viết lại: Любо́й из прису́тствующих..."},{"t":"para","text":"Dịch: Bất kỳ ai trong số những người có mặt đều có thể kiểm chứng lời tôi nói."},{"t":"para","text":"Ты мо́жешь звони́ть мне при ка́ждом удо́бном слу́чае.","b":1},{"t":"note","text":"Lưu ý: Thành ngữ при каждом удобном случае (bất cứ khi nào có dịp). Không dùng из."},{"t":"para","text":"Dịch: Bạn có thể gọi tôi vào mọi dịp thuận tiện."},{"t":"para","text":"Ка́ждый из нас досто́ин того́, что́бы его́ напеча́тали в журна́ле.","b":1},{"t":"note","text":"Lưu ý: Câu gốc đã có из."},{"t":"para","text":"Dịch: Mỗi người trong số chúng ta đều xứng đáng được đăng bài trên tạp chí."},{"t":"para","text":"Он вника́л во вся́кую ме́лочь.","b":1},{"t":"note","text":"Lưu ý: Всякую ở đây nghĩa là \"bất cứ thứ nhỏ nhặt nào\", không trích xuất từ tập hợp xác định. Không dùng из."},{"t":"para","text":"Dịch: Anh ấy đi sâu vào từng chi tiết nhỏ."},{"t":"para","text":"Он выдвига́л вся́кие аргуме́нты в свою́ защи́ту.","b":1},{"t":"note","text":"Lưu ý: Всякие = đủ loại/khác nhau. Không dùng из."},{"t":"para","text":"Dịch: Anh ấy đưa ra đủ loại lập luận để bảo vệ mình."},{"t":"para","text":"Ка́ждая его́ фра́за надо́лго вреза́лась в мою́ па́мять.","b":1},{"t":"para","text":"Viết lại: Ка́ждая из его́ фраз..."},{"t":"para","text":"Dịch: Mỗi câu trong số những câu nói của anh ấy đều khắc sâu vào trí nhớ tôi rất lâu."},{"t":"para","text":"Он мо́жет горди́ться ка́ждым свои́м выступле́нием.","b":1},{"t":"para","text":"Viết lại: ...ка́ждым из свои́х выступле́ний."},{"t":"para","text":"Dịch: Anh ấy có thể tự hào về từng buổi biểu diễn trong số các buổi diễn của mình."},{"t":"para","text":"Ка́ждую весну́ мы уезжа́ем из го́рода.","b":1},{"t":"note","text":"Lưu ý: Thời gian lặp lại. Không dùng из."},{"t":"para","text":"Dịch: Mỗi mùa xuân chúng tôi đều rời khỏi thành phố."},{"t":"para","text":"Любо́й шаг вперёд в э́тих сло́жных усло́виях заслу́живает уваже́ния.","b":1},{"t":"para","text":"Viết lại: Любо́й из шаго́в вперёд... (Có thể dùng nhưng hơi nặng nề)."},{"t":"para","text":"Dịch: Bất kỳ bước tiến nào trong những điều kiện khó khăn này đều đáng được tôn trọng."},{"t":"para","text":"Мне ка́жется, в тако́й ситуа́ции вся́кие разгово́ры о справедли́вости неуме́стны.","b":1},{"t":"note","text":"Lưu ý: Всякие = bất cứ loại nào. Không dùng из."},{"t":"para","text":"Dịch: Tôi thấy trong tình huống này mọi cuộc nói chuyện về công lý đều không phù hợp."}]},{"id":"03-s061","type":"exercise","title":"Bài 375 (Trang 183)","num":375,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 183):","b":1},{"t":"subhead","text":"Cấu trúc Ка́ждый (любо́й, вся́кий) + из + Danh từ bất động vật (ở cách 2) được dùng đồng nghĩa với đại từ вся́кий mang nghĩa \"khác nhau/đủ loại\" (ра́зный) hoặc trong các cụm từ chỉ thời gian."},{"t":"para","text":"Đề bài: Điền ка́ждый, любо́й, вся́кий vào chỗ trống. Giải thích sự lựa chọn."},{"t":"para","text":"С (Со) (любы́ми / вся́кими) тру́дностями мы смо́жем спра́виться.","b":1},{"t":"para","text":"Dịch: Chúng ta sẽ có thể giải quyết được bất kỳ / mọi khó khăn nào."},{"t":"para","text":"Giải thích: Ý nghĩa \"bất kể khó khăn gì\"."},{"t":"para","text":"... (Ка́ждый) случа́й до́лжен быть рассмо́трен отде́льно.","b":1},{"t":"para","text":"Dịch: Mỗi trường hợp cần được xem xét riêng biệt."},{"t":"example","text":"Giải thích: Отдельно (riêng biệt) đòi hỏi sự tách biệt từng cái → Каждый."},{"t":"para","text":"... (Ка́ждую / Любу́ю) ме́лочь на́до учи́тывать при подгото́вке к соревнова́ниям.","b":1},{"t":"para","text":"Dịch: Cần tính đến từng / bất kỳ chi tiết nhỏ nào khi chuẩn bị thi đấu."},{"t":"para","text":"С (Со) (ка́ждым) днём я всё бо́лее утвержда́лся в пра́вильности сде́ланного мной вы́бора.","b":1},{"t":"para","text":"Dịch: Qua mỗi ngày (ngày càng...), tôi càng khẳng định sự đúng đắn trong lựa chọn của mình."},{"t":"example","text":"Giải thích: Chỉ sự tiến triển theo thời gian → C каждым."},{"t":"para","text":"... (Вся́кие / Любы́е) его́ предложе́ния бу́дут подро́бно рассмо́трены коми́ссией.","b":1},{"t":"para","text":"Dịch: Mọi / Bất kỳ đề xuất nào của anh ấy cũng sẽ được ủy ban xem xét kỹ lưỡng."},{"t":"example","text":"Giải thích: Предложения số nhiều → Любые (bất kỳ cái nào) hoặc Всякие (đủ loại)."},{"t":"para","text":"... (Вся́кому) терпе́нью есть преде́л.","b":1},{"t":"para","text":"Dịch: Sự kiên nhẫn nào cũng có giới hạn (Giọt nước tràn ly)."},{"t":"para","text":"Giải thích: Thành ngữ cố định."},{"t":"para","text":"Я внима́тельно слу́шаю ... (ка́ждое) ва́ше сло́во.","b":1},{"t":"para","text":"Dịch: Tôi chăm chú lắng nghe từng lời của bạn."},{"t":"example","text":"Giải thích: Nhấn mạnh không bỏ sót từ nào → Каждое."},{"t":"para","text":"Пе́редо мной лежа́ли флома́стеры ... (вся́ких / ра́зных) цвето́в и разме́ров.","b":1},{"t":"para","text":"Dịch: Trước mặt tôi là những chiếc bút dạ đủ màu sắc và kích cỡ."},{"t":"example","text":"Giải thích: Chỉ sự đa dạng → Всяких."},{"t":"para","text":"Я могу́ поме́риться си́лами с (со) ... (любы́м) спортсме́ном ва́шей кома́нды.","b":1},{"t":"para","text":"Dịch: Tôi có thể đọ sức với bất kỳ vận động viên nào trong đội bạn."},{"t":"example","text":"Giải thích: Sự lựa chọn tùy ý → Любым."},{"t":"para","text":"... (Ка́ждый) наро́д заслу́живает то прави́тельство, кото́рое име́ет.","b":1},{"t":"para","text":"Dịch: Mỗi dân tộc đều xứng đáng với chính phủ mà họ có."},{"t":"example","text":"Giải thích: Câu danh ngôn → Каждый."},{"t":"para","text":"По́сле э́той их встре́чи она́ потеря́ла к нему́ ... (вся́кий) интере́с.","b":1},{"t":"para","text":"Dịch: Sau cuộc gặp đó, cô ấy đã mất mọi hứng thú với anh ta."},{"t":"example","text":"Giải thích: Потеряла (mất) + danh từ trừu tượng → Всякий."},{"t":"para","text":"Я получа́ю стипе́ндию ... (ка́ждый) ме́сяц.","b":1},{"t":"para","text":"Dịch: Tôi nhận học bổng mỗi tháng."},{"t":"example","text":"Giải thích: Chu kỳ thời gian → Каждый."},{"t":"para","text":"Мне бы́ло не по себе́, но я успока́ивал себя́ ... (вся́кими) рассужде́ниями о по́льзе де́ла...","b":1},{"t":"para","text":"Dịch: Tôi thấy khó chịu, nhưng tôi tự trấn an mình bằng đủ loại lý lẽ về lợi ích công việc..."},{"t":"example","text":"Giải thích: Đa dạng lý lẽ → Всякими."},{"t":"para","text":"Вы мо́жете вы́брать ... (любы́е) два сло́ва из запи́санных на э́том листке́.","b":1},{"t":"para","text":"Dịch: Bạn có thể chọn bất kỳ hai từ nào trong số những từ viết trên tờ giấy này."},{"t":"example","text":"Giải thích: Lựa chọn tùy ý → Любые."},{"t":"para","text":"Он чита́л стихотворе́ние пло́хо, без ... (вся́кого) выраже́ния.","b":1},{"t":"para","text":"Dịch: Anh ấy đọc thơ dở tệ, không có chút biểu cảm nào."},{"t":"example","text":"Giải thích: Без (không có) → Всякого."},{"t":"para","text":"При ... (любо́м / ка́ждом) движе́нии её глаза́ загора́лись.","b":1},{"t":"para","text":"Dịch: Tại mỗi / bất cứ cử động nào, mắt cô ấy lại sáng lên."},{"t":"para","text":"Вы мо́жете откры́ть ... (любу́ю) страни́цу и нача́ть чита́ть.","b":1},{"t":"para","text":"Dịch: Bạn có thể mở bất kỳ trang nào và bắt đầu đọc."},{"t":"example","text":"Giải thích: Lựa chọn ngẫu nhiên → Любую."},{"t":"para","text":"В э́тих усло́виях ва́ше молча́ние теря́ет ... (вся́кий) смысл.","b":1},{"t":"para","text":"Dịch: Trong điều kiện này, sự im lặng của bạn mất đi mọi ý nghĩa."},{"t":"example","text":"Giải thích: Теряет (mất) → Всякий."},{"t":"para","text":"Возьмём после́довательно ... (ка́ждое) число́ от одного́ до десяти́.","b":1},{"t":"para","text":"Dịch: Hãy lấy lần lượt từng số từ một đến mười."},{"t":"example","text":"Giải thích: Последовательно (lần lượt) → Каждое."},{"t":"para","text":"Ты мо́жешь переключи́ть телеви́зор на ... (любу́ю) програ́мму, кото́рая тебе́ понра́вится.","b":1},{"t":"para","text":"Dịch: Bạn có thể chuyển tivi sang bất kỳ kênh nào bạn thích."},{"t":"example","text":"Giải thích: Lựa chọn tùy ý → Любую."},{"t":"para","text":"По го́роду поползли́ ... (вся́кие) слу́хи.","b":1},{"t":"para","text":"Dịch: Trong thành phố lan truyền đủ loại tin đồn."},{"t":"example","text":"Giải thích: Tin đồn đa dạng/linh tinh → Всякие."},{"t":"para","text":"С (Со) ... (ка́ждой) встре́чей на́ши отноше́ния станови́лись всё бо́лее холо́дными.","b":1},{"t":"para","text":"Dịch: Qua mỗi cuộc gặp, quan hệ của chúng tôi ngày càng lạnh nhạt hơn."},{"t":"example","text":"Giải thích: Tiến trình theo từng lần → Каждой."},{"t":"para","text":"Твоё поведе́ние заслу́живает ... (вся́ческой / вся́кой) похвалы́.","b":1},{"t":"para","text":"Dịch: Hành vi của bạn xứng đáng nhận được mọi lời khen ngợi."},{"t":"example","text":"Giải thích: Всяческой (đủ kiểu/mọi sự) là từ hay dùng với похвала."},{"t":"para","text":"От метро́ до моего́ до́ма ты мо́жешь дое́хать на ... (любо́м) ви́де тра́нспорта.","b":1},{"t":"para","text":"Dịch: Từ tàu điện ngầm đến nhà tôi, bạn có thể đi bằng bất kỳ loại phương tiện nào."},{"t":"example","text":"Giải thích: Tùy chọn phương tiện → Любом."}]},{"id":"03-s062","type":"exercise","title":"Bài 376 (Trang 184)","num":376,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu tục ngữ. Giải thích việc sử dụng các đại từ ка́ждый, любо́й, вся́кий. Xác định ý nghĩa của câu tục ngữ."},{"t":"para","text":"Giải thích ngữ pháp:","b":1},{"t":"vocab","ru":"Ка́ждый (Mỗi)","vi":"Chỉ từng cá thể riêng biệt trong một nhóm.","g":null},{"t":"vocab","ru":"Вся́кий / Всяк (Mọi, bất cứ ai)","vi":"Mang tính khái quát hóa, chỉ bất kỳ người nào hoặc vật nào thuộc loại đó.","g":null},{"t":"vocab","ru":"Любо́й (Bất kỳ)","vi":"Nhấn mạnh sự tùy chọn.","g":null},{"t":"para","text":"Dịch và Giải thích chi tiết:","b":1},{"t":"para","text":"Ка́ждый челове́к кузне́ц своему́ сча́стью.","b":1},{"t":"example","text":"Dịch: Mỗi người là thợ rèn cho hạnh phúc của chính mình."},{"t":"example","text":"Ý nghĩa: Hạnh phúc do chính bàn tay và nỗ lực của từng cá nhân tạo nên, không phải do may mắn."},{"t":"example","text":"Ngữ pháp: Dùng ка́ждый để nhấn mạnh trách nhiệm cá nhân của từng người."},{"t":"para","text":"На вся́кого мудреца́ дово́льно простоты́.","b":1},{"t":"example","text":"Dịch: Mọi kẻ khôn ngoan đều có lúc dại khờ / Thánh nhân đãi kẻ khù khờ. (Nghĩa đen: Đối với bất cứ kẻ khôn ngoan nào cũng có đủ sự đơn giản/ngu ngơ)."},{"t":"example","text":"Ý nghĩa: Không ai là hoàn hảo hay khôn ngoan tuyệt đối, người giỏi cũng có lúc mắc sai lầm ngớ ngẩn."},{"t":"example","text":"Ngữ pháp: Dùng вся́кого (bất cứ loại nào) để chỉ chung tất cả những người được coi là khôn ngoan."},{"t":"para","text":"Всяк сверчо́к знай свой шесто́к.","b":1},{"t":"example","text":"Dịch: Mọi con dế hãy biết cái bệ lò của mình (Trâu ta ăn cỏ đồng ta / Biết thân biết phận)."},{"t":"example","text":"Ý nghĩa: Mỗi người nên biết vị trí, khả năng của mình và không nên can thiệp vào chuyện không phải của mình."},{"t":"example","text":"Ngữ pháp: Всяк là dạng ngắn (cổ) của вся́кий."},{"t":"para","text":"Ка́ждый кули́к своё боло́то хва́лит.","b":1},{"t":"example","text":"Dịch: Mỗi con chim dẽ giun đều khen đầm lầy của mình (Ta về ta tắm ao ta)."},{"t":"example","text":"Ý nghĩa: Ai cũng ca ngợi nơi chốn hoặc những gì thuộc về mình."},{"t":"example","text":"Ngữ pháp: Dùng ка́ждый để chỉ bản năng riêng của từng cá thể."},{"t":"para","text":"На вся́кое хоте́нье есть терпе́нье.","b":1},{"t":"example","text":"Dịch: Đối với mọi ham muốn đều cần có sự kiên nhẫn (Có chí thì nên)."},{"t":"example","text":"Ý nghĩa: Để đạt được bất cứ mong muốn nào cũng cần phải biết kiên trì, nhẫn nại."},{"t":"example","text":"Ngữ pháp: Вся́кое chỉ bất cứ loại mong muốn nào."}]},{"id":"03-s063","type":"exercise","title":"Bài 377 (Trang 184)","num":377,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu văn, chú ý đến các cụm từ cố định với các đại từ ка́ждый, любо́й, вся́кий. Xác định ý nghĩa của chúng."},{"t":"para","text":"Не мо́жет быть, что спектакль отме́нят, во вся́ком слу́чае, я об э́том ничего́ не слы́шал.","b":1},{"t":"example","text":"Dịch: Không thể có chuyện buổi diễn bị hủy, dù trong bất cứ trường hợp nào / ít nhất thì, tôi cũng chưa nghe gì về việc đó."},{"t":"example","text":"Cụm từ: Во вся́ком слу́чае (Dù thế nào đi nữa / Ít nhất là)."},{"t":"para","text":"Да́же в со́лнечную пого́ду я всегда́ беру́ с собо́й зонт на вся́кий слу́чай.","b":1},{"t":"example","text":"Dịch: Ngay cả khi trời nắng tôi vẫn luôn mang theo ô để phòng hờ / cho mọi tình huống."},{"t":"example","text":"Cụm từ: На вся́кий слу́чай (Để phòng xa / Nhỡ đâu có chuyện)."},{"t":"para","text":"Он люби́л проводи́ть вре́мя о́коло взро́слых, часа́ми слу́шая вся́кую вся́чину, о кото́рой они́ говори́ли.","b":1},{"t":"example","text":"Dịch: Nó thích dành thời gian bên cạnh người lớn, hàng giờ liền nghe đủ thứ chuyện trên đời / chuyện linh tinh mà họ nói."},{"t":"example","text":"Cụm từ: Вся́кая вся́чина (Đủ thứ hầm bà lằng / Chuyện linh tinh)."},{"t":"para","text":"Ты не пе́рвый, кто говори́т мне о его́ стра́нностях, я слы́шу об э́том на ка́ждом шагу́.","b":1},{"t":"example","text":"Dịch: Bạn không phải người đầu tiên nói với tôi về những sự kỳ quặc của anh ta, tôi nghe về điều này ở khắp mọi nơi / nhan nhản."},{"t":"example","text":"Cụm từ: На ка́ждом шагу́ (Tại mỗi bước đi → Khắp nơi, thường xuyên)."},{"t":"para","text":"Бу́дет тру́дно, но мы должны́ зако́нчить на́чатое де́ло любо́й цено́й.","b":1},{"t":"example","text":"Dịch: Sẽ khó khăn đấy, nhưng chúng ta phải hoàn thành công việc đã bắt đầu bằng bất cứ giá nào."},{"t":"example","text":"Cụm từ: Любо́й цено́й (Bằng mọi giá)."},{"t":"para","text":"Прове́рь всех и ка́ждого, ни оди́н челове́к не до́лжен уйти́ без прове́рки.","b":1},{"t":"example","text":"Dịch: Hãy kiểm tra tất cả và từng người một (không sót ai), không một người nào được phép rời đi mà không bị kiểm tra."},{"t":"example","text":"Cụm từ: Всех и ка́ждого (Tất tần tật mọi người, nhấn mạnh tính toàn thể và chi tiết)."}]},{"id":"03-s064","type":"exercise","title":"Bài 378 (Trang 184)","num":378,"blocks":[{"t":"example","text":"Đề bài: Sử dụng các cụm từ cố định với ка́ждый, любо́й, вся́кий, hãy chọn từ đồng nghĩa cho các phần in đậm (đã được thay thế trong bài giải)."},{"t":"example","text":"Вряд ли за́втра бу́дет дождь, к тому́ же в прогно́зе пого́ды об э́том ничего́ не бы́ло ска́зано.","b":1},{"t":"para","text":"Thay thế: во вся́ком слу́чае (dù sao thì / ít nhất thì)."},{"t":"example","text":"Dịch: Khó có khả năng mai mưa, dù sao thì dự báo thời tiết cũng không nói gì về điều đó."},{"t":"para","text":"Везде́ то́лько и говоря́т, что о вчера́шнем футбо́льном ма́тче;","b":1},{"t":"para","text":"Thay thế: На ка́ждом шагу́ (Khắp nơi / đâu đâu cũng)."},{"t":"example","text":"Dịch: Đi đâu cũng/Khắp nơi người ta chỉ toàn nói về trận bóng đá hôm qua."},{"t":"example","text":"Ты до́лжен э́то сде́лать не смотря́ ни на что;","b":1},{"t":"para","text":"Thay thế: любо́й цено́й (bằng mọi giá)."},{"t":"example","text":"Dịch: Bạn phải làm điều đó bằng mọi giá."},{"t":"example","text":"Я проси́л тебя́ молча́ть об э́том всем;","b":1},{"t":"para","text":"Thay thế: всем и ка́ждому (với bất cứ ai / tất cả mọi người)."},{"t":"example","text":"Dịch: Tôi đã yêu cầu bạn phải giữ im lặng về chuyện này với tất cả mọi người."},{"t":"example","text":"Когда́ зуб начина́ет боле́ть, по́здно идти́ к врачу́, на́до посеща́ть зубну́ю поликли́нику два ра́за в год, что́бы быть споко́йным;","b":1},{"t":"para","text":"Thay thế: на вся́кий слу́чай (để phòng xa)."},{"t":"example","text":"Dịch: Khi răng bắt đầu đau thì đi khám đã muộn, cần đến phòng khám nha khoa hai lần một năm để phòng xa."},{"t":"example","text":"В магази́не продава́лось молоко́, хлеб, о́вощи — всё, что уго́дно.","b":1},{"t":"para","text":"Thay thế: вся́кая вся́чина (đủ thứ linh tinh / hầm bà lằng)."},{"t":"example","text":"Dịch: Trong cửa hàng có bán sữa, bánh mì, rau củ — đủ thứ linh tinh."}]},{"id":"03-s065","type":"grammar","title":"Chủ đề: Đại từ ВЕСЬ, Tính từ ЦЕЛЫЙ, ПОЛНЫЙ","num":null,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 185):","b":1},{"t":"vocab","ru":"Весь (всё, вся, все)","vi":"Toàn bộ, tất cả. Chỉ sự bao quát trọn vẹn đối tượng từ đầu đến cuối.","g":null},{"t":"subhead","text":"Це́лый (nguyên, cả, toàn bộ):","b":1},{"t":"para","text":"Nghĩa 1: Nguyên vẹn, không bị hỏng, chưa bị bắt đầu (dùng)."},{"t":"example","text":"Nghĩa 2: Rất lớn, đáng kể (thường dùng với thời gian để nhấn mạnh độ dài: це́лый день - cả một ngày trời)."},{"t":"subhead","text":"По́лный (đầy, hoàn toàn):","b":1},{"t":"example","text":"Nghĩa 1: Chứa đầy, không còn chỗ trống (по́лный стака́н - cốc đầy)."},{"t":"example","text":"Nghĩa 2: Trọn vẹn, đầy đủ các bộ phận (по́лное собра́ние сочине́ний - tuyển tập trọn bộ)."},{"t":"example","text":"Nghĩa 3: Tuyệt đối, hoàn toàn (dùng với danh từ trừu tượng: по́лная тишина́ - sự im lặng hoàn toàn)."}]},{"id":"03-s066","type":"exercise","title":"Bài 379 (Trang 185)","num":379,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu. Xác định sự khác biệt về ý nghĩa giữa đại từ весь và các tính từ це́лый, по́лный."},{"t":"para","text":"а)","b":1},{"t":"para","text":"Вся коро́бка (со всех сторо́н) в целлофа́не. (Toàn bộ hộp được bọc kính - Bề mặt). Коро́бка це́лая (ни одна́ конфе́та не отсу́тствует, коро́бка не помя́та). (Hộp còn nguyên - Chưa bóc/không hỏng). Коро́бка по́лная конфе́т, ско́лько должно́ быть в э́той коро́бке. (Hộp đầy kẹo - Chứa đầy lượng quy định)."},{"t":"para","text":"Вчера́ я потеря́л весь компле́кт (от пе́рвого до после́днего инструме́нта). (Mất toàn bộ bộ dụng cụ - Tất cả). Я ви́жу це́лый компле́кт инструме́нтов (ни оди́н инструме́нт не отсу́тствует). (Thấy bộ dụng cụ còn nguyên vẹn/đầy đủ). Я хочу́ купи́ть по́лный компле́кт инструме́нтов (всё, что ну́жно). (Mua bộ dụng cụ đầy đủ chức năng)."},{"t":"para","text":"Весь день (с утра́ до ве́чера) я рабо́тал. (Tôi làm việc suốt ngày - Thời gian). Я рабо́тал це́лый день (ни на мину́ты не прекраща́я рабо́ту). (Tôi làm việc cả một ngày trời - Nhấn mạnh sự vất vả/liên tục). Устра́иваюсь на рабо́ту на по́лный рабо́чий день (на обы́чный 8-часово́й рабо́чий день). (Làm việc toàn thời gian - Thuật ngữ hành chính)."},{"t":"subhead","text":"б) (Dùng ВЕСЬ - Tất cả/Toàn bộ):","b":1},{"t":"example","text":"Все прису́тствующие согласи́лись... (Tất cả những người có mặt đã đồng ý...)."},{"t":"example","text":"Де́ти бе́гали по всему́ до́му... (Lũ trẻ chạy khắp nhà...)."},{"t":"example","text":"Всех веще́й взять с собо́й нельзя́... (Không thể mang theo tất cả đồ đạc...)."},{"t":"example","text":"Всю доро́гу мы молча́ли... (Chúng tôi im lặng suốt quãng đường...)."},{"t":"example","text":"Всем коллекти́вом мы спра́вимся... (Cả tập thể chúng ta sẽ giải quyết được...)."},{"t":"example","text":"Во всех райо́нах прошли́ ми́тинги. (Các cuộc mít tinh diễn ra ở tất cả các quận)."},{"t":"subhead","text":"в) (Dùng ЦЕЛЫЙ - Nguyên vẹn/Cả một...):","b":1},{"t":"example","text":"Я не брал ни одно́й конфе́ты, посмотри́, коро́бка це́лая... (Hộp còn nguyên)."},{"t":"example","text":"Уси́лий це́лого коллекти́ва не доста́точно... (Nỗ lực của cả một tập thể lớn cũng không đủ...)."},{"t":"example","text":"Он дал нам по це́лому апельси́ну... (Mỗi người một quả cam nguyên)."},{"t":"example","text":"Я не был здесь це́лую ве́чность... (Tôi không ở đây cả một thế kỷ rồi - Nhấn mạnh thời gian dài)."},{"t":"example","text":"Не на́до ре́зать мя́со, пода́й его́ к столу́ це́лым куско́м... (Hãy dọn ra nguyên miếng)."},{"t":"example","text":"В це́лом ми́ре не найдётся челове́ка... (Trên cả thế giới rộng lớn này...)."},{"t":"subhead","text":"г) (Dùng ПОЛНЫЙ - Đầy/Trọn vẹn/Hoàn toàn):","b":1},{"t":"example","text":"Посмотри́, по́лный теа́тр зри́телей... (Nhìn xem, nhà hát chật kín khán giả...)."},{"t":"example","text":"Ду́маю, по́лного комфо́рта ждать не прихо́дится... (Sự tiện nghi hoàn toàn)."},{"t":"example","text":"Мы учи́лись по по́лной програ́мме... (Học theo chương trình đầy đủ)."},{"t":"example","text":"Не на́до мне налива́ть по́лный стака́н ча́я... (Đừng rót cho tôi cốc trà đầy ắp...)."},{"t":"example","text":"Мы дви́гались вперёд по́лным хо́дом... (Tiến lên với tốc độ tối đa)."},{"t":"example","text":"Он был в по́лном расцве́те сил. (Anh ấy đang ở độ sung sức nhất)."}]},{"id":"03-s067","type":"exercise","title":"Bài 380 (Trang 185)","num":380,"blocks":[{"t":"example","text":"Đề bài: Điền vào chỗ trống hình thức cần thiết của đại từ весь hoặc tính từ це́лый, по́лный."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 185):","b":1},{"t":"vocab","ru":"Весь","vi":"Có ý nghĩa \"từ đầu đến cuối\" hoặc \"từ cái đầu tiên đến cái cuối cùng\".","g":null},{"t":"vocab","ru":"Це́лый","vi":"Nhấn mạnh \"không bị sứt mẻ/còn nguyên\" hoặc \"số lượng lớn/kéo dài\".","g":null},{"t":"vocab","ru":"По́лный","vi":"Nhấn mạnh \"đầy ắp/chứa đến mức tối đa\" hoặc \"trọn bộ\".","g":null},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"vocab","ru":"Я не потеря́л ни одно́го флома́стера, посмотри́","vi":"набо́р (це́лый).","g":null},{"t":"example","text":"Dịch: Tôi không làm mất cái bút dạ nào, nhìn xem: bộ bút còn nguyên."},{"t":"example","text":"Giải thích: Không mất cái nào → còn nguyên vẹn → целый."},{"t":"para","text":"Е́сли тебе́ не ну́жен (весь) набо́р флома́стеров, я возьму́ у тебя́ две шту́ки.","b":1},{"t":"example","text":"Dịch: Nếu bạn không cần cả/toàn bộ bộ bút dạ, tôi sẽ lấy của bạn hai cái."},{"t":"example","text":"Giải thích: Đối lập với \"hai cái\" là \"tất cả\" → весь."},{"t":"para","text":"Я хочу́ купи́ть (по́лный) набо́р флома́стеров, в кото́рый вхо́дит 36 цвето́в.","b":1},{"t":"example","text":"Dịch: Tôi muốn mua một bộ bút dạ đầy đủ, bao gồm 36 màu."},{"t":"example","text":"Giải thích: Bộ trọn gói đầy đủ → полный."},{"t":"para","text":"Он вы́пил (по́лный) стака́н молока́ до после́дней ка́пли.","b":1},{"t":"example","text":"Dịch: Nó đã uống một cốc sữa đầy đến giọt cuối cùng."},{"t":"example","text":"Giải thích: Chứa đầy → полный."},{"t":"para","text":"Стака́н и так (по́лный), того́ и гляди́ молоко́ польётся че́рез край.","b":1},{"t":"example","text":"Dịch: Cốc đã đầy rồi, trông kìa sữa sắp tràn ra ngoài."},{"t":"example","text":"Giải thích: Đầy ắp → полный."},{"t":"para","text":"Не бо́йся, стака́н (це́лый), он не разби́лся.","b":1},{"t":"example","text":"Dịch: Đừng sợ, cái cốc còn nguyên, nó không bị vỡ đâu."},{"t":"example","text":"Giải thích: Không vỡ → целый."},{"t":"para","text":"Игру́шка (це́лая), ничего́ с ней не случи́лось.","b":1},{"t":"example","text":"Dịch: Đồ chơi còn nguyên, không có chuyện gì xảy ra với nó cả."},{"t":"example","text":"Giải thích: Không hỏng → целая."},{"t":"para","text":"Игру́шка сде́лана из (це́льного) куска́ пластма́ссы.","b":1},{"t":"example","text":"Dịch: Đồ chơi được làm từ một khối nhựa liền khối/nguyên khối."},{"t":"note","text":"Lưu ý: Sách dùng цельный (tính từ gốc целый nhưng chuyên chỉ vật liệu liền khối), nhưng nếu đề bắt dùng nhóm từ trên thì là целого. Tuy nhiên, ngữ cảnh này цельный chính xác hơn. Trong khuôn khổ bài tập целый cũng chấp nhận được với nghĩa \"một miếng to nguyên vẹn\". Đáp án sách thường là целого."},{"t":"vocab","ru":"Не на́до бы́ло роня́ть игру́шку в лу́жу, тепе́рь посмотри́","vi":"(вся) игру́шка в воде́.","g":null},{"t":"example","text":"Dịch: Lẽ ra không nên đánh rơi đồ chơi xuống vũng nước, giờ nhìn xem: toàn bộ đồ chơi bị ướt/dính nước."},{"t":"example","text":"Giải thích: Phủ khắp bề mặt → вся."},{"t":"para","text":"Мы е́хали по доро́ге, (всей) разби́той маши́нами.","b":1},{"t":"example","text":"Dịch: Chúng tôi đi trên con đường bị xe cộ cày nát toàn bộ."},{"t":"example","text":"Giải thích: Toàn bộ bề mặt → всей."},{"t":"para","text":"Доро́га (це́лая), наводне́ние её не разру́шило.","b":1},{"t":"example","text":"Dịch: Con đường vẫn còn nguyên, lũ lụt không phá hủy nó."},{"t":"example","text":"Giải thích: Không bị phá hủy → целая."},{"t":"para","text":"Вдоль (всей) доро́ги возвыша́лись телегра́фные столбы́.","b":1},{"t":"example","text":"Dịch: Dọc theo toàn bộ con đường là những cột điện báo sừng sững."},{"t":"example","text":"Giải thích: Suốt chiều dài → всей."},{"t":"para","text":"Ду́маю, карма́нные вариа́нты меня́ не устро́ят, мне ну́жен (по́лный) слова́рь.","b":1},{"t":"example","text":"Dịch: Tôi nghĩ các bản bỏ túi sẽ không làm tôi hài lòng, tôi cần một cuốn từ điển đầy đủ."},{"t":"example","text":"Giải thích: Trọn bộ/đầy đủ → полный."},{"t":"para","text":"...разде́лы словаря́ соста́влены коллекти́вом сотру́дников Акаде́мии нау́к. → Điền Все."},{"t":"example","text":"Dịch: Tất cả các phần của từ điển được biên soạn bởi tập thể nhân viên Viện Hàn lâm Khoa học."},{"t":"example","text":"Giải thích: Mọi phần → Все."},{"t":"para","text":"Я́годы положи́ть не́куда, (вся) корзи́на запо́лнена гриба́ми.","b":1},{"t":"example","text":"Dịch: Không còn chỗ để dâu, cả cái giỏ đã đầy nấm rồi."},{"t":"example","text":"Giải thích: Toàn bộ không gian giỏ → вся."},{"t":"para","text":"Вчера́ из ле́са мы принесли́ (по́лную / це́лую) корзи́ну грибо́в.","b":1},{"t":"example","text":"Dịch: Hôm qua từ rừng về chúng tôi mang được một giỏ nấm đầy / nguyên một giỏ."},{"t":"example","text":"Giải thích: Полную (đầy ắp) hoặc целую (nhấn mạnh số lượng nhiều: cả một giỏ). Cả hai đều được tùy sắc thái."},{"t":"para","text":"В воскресе́нье прие́дут го́сти, бу́дет (по́лон) дом наро́ду.","b":1},{"t":"example","text":"Dịch: Chủ nhật khách sẽ đến, sẽ đầy nhà người."},{"t":"example","text":"Giải thích: Полон (dạng rút gọn của полный): đầy."},{"t":"para","text":"Ду́маю, не́сколько ко́мнат нас не устро́ят, нам пона́добится (весь) дом.","b":1},{"t":"example","text":"Dịch: Tôi nghĩ vài phòng sẽ không đủ cho chúng tôi, chúng tôi sẽ cần toàn bộ/cả căn nhà."},{"t":"example","text":"Giải thích: Tất cả ngôi nhà → весь."}]},{"id":"03-s068","type":"exercise","title":"Bài 381 (Trang 186)","num":381,"blocks":[{"t":"example","text":"Đề bài: Đọc các câu văn. Xác định sự khác biệt về ý nghĩa giữa đại từ весь (toàn bộ) và tính từ це́лый (nguyên, cả) khi biểu thị thời gian và số lượng."},{"t":"para","text":"Giải thích ngữ pháp:","b":1},{"t":"vocab","ru":"Весь (всё, вся, все)","vi":"Chỉ sự bao quát trọn vẹn một khoảng thời gian hoặc một tập hợp từ đầu đến cuối (mang tính trung lập, thông báo sự việc).","g":null},{"t":"vocab","ru":"Це́лый (це́лая, це́лое, це́лые)","vi":"Khi đi với danh từ chỉ thời gian hoặc đơn vị đo lường, nó mang sắc thái nhấn mạnh cảm xúc về độ lớn, độ dài hoặc số lượng nhiều (nghĩa là \"cả một...\", \"tận...\", \"suốt cả...\").","g":null},{"t":"para","text":"Dịch và Phân tích:","b":1},{"t":"para","text":"Весь день я был на рабо́те, поэ́тому ты и не мог дозвони́ться.","b":1},{"t":"example","text":"Dịch: Tôi đã ở chỗ làm suốt (toàn bộ) ngày, vì thế bạn không gọi được."},{"t":"example","text":"Ý nghĩa: Chỉ đơn thuần là thông báo khoảng thời gian từ sáng đến tối (весь)."},{"t":"para","text":"Я ждал тебя́ це́лый день, никуда́ не выходи́л, а ты так и не прие́хал!","b":1},{"t":"example","text":"Dịch: Tôi đã đợi bạn cả một ngày trời, chẳng đi đâu cả, thế mà bạn vẫn không đến!"},{"t":"example","text":"Ý nghĩa: Nhấn mạnh sự chờ đợi mòn mỏi, thời gian trôi qua rất lâu (це́лый)."},{"t":"para","text":"Весь сле́дующий ме́сяц мы бу́дем начина́ть и зака́нчивать рабо́ту на час по́зже.","b":1},{"t":"example","text":"Dịch: Toàn bộ tháng sau chúng ta sẽ bắt đầu và kết thúc công việc muộn hơn một tiếng."},{"t":"example","text":"Ý nghĩa: Thông báo lịch trình (весь)."},{"t":"para","text":"Он ду́мал, что ско́ро попра́вится, а ему́ пришло́сь це́лый ме́сяц пролежа́ть в больни́це.","b":1},{"t":"example","text":"Dịch: Anh ấy tưởng sẽ sớm bình phục, ai dè phải nằm viện tận (cả một) tháng trời."},{"t":"example","text":"Ý nghĩa: Nhấn mạnh thời gian nằm viện dài hơn mong đợi (це́лый)."},{"t":"para","text":"За весь год я не пропусти́л ни одно́го заня́тия.","b":1},{"t":"example","text":"Dịch: Trong suốt (cả) năm tôi không bỏ lỡ buổi học nào."},{"t":"example","text":"Ý nghĩa: Chỉ sự trọn vẹn của khoảng thời gian (весь)."},{"t":"para","text":"Неуже́ли я не смогу́ пое́хать в экспеди́цию, я мечта́л об э́том це́лый год!","b":1},{"t":"example","text":"Dịch: Chẳng lẽ tôi không thể đi thám hiểm sao, tôi đã mơ về điều đó suốt cả một năm trời!"},{"t":"example","text":"Ý nghĩa: Nhấn mạnh sự khao khát kéo dài rất lâu (це́лый)."},{"t":"para","text":"Я неда́вно покупа́л килогра́мм са́хара, где он? Весь са́хар уже́ зако́нчился.","b":1},{"t":"example","text":"Dịch: Tôi mới mua một cân đường, nó đâu rồi? Toàn bộ số đường đã hết rồi."},{"t":"example","text":"Ý nghĩa: Tất cả số lượng đó (весь)."},{"t":"para","text":"Неуже́ли ты съел все конфе́ты?! Там был це́лый килогра́мм!","b":1},{"t":"example","text":"Dịch: Chẳng lẽ bạn ăn hết kẹo rồi sao?! Ở đó có tận (cả) một cân đấy!"},{"t":"example","text":"Ý nghĩa: Nhấn mạnh số lượng lớn đáng ngạc nhiên (це́лый)."}]},{"id":"03-s069","type":"exercise","title":"Bài 382 (Trang 186)","num":382,"blocks":[{"t":"example","text":"Đề bài: Điền đại từ весь hoặc tính từ це́лый vào chỗ trống."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 186):","b":1},{"t":"para","text":"Tính từ це́лый thường có được ý nghĩa biểu cảm, chỉ một số lượng rất lớn, quá mức hoặc thời gian kéo dài."},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"para","text":"На пло́щади собрала́сь (це́лая) толпа́ наро́да.","b":1},{"t":"example","text":"Dịch: Trên quảng trường đã tụ tập cả một đám đông người. (Nhấn mạnh số lượng đông)."},{"t":"para","text":"Мы прое́хали по (всем) дере́вням райо́на...","b":1},{"t":"example","text":"Dịch: Chúng tôi đã đi qua tất cả các ngôi làng trong huyện... (Chỉ sự bao quát toàn bộ, không sót làng nào)."},{"t":"para","text":"К сожале́нию, (всю) сле́дующую неде́лю я бу́ду за́нят.","b":1},{"t":"example","text":"Dịch: Tiếc là toàn bộ (suốt) tuần sau tôi sẽ bận. (Chỉ khoảng thời gian trọn vẹn)."},{"t":"para","text":"...с утра́ до ве́чера я рабо́тал в архи́ве, но так и не нашёл ну́жных мне докуме́нтов; (це́лую) неде́лю я пересма́тривал тома́...","b":1},{"t":"example","text":"Dịch: ...từ sáng đến tối tôi làm việc trong kho lưu trữ nhưng không tìm thấy tài liệu cần thiết; tôi đã xem lại các tập hồ sơ suốt cả một tuần trời... (Nhấn mạnh công sức và thời gian dài)."},{"t":"para","text":"Все счита́ли меня́ ма́леньким, хотя́ к э́тому вре́мени мне уже́ испо́лнилось (це́лых) де́вять лет.","b":1},{"t":"example","text":"Dịch: Mọi người đều coi tôi là bé bỏng, mặc dù lúc đó tôi đã tròn tận chín tuổi. (Nhấn mạnh số tuổi lớn đối với đứa trẻ)."},{"t":"para","text":"В тече́ние (всех) девяти́ лет, проведённых мно́ю на Се́вере, я переезжа́л с одного́ ме́ста на друго́е...","b":1},{"t":"example","text":"Dịch: Trong suốt cả (tất cả) chín năm sống ở phương Bắc, tôi đã chuyển từ nơi này sang nơi khác... (Chỉ tổng thời gian bao quát)."},{"t":"para","text":"Э́та но́вость бы́стро распространи́лась по (всему́) ми́ру.","b":1},{"t":"example","text":"Dịch: Tin tức này nhanh chóng lan truyền ra toàn thế giới. (Bao quát không gian)."}]},{"id":"03-s070","type":"exercise","title":"Bài 383 (Trang 187)","num":383,"blocks":[{"t":"example","text":"Đề bài: Thay đổi trật tự từ trong các cụm từ với tính từ по́лный."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 187):","b":1},{"t":"example","text":"Nếu tính từ по́лный đứng sau danh từ (корзи́на, по́лная грибо́в), nó mang nghĩa tính chất: \"cái giỏ được lấp đầy bởi nấm\"."},{"t":"example","text":"Nếu tính từ по́лный đứng trước danh từ (по́лная корзи́на грибо́в), nó mang nghĩa định lượng: \"cả một giỏ nấm\" (số lượng nhiều)."},{"t":"subhead","text":"Đáp án và Dịch:","b":1},{"t":"para","text":"У нас до́ма холоди́льник, по́лный проду́ктов → по́лный холоди́льник проду́ктов.","b":1},{"t":"example","text":"Dịch: Ở nhà chúng tôi có cả một tủ lạnh đầy thực phẩm."},{"t":"para","text":"Мне ну́жно ведро́, по́лное воды́ → по́лное ведро́ воды́.","b":1},{"t":"example","text":"Dịch: Tôi cần một xô đầy nước."},{"t":"para","text":"Я до́лго ду́мал об э́тих слова́х, по́лных глубо́кого смы́сла → по́лных глубо́кого смы́сла слова́х (ít dùng) / словах, исполненных глубокого смысла.","b":1},{"t":"note","text":"Lưu ý: Với danh từ trừu tượng, thường giữ nguyên vị trí sau hoặc dùng cấu trúc khác. Nhưng nếu ép theo bài: по́лных глубо́кого смы́сла слова́х."},{"t":"example","text":"Dịch: Tôi đã suy nghĩ rất lâu về những lời tràn đầy ý nghĩa sâu sắc này."},{"t":"para","text":"На столе́ стоя́л кувши́н, по́лный молока́ → по́лный кувши́н молока́.","b":1},{"t":"example","text":"Dịch: Trên bàn có một bình đầy sữa."},{"t":"para","text":"В толпе́ я сра́зу уви́дел его́ глаза́, по́лные у́жаса → по́лные у́жаса глаза́.","b":1},{"t":"example","text":"Dịch: Trong đám đông tôi thấy ngay đôi mắt đầy kinh hoàng của anh ấy."},{"t":"para","text":"В углу́ стоя́л шкаф, по́лный книг → по́лный шкаф книг.","b":1},{"t":"example","text":"Dịch: Trong góc có cả một tủ đầy sách."},{"t":"para","text":"Пока́ мы шли по пля́жу, у меня́ бы́ли ту́фли, по́лные песка́ → по́лные ту́фли песка́.","b":1},{"t":"example","text":"Dịch: Khi chúng tôi đi trên bãi biển, giày tôi đầy ắp cát."},{"t":"para","text":"Я с трудо́м смог пройти́ че́рез зал, по́лный госте́й → по́лный зал госте́й.","b":1},{"t":"example","text":"Dịch: Tôi khó khăn lắm mới đi qua được căn phòng đầy khách."},{"t":"para","text":"Я получи́л от неё письмо́, по́лное трево́ги за сы́на → по́лное трево́ги письмо́.","b":1},{"t":"example","text":"Dịch: Tôi nhận được từ bà ấy một lá thư tràn đầy sự lo lắng cho con trai."},{"t":"para","text":"Вдоль у́лиц расположи́лись магази́ны с витри́нами, по́лными разнообра́зных това́ров → по́лными разнообра́зных това́ров витри́нами.","b":1},{"t":"example","text":"Dịch: Dọc các con phố là các cửa hàng với những tủ kính đầy ắp hàng hóa đa dạng."},{"t":"para","text":"Впереди́ у нас была́ жизнь, по́лная приключе́ний → по́лная приключе́ний жизнь.","b":1},{"t":"example","text":"Dịch: Phía trước chúng tôi là một cuộc đời đầy những cuộc phiêu lưu."}]},{"id":"03-s071","type":"exercise","title":"Bài 384 (Trang 187)","num":384,"blocks":[{"t":"example","text":"Đề bài: Điền vào chỗ trống весь (toàn bộ), це́лый (cả một, nguyên) hoặc по́лный (đầy, trọn vẹn) ở dạng phù hợp."},{"t":"para","text":"У нас был (це́лый) мешо́к са́хара, неуже́ли (весь) са́хар зако́нчился?","b":1},{"t":"example","text":"Dịch: Chúng ta có cả một bao đường, chẳng lẽ toàn bộ chỗ đường đã hết rồi sao?"},{"t":"example","text":"Giải thích: Целый nhấn mạnh số lượng bao, весь chỉ sự tổng thể đã hết."},{"t":"para","text":"Ты пришёл по́зже на (це́лый) час, неуже́ли ты не мог поторопи́ться?","b":1},{"t":"example","text":"Dịch: Bạn đến muộn tận/cả một tiếng, chẳng lẽ bạn không thể nhanh hơn sao?"},{"t":"example","text":"Giải thích: Целый nhấn mạnh thời gian dài."},{"t":"para","text":"Авто́бус подъе́хал к кольцу́, и (все) пассажи́ры вы́шли.","b":1},{"t":"example","text":"Dịch: Xe buýt đi đến bến cuối, và tất cả hành khách xuống xe."},{"t":"example","text":"Giải thích: Все chỉ toàn thể mọi người."},{"t":"para","text":"Я не был в родно́м го́роде (це́лых) пять лет.","b":1},{"t":"example","text":"Dịch: Tôi đã không ở thành phố quê hương tận năm năm."},{"t":"example","text":"Giải thích: Nhấn mạnh thời gian dài đi với số từ (целых)."},{"t":"para","text":"Мне хо́чется предста́вить себе́ (по́лную) карти́ну того́, что здесь произошло́.","b":1},{"t":"example","text":"Dịch: Tôi muốn hình dung ra bức tranh toàn cảnh/đầy đủ về những gì đã xảy ra ở đây."},{"t":"example","text":"Giải thích: Полную nghĩa là đầy đủ chi tiết."},{"t":"example","text":"...его́ де́йствия бы́ли то́чными и разме́ренными; (все) его́ де́йствия... (Theo văn cảnh câu 201 trong sách gốc). Hoặc nếu ý là \"toàn bộ quá trình\": (Весь) ход.... Tuy nhiên, nếu điền cho từ действия (số nhiều) thì là Все."},{"t":"example","text":"Dịch: Tất cả hành động của anh ấy đều chính xác và nhịp nhàng."},{"t":"para","text":"Э́тот фильм пока́зывали в сокращённом вариа́нте, а я хочу́ посмотре́ть (по́лную) ве́рсию.","b":1},{"t":"example","text":"Dịch: Phim này chiếu bản rút gọn, còn tôi muốn xem phiên bản đầy đủ."},{"t":"example","text":"Giải thích: Полную đối lập với rút gọn."},{"t":"para","text":"Он дал мне не со́рок, не шестьдеся́т, а (це́лых) сто рубле́й.","b":1},{"t":"example","text":"Dịch: Anh ấy đưa tôi không phải 40, không phải 60, mà là tận/tròn 100 rúp."},{"t":"example","text":"Giải thích: Nhấn mạnh số lượng lớn (целых)."},{"t":"para","text":"Над э́той пробле́мой рабо́тают (це́лые) нау́чные коллекти́вы, а ты хо́чешь реши́ть её в одино́чку.","b":1},{"t":"example","text":"Dịch: Cả những tập thể khoa học lớn đang làm việc với vấn đề này, thế mà bạn muốn giải quyết một mình."},{"t":"example","text":"Giải thích: Целые nhấn mạnh quy mô lớn của nhóm."},{"t":"para","text":"... четве́рг я ду́мал над его́ предложе́нием; (Весь) четве́рг...","b":1},{"t":"example","text":"Dịch: Suốt cả ngày thứ Năm tôi đã suy nghĩ về đề nghị của anh ấy."},{"t":"example","text":"Giải thích: Весь chỉ trọn vẹn thời gian."},{"t":"para","text":"Он дал мне на размышле́ния (це́лых) де́сять мину́т.","b":1},{"t":"example","text":"Dịch: Anh ấy cho tôi tận mười phút để suy nghĩ."},{"t":"example","text":"Giải thích: Nhấn mạnh thời gian (dù ngắn hay dài, tùy ngữ cảnh, ở đây có thể là mỉa mai hoặc nhấn mạnh sự hào phóng)."},{"t":"para","text":"Назови́те ва́ше (по́лное) и́мя.","b":1},{"t":"example","text":"Dịch: Hãy nói tên đầy đủ của bạn."},{"t":"para","text":"...бума́ги в твоём отчёте перепу́таны; (Все) бума́ги...","b":1},{"t":"example","text":"Dịch: Tất cả giấy tờ trong báo cáo của bạn bị lộn xộn."},{"t":"para","text":"По́езд шёл (по́лным) хо́дом.","b":1},{"t":"example","text":"Dịch: Tàu hỏa chạy hết tốc lực."},{"t":"example","text":"Giải thích: Thành ngữ полным ходом."},{"t":"para","text":"Вам колбасу́ наре́зать? — Нет, взве́сьте, пожа́луйста (це́лым) куско́м.","b":1},{"t":"example","text":"Dịch: Ông muốn thái lát xúc xích không? — Không, làm ơn cân nguyên cả miếng."},{"t":"example","text":"Giải thích: Целым nghĩa là nguyên vẹn, chưa cắt."},{"t":"example","text":"У на́шей жи́зни (по́лной) жи́зни! (Câu này có vẻ thiếu từ hoặc là thành ngữ жить полной жизнью)."},{"t":"example","text":"Sửa: Е́сли ты рабо́тал в (по́лную) си́лу... (Nếu bạn làm việc hết sức...)."},{"t":"example","text":"Dịch: Sống cuộc sống trọn vẹn."},{"t":"para","text":"Е́сли ты рабо́тал в (по́лную) си́лу...","b":1},{"t":"example","text":"Dịch: Nếu bạn đã làm việc hết sức mình..."},{"t":"para","text":"Мы е́хали почти́ час, так как по́езд остана́вливался на (ка́ждой / всех) ста́нциях; (Câu gốc trong sách khác)."},{"t":"example","text":"Sách gốc câu 18: Мы обе́дали (це́лый) час."},{"t":"example","text":"Dịch: Chúng tôi đã ăn trưa suốt cả một tiếng đồng hồ."},{"t":"para","text":"При ... моём к вам уваже́нии... → При (всем) моём к вам уваже́нии...","b":1},{"t":"example","text":"Dịch: Với tất cả sự tôn trọng của tôi dành cho ông... (Cụm cố định)."},{"t":"para","text":"...свобо́ду вам не мо́жет предоста́вить никто́; (По́лную) свобо́ду...","b":1},{"t":"example","text":"Dịch: Không ai có thể cho bạn sự tự do hoàn toàn."},{"t":"para","text":"Я не ви́дел тебя́ (це́лую) ве́чность!","b":1},{"t":"example","text":"Dịch: Tôi không gặp bạn cả một thế kỷ rồi! (Nhấn mạnh thời gian dài)."},{"t":"para","text":"По́сле э́того собы́тия мы бы́ли в ... расте́рянности; (по́лной) расте́рянности.","b":1},{"t":"example","text":"Dịch: Sau sự kiện đó chúng tôi hoàn toàn bối rối (trong sự bối rối hoàn toàn)."},{"t":"para","text":"Я хочу́, что́бы ты съел (весь) суп. Но заче́м ты мне нали́ла (по́лную) таре́лку.","b":1},{"t":"example","text":"Dịch: Mẹ muốn con ăn hết (toàn bộ) súp. Nhưng sao mẹ lại rót cho con đầy một đĩa thế."},{"t":"para","text":"...дня́ми он ничего́ не де́лал; (Це́лыми) дня́ми...","b":1},{"t":"example","text":"Dịch: Suốt cả ngày này qua ngày khác anh ấy chẳng làm gì cả."}]},{"id":"03-s072","type":"exercise","title":"Bài 385 (Trang 188)","num":385,"blocks":[{"t":"example","text":"Đề bài: Hoàn thành câu, sử dụng các cụm từ cố định với весь, це́лый, по́лный. Xác định ý nghĩa của chúng."},{"t":"para","text":"Я всей душо́й подде́рживаю ва́ше предложе́ние.","b":1},{"t":"example","text":"Dịch: Tôi ủng hộ đề xuất của bạn bằng cả tấm lòng (hết lòng)."},{"t":"example","text":"Ý nghĩa: Chân thành, tuyệt đối (всей душой)."},{"t":"para","text":"Хара́ктером он весь в отца́, тако́й же упря́мый.","b":1},{"t":"example","text":"Dịch: Về tính cách nó giống hệt/toàn bộ bố nó, cũng bướng bỉnh như thế."},{"t":"example","text":"Ý nghĩa: Giống hoàn toàn (весь в кого-то)."},{"t":"para","text":"Мы пыта́лись все́ми пра́вдами и непра́вдами разузна́ть э́ту информа́цию.","b":1},{"t":"example","text":"Dịch: Chúng tôi đã cố gắng tìm hiểu thông tin này bằng mọi cách (dù đúng hay sai)."},{"t":"example","text":"Ý nghĩa: Bằng bất cứ giá nào (всеми правдами и неправдами)."},{"t":"para","text":"Посмотре́в вслед челове́ку, кото́рый так стра́нно себя́ повёл при встре́че с на́ми, он покрути́л па́льцем у виска́ и сказа́л: — Чуда́к челове́к, не обраща́йте на него́ внима́ния, у него́ всегда́ бы́ли не все до́ма.","b":1},{"t":"example","text":"Dịch: ...anh ấy xoay ngón tay thái dương và nói: — Người kỳ quặc, đừng để ý, hắn ta lúc nào cũng chạm mạch/không bình thường (nghĩa đen: không có tất cả ở nhà)."},{"t":"example","text":"Ý nghĩa: Bị điên, dở hơi (не все дома)."},{"t":"para","text":"Он верну́лся с войны́ це́лым и невреди́мым.","b":1},{"t":"example","text":"Dịch: Anh ấy trở về từ cuộc chiến bình an vô sự (lành lặn)."},{"t":"example","text":"Ý nghĩa: Không bị thương tích (целым и невредимым)."},{"t":"para","text":"Ну, ка́жется, в о́бщем и це́лом мы разобра́лись в э́том де́ле.","b":1},{"t":"example","text":"Dịch: Chà, có vẻ như nhìn chung / về cơ bản chúng ta đã giải quyết xong việc này."},{"t":"example","text":"Ý nghĩa: Tổng quát (в общем и целом)."},{"t":"para","text":"Да́йте по́лную фо́рму э́того прилага́тельного.","b":1},{"t":"example","text":"Dịch: Hãy đưa ra dạng đầy đủ của tính từ này."},{"t":"example","text":"Ý nghĩa: Thuật ngữ ngữ pháp (đối lập với dạng ngắn)."},{"t":"para","text":"Живу́т они́ хорошо́, дом — по́лная ча́ша.","b":1},{"t":"example","text":"Dịch: Họ sống sung túc, nhà đầy ắp của cải (như cái bát đầy)."},{"t":"example","text":"Ý nghĩa: Giàu có, sung túc (дом — полная чаша)."},{"t":"para","text":"Ду́маю, я не смогу́ вы́полнить твою́ про́сьбу, у меня́ на рабо́те хло́пот по́лон рот.","b":1},{"t":"example","text":"Dịch: Tôi nghĩ tôi không thể thực hiện lời nhờ của bạn, ở chỗ làm tôi bận tối mắt tối mũi (việc ngập đến mồm)."},{"t":"example","text":"Ý nghĩa: Rất bận rộn (хлопот полон рот)."}]},{"id":"03-s073","type":"exercise","title":"Bài 386 (Trang 188)","num":386,"blocks":[{"t":"example","text":"Đề bài: Sử dụng các cụm từ cố định với các từ весь (toàn bộ), це́лый (nguyên/cả), по́лный (đầy), hãy chọn từ đồng nghĩa cho các phần in đậm (đã được thay thế trong bài giải)."},{"t":"example","text":"Не бо́йся, ничего́ с тобо́й не случи́тся, бу́дешь жив и здоро́в.","b":1},{"t":"para","text":"Thay thế: цел и невреди́м","b":1},{"t":"example","text":"Dịch: Đừng sợ, sẽ không có chuyện gì xảy ra với bạn đâu, bạn sẽ bình an vô sự (lành lặn)."},{"t":"example","text":"Giải thích: Цел и невреди́м là thành ngữ chỉ sự an toàn tuyệt đối về thể chất sau một biến cố."},{"t":"example","text":"Я и́скренне жела́ю вам успе́ха в э́том де́ле.","b":1},{"t":"example","text":"Thay thế: всей душо́й (hoặc всем се́рдцем)"},{"t":"example","text":"Dịch: Tôi chúc bạn thành công trong việc này bằng cả tấm lòng."},{"t":"example","text":"Giải thích: Всей душой thể hiện sự chân thành sâu sắc."},{"t":"example","text":"Су́дя по вне́шнему ви́ду, э́то дом бога́тый, зажи́точный.","b":1},{"t":"para","text":"Thay thế: по́лная ча́ша","b":1},{"t":"example","text":"Dịch: Nhìn bề ngoài thì đây là một ngôi nhà sung túc, giàu có (như bát nước đầy)."},{"t":"example","text":"Giải thích: Thành ngữ дом — полная чаша chỉ sự thịnh vượng, dư dả."},{"t":"example","text":"Ду́маю, не затра́гивая ча́стностей, нам уда́стся сего́дня реши́ть э́ту пробле́му.","b":1},{"t":"para","text":"Thay thế: в о́бщем и це́лом","b":1},{"t":"example","text":"Dịch: Tôi nghĩ rằng, về cơ bản / nhìn chung (không đi vào chi tiết), hôm nay chúng ta sẽ giải quyết được vấn đề này."},{"t":"example","text":"Giải thích: В общем и целом dùng để tóm tắt hoặc nói về tổng thể."},{"t":"example","text":"Он так похо́ж на своего́ де́да.","b":1},{"t":"para","text":"Thay thế: весь в (своего деда)"},{"t":"example","text":"Dịch: Cậu ấy giống hệt (giống như đúc) ông nội của mình."},{"t":"example","text":"Giải thích: Cấu trúc весь в кого-то nghĩa là giống ai đó hoàn toàn (về ngoại hình hoặc tính cách)."},{"t":"example","text":"Стра́нный челове́к, непредсказу́емый, с таки́м тру́дно обща́ться; по-мо́ему, у него́ не все в поря́дке с голово́й.","b":1},{"t":"para","text":"Thay thế: у него́ не все до́ма","b":1},{"t":"example","text":"Dịch: Một người kỳ lạ, khó đoán, thật khó giao tiếp với người như vậy; theo tôi thì hắn ta bị chạm mạch / dở hơi (không bình thường)."},{"t":"example","text":"Giải thích: Не все дома là cách nói lóng chỉ người có vấn đề về thần kinh hoặc hành xử kỳ quặc."},{"t":"example","text":"Не́когда ей разгова́ривать, она́ о́чень занята́.","b":1},{"t":"para","text":"Thay thế: у неё хло́пот по́лон рот","b":1},{"t":"example","text":"Dịch: Cô ấy không có thời gian nói chuyện đâu, cô ấy bận tối mắt tối mũi (việc ngập đến mồm)."},{"t":"example","text":"Giải thích: Хлопот полон рот chỉ trạng thái cực kỳ bận rộn với nhiều việc vặt."},{"t":"example","text":"Ни пе́ред чем не остана́вливайся, попро́буй любы́ми путя́ми вы́яснить э́ту информа́цию, мне о́чень ва́жно её знать.","b":1},{"t":"para","text":"Thay thế: все́ми пра́вдами и непра́вдами","b":1},{"t":"example","text":"Dịch: Đừng dừng lại trước bất cứ điều gì, hãy thử tìm hiểu thông tin này bằng mọi giá (dù đúng hay sai), tôi rất cần biết nó."},{"t":"example","text":"Giải thích: Всеми правдами и неправдами nghĩa là dùng mọi thủ đoạn, không kể tốt xấu để đạt mục đích."}]},{"id":"03-s074","type":"grammar","title":"Mục 3: Ôn tập (Материал для повторения. Раздел 3)","num":null,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp chung cho phần này:","b":1},{"t":"para","text":"Phần này ôn tập về các loại đại từ:"},{"t":"vocab","ru":"Đại từ nhân xưng (я, мы, ты, вы, он, она, оно, они)","vi":"Thay đổi theo cách (Case). Cần chú ý khi đi với giới từ, đại từ ngôi thứ 3 (он, она, они) thường thêm chữ н- vào đầu (ví dụ: у него, с ними).","g":null},{"t":"vocab","ru":"Đại từ chỉ định (этот, тот)","vi":"Этот (này - gần), Тот (kia/đó - xa hoặc quá khứ).","g":null},{"t":"vocab","ru":"Đại từ phản thân (себя)","vi":"Chỉ hành động hướng về chính chủ thể.","g":null},{"t":"vocab","ru":"Đại từ sở hữu phản thân (свой)","vi":"Của chính chủ ngữ.","g":null}]},{"id":"03-s075","type":"exercise","title":"Bài 387 (Trang 189)","num":387,"blocks":[{"t":"para","text":"Đề bài: Mở ngoặc, sử dụng đại từ nhân xưng hoặc cụm danh từ ở dạng phù hợp (có giới từ hoặc không)."},{"t":"para","text":"a) (Đoạn văn trích từ tác phẩm \"Lolli\" của A. Kuprin)"},{"t":"para","text":"В Эрла́у (мы) присоедини́лся со свои́ми пятью́ дрессиро́ванными слона́ми оди́н иностра́нный господи́н.","b":1},{"t":"subhead","text":"Đáp án: к нам"},{"t":"example","text":"Dịch: Tại Erlau, một quý ông nước ngoài cùng 5 con voi được huấn luyện của mình đã gia nhập với chúng tôi. (Присоединиться к кому? - Cách 3)."},{"t":"para","text":"Настоя́щего (он) и́мени и происхожде́ния никто́ не знал.","b":1},{"t":"subhead","text":"Đáp án: его́"},{"t":"example","text":"Dịch: Không ai biết tên thật và xuất thân của ông ấy. (Sở hữu cách)."},{"t":"para","text":"Су́дя по нару́жности, (он) жи́лах текла́ нема́лая при́месь ара́бской или негритя́нской кро́ви.","b":1},{"t":"subhead","text":"Đáp án: в его́"},{"t":"example","text":"Dịch: Đánh giá qua ngoại hình, trong huyết quản ông ấy chảy một dòng máu pha trộn không nhỏ của người Ả Rập hoặc người da đen. (В чьих жилах?)."},{"t":"para","text":"(Он) тёмное краси́вое лицо́ с немига́ющими грома́дными чёрными глаза́ми бы́ло зло и вла́стно.","b":1},{"t":"subhead","text":"Đáp án: У него́ (cấu trúc sở hữu У кого-то есть... nhưng ở đây là miêu tả đặc điểm) hoặc Его́ (Sở hữu: Khuôn mặt của ông ấy)."},{"t":"example","text":"Lựa chọn tốt nhất: Его́ (Khuôn mặt đen đẹp đẽ của ông ấy...)."},{"t":"para","text":"Все мы как-то чутьём избега́ли бли́зости (он).","b":1},{"t":"subhead","text":"Đáp án: с ним"},{"t":"example","text":"Dịch: Tất cả chúng tôi bằng linh cảm nào đó đều tránh sự gần gũi với ông ta. (Близости с кем?)."},{"t":"para","text":"Да́же (он) слоны́, по-ви́димому, ненави́дели (он) со всей си́лою.","b":1},{"t":"subhead","text":"Đáp án: его́ ... его́"},{"t":"example","text":"Dịch: Ngay cả những con voi của ông ta, dường như, cũng căm ghét ông ta bằng tất cả sức mạnh."},{"t":"para","text":"...на кото́рую то́лько спосо́бны ненави́деть э́ти великоду́шные, терпели́вые... живо́тные. Во вре́мя репети́ций Энри́ко обраща́лся (они) так ре́зко...","b":1},{"t":"subhead","text":"Đáp án: с ни́ми"},{"t":"example","text":"Dịch: ...Trong các buổi tập, Enrico đối xử với chúng (những con voi) rất thô bạo... (Обращаться с кем?)."},{"t":"para","text":"...что мы иногда́ не могли́ бы́ли уве́рены, что (он) вы́йдет живы́м с аре́ны: он бил (они) без милосе́рдия...","b":1},{"t":"subhead","text":"Đáp án: он ... их"},{"t":"example","text":"Dịch: ...rằng đôi khi chúng tôi không thể chắc chắn liệu ông ta có sống sót rời khỏi sân khấu hay không: ông ta đánh chúng không thương tiếc... (Бил кого? - Cách 4)."},{"t":"para","text":"б) (Đoạn văn trích từ tác phẩm \"Phòng thủ của Luzhin\" của V. Nabokov)"},{"t":"para","text":"Она́ познако́милась (он) на тре́тий день по́сле (прие́зд)...","b":1},{"t":"subhead","text":"Đáp án: с ним"},{"t":"example","text":"Dịch: Cô ấy làm quen với anh ấy vào ngày thứ ba sau khi đến..."},{"t":"para","text":"...она́ роня́ет плато́к, он (он) поднима́ет...","b":1},{"t":"subhead","text":"Đáp án: его́"},{"t":"example","text":"Dịch: ...cô ấy đánh rơi chiếc khăn tay, anh ấy nhặt nó lên... (Thay thế cho платок - giống đực)."},{"t":"para","text":"Лу́жин шёл по тропи́нке (она)...","b":1},{"t":"subhead","text":"Đáp án: за ней"},{"t":"example","text":"Dịch: Luzhin đi theo con đường mòn phía sau cô ấy. (Ngữ cảnh: anh ấy đi theo sau và nhặt đồ)."},{"t":"para","text":"...и после́довательно роня́л... плато́к, смя́тую папиро́су... Она́ подбира́ла то́лько плато́к и моне́ту и ме́дленно догоня́ла (он)...","b":1},{"t":"subhead","text":"Đáp án: его́"},{"t":"example","text":"Dịch: ...Cô ấy chỉ nhặt khăn tay và đồng xu rồi chậm rãi đuổi kịp anh ấy."},{"t":"para","text":"Лу́жин, наконе́ц, останови́лся, вы́вернул карма́н и стал разгля́дывать (он) ды́рку.","b":1},{"t":"subhead","text":"Đáp án: в нём"},{"t":"example","text":"Dịch: Luzhin cuối cùng dừng lại, lộn trái túi áo và bắt đầu xem xét cái lỗ thủng trong đó (trong cái túi)."},{"t":"para","text":"“Наскво́зь”, — сказа́л он по-неме́цки, взяв (она) руки́ плато́к.","b":1},{"t":"subhead","text":"Đáp án: из её (hoặc у неё из)"},{"t":"example","text":"Dịch: \"Xuyên qua\", - anh ấy nói bằng tiếng Đức, cầm lấy chiếc khăn tay từ tay cô ấy."},{"t":"para","text":"Он по́днял го́лову и хму́ро (она) посмотре́л.","b":1},{"t":"subhead","text":"Đáp án: на неё"},{"t":"example","text":"Dịch: Anh ấy ngẩng đầu lên và cau mày nhìn cô ấy."},{"t":"para","text":"(Он) бы́ли удиви́тельные глаза́...","b":1},{"t":"subhead","text":"Đáp án: У него́"},{"t":"example","text":"Dịch: Anh ấy có đôi mắt thật kỳ lạ..."},{"t":"para","text":"“Не роня́йте бо́льше”, — сказа́ла она́ и пошла́ (он) прочь, чу́вствуя (он) взгляд у себя́ на спине́.","b":1},{"t":"subhead","text":"Đáp án: от него́ ... его́"},{"t":"example","text":"Dịch: \"Đừng đánh rơi nữa nhé\", - cô ấy nói và đi xa khỏi anh ấy, cảm nhận ánh nhìn của anh ấy trên lưng mình."}]},{"id":"03-s076","type":"exercise","title":"Bài 388 (Trang 189)","num":388,"blocks":[{"t":"example","text":"Đề bài: Mở ngoặc, sử dụng các đại từ э́то, э́тот hoặc тот có hoặc không có giới từ."},{"t":"subhead","text":"Gợi ý:","b":1},{"t":"vocab","ru":"Э́тот (này)","vi":"Chỉ cái gần, hiện tại, hoặc vừa nhắc đến.","g":null},{"t":"vocab","ru":"Тот (kia/đó)","vi":"Chỉ cái xa, quá khứ, hoặc đối lập với этот.","g":null},{"t":"para","text":"Он заме́тно поседе́л ... пор, как мы расста́лись...","b":1},{"t":"subhead","text":"Đáp án: с тех"},{"t":"example","text":"Dịch: Ông ấy bạc đi trông thấy kể từ khi chúng tôi chia tay... (Cụm cố định с тех пор - từ đó)."},{"t":"para","text":"Степа́н Арка́дьич не избира́л ни направле́ния, ни взгля́дов, а ... направле́ния и взгля́ды са́ми приходи́ли к нему́...","b":1},{"t":"subhead","text":"Đáp án: э́ти ... э́ти"},{"t":"example","text":"Dịch: Stepan Arkadyich không chọn phương hướng hay quan điểm, mà những phương hướng và quan điểm này tự tìm đến ông ấy... (Chỉ những cái đang hiện hữu với ông ấy)."},{"t":"para","text":"Как он выбира́л фо́рмы шля́пы... (Брал ..., кото́рые но́сят).","b":1},{"t":"subhead","text":"Đáp án: те"},{"t":"example","text":"Dịch: ...Ông ấy chọn (lấy) những cái mà người ta đang đội. (Те, которые - những cái mà)."},{"t":"para","text":"...бы́ло в 18 тако́м-то году́. ... вре́мя я то́лько что получи́л ме́сто...**"},{"t":"subhead","text":"Đáp án: В то"},{"t":"example","text":"Dịch: ...Chuyện xảy ra vào năm 18xx. Vào thời gian đó tôi vừa mới nhận được chỗ làm... (Chỉ quá khứ)."},{"t":"para","text":"Вообще́, мно́го говори́ли о де́тстве. Но Лу́жин ... бесе́дах оживля́лся ре́дко. Зато́ мысль его́... сно́ва к о́бласти (тот) де́тства.","b":1},{"t":"subhead","text":"Đáp án: в э́тих ... того́"},{"t":"example","text":"Dịch: Nói chung, người ta nói nhiều về tuổi thơ. Nhưng Luzhin hiếm khi hào hứng trong những cuộc trò chuyện này. Bù lại, suy nghĩ của anh ấy... lại quay về vùng ký ức của tuổi thơ đó (tuổi thơ của chính mình trong quá khứ)."},{"t":"para","text":"Мы до́лго не могли́ сказа́ть ни сло́ва. ..., что та́йно волнова́ло нас после́дний ме́сяц, бы́ло тепе́рь ска́зано...","b":1},{"t":"subhead","text":"Đáp án: То"},{"t":"example","text":"Dịch: Chúng tôi mãi không nói được lời nào. Điều mà đã bí mật làm chúng tôi lo lắng suốt tháng qua, giờ đây đã được nói ra... (То, что - cái mà)."},{"t":"para","text":"Ка́рманные часы́... торопли́во и однообра́зно пе́ли две но́ты. Ра́зницу ме́жду ... но́тами тру́дно улови́ть...","b":1},{"t":"subhead","text":"Đáp án: э́тими (hoặc те́ми)"},{"t":"example","text":"Dịch: Đồng hồ bỏ túi... hối hả và đơn điệu hát hai nốt nhạc. Sự khác biệt giữa những nốt nhạc này thật khó nắm bắt... (Vừa nhắc đến → этими)."},{"t":"para","text":"Кто жил и мы́слил, ... не мо́жет В душе́ не презира́ть люде́й; Кто чу́вствовал, (тот) трево́жит При́зрак невозврати́мых дней...","b":1},{"t":"subhead","text":"Đáp án: тот ... того́"},{"t":"example","text":"Dịch: Ai đã sống và suy tư, kẻ đó không thể không coi khinh con người trong lòng; Ai đã cảm nhận, kẻ đó sẽ bị bóng ma của những ngày không trở lại quấy rầy... (Cấu trúc Кто..., тот...)."},{"t":"para","text":"Tiếp tục đoạn thơ: Тому́ уж нет очарова́ний, Того́ змия́ воспомина́ний, Того́ раска́янье грызёт. (Đối với kẻ đó không còn sự quyến rũ, kẻ đó bị con rắn ký ức, kẻ đó bị sự hối hận gặm nhấm)."}]},{"id":"03-s077","type":"exercise","title":"Bài 389 (Trang 190)","num":389,"blocks":[{"t":"example","text":"Đề bài: Điền vào chỗ trống dạng cần thiết của đại từ nhân xưng hoặc đại từ phản thân (себя), có hoặc không có giới từ."},{"t":"para","text":"Жду вас непреме́нно ... (Ф.Достое́вский).","b":1},{"t":"subhead","text":"Đáp án: у себя́"},{"t":"example","text":"Dịch: Tôi nhất định đợi ông ở chỗ tôi."},{"t":"para","text":"Я уезжа́ю сего́дня, увозя́ ... никако́й наде́жды (И.Турге́нев).","b":1},{"t":"subhead","text":"Đáp án: с собо́й (hoặc в себе́ - nhưng văn cảnh \"mang đi\" thường là с собой)"},{"t":"example","text":"Dịch: Hôm nay tôi đi đây, không mang theo mình chút hy vọng nào."},{"t":"para","text":"Но то́лько так че́рез час и́ли не бо́лее как че́рез два, смотрю́, вбега́ет го́рничная, кото́рая о́троду у нас на коню́шне никогда́ не была́, и де́ржит ... в руке́ зо́нтик, а сама́ кричи́т:","b":1},{"t":"note","text":"Lưu ý: Câu này yêu cầu điền cho động từ держит (cầm)."},{"t":"subhead","text":"Đáp án: Cầm ô thì không cần đại từ ở đây nếu ô là tân ngữ. Nếu ý là \"cầm theo mình\" → при себе́? Hoặc nếu là \"dẫn ai đó theo\" -> собой. Nhưng ngữ cảnh này là cầm cái ô. Có thể sách muốn điền перед собой (trước mặt)?"},{"t":"example","text":"Xem xét lại: \"держит ... в руке зонтик\". Cầm cái ô trong tay. Chỗ trống trước \"в руке\". Có thể là у себя? Không tự nhiên."},{"t":"subhead","text":"Gợi ý từ đáp án (nếu có): Thường là không cần điền gì hoặc điền перед собой."},{"t":"example","text":"Phân tích lại câu: \"...которая отроду у нас на конюшне никогда не была, и держит ...\" -> À, câu gốc của Leskov là: \"...и держит перед собой в руке зонтик...\"."},{"t":"example","text":"Dịch: ...và cầm cái ô trong tay trước mặt mình."},{"t":"para","text":"— Бо́же мой! Ведь да́же нельзя́ предста́вить ... всех после́дствий.","b":1},{"t":"subhead","text":"Đáp án: себе́"},{"t":"example","text":"Dịch: — Chúa ơi! Thậm chí không thể hình dung (cho bản thân) hết mọi hậu quả. (Представить себе - tưởng tượng/hình dung)."},{"t":"para","text":"Профе́ссор с презре́нием ткнул ле́вую кало́шу, кото́рая раздража́ла ..., жела́я налезть на пра́вую...","b":1},{"t":"subhead","text":"Đáp án: его́"},{"t":"example","text":"Dịch: Vị giáo sư khinh bỉ chọc vào chiếc ủng cao su bên trái, cái mà làm ông ấy bực mình vì cứ muốn chui vào chân phải... (Tác nhân gây bực là vật, đối tượng là người → его)."},{"t":"para","text":"Посыла́ю вам три́дцать копе́ек серебро́м; бо́льше ника́к не могу́. Купи́те ... там, что́ бо́лсе ну́жно...","b":1},{"t":"subhead","text":"Đáp án: себе́"},{"t":"example","text":"Dịch: Tôi gửi cho bạn 30 kopeck bạc; không thể hơn được nữa. Hãy mua cho mình ở đó những gì cần thiết nhất..."},{"t":"para","text":"Пе́ред глаза́ми Тере́нтия, Дани́лы и Фёклы мчи́тся това́рный по́езд.","b":1},{"t":"example","text":"Điền thay thế tên người: Пе́ред ни́ми (Trước mặt họ) hoặc У них пе́ред глаза́ми (Trước mắt họ)."},{"t":"subhead","text":"Đáp án: У них пе́ред глаза́ми (hoặc перед их глазами). Nhưng đề bài thường yêu cầu đại từ nhân xưng thay thế danh từ → У них."},{"t":"example","text":"Dịch: Một đoàn tàu hàng lao vút qua trước mắt họ."},{"t":"para","text":"Был я тру́дный, своенра́вный, до прекра́сной кра́йности избало́ванный ребёнок (балу́йте дете́й побо́льше, господа́, вы не зна́ете, что ... ожида́ет!).","b":1},{"t":"subhead","text":"Đáp án: их"},{"t":"example","text":"Dịch: ...hãy nuông chiều trẻ con nhiều hơn, các ngài ạ, các ngài không biết điều gì đang chờ đợi chúng đâu!"},{"t":"para","text":"Могу́ ... предста́вить, как э́тим бе́дным воспита́тельницам иногда́ быва́ло ску́чно со мной.","b":1},{"t":"subhead","text":"Đáp án: себе́"},{"t":"example","text":"Dịch: Tôi có thể hình dung (cho mình) các cô bảo mẫu tội nghiệp đó đôi khi đã chán chường với tôi thế nào."},{"t":"para","text":"...дли́нные пи́сьма писа́ли они́ в тишине́ свои́х ску́чных ко́мнат.","b":1},{"t":"subhead","text":"Đáp án: у себя́ (nếu điền vào chỗ trống ý chỉ địa điểm \"tại chỗ mình\") hoặc свои́х (nếu điền vào tính từ sở hữu trong ngoặc)."},{"t":"example","text":"Nếu đề là: \"...писали они в тишине (...) скучных комнат\". → свои́х (của mình)."},{"t":"example","text":"Dịch: ...họ đã viết những lá thư dài trong sự tĩnh lặng của những căn phòng tẻ nhạt của mình."}]},{"id":"03-s078","type":"exercise","title":"Bài 390 (Trang 191)","num":390,"blocks":[{"t":"example","text":"Đề bài: Hoàn thành các câu sử dụng các cụm từ cố định với đại từ phản thân себя."},{"t":"para","text":"Ты мо́жешь поручи́ть э́то кому́-нибудь друго́му, нельзя́ всё де́лать самому́, ты сли́шком мно́го ...","b":1},{"t":"subhead","text":"Đáp án: берёшь на себя́"},{"t":"example","text":"Dịch: Bạn có thể giao việc này cho ai khác, không thể tự làm tất cả được, bạn đang ôm đồm quá nhiều (gánh vác quá nhiều lên mình)."},{"t":"para","text":"Что ты не́рвничаешь, возьми́ ...","b":1},{"t":"subhead","text":"Đáp án: себя́ в ру́ки"},{"t":"example","text":"Dịch: Sao bạn lại lo lắng thế, hãy bình tĩnh lại / kiềm chế bản thân đi."},{"t":"para","text":"...разуме́ется, я приму́ ва́ше предложе́ние.","b":1},{"t":"subhead","text":"Đáp án: Само́ собо́й"},{"t":"example","text":"Dịch: Tất nhiên là (tự nó đã rõ), tôi sẽ chấp nhận đề nghị của bạn."},{"t":"para","text":"Я никого́ никогда́ не подде́рживаю, предпочита́ю вести́ себя́ незави́симо, я всегда́ сам ...","b":1},{"t":"subhead","text":"Đáp án: по себе́"},{"t":"example","text":"Dịch: Tôi không bao giờ ủng hộ ai, tôi thích cư xử độc lập, tôi luôn đứng riêng một mình / độc lập."},{"t":"para","text":"Нет, я не бо́лен, про́сто мне ста́ло ...","b":1},{"t":"subhead","text":"Đáp án: не по себе́"},{"t":"example","text":"Dịch: Không, tôi không ốm, chỉ là tôi thấy hơi khó ở / nôn nao / không thoải mái."},{"t":"para","text":"Я сказа́л э́то ти́хо, ..., что́бы никто́ не услы́шал.","b":1},{"t":"subhead","text":"Đáp án: про себя́"},{"t":"example","text":"Dịch: Tôi đã nói điều đó khẽ khàng, thầm / lẩm bẩm, để không ai nghe thấy."},{"t":"para","text":"Позво́льте мне взять ... вы́брать маршру́т на́шего путеше́ствия.","b":1},{"t":"subhead","text":"Đáp án: на себя́ сме́лость (mạo muội) hoặc на себя́ отве́тственность (trách nhiệm)."},{"t":"example","text":"Dịch: Cho phép tôi mạo muội / nhận trách nhiệm chọn lộ trình cho chuyến đi của chúng ta."},{"t":"vocab","ru":"Как ка́жется, будь уве́рен, он ... (Câu gốc","vi":"\"Он не такой простой...\").","g":null},{"t":"subhead","text":"Đáp án: себе́ на уме́"},{"t":"example","text":"Dịch: Hắn không đơn giản như vẻ ngoài đâu, cứ tin đi, hắn là kẻ khôn ngầm / thâm trầm / kín tiếng."},{"t":"para","text":"Свои́м вчера́шним посту́пком он вы́дал ..., тепе́рь никто́ не сомнева́ется, что э́то он вино́ват во всём.","b":1},{"t":"subhead","text":"Đáp án: себя́ с голово́й"},{"t":"example","text":"Dịch: Với hành động hôm qua, hắn đã tự tố cáo mình hoàn toàn (lộ tẩy), giờ thì không ai nghi ngờ việc hắn có lỗi trong mọi chuyện."},{"t":"para","text":"Ты зна́ешь, что разгово́ры на э́ту те́му меня́ раздража́ют, заче́м ты выво́дишь ...","b":1},{"t":"subhead","text":"Đáp án: меня́ из себя́"},{"t":"example","text":"Dịch: Bạn biết là những cuộc nói chuyện về chủ đề này làm tôi bực mình, tại sao bạn lại chọc tức tôi / làm tôi điên lên thế."}]},{"id":"03-s079","type":"exercise","title":"Bài 391 (Trang 191)","num":391,"blocks":[{"t":"example","text":"Đề bài: Thay thế các dấu ba chấm bằng đại từ sở hữu (мой, твой, его...) hoặc đại từ sở hữu phản thân (свой) ở dạng phù hợp."},{"t":"note","text":"Lưu ý ngữ pháp (Trang 165):","b":1},{"t":"vocab","ru":"Свой (của mình)","vi":"Chỉ sự sở hữu thuộc về chủ ngữ của câu. Nó được dùng cho tất cả các ngôi (tôi, bạn, anh ấy...).","g":null},{"t":"vocab","ru":"Đại từ sở hữu ngôi thứ 3 (его, её, их)","vi":"Được dùng khi vật sở hữu không thuộc về chủ ngữ của mệnh đề đó, hoặc khi chủ ngữ là chính vật sở hữu đó (ở cách 1).","g":null},{"t":"note","text":"Lưu ý: Свой không bao giờ dùng ở Cách 1 (Chủ ngữ)."},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"а) (Gogol, \"Viy\")","b":1},{"t":"para","text":"И сама́ ты бу́дешь несча́стна, и де́ти (твои́) бу́дут несча́стны.","b":1},{"t":"example","text":"Dịch: Và bản thân em sẽ bất hạnh, và con cái của em cũng sẽ bất hạnh."},{"t":"example","text":"Giải thích: Chủ ngữ của vế sau là дети (con cái). Con cái không thể là \"của mình\" (thuộc về chính nó trong ngữ cảnh này được), mà là thuộc về \"em\" (ngôi thứ 2). Vì дети là chủ ngữ, ta dùng твои (của bạn/em), không dùng свои."},{"t":"vocab","ru":"Э́та про́сьба произвела́ (своё) де́йствие","vi":"судья́ был (свой) челове́к.","g":null},{"t":"example","text":"Dịch: Lời thỉnh cầu này đã phát huy tác dụng của nó: quan tòa là người nhà/thân tín."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"Своё действие","vi":"Tác dụng thuộc về \"lời thỉnh cầu\" (chủ ngữ) → dùng своё.","g":null},{"t":"vocab","ru":"Свой человек","vi":"Cụm cố định chỉ người quen thân, người trong nhà.","g":null},{"t":"para","text":"Он обрати́лся к секретарю́. Но секрета́рь пусти́л сквозь гу́бы густо́й “гм” и показа́л на лице́ (своём) равноду́шие и дья́вольски двусмы́сленную ми́ну, кото́рую принима́ет оди́н то́лько сатана́, когда́ ви́дит у ног (свои́х) прибега́ющую к нему́ же́ртву.","b":1},{"t":"example","text":"Dịch: Hắn quay sang thư ký. Nhưng tên thư ký thốt ra một tiếng \"hừm\" trầm qua môi và thể hiện trên khuôn mặt của mình sự thờ ơ và vẻ mặt hai mặt quỷ quyệt, vẻ mặt mà chỉ có Satan mới có khi nhìn thấy nạn nhân chạy đến bên chân hắn."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"На лице́ своём","vi":"Khuôn mặt của thư ký (chủ ngữ) → своём.","g":null},{"t":"vocab","ru":"У ног свои́х","vi":"Chân của Satan (chủ ngữ mệnh đề который...) → свои́х.","g":null},{"t":"para","text":"б) (Turgenev, \"Mumu\")","b":1},{"t":"para","text":"Во-пе́рвых, стра́нный гость никогда́ ничего́ не спра́шивал. Ка́ждый раз он пря́мо проходи́л в у́гол к пе́чке и там сажа́л (о́коло себя́ / с собо́й?) соба́ку.","b":1},{"t":"note","text":"Lưu ý: Chỗ trống này có thể điền о́коло себя́ (cạnh mình). Nhưng đề bài yêu cầu свой hoặc đại từ sở hữu. Nếu là \"đặt con chó của mình\" → свою собаку. Nhưng vị trí dấu ba chấm ở sau động từ, trước собаку? Hay sau? Nếu điền cho собаку thì là свою́. (Ông ấy đặt con chó của mình)."},{"t":"example","text":"Dịch: Thứ nhất, vị khách lạ không bao giờ hỏi gì cả. Lần nào ông ta cũng đi thẳng vào góc lò sưởi và đặt con chó của mình ở đó."},{"t":"para","text":"Е́сли же ... ме́сто у пе́чки быва́ло за́нято, то он стоя́л не́сколько вре́мени в бессмы́сленном недоуме́нии про́тив господи́на, заня́вшего (его́) ме́сто.","b":1},{"t":"example","text":"Dịch: Nếu chỗ cạnh lò sưởi bị chiếm, ông ta đứng một lúc trong sự ngơ ngác vô nghĩa trước người đàn ông đã chiếm chỗ của ông ta."},{"t":"example","text":"Giải thích: Место thuộc về \"ông ta\" (khách), nhưng chủ ngữ của mệnh đề phân từ là господина (người đàn ông khác). Người đàn ông chiếm chỗ của khách → dùng его (của ông ấy). Nếu dùng своё, nghĩa là người đàn ông chiếm chỗ của chính mình (không hợp lý)."},{"t":"para","text":"Соба́ка же, покрути́вшись ра́за два и́ли три на одно́м ме́сте, угрю́мо укла́дывалась у ног (его́) ..., втыка́ла ... мо́рду ме́жду (его́) сапога́ми, глубоко́ вздыха́ла и, вы́тянувшись во всю (свою́) дли́ну на полу́, то́же остава́лась неподви́жною.","b":1},{"t":"example","text":"Dịch: Còn con chó, sau khi xoay hai ba vòng tại chỗ, ủ rũ nằm xuống chân ông ta, rúc mõm vào giữa đôi ủng của ông ta, thở dài thườn thượt và, duỗi thẳng toàn bộ chiều dài của nó trên sàn, cũng nằm im bất động."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"У ног его́","vi":"Chân của ông khách. Chủ ngữ là Собака. Vật sở hữu (chân) không thuộc về chủ ngữ (chó) → его.","g":null},{"t":"vocab","ru":"Между его́ сапогами","vi":"Ủng của ông khách → его.","g":null},{"t":"vocab","ru":"Во всю свою́ длину","vi":"Chiều dài của con chó (chủ ngữ) → свою́.","g":null},{"t":"para","text":"в) (L. Tolstoy, \"Anna Karenina\")","b":1},{"t":"para","text":"Степа́н Арка́дьич в шко́ле учи́лся хорошо́ благодаря́ (свои́м) хоро́шим спосо́бностям, но был лени́в и шалу́н и потому́ вы́шел из после́дних.","b":1},{"t":"example","text":"Dịch: Stepan Arkadyich ở trường học tốt nhờ năng lực tốt của mình, nhưng lại lười biếng và nghịch ngợm nên tốt nghiệp loại bét."},{"t":"example","text":"Giải thích: Năng lực của Stepan (chủ ngữ) → свои́м."},{"t":"para","text":"Ме́сто э́то он получи́л че́рез му́жа сестры́ А́нны, Алексе́я Алекса́ндровича Каре́нина, занима́вшего одно́ из важне́йших мест в министе́рстве, к кото́рому принадлежа́ло прису́щее (ему́) учрежде́ние.","b":1},{"t":"example","text":"Dịch: Ông ấy có được chỗ làm này nhờ chồng của em gái Anna là Alexei Alexandrovich Karenin, người giữ chức vụ quan trọng trong bộ mà cơ quan của ông ấy (Stepan) trực thuộc."},{"t":"example","text":"Giải thích: Cơ quan thuộc về Stepan (hoặc gắn với ông ấy). Trong mệnh đề к которому..., chủ ngữ là учреждение. Vậy учреждение thuộc về Stepan (người khác) → ему."},{"t":"para","text":"Но е́сли бы Каре́нин не назна́чил шу́рина на э́то ме́сто, то че́рез со́тню други́х лиц, бра́тьев, сестёр, родны́х, двою́родных, дяде́й, тёток, Сти́ва Обло́нский получи́л бы э́то ме́сто и́ли подо́бное, ну́жное (свои́м) ну́ждам, так как дела́ (его́) ..., несмотря́ на доста́точное состоя́ние жены́, бы́ли расстро́ены.","b":1},{"t":"example","text":"Dịch: Nhưng nếu Karenin không bổ nhiệm em vợ vào chỗ này... Stiva Oblonsky cũng sẽ nhận được chỗ này hoặc chỗ tương tự, cần thiết cho nhu cầu của mình, bởi vì công việc kinh doanh của ông ấy..., bất chấp tài sản khá giả của vợ, đã bị sa sút."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"Своим нуждам","vi":"Nhu cầu của Stiva (chủ ngữ) → свои́м.","g":null},{"t":"vocab","ru":"Дела его","vi":"Công việc của Stiva. Nhưng ở đây дела là chủ ngữ của mệnh đề так как дела.... Свой không làm chủ ngữ hoặc bổ nghĩa cho chủ ngữ ở cách 1 → dùng его.","g":null}]},{"id":"03-s080","type":"exercise","title":"Bài 392 (Trang 192)","num":392,"blocks":[{"t":"example","text":"Đề bài: Hoàn thành câu với các cụm từ cố định chứa đại từ phản thân себя hoặc свой (dựa trên các bài tập trước)."},{"t":"para","text":"Не на́до повторя́ть всё сло́во в сло́во, перескажи́ (свои́ми слова́ми).","b":1},{"t":"example","text":"Dịch: Không cần lặp lại từng từ một, hãy kể lại bằng lời của mình."},{"t":"para","text":"Мне ва́ши сове́ты не нужны́, я предпочита́ю жить (свои́м умо́м).","b":1},{"t":"example","text":"Dịch: Tôi không cần lời khuyên của các bạn, tôi thích sống bằng trí óc của mình (tự chủ)."},{"t":"para","text":"Коне́чно, он говори́л обо мне, во вся́ком слу́чае, я при́нял его́ слова́ (на свой счёт).","b":1},{"t":"example","text":"Dịch: Tất nhiên là hắn nói về tôi, dù sao thì tôi cũng đã nhận những lời đó về phần mình (vơ vào mình/để bụng)."},{"t":"para","text":"Мне бы́ло стра́шно нело́вко, весь ве́чер я чу́вствовал себя́ (не в свое́й таре́лке).","b":1},{"t":"example","text":"Dịch: Tôi thấy cực kỳ gượng gạo, cả buổi tối tôi cảm thấy không thoải mái (như cá mắc cạn)."},{"t":"para","text":"Мне никто́ не разреша́л туда́ е́здить, я э́то сде́лал (на свой страх и риск).","b":1},{"t":"example","text":"Dịch: Không ai cho phép tôi đi đến đó, tôi đã làm điều đó bằng sự liều lĩnh của chính mình (tự chịu rủi ro)."},{"t":"para","text":"Что ты хо́дишь вокру́г да о́коло, называ́й (ве́щи свои́ми имена́ми).","b":1},{"t":"example","text":"Dịch: Sao bạn cứ vòng vo tam quốc thế, hãy gọi sự vật bằng đúng tên của nó (nói toạc móng heo ra)."},{"t":"para","text":"Заче́м тебе́ ли́шние забо́ты?! Живи́ для себя́, (в своё удово́льствие).","b":1},{"t":"example","text":"Dịch: Bạn cần gì những lo toan thừa thãi?! Hãy sống cho bản thân, sống hưởng thụ (thỏa thích)."},{"t":"para","text":"Пришёл он вчера́ бле́дный, сам (не свой).","b":1},{"t":"example","text":"Dịch: Hôm qua anh ấy đến mặt tái nhợt, người như mất hồn (bàng hoàng/không còn là mình)."},{"t":"para","text":"Ра́зве норма́льный челове́к так сде́лает! Он (не в своём уме́ / вы́жил из ума́).","b":1},{"t":"example","text":"Dịch: Chẳng lẽ người bình thường lại làm thế! Hắn bị điên rồi (không tỉnh táo)."},{"t":"para","text":"Он ни за что не хоте́л ложи́ться в больни́цу, говори́л, что предпочита́ет умере́ть (свое́й сме́ртью).","b":1},{"t":"example","text":"Dịch: Ông ấy nhất quyết không chịu nằm viện, nói rằng thà chết già (chết tự nhiên ở nhà)."}]},{"id":"03-s081","type":"exercise","title":"Bài 393 (Trang 192)","num":393,"blocks":[{"t":"example","text":"Đề bài: Thay thế dấu ba chấm bằng đại từ phủ định có tiểu từ не hoặc ни kèm giới từ nếu cần."},{"t":"para","text":"Алекса́ндра Па́вловна и Ле́жнев посмотре́ли ему́ вслед и обменя́лись взгля́дом, но (ничего́) не сказа́ли друг дру́гу.","b":1},{"t":"example","text":"Dịch: Alexandra Pavlovna và Lezhnev nhìn theo ông ấy và trao đổi ánh mắt, nhưng không nói gì với nhau cả."},{"t":"para","text":"Э́то был о́чень высо́кий и необыкнове́нно си́льный мужчи́на, молчали́вый, не теря́вший (ни в каки́х / ни при каки́х) опа́сностях свое́й суро́вой медли́тельности. Мне всегда́ безотчётно каза́лось, что на душе́ э́того челове́ка лежи́т что́-то стра́шное, чего́ он (никому́) не пове́дает, мо́жет быть, крова́вое преступле́ние.","b":1},{"t":"example","text":"Dịch: Đó là một người đàn ông rất cao lớn và cực kỳ khỏe mạnh, ít nói, người không đánh mất sự chậm chạp nghiêm nghị của mình trong bất kỳ nguy hiểm nào. Tôi luôn mơ hồ cảm thấy rằng trong tâm hồn người này có điều gì đó khủng khiếp mà ông ta sẽ không kể cho ai, có lẽ là một tội ác đẫm máu."},{"t":"para","text":"Я ... здесь не знако́м, А те, что по́мнили, давно́ забы́ли. И там, где был когда́-то о́тчий дом, Тепе́рь лежи́т зола́ да слой доро́жной пы́ли. А жизнь кипи́т. Вокру́г меня́ сную́т И ста́рые и молоды́е ли́ца. Но (не́кому) мне шля́пой поклони́ться, (Ни в чьих) глаза́х не нахожу́ прию́т.","b":1},{"t":"example","text":"Dịch: Tôi (không quen ai) ở đây (câu gốc có thể là ни с кем nhưng cấu trúc я не знаком cần bổ ngữ). Mà những người nhớ thì đã quên lâu rồi... Nhưng tôi không có ai để ngả mũ chào, tôi không tìm thấy sự nương tựa trong ánh mắt của bất kỳ ai."},{"t":"example","text":"Giải thích:"},{"t":"vocab","ru":"Некому поклониться","vi":"Không có đối tượng để chào (Vô nhân xưng với не).","g":null},{"t":"vocab","ru":"Ни в чьих глазах","vi":"Trong mắt của ai cả (Phủ định chung với ни).","g":null},{"t":"para","text":"— Чего́ смеёшься, болва́н? — Да чего́ мне смея́ться-то? Что мне! Я (ничему́) -с ... (не́над кем) на́шему бра́ту смея́ться.","b":1},{"t":"example","text":"Dịch: — Cười cái gì, đồ ngốc? — Tôi việc gì phải cười? Tôi có là gì đâu! Tôi chẳng cười cái gì cả ạ... Anh em chúng tôi chẳng có ai (tư cách gì) để mà cười nhạo."},{"t":"example","text":"Giải thích: Câu này trích trong văn học cổ (Dostoevsky), cấu trúc hơi đặc biệt. Ничему (không cười gì), не над кем (không có ai để cười nhạo)."},{"t":"para","text":"По вечера́м О́ленька сиде́ла на крыле́чке, и ей слы́шно бы́ло, как в “Ти́воли” игра́ла му́зыка и ло́пались раке́ты, но э́то уже́ не вызыва́ло (никаки́х) мы́слей. Гляде́ла она́ безуча́стно на свой пусто́й двор, (ни о чём) не ду́мала, (ничего́) не хоте́ла, а пото́м, когда́ наступа́ла ночь, шла спать и ви́дела во сне свой пусто́й двор. А гла́вное, что ху́же всего́, у неё уже́ не́ было (никако́го) мне́ния. Она́ ви́дела круго́м себя́ предме́ты и понима́ла всё, что происходи́ло вокру́г, но (ни о чём) не могла́ соста́вить мне́ния и не зна́ла, о чём ей говори́ть. А как э́то ужа́сно не име́ть (никако́го) мне́ния! Ви́дишь, наприме́р, как стои́т буты́лка, и́ли идёт дождь, и́ли е́дет мужи́к на теле́ге, но для чего́ э́та буты́лка, и́ли дождь, и́ли мужи́к, како́й в них смысл, сказа́ть не мо́жешь и да́же за ты́сячу рубле́й — не сказа́л бы (ничего́).","b":1},{"t":"example","text":"Dịch: ...nhưng điều đó không còn gợi lên suy nghĩ nào. Cô nhìn hờ hững... không nghĩ về điều gì, không muốn gì cả... tồi tệ nhất là cô không còn ý kiến nào nữa... nhưng không thể hình thành ý kiến về bất cứ điều gì... Thật kinh khủng khi không có ý kiến nào!... không thể nói được gì cả."},{"t":"para","text":"“Ну, что ж, (де́лать не́чего)”, — сказа́л стари́к. Он дви́нул не́сколько раз туда́ и сюда́ ферзём, как дви́гаешь рычаго́м испо́ртившейся маши́ны, и повтори́л: “... Ве́чный шах”. (В.Набо́ков).","b":1},{"t":"example","text":"Dịch: \"Chà, đành chịu thôi (chẳng làm gì được)\", ông già nói... và lặp lại: \"Hòa. Chiếu vĩnh viễn\"."},{"t":"example","text":"Giải thích: Делать нечего = đành chịu. Ничья = ván hòa (ở chỗ trống thứ 2 nếu cần danh từ, nhưng văn cảnh Nabokov có thể là Ничего не поделаешь hoặc tương tự. Tuy nhiên, Ничья hợp lý với cờ vua)."}]},{"id":"03-s082","type":"exercise","title":"Bài 394 (Trang 193)","num":394,"blocks":[{"t":"para","text":"Đề bài: Hoàn thành câu với các cụm từ cố định với đại từ phủ định."},{"t":"para","text":"Я здесь (ни при чём), меня́ в э́тот моме́нт вообще́ не́ было до́ма.","b":1},{"t":"example","text":"Dịch: Tôi không liên quan gì / vô can ở đây, lúc đó tôi hoàn toàn không có nhà."},{"t":"para","text":"— Как он? Жале́ет о том, что случи́лось? — (Ничего́) подо́бного! Хо́дит (как ни в чём) не быва́ло;","b":1},{"t":"example","text":"Dịch: — Nó thế nào? Có hối hận không? — Không đời nào (chẳng có chuyện đó)! Nó đi lại như không có chuyện gì xảy ra."},{"t":"para","text":"Не на́до зря теря́ть вре́мя, мне ва́ша по́мощь (ни к чему́);","b":1},{"t":"example","text":"Dịch: Đừng lãng phí thời gian vô ích, sự giúp đỡ của bạn chẳng cần thiết / vô ích với tôi."},{"t":"para","text":"Наве́рное, сего́дня ничего́ у нас с тобо́й не полу́чится, придётся верну́ться (ни с чем);","b":1},{"t":"example","text":"Dịch: Chắc hôm nay chúng ta chẳng làm được gì đâu, đành phải quay về tay trắng."},{"t":"para","text":"О чём тут ду́мать! Ра́зве у нас есть друго́й вы́ход? Де́лать (не́чего), придётся с ни́ми согласи́ться;","b":1},{"t":"example","text":"Dịch: Còn nghĩ ngợi gì nữa! Chúng ta làm gì còn lối thoát nào khác? Chẳng làm gì được khác (Đành chịu), buộc phải đồng ý với họ thôi."},{"t":"para","text":"... (Ничего́) себе́ сове́т! Да ра́зве я смогу́ им когда́-нибу́дь воспо́льзоваться?!","b":1},{"t":"example","text":"Dịch: Gớm, lời khuyên ghê nhỉ! Liệu tôi có bao giờ dùng được nó không?! (Ничего себе - thán từ ngạc nhiên/mỉa mai)."},{"t":"para","text":"... (Не́чего) таи́ть, расска́зывай, как всё бы́ло;","b":1},{"t":"example","text":"Dịch: Giấu giếm làm gì (Không việc gì phải giấu), kể xem mọi chuyện thế nào. (Нечего греха таить - thành ngữ)."},{"t":"para","text":"На́чал я чита́ть э́ту кни́гу от ску́ки, от (не́чего де́лать), но пото́м втяну́лся;","b":1},{"t":"example","text":"Dịch: Tôi bắt đầu đọc cuốn này vì buồn chán, vì rảnh rỗi quá (không có việc gì làm), nhưng sau đó lại bị cuốn hút."},{"t":"para","text":"По-мо́ему, положе́ние у тебя́ и так сло́жное, теря́ть (не́чего), мо́жно попро́бовать и э́тот вариа́нт.","b":1},{"t":"example","text":"Dịch: Theo tôi, tình thế của bạn đằng nào cũng phức tạp rồi, chẳng còn gì để mất, có thể thử phương án này xem sao."}]},{"id":"03-s083","type":"exercise","title":"Bài 395 (Trang 193)","num":395,"blocks":[{"t":"example","text":"Đề bài: Thay thế dấu ba chấm bằng đại từ bất định (некто, нечто...) hoặc số từ несколько. Mở ngoặc."},{"t":"para","text":"a)","b":1},{"t":"para","text":"Пра́вильный ова́л лица́, (не́сколько сму́глый), превосхо́дные зу́бы...","b":1},{"t":"example","text":"Dịch: Khuôn mặt trái xoan cân đối, hơi ngăm đen, hàm răng tuyệt vời..."},{"t":"example","text":"Giải thích: Несколько + tính từ ngắn đuôi/dài đuôi = hơi, một chút."},{"t":"para","text":"... (не́которые сло́ги) он произно́сит необыкнове́нно сла́дко...","b":1},{"t":"example","text":"Dịch: ...anh ấy phát âm một số âm tiết nhất định ngọt ngào lạ thường..."},{"t":"example","text":"Giải thích: Chỉ một bộ phận cụ thể → некоторые."},{"t":"para","text":"Бе́дная мада́м Леота́р... начала́ объясня́ть ему́, что наказа́ние само́ по себе́ хоро́шее... и что да́же Жан-Жак Руссо́ говори́т (не́что подо́бное).","b":1},{"t":"example","text":"Dịch: Bà Leotar tội nghiệp... bắt đầu giải thích... rằng ngay cả Rousseau cũng nói điều gì đó tương tự."},{"t":"example","text":"Giải thích: Điều gì đó trừu tượng → нечто."},{"t":"para","text":"... (не́сколько) раз я просыпа́лся и ка́ждый раз ви́дел склони́вшееся на́до мной сострада́тельное, забо́тливое ли́чико Еле́ны (Ф.Достое́вский).","b":1},{"t":"example","text":"Dịch: Tôi đã tỉnh giấc vài lần và lần nào cũng thấy khuôn mặt nhỏ nhắn đầy thương cảm và lo lắng của Elena cúi xuống tôi."},{"t":"example","text":"Giải thích: Số lượng lần → несколько."},{"t":"para","text":"б)","b":1},{"t":"para","text":"Несмотря́ на то что недослу́шанный план Серге́я Ива́новича о том, как освобождённый сорокамиллио́нный мир славя́н до́лжен вме́сте с Росси́ей нача́ть но́вую эпо́ху в исто́рии, о́чень заинтересова́л его́, как (не́что соверше́нно но́вое) для него́...","b":1},{"t":"example","text":"Dịch: Mặc dù kế hoạch chưa nghe hết của Sergei Ivanovich... đã làm ông rất quan tâm, như là một điều gì đó hoàn toàn mới mẻ đối với ông..."},{"t":"example","text":"Giải thích: Нечто đi với tính từ giống trung số ít."},{"t":"para","text":"Ки́ти взгляну́ла на сестру́, и холо́дное, (не́сколько) суро́вое выраже́ние её лица́ измени́лось;","b":1},{"t":"example","text":"Dịch: Kitty nhìn chị gái, và vẻ mặt lạnh lùng, hơi nghiêm nghị của cô ấy đã thay đổi."},{"t":"para","text":"Весь день э́тот А́нна провела́ до́ма, то есть у Обло́нских, и не принима́ла никого́, так как уж (не́которые из её знако́мых), из её знако́мых, узна́в о её прибы́тии, приезжа́ли в э́тот же день.","b":1},{"t":"example","text":"Dịch: Anna ở nhà cả ngày... và không tiếp ai, vì một số người quen của cô ấy, khi biết tin cô đến, đã ghé qua ngay trong ngày."},{"t":"example","text":"Giải thích: Một nhóm người trong số những người quen → некоторые."},{"t":"para","text":"Они́ объе́здили Вене́цию, Рим, Неа́поль и то́лько что прие́хали в небольшо́й италья́нский го́род, где хоте́ли посели́ться на (не́которое вре́мя).","b":1},{"t":"example","text":"Dịch: Họ đã đi khắp Venice, Rome, Naples và vừa đến một thị trấn nhỏ ở Ý, nơi họ muốn định cư trong một khoảng thời gian (nào đó)."},{"t":"para","text":"Пото́м до́брая и (не́сколько) жа́лкая улы́бка показа́лась на его́ краси́вом лице́ (Л.Толсто́й).","b":1},{"t":"example","text":"Dịch: Sau đó một nụ cười hiền hậu và hơi thảm hại hiện lên trên khuôn mặt đẹp trai của anh ấy."}]},{"id":"03-s084","type":"exercise","title":"Bài 396 (Trang 194)","num":396,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"para","text":"Bài tập này yêu cầu phân biệt các đại từ ка́ждый (mỗi/từng), вся́кий (mọi/đủ loại), любо́й (bất kỳ)."},{"t":"vocab","ru":"Ка́ждый","vi":"Nhấn mạnh từng cá thể trong một nhóm, mang tính liệt kê.","g":null},{"t":"vocab","ru":"Вся́кий","vi":"Mang nghĩa \"đủ loại\", \"khác nhau\", hoặc \"bất cứ ai\" (nhấn mạnh tính chất đa dạng).","g":null},{"t":"vocab","ru":"Любо́й","vi":"Mang nghĩa \"bất kỳ cái nào\" (nhấn mạnh sự tự do lựa chọn).","g":null},{"t":"example","text":"Đề bài: Thay thế dấu ba chấm bằng các từ cần thiết (ка́ждый, вся́кий, любо́й)."},{"t":"para","text":"a)","b":1},{"t":"vocab","ru":"У дверей ка́ждого третьего дома была вывешена дощечка","vi":"сдается, мол, комната;","g":null},{"t":"example","text":"Dịch: Trước cửa mỗi ngôi nhà thứ ba đều có treo một tấm biển nhỏ: cho thuê phòng."},{"t":"example","text":"Giải thích: Chỉ sự lặp lại theo quy luật (cứ cách 3 nhà lại có 1 nhà), nhấn mạnh từng trường hợp cụ thể → ка́ждого."},{"t":"para","text":"Осмотрел он за два часа одиннадцать комнат, на трёх улицах. Строго говоря, ... из них была прекрасна, но у ... был крохотный недостаток;","b":1},{"t":"subhead","text":"Đáp án: ка́ждая ... ка́ждой (hoặc люба́я ở vế đầu nếu ý là \"cái nào cũng được\", nhưng theo văn cảnh mô tả từng cái thì каждая chuẩn hơn)."},{"t":"example","text":"Viết lại: Строго говоря, ка́ждая из них была прекрасна, но у ка́ждой был крохотный недостаток."},{"t":"example","text":"Dịch: Nói một cách nghiêm túc, mỗi phòng trong số đó đều tuyệt vời, nhưng ở mỗi phòng đều có một khuyết điểm nhỏ tí xíu."},{"t":"para","text":"Нужно, значит, обратиться к другим способам передвижения, вплоть до подземной железной дороги, привозившей очень удобно из любо́й части города на ту улицу, которая выходила на площадь, где по вторникам и пятницам продавалась рыба, шерстяные носки, ... всячина (В.Набоков).","b":1},{"t":"subhead","text":"Đáp án: любо́й ... вся́кая"},{"t":"example","text":"Dịch: Có nghĩa là cần phải tìm đến các phương thức di chuyển khác, kể cả tàu điện ngầm, loại tàu chở khách rất thuận tiện từ bất kỳ phần nào của thành phố đến con phố dẫn ra quảng trường, nơi mà vào thứ Ba và thứ Sáu người ta bán cá, tất len và đủ thứ linh tinh."},{"t":"example","text":"Giải thích: из любой части (từ bất kỳ đâu - sự lựa chọn); всякая всячина (thành ngữ: đủ thứ hầm bà lằng/chuyện linh tinh)."},{"t":"para","text":"б)","b":1},{"t":"para","text":"Вернее, это был не разговор, а мой монолог. Блестящий монолог, за который любо́й из профессоров поставил бы пятёрку пятикурснику;","b":1},{"t":"subhead","text":"Đáp án: любо́й"},{"t":"example","text":"Dịch: Đúng hơn, đó không phải là cuộc trò chuyện, mà là độc thoại của tôi. Một màn độc thoại xuất sắc mà bất kỳ giáo sư nào cũng sẽ cho sinh viên năm 5 điểm xuất sắc."},{"t":"example","text":"Giải thích: Ai cũng được, không quan trọng là ai → любо́й."},{"t":"para","text":"С (Со) ... днем всё сильнее зеленеющие липы и ветла за окном источали весенний запах;","b":1},{"t":"subhead","text":"Đáp án: ка́ждым"},{"t":"example","text":"Viết lại: С ка́ждым днём всё сильнее..."},{"t":"example","text":"Dịch: Qua mỗi ngày, những cây bồ đề và cây liễu sau cửa sổ ngày càng xanh hơn và tỏa hương xuân."},{"t":"example","text":"Giải thích: Cụm cố định с каждым днём (ngày qua ngày/mỗi ngày một...)."},{"t":"para","text":"Неблагодарный! Я забыл свой боевой пост, где я один без ... поддержки боролся с болезнями, своими силами, помню, как герой Фенимора Купера выбираясь из самых диковинных положений;","b":1},{"t":"subhead","text":"Đáp án: вся́кой"},{"t":"example","text":"Viết lại: ...без вся́кой поддержки..."},{"t":"example","text":"Dịch: Đồ vô ơn! Tôi đã quên vị trí chiến đấu của mình, nơi tôi một mình chiến đấu với bệnh tật mà không có bất kỳ sự hỗ trợ nào..."},{"t":"example","text":"Giải thích: Trong câu phủ định (без), всякий mang nghĩa \"bất cứ... nào\" (hoàn toàn không)."},{"t":"para","text":"Об исчезнувших и о проклятой квартире долго в доме рассказывали ... легенды;","b":1},{"t":"subhead","text":"Đáp án: вся́кие"},{"t":"example","text":"Dịch: Trong ngôi nhà đó người ta đã kể mãi đủ loại truyền thuyết về những người mất tích và về căn hộ bị nguyền rủa."},{"t":"example","text":"Giải thích: Всякие = các loại khác nhau, đa dạng."},{"t":"para","text":"Нет сомнения, что если бы профессор осуществил этот план, ему очень легко удалось бы устроиться при кафедре зоологии в любо́м университете мира;","b":1},{"t":"subhead","text":"Đáp án: любо́м"},{"t":"example","text":"Dịch: Không nghi ngờ gì nữa, nếu giáo sư thực hiện kế hoạch này, ông ấy sẽ rất dễ dàng xin được việc tại khoa động vật học ở bất kỳ trường đại học nào trên thế giới."},{"t":"example","text":"Giải thích: Tùy chọn trường nào cũng được → любо́м."},{"t":"para","text":"... букву на листе можно было разглядеть без ... лампы (М.Булгаков).","b":1},{"t":"subhead","text":"Đáp án: Ка́ждую ... вся́кой"},{"t":"example","text":"Viết lại: Ка́ждую букву на листе можно было разглядеть без вся́кой лампы."},{"t":"example","text":"Dịch: Có thể nhìn rõ từng/mỗi chữ cái trên tờ giấy mà không cần bất kỳ ngọn đèn nào."}]},{"id":"03-s085","type":"exercise","title":"Bài 397 (Trang 194)","num":397,"blocks":[{"t":"example","text":"Đề bài: Thay thế dấu ba chấm bằng các từ cần thiết (весь, вся́кий - đại từ) hoặc (це́лый, по́лный - tính từ)."},{"t":"para","text":"Хотя Пандалевский и рассказывал про нее, что она знает всю Европу, да и Европа её знает! — однако Европа её знала мало, даже в Петербурге она важной роли не играла; зато в Москве её все знали и ездили к ней;","b":1},{"t":"example","text":"Dịch: Mặc dù Pandalevsky kể về bà ấy rằng bà ấy biết toàn bộ châu Âu, và châu Âu cũng biết bà! — tuy nhiên châu Âu biết bà rất ít... bù lại ở Moscow tất cả mọi người (ai ai cũng) đều biết và đến thăm bà."},{"t":"example","text":"Điền: всю (toàn bộ - địa lý), все (tất cả mọi người)."},{"t":"para","text":"Вы, может, думаете, я стихов не писал? Писал-с и даже це́лую драму сочинил, в подражание “Манфреду”;","b":1},{"t":"example","text":"Dịch: Có lẽ các ngài nghĩ tôi không làm thơ ư? Tôi có viết đấy và thậm chí đã soạn cả một vở kịch (nguyên vẹn), bắt chước \"Manfred\"."},{"t":"example","text":"Điền: це́лую (nhấn mạnh sự trọn vẹn, độ lớn của tác phẩm)."},{"t":"para","text":"Я не знаю, согласитесь ли вы со мною, Дарья Михайловна, но в отрицании — в отрицании и всеобщем — нет благодати. Отрицайте всё — и вы легко прослывете за умницу: это уловка известная. Простодушные люди сейчас готовы заключить, что вы стоите выше того, что отрицаете...;","b":1},{"t":"example","text":"Dịch: ...nhưng trong sự phủ nhận — sự phủ nhận toàn diện... Hãy phủ nhận tất cả (mọi thứ)... các ngài đứng cao hơn điều mà các ngài phủ nhận."},{"t":"example","text":"Điền: всё (tất cả mọi thứ). (Lưu ý: Chỗ trống đầu trong ảnh bị mờ, nếu là \"в отрицании всего\" - phủ nhận mọi thứ, hoặc ngữ cảnh này điền всё ở chỗ thứ 2 là chắc chắn)."},{"t":"para","text":"А вот и ваше имущество, Маргарита Николаевна, — и он подал Маргарите тетрадь с обгоревшими краями, засохшую розу, фотографию и, с ... бережностью, сберегательную книжку (М.Булгаков);","b":1},{"t":"example","text":"Điền: по́лной (hoặc вели́кой/осо́бой nhưng đề yêu cầu nhóm từ полный...) → по́лной."},{"t":"example","text":"Dịch: ...và, với sự cẩn trọng hết mức/hoàn toàn, cuốn sổ tiết kiệm."},{"t":"para","text":"Охотник сел на скамью, подумал и, мокрый, разлёгся вдоль всей скамьи;","b":1},{"t":"example","text":"Dịch: Người thợ săn ngồi xuống ghế, suy nghĩ và, ướt sũng, nằm dài dọc theo toàn bộ chiếc ghế."},{"t":"example","text":"Điền: всей (chỉ toàn bộ chiều dài)."},{"t":"para","text":"И в этом постоянстве, в ... равнодушии к жизни и смерти каждого из нас кроется, быть может, залог нашего вечного спасения, непрерывного движения жизни на земле, непрерывного совершенства;","b":1},{"t":"example","text":"Điền: по́лном"},{"t":"example","text":"Dịch: Và trong sự bất biến này, trong sự thờ ơ hoàn toàn đối với sự sống và cái chết của mỗi chúng ta..."},{"t":"para","text":"Прощай! Я так несчастлив! Ты оставляешь меня на це́лую неделю!","b":1},{"t":"example","text":"Dịch: Tạm biệt! Anh thật bất hạnh! Em bỏ lại anh tận (cả một) tuần!"},{"t":"example","text":"Điền: це́лую (nhấn mạnh thời gian dài)."},{"t":"para","text":"Для любящего сердца день вещь это ... вечность!","b":1},{"t":"example","text":"Điền: це́лая"},{"t":"example","text":"Dịch: Đối với trái tim đang yêu, một ngày là cả một sự vĩnh hằng!"},{"t":"para","text":"Маленький лоб его собрался в морщины, на носу играют пятна вся́ких цветов, начиная с розового и кончая тёмно-синим;","b":1},{"t":"example","text":"Dịch: ...trên mũi hiện lên những đốm đủ màu sắc (mọi loại màu)..."},{"t":"example","text":"Điền: вся́ких (chỉ sự đa dạng)."},{"t":"para","text":"Её сестёр, Мисю́сь, не имела никаких забот и проводила свою жизнь в по́лной праздности, как я;","b":1},{"t":"example","text":"Dịch: Em gái cô ấy, Misyus, không phải lo nghĩ gì và sống cuộc đời mình trong sự nhàn rỗi hoàn toàn, giống như tôi."},{"t":"example","text":"Điền: по́лной (mức độ tuyệt đối)."},{"t":"para","text":"Прошло этак два месяца, и кончилась ... эта история ужаснейшим образом;","b":1},{"t":"example","text":"Điền: вся"},{"t":"example","text":"Dịch: Khoảng hai tháng trôi qua, và toàn bộ câu chuyện này đã kết thúc một cách khủng khiếp."},{"t":"para","text":"Нетерпеливый, замученный генерал пообещал дать пять рублей тому, кто вспомнит настоящую фамилию, и за Иваном Евсеичем стали ходить це́лыми толпами (А.Чехов).","b":1},{"t":"example","text":"Dịch: ...và người ta bắt đầu đi theo Ivan Evseich thành cả đám đông (từng đoàn đông đúc)."},{"t":"example","text":"Điền: це́лыми."}]},{"id":"03-s086","type":"exercise","title":"Bài 398 (Trang 195)","num":398,"blocks":[{"t":"example","text":"Đề bài: Hoàn thành câu bằng các cụm từ cố định (thành ngữ) chứa весь, це́лый, по́лный, ка́ждый, любо́й."},{"t":"para","text":"День у меня завтра будет тяжёлый, хлопот по́лон рот;","b":1},{"t":"example","text":"Dịch: Ngày mai tôi sẽ rất vất vả, bận tối mắt tối mũi (việc ngập đến mồm)."},{"t":"para","text":"Постарайся достать билет все́ми пра́вдами и непра́вдами;","b":1},{"t":"example","text":"Dịch: Hãy cố gắng kiếm vé bằng mọi giá (bằng mọi cách dù đúng hay sai)."},{"t":"para","text":"Чего ещё человеку нужно?! Двое детей, дом — по́лная ча́ша, а жена красавица;","b":1},{"t":"example","text":"Dịch: Con người ta còn cần gì nữa?! Hai đứa con, nhà giàu có sung túc (như bát đầy), lại có vợ đẹp."},{"t":"para","text":"Главное, чтобы ты вернулся домой це́лым и невреди́мым;","b":1},{"t":"example","text":"Dịch: Quan trọng nhất là con trở về nhà bình an vô sự (lành lặn)."},{"t":"para","text":"От этого прилагательного нельзя образовать по́лную фо́рму;","b":1},{"t":"example","text":"Dịch: Từ tính từ này không thể tạo thành dạng đầy đủ (thuật ngữ ngữ pháp)."},{"t":"para","text":"Сейчас важно обсудить этот вопрос в о́бщем и це́лом, а уж потом мы вернёмся к деталям;","b":1},{"t":"example","text":"Dịch: Bây giờ quan trọng là thảo luận vấn đề này một cách tổng quát (nhìn chung), rồi sau đó chúng ta sẽ quay lại các chi tiết."},{"t":"para","text":"Эту информацию надо довести до сведения всех и ка́ждого;","b":1},{"t":"example","text":"Dịch: Thông tin này cần được phổ biến đến tất cả và từng người một (mọi người)."},{"t":"para","text":"Ты должен любо́й цено́й выполнить это задание;","b":1},{"t":"example","text":"Dịch: Bạn phải hoàn thành nhiệm vụ này bằng bất cứ giá nào."},{"t":"para","text":"Я думаю, всё будет так, как запланировано, во вся́ком слу́чае, никто об изменениях ничего не знает;","b":1},{"t":"example","text":"Dịch: Tôi nghĩ mọi việc sẽ như kế hoạch, dù sao thì (ít nhất là) cũng không ai biết gì về những thay đổi."},{"t":"para","text":"Запиши на вся́кий слу́чай мой номер телефона, может быть, тебе понадобится моя помощь;","b":1},{"t":"example","text":"Dịch: Hãy ghi lại số điện thoại của tôi để phòng hờ (nhỡ đâu), có thể bạn sẽ cần tôi giúp."},{"t":"para","text":"Уже все сотрудники знают, что ты уезжаешь в командировку, я слышу об этом на ка́ждом углу́ (шагу́).","b":1},{"t":"example","text":"Dịch: Tất cả nhân viên đều biết bạn đi công tác, tôi nghe thấy điều này ở khắp nơi (mọi ngóc ngách)."}]}]};
